export enum Stage {
  KINESIOLOGY = 'Kinesiología',
  GYM = 'Gimnasio',
}

export interface ExerciseLog {
  date: string;
  load: number;
  reps: number;
  rpe: number; // Rate of Perceived Exertion (1-10)
}

export interface ExerciseDefinition {
  id: string;
  name: string;
  category: string;
  videoUrl?: string; // Placeholder for GIF/Video
}

export interface RoutineExercise {
  id: string; // Unique instance id in routine
  definitionId: string;
  definition: ExerciseDefinition;
  targetSets: number;
  targetReps: number;
  targetLoad: number; // kg
  currentRpe?: number; // For the current active session
  notes?: string;
  isDone: boolean;
  history: ExerciseLog[];
}

export interface RoutineDay {
  id: string;
  name: string; // "Día 1", "Tren Superior", etc.
  exercises: RoutineExercise[];
}

export interface Routine {
  id: string;
  stage: Stage;
  days: RoutineDay[];
}

