import React from 'react';
import { Patient } from '../types';
import { Users, Plus, X } from 'lucide-react';

interface SidebarProps {
  activePatients: Patient[];
  selectedPatientId: string | null;
  onSelectPatient: (patientId: string) => void;
  onRemoveActive: (patientId: string, e: React.MouseEvent) => void;
  onGoHome: () => void;
}

export const Sidebar: React.FC<SidebarProps> = ({
  activePatients,
  selectedPatientId,
  onSelectPatient,
  onRemoveActive,
  onGoHome,
}) => {
  return (
    <div className="w-24 bg-white border-r border-slate-200 flex flex-col items-center py-6 h-screen z-50 shadow-sm shrink-0">
      {/* Home / Patient List Button */}
      <button
        onClick={onGoHome}
        className={`w-14 h-14 rounded-2xl flex items-center justify-center mb-8 transition-colors ${
          !selectedPatientId
            ? 'bg-primary-600 text-white shadow-md'
            : 'bg-slate-100 text-slate-500 hover:bg-slate-200'
        }`}
      >
        <Users size={28} />
      </button>

      {/* Separator */}
      <div className="w-10 h-px bg-slate-200 mb-6"></div>

      {/* Active Patients List */}
      <div className="flex flex-col gap-4 overflow-y-auto no-scrollbar w-full items-center pb-20">
        {activePatients.map((patient) => {
          const isActive = selectedPatientId === patient.id;
          return (
            <div key={patient.id} className="relative group">
              <button
                onClick={() => onSelectPatient(patient.id)}
                className={`relative w-16 h-16 rounded-full border-4 overflow-hidden transition-all duration-200 ${
                  isActive
                    ? 'border-primary-500 ring-4 ring-primary-100 scale-110 z-10'
                    : 'border-white bg-slate-100 grayscale-[0.5] hover:grayscale-0'
                }`}
              >
                <img
                  src={patient.photoUrl}
                  alt={patient.firstName}
                  className="w-full h-full object-cover"
                />
              </button>

              {/* Initials Label (for quick scanning) */}
              <div className="text-xs text-center font-bold text-slate-600 mt-1 truncate w-16">
                {patient.firstName}
              </div>

              {/* Quick Close Button (Visible on hover/active) */}
              <button
                onClick={(e) => onRemoveActive(patient.id, e)}
                className="absolute -top-1 -right-1 bg-red-500 text-white rounded-full p-1 opacity-0 group-hover:opacity-100 transition-opacity shadow-sm"
              >
                <X size={12} />
              </button>
            </div>
          );
        })}

        {activePatients.length === 0 && (
          <div className="text-xs text-slate-400 text-center px-2">
            Sin pacientes activos
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Patient, Stage } from '../types';
import { Search, Clock, ChevronRight, Activity } from 'lucide-react';

interface PatientListProps {
  patients: Patient[];
  onSelectPatient: (patient: Patient) => void;
}

export const PatientList: React.FC<PatientListProps> = ({
  patients,
  onSelectPatient,
}) => {
  const [searchTerm, setSearchTerm] = useState('');

  const filteredPatients = patients.filter((p) => {
    const fullName = `${p.firstName} ${p.lastName}`.toLowerCase();
    return fullName.includes(searchTerm.toLowerCase());
  });

  // Simple logic for "Recent" - in a real app this would be sorted by access time
  const recentPatients = patients.slice(0, 3);

  return (
    <div className="flex-1 h-screen overflow-y-auto bg-slate-50 p-6 md:p-8">
      <div className="max-w-4xl mx-auto space-y-8">

        {/* Header & Search */}
        <div className="space-y-4">
          <h1 className="text-3xl font-bold text-slate-900">Pacientes</h1>
          <div className="relative">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={24} />
            <input
              type="text"
              placeholder="Buscar paciente por nombre..."
              className="w-full h-16 pl-14 pr-6 rounded-2xl border-none shadow-sm text-lg focus:ring-4 focus:ring-primary-100"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              autoFocus
            />
          </div>
        </div>

        {/* Recent Patients (Only show if not searching) */}
        {!searchTerm && (
          <div className="space-y-4">
            <div className="flex items-center gap-2 text-slate-500 font-semibold uppercase text-sm tracking-wider">
              <Clock size={16} />
              <span>Recientes</span>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              {recentPatients.map((patient) => (
                <button
                  key={patient.id}
                  onClick={() => onSelectPatient(patient)}
                  className="bg-white p-4 rounded-xl shadow-sm border border-slate-100 flex items-center gap-4 hover:shadow-md transition-shadow text-left"
                >
                  <img
                    src={patient.photoUrl}
                    alt={patient.firstName}
                    className="w-14 h-14 rounded-full object-cover"
                  />
                  <div>
                    <h3 className="font-bold text-slate-800 text-lg">
                      {patient.firstName} {patient.lastName}
                    </h3>
                    <p className="text-slate-500 text-sm">{patient.condition}</p>
                  </div>
                </button>
              ))}
            </div>
          </div>
        )}

        {/* All Patients List */}
        <div className="space-y-4">
          <div className="flex items-center gap-2 text-slate-500 font-semibold uppercase text-sm tracking-wider">
            <UsersIcon size={16} />
            <span>Todos los pacientes</span>
          </div>

          <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
            {filteredPatients.length > 0 ? (
              filteredPatients.map((patient, index) => (
                <div
                  key={patient.id}
                  onClick={() => onSelectPatient(patient)}
                  className={`flex items-center p-5 cursor-pointer hover:bg-slate-50 transition-colors ${
                    index !== filteredPatients.length - 1 ? 'border-b border-slate-100' : ''
                  }`}
                >
                  <img
                    src={patient.photoUrl}
                    alt={patient.firstName}
                    className="w-12 h-12 rounded-full object-cover mr-4"
                  />
                  <div className="flex-1">
                    <h3 className="font-bold text-slate-800 text-lg">
                      {patient.firstName} {patient.lastName}
                    </h3>
                    <div className="flex items-center gap-2 mt-1">
                        <span className={`px-2 py-0.5 rounded-full text-xs font-bold ${
                            patient.routine.stage === Stage.KINESIOLOGY ? 'bg-kine/10 text-kine' : 'bg-gym/10 text-gym'
                        }`}>
                            {patient.routine.stage}
                        </span>
                        <span className="text-slate-400 text-sm">• {patient.condition}</span>
                    </div>
                  </div>
                  <ChevronRight className="text-slate-300" />
                </div>
              ))
            ) : (
              <div className="p-10 text-center text-slate-400">
                No se encontraron pacientes
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

