import React, { useState, useEffect } from 'react';
import { Patient, RoutineDay, RoutineExercise } from '../types';
import { EXERCISES } from '../constants';
import { ExerciseCard } from './ExerciseCard';
import { ProgressChart } from './ProgressChart';
import { Calendar, AlertCircle, FileText, ChevronDown, Plus, Search, X, LayoutGrid, Save } from 'lucide-react';

interface PatientDetailProps {
  patient: Patient;
  onUpdatePatient: (updated: Patient) => void;
}

export const PatientDetail: React.FC<PatientDetailProps> = ({
  patient,
  onUpdatePatient,
}) => {
  const [activeDayId, setActiveDayId] = useState<string>(
    patient.routine.days[0]?.id || ''
  );
  const [showHistory, setShowHistory] = useState<boolean>(false);
  const [showWeeklyView, setShowWeeklyView] = useState<boolean>(false);
  const [chartExercise, setChartExercise] = useState<RoutineExercise | null>(null);
  const [isAddingExercise, setIsAddingExercise] = useState(false);
  const [exerciseSearch, setExerciseSearch] = useState('');

  // Local state for editable notes
  const [notes, setNotes] = useState(patient.history[0] || '');

  // Sync notes when patient changes
  useEffect(() => {
    setNotes(patient.history[0] || '');
  }, [patient.id]);

  const activeDay = patient.routine.days.find((d) => d.id === activeDayId);

  // --- Handlers ---
  const handleSaveNotes = () => {
      const newHistory = [...patient.history];
      if (newHistory.length === 0) {
          newHistory.push(notes);
      } else {
          newHistory[0] = notes;
      }
      onUpdatePatient({ ...patient, history: newHistory });
  };

  const handleExerciseUpdate = (exerciseId: string, updates: Partial<RoutineExercise>) => {
    const newPatient = { ...patient };
    const dayIndex = newPatient.routine.days.findIndex(d => d.id === activeDayId);
    if (dayIndex === -1) return;

    const exIndex = newPatient.routine.days[dayIndex].exercises.findIndex(e => e.id === exerciseId);
    if (exIndex === -1) return;

    newPatient.routine.days[dayIndex].exercises[exIndex] = {
        ...newPatient.routine.days[dayIndex].exercises[exIndex],
        ...updates
    };

    onUpdatePatient(newPatient);
  };

  const handleRemoveExercise = (exerciseId: string) => {
      const newPatient = { ...patient };
      const dayIndex = newPatient.routine.days.findIndex(d => d.id === activeDayId);
      if (dayIndex === -1) return;

      newPatient.routine.days[dayIndex].exercises = newPatient.routine.days[dayIndex].exercises.filter(
          e => e.id !== exerciseId
      );
      onUpdatePatient(newPatient);
  };

  const handleAddExercise = (defId: string) => {
      const definition = EXERCISES.find(e => e.id === defId);
      if(!definition) return;

      const newPatient = { ...patient };
      const dayIndex = newPatient.routine.days.findIndex(d => d.id === activeDayId);
      if (dayIndex === -1) return;

      const newExercise: RoutineExercise = {
          id: `re-${Date.now()}`,
          definitionId: definition.id,
          definition: definition,
          targetSets: 3,
          targetReps: 10,
          targetLoad: 0,
          isDone: false,
          history: []
      };

      newPatient.routine.days[dayIndex].exercises.push(newExercise);
      onUpdatePatient(newPatient);
      setIsAddingExercise(false);
      setExerciseSearch('');
  };

  const filteredCatalog = EXERCISES.filter(ex => 
    ex.name.toLowerCase().includes(exerciseSearch.toLowerCase()) || 
    ex.category.toLowerCase().includes(exerciseSearch.toLowerCase())
  );

  return (
    <div className="flex-1 h-screen flex flex-col bg-slate-50 overflow-hidden relative">

      {/* 1. TOP HEADER: Patient Info & Context */}
      <header className="bg-white border-b border-slate-200 px-6 py-4 flex items-center justify-between shadow-sm shrink-0 z-20">
        <div className="flex items-center gap-4">
          <div className="flex flex-col">
            <h2 className="text-2xl font-bold text-slate-900 leading-none">
              {patient.firstName} {patient.lastName}
            </h2>
            <div className="flex items-center gap-2 mt-1">
                <span className="text-sm font-medium text-slate-500">{patient.condition}</span>
                <span className="w-1 h-1 bg-slate-300 rounded-full"></span>
                <span className="text-sm text-slate-400">{patient.age} años</span>
            </div>
          </div>
        </div>

        {/* Action Buttons */}
        <div className="flex gap-2">
            <button 
                onClick={() => setShowWeeklyView(true)}
                className="flex items-center gap-2 px-4 py-2 rounded-lg font-medium transition-colors bg-white border border-slate-200 text-slate-600 hover:bg-slate-50"
            >
                <LayoutGrid size={18} />
                <span>Vista Semanal</span>
            </button>
            <button 
                onClick={() => setShowHistory(!showHistory)}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg font-medium transition-colors ${showHistory ? 'bg-slate-800 text-white' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'}`}
            >
                <FileText size={18} />
                <span>{showHistory ? 'Ocultar Ficha' : 'Ver Ficha'}</span>
            </button>
        </div>
      </header>

      {/* 2. HISTORY DRAWER (Collapsible) */}
      {showHistory && (
          <div className="bg-slate-800 text-slate-200 px-8 py-6 shadow-inner shrink-0 animate-in slide-in-from-top-5 border-b border-slate-700">
              <div className="grid grid-cols-1 md:grid-cols-3 gap-8 max-w-5xl">
                  <div className="md:col-span-1">
                       <h4 className="text-slate-400 text-xs uppercase font-bold mb-2">Datos Clínicos</h4>
                       <div className="space-y-4">
                            <div>
                                <h5 className="text-slate-500 text-xs font-bold">Última Visita</h5>
                                <p className="text-sm font-mono bg-slate-700 w-fit px-2 py-1 rounded mt-1">{patient.lastVisit}</p>
                            </div>
                            <div>
                                <h5 className="text-slate-500 text-xs font-bold">Alertas</h5>
                                <div className="flex items-start gap-2 text-amber-400 text-sm mt-1">
                                    <AlertCircle size={16} className="mt-0.5 shrink-0" />
                                    <span>Controlar dolor.</span>
                                </div>
                            </div>
                       </div>
                  </div>
                  <div className="md:col-span-2">
                      <div className="flex justify-between items-center mb-2">
                        <h4 className="text-slate-400 text-xs uppercase font-bold">Observaciones / Evolución</h4>
                        <span className="text-xs text-slate-500 italic">Se guarda automáticamente</span>
                      </div>
                      <textarea 
                        className="w-full h-32 bg-slate-700 text-slate-200 p-4 rounded-xl border border-slate-600 focus:ring-2 focus:ring-primary-500 outline-none resize-none leading-relaxed"
                        value={notes}
                        onChange={(e) => setNotes(e.target.value)}
                        onBlur={handleSaveNotes}
                        placeholder="Escribe aquí las observaciones clínicas..."
                      />
                  </div>
              </div>
          </div>
      )}

      {/* 3. DAY SELECTOR (Tabs) */}
      <div className="bg-white border-b border-slate-200 px-6 flex gap-1 pt-4 overflow-x-auto no-scrollbar shrink-0">
        {patient.routine.days.map((day) => (
          <button
            key={day.id}
            onClick={() => setActiveDayId(day.id)}
            className={`px-6 py-3 rounded-t-xl font-bold text-sm tracking-wide transition-all border-t border-x ${
              activeDayId === day.id
                ? 'bg-slate-50 border-slate-200 text-primary-600 border-b-slate-50 -mb-px z-10'
                : 'bg-white border-transparent text-slate-400 hover:bg-slate-50 hover:text-slate-600'
            }`}
          >
            {day.name}
          </button>
        ))}
        {/* Add Day Button Placeholder */}
        <button className="px-4 py-3 text-slate-300 hover:text-primary-500">
            <Calendar size={18} />
        </button>
      </div>

      {/* 4. MAIN ROUTINE AREA */}
      <main className="flex-1 overflow-y-auto p-6 md:p-8 scroll-smooth">
        <div className="max-w-3xl mx-auto pb-20">

          {activeDay ? (
            <div className="space-y-4">
              {activeDay.exercises.length > 0 ? (
                  activeDay.exercises.map((exercise) => (
                    <ExerciseCard
                      key={exercise.id}
                      exercise={exercise}
                      onUpdate={handleExerciseUpdate}
                      onShowHistory={(ex) => setChartExercise(ex)}
                      onDelete={handleRemoveExercise}
                    />
                  ))
              ) : (
                  <div className="text-center py-10 text-slate-400">
                      No hay ejercicios en este día
                  </div>
              )}

              {/* Add Exercise Button (Big at bottom) */}
              <button 
                onClick={() => setIsAddingExercise(true)}
                className="w-full py-4 rounded-2xl border-2 border-dashed border-primary-200 text-primary-600 font-bold hover:bg-primary-50 transition-colors flex items-center justify-center gap-2"
              >
                  <Plus size={20} />
                  Agregar Ejercicio
              </button>

            </div>
          ) : (
            <div className="text-center text-slate-400 mt-20">Selecciona un día</div>
          )}
        </div>
      </main>

      {/* --- MODALS --- */}

      {/* Chart Overlay */}
      {chartExercise && (
        <ProgressChart exercise={chartExercise} onClose={() => setChartExercise(null)} />
      )}

      {/* Add Exercise Modal */}
      {isAddingExercise && (
          <div className="fixed inset-0 z-50 bg-black/50 backdrop-blur-sm flex items-center justify-center p-4">
              <div className="bg-white w-full max-w-2xl h-[80vh] rounded-2xl shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95">
                  <div className="p-4 border-b border-slate-100 flex items-center justify-between">
                      <div className="relative flex-1 mr-4">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
                        <input 
                            type="text"
                            autoFocus
                            placeholder="Buscar ejercicio..."
                            className="w-full pl-10 pr-4 py-3 bg-slate-50 rounded-xl outline-none focus:ring-2 focus:ring-primary-100"
                            value={exerciseSearch}
                            onChange={(e) => setExerciseSearch(e.target.value)}
                        />
                      </div>
                      <button onClick={() => setIsAddingExercise(false)} className="p-2 bg-slate-100 rounded-full"><X size={20} /></button>
                  </div>
                  <div className="flex-1 overflow-y-auto p-4">
                      <div className="grid grid-cols-1 gap-2">
                        {filteredCatalog.map(ex => (
                            <button 
                                key={ex.id}
                                onClick={() => handleAddExercise(ex.id)}
                                className="flex items-center p-4 hover:bg-primary-50 rounded-xl text-left group transition-colors border border-transparent hover:border-primary-100"
                            >
                                <div className="w-16 h-16 bg-slate-100 rounded-lg flex items-center justify-center mr-4 overflow-hidden shrink-0 border border-slate-200">
                                    {ex.videoUrl ? (
                                        <img src={ex.videoUrl} alt="" className="w-full h-full object-cover" />
                                    ) : (
                                        <Plus size={24} className="text-slate-400" />
                                    )}
                                </div>
                                <div>
                                    <h4 className="font-bold text-slate-800">{ex.name}</h4>
                                    <span className="text-xs text-slate-400 uppercase font-semibold">{ex.category}</span>
                                </div>
                            </button>
                        ))}
                        {filteredCatalog.length === 0 && (
                            <div className="text-center text-slate-400 mt-10">No se encontraron ejercicios</div>
                        )}
                      </div>
                  </div>
              </div>
          </div>
      )}

      {/* Weekly View Modal */}
      {showWeeklyView && (
          <div className="fixed inset-0 z-50 bg-black/50 backdrop-blur-sm flex items-center justify-center p-6">
              <div className="bg-white w-full max-w-5xl rounded-3xl shadow-2xl p-8 animate-in zoom-in-95 relative max-h-[90vh] overflow-y-auto">
                  <div className="flex justify-between items-center mb-8">
                      <h2 className="text-3xl font-bold text-slate-900">Vista Semanal</h2>
                      <button onClick={() => setShowWeeklyView(false)} className="p-2 bg-slate-100 rounded-full hover:bg-slate-200">
                         <X size={24} />
                      </button>
                  </div>

                  <div className="grid grid-cols-2 md:grid-cols-3 gap-6">
                      {patient.routine.days.map(day => (
                          <div key={day.id} className="bg-slate-50 rounded-2xl p-5 border border-slate-200">
                              <h3 className="font-bold text-lg text-slate-800 mb-4 border-b border-slate-200 pb-2 flex justify-between">
                                  {day.name}
                                  <span className="text-slate-400 text-sm font-normal">{day.exercises.length} ejs</span>
                              </h3>
                              <ul className="space-y-3">
                                  {day.exercises.map(ex => (
                                      <li key={ex.id} className="flex items-start gap-2 text-sm text-slate-600">
                                          <div className={`mt-1.5 w-1.5 h-1.5 rounded-full ${ex.isDone ? 'bg-kine' : 'bg-slate-300'}`}></div>
                                          <span className={ex.isDone ? 'line-through opacity-50' : ''}>{ex.definition.name}</span>
                                      </li>
                                  ))}
                                  {day.exercises.length === 0 && <li className="text-slate-400 text-sm italic">Día de descanso</li>}
                              </ul>
                          </div>
                      ))}
                      {/* Add Day Card Placeholder */}
                      <button className="border-2 border-dashed border-slate-200 rounded-2xl flex flex-col items-center justify-center text-slate-400 hover:border-primary-300 hover:text-primary-600 hover:bg-primary-50 transition-all min-h-[200px]">
                          <Plus size={32} />
                          <span className="font-bold mt-2">Agregar Día</span>
                      </button>
                  </div>
              </div>
          </div>
      )}

    </div>
  );
};

import React from 'react';
import { RoutineExercise } from '../types';
import { PlayCircle, CheckCircle, Circle, Minus, Plus, TrendingUp, Trash2 } from 'lucide-react';

interface ExerciseCardProps {
  exercise: RoutineExercise;
  onUpdate: (id: string, updates: Partial<RoutineExercise>) => void;
  onShowHistory: (exercise: RoutineExercise) => void;
  onDelete: (id: string) => void;
}

export const ExerciseCard: React.FC<ExerciseCardProps> = ({
  exercise,
  onUpdate,
  onShowHistory,
  onDelete,
}) => {
  const { definition, targetSets, targetReps, targetLoad, currentRpe, isDone } = exercise;

  // Handlers for stepper controls (Touch friendly)
  const adjustLoad = (amount: number, e: React.MouseEvent) => {
    e.stopPropagation();
    const newLoad = Math.max(0, targetLoad + amount);
    onUpdate(exercise.id, { targetLoad: newLoad });
  };

  const adjustReps = (amount: number, e: React.MouseEvent) => {
    e.stopPropagation();
    const newReps = Math.max(1, targetReps + amount);
    onUpdate(exercise.id, { targetReps: newReps });
  };

  const toggleDone = () => {
    onUpdate(exercise.id, { isDone: !isDone });
  };

  return (
    <div
      className={`bg-white rounded-2xl p-5 shadow-sm border transition-all duration-300 relative group ${
        isDone ? 'border-slate-100 opacity-60 bg-slate-50' : 'border-slate-200 hover:shadow-md'
      }`}
    >
      <div className="flex items-start gap-4">
        {/* Checkbox (Big touch target) */}
        <button
          onClick={toggleDone}
          className={`shrink-0 mt-1 transition-colors ${
            isDone ? 'text-kine' : 'text-slate-300 hover:text-primary-400'
          }`}
        >
          {isDone ? <CheckCircle size={32} fill="currentColor" className="text-white" /> : <Circle size={32} />}
        </button>

        {/* GIF Thumbnail (New) */}
        {definition.videoUrl && (
            <div className="w-24 h-24 bg-slate-100 rounded-xl overflow-hidden shrink-0 border border-slate-200 hidden sm:block">
                <img src={definition.videoUrl} alt={definition.name} className="w-full h-full object-cover mix-blend-multiply" />
            </div>
        )}

        <div className="flex-1 space-y-4">
          {/* Header */}
          <div className="flex justify-between items-start pr-8">
            <div>
              <h4 className={`font-bold text-lg leading-tight ${isDone ? 'text-slate-500 line-through' : 'text-slate-900'}`}>
                {definition.name}
              </h4>
              <span className="text-xs text-slate-400 uppercase font-semibold">{definition.category}</span>
            </div>

            <div className="flex gap-2">
                 <button 
                    onClick={() => onShowHistory(exercise)}
                    className="p-2 text-primary-600 bg-primary-50 rounded-lg hover:bg-primary-100"
                    title="Ver progreso"
                 >
                    <TrendingUp size={20} />
                 </button>
            </div>
          </div>

          {/* Controls Grid */}
          <div className={`grid grid-cols-12 gap-4 ${isDone ? 'pointer-events-none' : ''}`}>

            {/* Sets & Reps */}
            <div className="col-span-5 flex flex-col justify-center">
              <div className="text-xs text-slate-400 font-bold mb-1">SERIES x REPS</div>
              <div className="flex items-center gap-3">
                 <span className="text-2xl font-bold text-slate-800">{targetSets}</span>
                 <span className="text-slate-300 text-xl">x</span>
                 <div className="flex items-center bg-slate-100 rounded-lg p-1">
                    <button onClick={(e) => adjustReps(-1, e)} className="p-2 bg-white rounded-md shadow-sm active:scale-95 text-slate-600"><Minus size={16}/></button>
                    <span className="w-10 text-center font-bold text-xl">{targetReps}</span>
                    <button onClick={(e) => adjustReps(1, e)} className="p-2 bg-white rounded-md shadow-sm active:scale-95 text-slate-600"><Plus size={16}/></button>
                 </div>
              </div>
            </div>

            {/* Load (KG) */}
            <div className="col-span-4 flex flex-col justify-center border-l border-slate-100 pl-4">
              <div className="text-xs text-slate-400 font-bold mb-1">CARGA (KG)</div>
              <div className="flex items-center bg-slate-100 rounded-lg p-1 w-fit">
                    <button onClick={(e) => adjustLoad(-1, e)} className="p-2 bg-white rounded-md shadow-sm active:scale-95 text-slate-600"><Minus size={16}/></button>
                    <span className="w-12 text-center font-bold text-xl text-primary-700">{targetLoad}</span>
                    <button onClick={(e) => adjustLoad(1, e)} className="p-2 bg-white rounded-md shadow-sm active:scale-95 text-slate-600"><Plus size={16}/></button>
              </div>
            </div>

             {/* RPE Input */}
             <div className="col-span-3 flex flex-col justify-center border-l border-slate-100 pl-4">
               <div className="text-xs text-slate-400 font-bold mb-1">ESFUERZO (1-10)</div>
               <select 
                className="bg-slate-50 border border-slate-200 text-slate-900 text-lg rounded-lg focus:ring-primary-500 focus:border-primary-500 block w-full p-2.5 font-bold"
                value={currentRpe || ""}
                onChange={(e) => onUpdate(exercise.id, { currentRpe: Number(e.target.value) })}
               >
                 <option value="" disabled>-</option>
                 {[...Array(10)].map((_, i) => (
                    <option key={i+1} value={i+1}>{i+1}</option>
                 ))}
               </select>
            </div>

          </div>
        </div>
      </div>

      {/* Delete Button (Top Right Absolute) */}
      <button 
        onClick={() => onDelete(exercise.id)}
        className="absolute top-4 right-4 p-2 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors"
        title="Eliminar ejercicio"
      >
          <Trash2 size={18} />
      </button>
    </div>
  );
};

import React from 'react';
import { RoutineExercise } from '../types';
import { PlayCircle, CheckCircle, Circle, Minus, Plus, TrendingUp, Trash2 } from 'lucide-react';

interface ExerciseCardProps {
  exercise: RoutineExercise;
  onUpdate: (id: string, updates: Partial<RoutineExercise>) => void;
  onShowHistory: (exercise: RoutineExercise) => void;
  onDelete: (id: string) => void;
}

export const ExerciseCard: React.FC<ExerciseCardProps> = ({
  exercise,
  onUpdate,
  onShowHistory,
  onDelete,
}) => {
  const { definition, targetSets, targetReps, targetLoad, currentRpe, isDone } = exercise;

  // --- Handlers ---

  // 1. SETS (Now editable with steppers)
  const adjustSets = (amount: number, e: React.MouseEvent) => {
    e.stopPropagation();
    const newSets = Math.max(1, targetSets + amount);
    onUpdate(exercise.id, { targetSets: newSets });
  };

  // 2. REPS
  const adjustReps = (amount: number, e: React.MouseEvent) => {
    e.stopPropagation();
    const newReps = Math.max(1, targetReps + amount);
    onUpdate(exercise.id, { targetReps: newReps });
  };

  // 3. LOAD (Buttons for integers, Input for decimals)
  const adjustLoad = (amount: number, e: React.MouseEvent) => {
    e.stopPropagation();
    // Simple logic: Buttons jump by 1kg for speed.
    // Floating point math safety: round to 2 decimal places.
    let newLoad = targetLoad + amount;
    newLoad = Math.round(newLoad * 100) / 100; 
    newLoad = Math.max(0, newLoad);
    onUpdate(exercise.id, { targetLoad: newLoad });
  };

  const handleLoadInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = parseFloat(e.target.value);
    onUpdate(exercise.id, { targetLoad: isNaN(val) ? 0 : val });
  };

  const toggleDone = () => {
    onUpdate(exercise.id, { isDone: !isDone });
  };

  return (
    <div
      className={`bg-white rounded-2xl p-5 shadow-sm border transition-all duration-300 relative group ${
        isDone ? 'border-slate-100 opacity-60 bg-slate-50' : 'border-slate-200 hover:shadow-md'
      }`}
    >
      <div className="flex items-start gap-4">
        {/* Checkbox (Big touch target) */}
        <button
          onClick={toggleDone}
          className={`shrink-0 mt-1 transition-colors ${
            isDone ? 'text-kine' : 'text-slate-300 hover:text-primary-400'
          }`}
        >
          {isDone ? <CheckCircle size={32} fill="currentColor" className="text-white" /> : <Circle size={32} />}
        </button>

        {/* GIF Thumbnail */}
        {definition.videoUrl && (
            <div className="w-24 h-24 bg-slate-100 rounded-xl overflow-hidden shrink-0 border border-slate-200 hidden sm:block">
                <img src={definition.videoUrl} alt={definition.name} className="w-full h-full object-cover mix-blend-multiply" />
            </div>
        )}

        <div className="flex-1 space-y-4">
          {/* Header */}
          <div className="flex justify-between items-start pr-8">
            <div>
              <h4 className={`font-bold text-lg leading-tight ${isDone ? 'text-slate-500 line-through' : 'text-slate-900'}`}>
                {definition.name}
              </h4>
              <span className="text-xs text-slate-400 uppercase font-semibold">{definition.category}</span>
            </div>

            <div className="flex gap-2">
                 <button 
                    onClick={() => onShowHistory(exercise)}
                    className="p-2 text-primary-600 bg-primary-50 rounded-lg hover:bg-primary-100"
                    title="Ver progreso"
                 >
                    <TrendingUp size={20} />
                 </button>
            </div>
          </div>

          {/* Controls Grid */}
          <div className={`grid grid-cols-12 gap-2 md:gap-4 ${isDone ? 'pointer-events-none' : ''}`}>

            {/* Sets & Reps */}
            <div className="col-span-6 md:col-span-5 flex flex-col justify-center">
              <div className="text-xs text-slate-400 font-bold mb-1">SERIES x REPS</div>
              <div className="flex items-center gap-2">

                 {/* SETS Stepper */}
                 <div className="flex items-center bg-slate-100 rounded-lg p-0.5">
                    <button onClick={(e) => adjustSets(-1, e)} className="p-1.5 bg-white rounded-md shadow-sm active:scale-95 text-slate-600"><Minus size={14}/></button>
                    <span className="w-8 text-center font-bold text-lg text-slate-800">{targetSets}</span>
                    <button onClick={(e) => adjustSets(1, e)} className="p-1.5 bg-white rounded-md shadow-sm active:scale-95 text-slate-600"><Plus size={14}/></button>
                 </div>

                 <span className="text-slate-300 text-sm">x</span>

                 {/* REPS Stepper */}
                 <div className="flex items-center bg-slate-100 rounded-lg p-0.5">
                    <button onClick={(e) => adjustReps(-1, e)} className="p-1.5 bg-white rounded-md shadow-sm active:scale-95 text-slate-600"><Minus size={14}/></button>
                    <span className="w-9 text-center font-bold text-lg text-slate-800">{targetReps}</span>
                    <button onClick={(e) => adjustReps(1, e)} className="p-1.5 bg-white rounded-md shadow-sm active:scale-95 text-slate-600"><Plus size={14}/></button>
                 </div>
              </div>
            </div>

            {/* Load (KG) */}
            <div className="col-span-6 md:col-span-4 flex flex-col justify-center border-l border-slate-100 pl-2 md:pl-4">
              <div className="text-xs text-slate-400 font-bold mb-1">CARGA (KG)</div>
              <div className="flex items-center bg-slate-100 rounded-lg p-0.5 w-fit">
                    <button onClick={(e) => adjustLoad(-1, e)} className="p-2 bg-white rounded-md shadow-sm active:scale-95 text-slate-600"><Minus size={16}/></button>

                    {/* Input allows decimal entry, standard view looks like text */}
                    <input 
                      type="number"
                      step="0.5"
                      min="0"
                      value={targetLoad}
                      onChange={handleLoadInputChange}
                      onClick={(e) => e.stopPropagation()}
                      className="w-14 text-center font-bold text-xl text-primary-700 bg-transparent outline-none focus:bg-white focus:ring-2 focus:ring-primary-100 rounded-md mx-1"
                    />

                    <button onClick={(e) => adjustLoad(1, e)} className="p-2 bg-white rounded-md shadow-sm active:scale-95 text-slate-600"><Plus size={16}/></button>
              </div>
            </div>

             {/* RPE Input */}
             <div className="col-span-12 md:col-span-3 flex flex-col justify-center md:border-l border-slate-100 md:pl-4 mt-2 md:mt-0">
               <div className="text-xs text-slate-400 font-bold mb-1">ESFUERZO (1-10)</div>
               <select 
                className="bg-slate-50 border border-slate-200 text-slate-900 text-lg rounded-lg focus:ring-primary-500 focus:border-primary-500 block w-full p-2.5 font-bold"
                value={currentRpe || ""}
                onChange={(e) => onUpdate(exercise.id, { currentRpe: Number(e.target.value) })}
               >
                 <option value="" disabled>-</option>
                 {[...Array(10)].map((_, i) => (
                    <option key={i+1} value={i+1}>{i+1}</option>
                 ))}
               </select>
            </div>

          </div>
        </div>
      </div>

      {/* Delete Button (Top Right Absolute) */}
      <button 
        onClick={() => onDelete(exercise.id)}
        className="absolute top-4 right-4 p-2 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors"
        title="Eliminar ejercicio"
      >
          <Trash2 size={18} />
      </button>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Patient, RoutineDay, RoutineExercise } from '../types';
import { EXERCISES } from '../constants';
import { ExerciseCard } from './ExerciseCard';
import { ProgressChart } from './ProgressChart';
import { Calendar, AlertCircle, FileText, ChevronDown, Plus, Search, X, LayoutGrid, Save } from 'lucide-react';

interface PatientDetailProps {
  patient: Patient;
  onUpdatePatient: (updated: Patient) => void;
}

export const PatientDetail: React.FC<PatientDetailProps> = ({
  patient,
  onUpdatePatient,
}) => {
  const [activeDayId, setActiveDayId] = useState<string>(
    patient.routine.days[0]?.id || ''
  );
  const [showHistory, setShowHistory] = useState<boolean>(false);
  const [showWeeklyView, setShowWeeklyView] = useState<boolean>(false);
  const [chartExercise, setChartExercise] = useState<RoutineExercise | null>(null);
  const [isAddingExercise, setIsAddingExercise] = useState(false);
  const [exerciseSearch, setExerciseSearch] = useState('');

  // Local state for editable notes
  const [notes, setNotes] = useState(patient.history[0] || '');

  // Sync notes when patient changes
  useEffect(() => {
    setNotes(patient.history[0] || '');
  }, [patient.id]);

  // Ensure activeDayId is valid if days change
  useEffect(() => {
     if (patient.routine.days.length > 0 && !patient.routine.days.find(d => d.id === activeDayId)) {
         setActiveDayId(patient.routine.days[0].id);
     }
  }, [patient.routine.days, activeDayId]);

  const activeDay = patient.routine.days.find((d) => d.id === activeDayId);

  // --- Handlers ---
  const handleSaveNotes = () => {
      const newHistory = [...patient.history];
      if (newHistory.length === 0) {
          newHistory.push(notes);
      } else {
          newHistory[0] = notes;
      }
      onUpdatePatient({ ...patient, history: newHistory });
  };

  const handleAddDay = () => {
      const newPatient = { ...patient };
      const dayCount = newPatient.routine.days.length + 1;

      const newDay: RoutineDay = {
        id: `day-${Date.now()}`,
        name: `Día ${dayCount}`,
        exercises: []
      };

      newPatient.routine.days.push(newDay);
      onUpdatePatient(newPatient);
      setActiveDayId(newDay.id);
  };

  const handleExerciseUpdate = (exerciseId: string, updates: Partial<RoutineExercise>) => {
    const newPatient = { ...patient };
    const dayIndex = newPatient.routine.days.findIndex(d => d.id === activeDayId);
    if (dayIndex === -1) return;

    const exIndex = newPatient.routine.days[dayIndex].exercises.findIndex(e => e.id === exerciseId);
    if (exIndex === -1) return;

    newPatient.routine.days[dayIndex].exercises[exIndex] = {
        ...newPatient.routine.days[dayIndex].exercises[exIndex],
        ...updates
    };

    onUpdatePatient(newPatient);
  };

  const handleRemoveExercise = (exerciseId: string) => {
      const newPatient = { ...patient };
      const dayIndex = newPatient.routine.days.findIndex(d => d.id === activeDayId);
      if (dayIndex === -1) return;

      newPatient.routine.days[dayIndex].exercises = newPatient.routine.days[dayIndex].exercises.filter(
          e => e.id !== exerciseId
      );
      onUpdatePatient(newPatient);
  };

  const handleAddExercise = (defId: string) => {
      const definition = EXERCISES.find(e => e.id === defId);
      if(!definition) return;

      const newPatient = { ...patient };
      const dayIndex = newPatient.routine.days.findIndex(d => d.id === activeDayId);
      if (dayIndex === -1) return;

      const newExercise: RoutineExercise = {
          id: `re-${Date.now()}`,
          definitionId: definition.id,
          definition: definition,
          targetSets: 3,
          targetReps: 10,
          targetLoad: 0,
          isDone: false,
          history: []
      };

      newPatient.routine.days[dayIndex].exercises.push(newExercise);
      onUpdatePatient(newPatient);
      setIsAddingExercise(false);
      setExerciseSearch('');
  };

  const filteredCatalog = EXERCISES.filter(ex => 
    ex.name.toLowerCase().includes(exerciseSearch.toLowerCase()) || 
    ex.category.toLowerCase().includes(exerciseSearch.toLowerCase())
  );

  return (
    <div className="flex-1 h-screen flex flex-col bg-slate-50 overflow-hidden relative">

      {/* 1. TOP HEADER: Patient Info & Context */}
      <header className="bg-white border-b border-slate-200 px-6 py-4 flex items-center justify-between shadow-sm shrink-0 z-20">
        <div className="flex items-center gap-4">
          <div className="flex flex-col">
            <h2 className="text-2xl font-bold text-slate-900 leading-none">
              {patient.firstName} {patient.lastName}
            </h2>
            <div className="flex items-center gap-2 mt-1">
                <span className="text-sm font-medium text-slate-500">{patient.condition}</span>
                <span className="w-1 h-1 bg-slate-300 rounded-full"></span>
                <span className="text-sm text-slate-400">{patient.age} años</span>
            </div>
          </div>
        </div>

        {/* Action Buttons */}
        <div className="flex gap-2">
            <button 
                onClick={() => setShowWeeklyView(true)}
                className="flex items-center gap-2 px-4 py-2 rounded-lg font-medium transition-colors bg-white border border-slate-200 text-slate-600 hover:bg-slate-50"
            >
                <LayoutGrid size={18} />
                <span>Vista Semanal</span>
            </button>
            <button 
                onClick={() => setShowHistory(!showHistory)}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg font-medium transition-colors ${showHistory ? 'bg-slate-800 text-white' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'}`}
            >
                <FileText size={18} />
                <span>{showHistory ? 'Ocultar Ficha' : 'Ver Ficha'}</span>
            </button>
        </div>
      </header>

      {/* 2. HISTORY DRAWER (Collapsible) */}
      {showHistory && (
          <div className="bg-slate-800 text-slate-200 px-8 py-6 shadow-inner shrink-0 animate-in slide-in-from-top-5 border-b border-slate-700">
              <div className="grid grid-cols-1 md:grid-cols-3 gap-8 max-w-5xl">
                  <div className="md:col-span-1">
                       <h4 className="text-slate-400 text-xs uppercase font-bold mb-2">Datos Clínicos</h4>
                       <div className="space-y-4">
                            <div>
                                <h5 className="text-slate-500 text-xs font-bold">Última Visita</h5>
                                <p className="text-sm font-mono bg-slate-700 w-fit px-2 py-1 rounded mt-1">{patient.lastVisit}</p>
                            </div>
                            <div>
                                <h5 className="text-slate-500 text-xs font-bold">Alertas</h5>
                                <div className="flex items-start gap-2 text-amber-400 text-sm mt-1">
                                    <AlertCircle size={16} className="mt-0.5 shrink-0" />
                                    <span>Controlar dolor.</span>
                                </div>
                            </div>
                       </div>
                  </div>
                  <div className="md:col-span-2">
                      <div className="flex justify-between items-center mb-2">
                        <h4 className="text-slate-400 text-xs uppercase font-bold">Observaciones / Evolución</h4>
                        <span className="text-xs text-slate-500 italic">Se guarda automáticamente</span>
                      </div>
                      <textarea 
                        className="w-full h-32 bg-slate-700 text-slate-200 p-4 rounded-xl border border-slate-600 focus:ring-2 focus:ring-primary-500 outline-none resize-none leading-relaxed"
                        value={notes}
                        onChange={(e) => setNotes(e.target.value)}
                        onBlur={handleSaveNotes}
                        placeholder="Escribe aquí las observaciones clínicas..."
                      />
                  </div>
              </div>
          </div>
      )}

      {/* 3. DAY SELECTOR (Tabs) */}
      <div className="bg-white border-b border-slate-200 px-6 flex gap-1 pt-4 overflow-x-auto no-scrollbar shrink-0">
        {patient.routine.days.map((day) => (
          <button
            key={day.id}
            onClick={() => setActiveDayId(day.id)}
            className={`px-6 py-3 rounded-t-xl font-bold text-sm tracking-wide transition-all border-t border-x ${
              activeDayId === day.id
                ? 'bg-slate-50 border-slate-200 text-primary-600 border-b-slate-50 -mb-px z-10'
                : 'bg-white border-transparent text-slate-400 hover:bg-slate-50 hover:text-slate-600'
            }`}
          >
            {day.name}
          </button>
        ))}
        {/* Add Day Button */}
        <button 
            onClick={handleAddDay}
            className="px-4 py-3 text-slate-300 hover:text-primary-600 hover:bg-slate-50 rounded-t-xl transition-all flex items-center gap-1 group"
            title="Agregar día"
        >
            <Plus size={20} className="group-hover:scale-110 transition-transform" />
        </button>
      </div>

      {/* 4. MAIN ROUTINE AREA */}
      <main className="flex-1 overflow-y-auto p-6 md:p-8 scroll-smooth">
        <div className="max-w-3xl mx-auto pb-20">

          {activeDay ? (
            <div className="space-y-4">
              {activeDay.exercises.length > 0 ? (
                  activeDay.exercises.map((exercise) => (
                    <ExerciseCard
                      key={exercise.id}
                      exercise={exercise}
                      onUpdate={handleExerciseUpdate}
                      onShowHistory={(ex) => setChartExercise(ex)}
                      onDelete={handleRemoveExercise}
                    />
                  ))
              ) : (
                  <div className="text-center py-10 text-slate-400">
                      <p className="mb-4">No hay ejercicios en este día</p>
                      <button 
                        onClick={() => setIsAddingExercise(true)}
                        className="bg-primary-50 text-primary-600 px-6 py-3 rounded-xl font-bold hover:bg-primary-100 transition-colors"
                      >
                          Agregar primer ejercicio
                      </button>
                  </div>
              )}

              {/* Add Exercise Button (Big at bottom) */}
              {activeDay.exercises.length > 0 && (
                <button 
                    onClick={() => setIsAddingExercise(true)}
                    className="w-full py-4 rounded-2xl border-2 border-dashed border-primary-200 text-primary-600 font-bold hover:bg-primary-50 transition-colors flex items-center justify-center gap-2"
                >
                    <Plus size={20} />
                    Agregar Ejercicio
                </button>
              )}

            </div>
          ) : (
            <div className="flex flex-col items-center justify-center h-full text-slate-400 mt-20">
                <p>No hay días en la rutina</p>
                <button onClick={handleAddDay} className="mt-4 text-primary-600 font-bold hover:underline">
                    Crear primer día
                </button>
            </div>
          )}
        </div>
      </main>

      {/* --- MODALS --- */}

      {/* Chart Overlay */}
      {chartExercise && (
        <ProgressChart exercise={chartExercise} onClose={() => setChartExercise(null)} />
      )}

      {/* Add Exercise Modal */}
      {isAddingExercise && (
          <div className="fixed inset-0 z-50 bg-black/50 backdrop-blur-sm flex items-center justify-center p-4">
              <div className="bg-white w-full max-w-2xl h-[80vh] rounded-2xl shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95">
                  <div className="p-4 border-b border-slate-100 flex items-center justify-between">
                      <div className="relative flex-1 mr-4">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
                        <input 
                            type="text"
                            autoFocus
                            placeholder="Buscar ejercicio..."
                            className="w-full pl-10 pr-4 py-3 bg-slate-50 rounded-xl outline-none focus:ring-2 focus:ring-primary-100"
                            value={exerciseSearch}
                            onChange={(e) => setExerciseSearch(e.target.value)}
                        />
                      </div>
                      <button onClick={() => setIsAddingExercise(false)} className="p-2 bg-slate-100 rounded-full"><X size={20} /></button>
                  </div>
                  <div className="flex-1 overflow-y-auto p-4">
                      <div className="grid grid-cols-1 gap-2">
                        {filteredCatalog.map(ex => (
                            <button 
                                key={ex.id}
                                onClick={() => handleAddExercise(ex.id)}
                                className="flex items-center p-4 hover:bg-primary-50 rounded-xl text-left group transition-colors border border-transparent hover:border-primary-100"
                            >
                                <div className="w-16 h-16 bg-slate-100 rounded-lg flex items-center justify-center mr-4 overflow-hidden shrink-0 border border-slate-200">
                                    {ex.videoUrl ? (
                                        <img src={ex.videoUrl} alt="" className="w-full h-full object-cover" />
                                    ) : (
                                        <Plus size={24} className="text-slate-400" />
                                    )}
                                </div>
                                <div>
                                    <h4 className="font-bold text-slate-800">{ex.name}</h4>
                                    <span className="text-xs text-slate-400 uppercase font-semibold">{ex.category}</span>
                                </div>
                            </button>
                        ))}
                        {filteredCatalog.length === 0 && (
                            <div className="text-center text-slate-400 mt-10">No se encontraron ejercicios</div>
                        )}
                      </div>
                  </div>
              </div>
          </div>
      )}

      {/* Weekly View Modal */}
      {showWeeklyView && (
          <div className="fixed inset-0 z-50 bg-black/50 backdrop-blur-sm flex items-center justify-center p-6">
              <div className="bg-white w-full max-w-5xl rounded-3xl shadow-2xl p-8 animate-in zoom-in-95 relative max-h-[90vh] overflow-y-auto">
                  <div className="flex justify-between items-center mb-8">
                      <h2 className="text-3xl font-bold text-slate-900">Vista Semanal</h2>
                      <button onClick={() => setShowWeeklyView(false)} className="p-2 bg-slate-100 rounded-full hover:bg-slate-200">
                         <X size={24} />
                      </button>
                  </div>

                  <div className="grid grid-cols-2 md:grid-cols-3 gap-6">
                      {patient.routine.days.map(day => (
                          <div key={day.id} className="bg-slate-50 rounded-2xl p-5 border border-slate-200">
                              <h3 className="font-bold text-lg text-slate-800 mb-4 border-b border-slate-200 pb-2 flex justify-between">
                                  {day.name}
                                  <span className="text-slate-400 text-sm font-normal">{day.exercises.length} ejs</span>
                              </h3>
                              <ul className="space-y-3">
                                  {day.exercises.map(ex => (
                                      <li key={ex.id} className="flex items-start gap-2 text-sm text-slate-600">
                                          <div className={`mt-1.5 w-1.5 h-1.5 rounded-full ${ex.isDone ? 'bg-kine' : 'bg-slate-300'}`}></div>
                                          <span className={ex.isDone ? 'line-through opacity-50' : ''}>{ex.definition.name}</span>
                                      </li>
                                  ))}
                                  {day.exercises.length === 0 && <li className="text-slate-400 text-sm italic">Día de descanso</li>}
                              </ul>
                          </div>
                      ))}
                      {/* Add Day Card Placeholder */}
                      <button 
                          onClick={() => {
                              handleAddDay();
                              setShowWeeklyView(false);
                          }}
                          className="border-2 border-dashed border-slate-200 rounded-2xl flex flex-col items-center justify-center text-slate-400 hover:border-primary-300 hover:text-primary-600 hover:bg-primary-50 transition-all min-h-[200px]"
                      >
                          <Plus size={32} />
                          <span className="font-bold mt-2">Agregar Día</span>
                      </button>
                  </div>
              </div>
          </div>
      )}

    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Patient, RoutineDay, RoutineExercise } from '../types';
import { EXERCISES } from '../constants';
import { ExerciseCard } from './ExerciseCard';
import { ProgressChart } from './ProgressChart';
import { Calendar, AlertCircle, FileText, ChevronDown, Plus, Search, X, LayoutGrid, Save, Trash2 } from 'lucide-react';

interface PatientDetailProps {
  patient: Patient;
  onUpdatePatient: (updated: Patient) => void;
}

export const PatientDetail: React.FC<PatientDetailProps> = ({
  patient,
  onUpdatePatient,
}) => {
  const [activeDayId, setActiveDayId] = useState<string>(
    patient.routine.days[0]?.id || ''
  );
  const [showHistory, setShowHistory] = useState<boolean>(false);
  const [showWeeklyView, setShowWeeklyView] = useState<boolean>(false);
  const [chartExercise, setChartExercise] = useState<RoutineExercise | null>(null);
  const [isAddingExercise, setIsAddingExercise] = useState(false);
  const [exerciseSearch, setExerciseSearch] = useState('');

  // Local state for editable notes
  const [notes, setNotes] = useState(patient.history[0] || '');

  // Sync notes when patient changes
  useEffect(() => {
    setNotes(patient.history[0] || '');
  }, [patient.id]);

  // Ensure activeDayId is valid if days change
  useEffect(() => {
     if (patient.routine.days.length > 0 && !patient.routine.days.find(d => d.id === activeDayId)) {
         setActiveDayId(patient.routine.days[0].id);
     }
  }, [patient.routine.days, activeDayId]);

  const activeDay = patient.routine.days.find((d) => d.id === activeDayId);

  // --- Handlers ---
  const handleSaveNotes = () => {
      const newHistory = [...patient.history];
      if (newHistory.length === 0) {
          newHistory.push(notes);
      } else {
          newHistory[0] = notes;
      }
      onUpdatePatient({ ...patient, history: newHistory });
  };

  const handleAddDay = () => {
      const newPatient = { ...patient };
      const dayCount = newPatient.routine.days.length + 1;

      const newDay: RoutineDay = {
        id: `day-${Date.now()}`,
        name: `Día ${dayCount}`,
        exercises: []
      };

      newPatient.routine.days.push(newDay);
      onUpdatePatient(newPatient);
      setActiveDayId(newDay.id);
  };

  const handleDeleteDay = (dayId: string) => {
    if (!window.confirm("¿Estás seguro de que quieres eliminar este día y todos sus ejercicios?")) {
        return;
    }

    const newPatient = { ...patient };
    newPatient.routine.days = newPatient.routine.days.filter(d => d.id !== dayId);

    // If we deleted the active day, switch to the first available or empty
    if (activeDayId === dayId) {
        setActiveDayId(newPatient.routine.days[0]?.id || '');
    }

    onUpdatePatient(newPatient);
  };

  const handleExerciseUpdate = (exerciseId: string, updates: Partial<RoutineExercise>) => {
    const newPatient = { ...patient };
    const dayIndex = newPatient.routine.days.findIndex(d => d.id === activeDayId);
    if (dayIndex === -1) return;

    const exIndex = newPatient.routine.days[dayIndex].exercises.findIndex(e => e.id === exerciseId);
    if (exIndex === -1) return;

    newPatient.routine.days[dayIndex].exercises[exIndex] = {
        ...newPatient.routine.days[dayIndex].exercises[exIndex],
        ...updates
    };

    onUpdatePatient(newPatient);
  };

  const handleRemoveExercise = (exerciseId: string) => {
      const newPatient = { ...patient };
      const dayIndex = newPatient.routine.days.findIndex(d => d.id === activeDayId);
      if (dayIndex === -1) return;

      newPatient.routine.days[dayIndex].exercises = newPatient.routine.days[dayIndex].exercises.filter(
          e => e.id !== exerciseId
      );
      onUpdatePatient(newPatient);
  };

  const handleAddExercise = (defId: string) => {
      const definition = EXERCISES.find(e => e.id === defId);
      if(!definition) return;

      const newPatient = { ...patient };
      const dayIndex = newPatient.routine.days.findIndex(d => d.id === activeDayId);
      if (dayIndex === -1) return;

      const newExercise: RoutineExercise = {
          id: `re-${Date.now()}`,
          definitionId: definition.id,
          definition: definition,
          targetSets: 3,
          targetReps: 10,
          targetLoad: 0,
          isDone: false,
          history: []
      };

      newPatient.routine.days[dayIndex].exercises.push(newExercise);
      onUpdatePatient(newPatient);
      setIsAddingExercise(false);
      setExerciseSearch('');
  };

  const filteredCatalog = EXERCISES.filter(ex => 
    ex.name.toLowerCase().includes(exerciseSearch.toLowerCase()) || 
    ex.category.toLowerCase().includes(exerciseSearch.toLowerCase())
  );

  return (
    <div className="flex-1 h-screen flex flex-col bg-slate-50 overflow-hidden relative">

      {/* 1. TOP HEADER: Patient Info & Context */}
      <header className="bg-white border-b border-slate-200 px-6 py-4 flex items-center justify-between shadow-sm shrink-0 z-20">
        <div className="flex items-center gap-4">
          <div className="flex flex-col">
            <h2 className="text-2xl font-bold text-slate-900 leading-none">
              {patient.firstName} {patient.lastName}
            </h2>
            <div className="flex items-center gap-2 mt-1">
                <span className="text-sm font-medium text-slate-500">{patient.condition}</span>
                <span className="w-1 h-1 bg-slate-300 rounded-full"></span>
                <span className="text-sm text-slate-400">{patient.age} años</span>
            </div>
          </div>
        </div>

        {/* Action Buttons */}
        <div className="flex gap-2">
            <button 
                onClick={() => setShowWeeklyView(true)}
                className="flex items-center gap-2 px-4 py-2 rounded-lg font-medium transition-colors bg-white border border-slate-200 text-slate-600 hover:bg-slate-50"
            >
                <LayoutGrid size={18} />
                <span>Vista Semanal</span>
            </button>
            <button 
                onClick={() => setShowHistory(!showHistory)}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg font-medium transition-colors ${showHistory ? 'bg-slate-800 text-white' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'}`}
            >
                <FileText size={18} />
                <span>{showHistory ? 'Ocultar Ficha' : 'Ver Ficha'}</span>
            </button>
        </div>
      </header>

      {/* 2. HISTORY DRAWER (Collapsible) */}
      {showHistory && (
          <div className="bg-slate-800 text-slate-200 px-8 py-6 shadow-inner shrink-0 animate-in slide-in-from-top-5 border-b border-slate-700">
              <div className="grid grid-cols-1 md:grid-cols-3 gap-8 max-w-5xl">
                  <div className="md:col-span-1">
                       <h4 className="text-slate-400 text-xs uppercase font-bold mb-2">Datos Clínicos</h4>
                       <div className="space-y-4">
                            <div>
                                <h5 className="text-slate-500 text-xs font-bold">Última Visita</h5>
                                <p className="text-sm font-mono bg-slate-700 w-fit px-2 py-1 rounded mt-1">{patient.lastVisit}</p>
                            </div>
                            <div>
                                <h5 className="text-slate-500 text-xs font-bold">Alertas</h5>
                                <div className="flex items-start gap-2 text-amber-400 text-sm mt-1">
                                    <AlertCircle size={16} className="mt-0.5 shrink-0" />
                                    <span>Controlar dolor.</span>
                                </div>
                            </div>
                       </div>
                  </div>
                  <div className="md:col-span-2">
                      <div className="flex justify-between items-center mb-2">
                        <h4 className="text-slate-400 text-xs uppercase font-bold">Observaciones / Evolución</h4>
                        <span className="text-xs text-slate-500 italic">Se guarda automáticamente</span>
                      </div>
                      <textarea 
                        className="w-full h-32 bg-slate-700 text-slate-200 p-4 rounded-xl border border-slate-600 focus:ring-2 focus:ring-primary-500 outline-none resize-none leading-relaxed"
                        value={notes}
                        onChange={(e) => setNotes(e.target.value)}
                        onBlur={handleSaveNotes}
                        placeholder="Escribe aquí las observaciones clínicas..."
                      />
                  </div>
              </div>
          </div>
      )}

      {/* 3. DAY SELECTOR (Tabs) */}
      <div className="bg-white border-b border-slate-200 px-6 flex gap-1 pt-4 overflow-x-auto no-scrollbar shrink-0">
        {patient.routine.days.map((day) => (
          <button
            key={day.id}
            onClick={() => setActiveDayId(day.id)}
            className={`px-6 py-3 rounded-t-xl font-bold text-sm tracking-wide transition-all border-t border-x ${
              activeDayId === day.id
                ? 'bg-slate-50 border-slate-200 text-primary-600 border-b-slate-50 -mb-px z-10'
                : 'bg-white border-transparent text-slate-400 hover:bg-slate-50 hover:text-slate-600'
            }`}
          >
            {day.name}
          </button>
        ))}
        {/* Add Day Button */}
        <button 
            onClick={handleAddDay}
            className="px-4 py-3 text-slate-300 hover:text-primary-600 hover:bg-slate-50 rounded-t-xl transition-all flex items-center gap-1 group"
            title="Agregar día"
        >
            <Plus size={20} className="group-hover:scale-110 transition-transform" />
        </button>
      </div>

      {/* 4. MAIN ROUTINE AREA */}
      <main className="flex-1 overflow-y-auto p-6 md:p-8 scroll-smooth">
        <div className="max-w-3xl mx-auto pb-20">

          {activeDay ? (
            <div className="space-y-4">
              {activeDay.exercises.length > 0 ? (
                  activeDay.exercises.map((exercise) => (
                    <ExerciseCard
                      key={exercise.id}
                      exercise={exercise}
                      onUpdate={handleExerciseUpdate}
                      onShowHistory={(ex) => setChartExercise(ex)}
                      onDelete={handleRemoveExercise}
                    />
                  ))
              ) : (
                  <div className="text-center py-10 text-slate-400">
                      <p className="mb-4">No hay ejercicios en este día</p>
                      <button 
                        onClick={() => setIsAddingExercise(true)}
                        className="bg-primary-50 text-primary-600 px-6 py-3 rounded-xl font-bold hover:bg-primary-100 transition-colors"
                      >
                          Agregar primer ejercicio
                      </button>
                  </div>
              )}

              {/* Add Exercise Button (Big at bottom) */}
              {activeDay.exercises.length > 0 && (
                <button 
                    onClick={() => setIsAddingExercise(true)}
                    className="w-full py-4 rounded-2xl border-2 border-dashed border-primary-200 text-primary-600 font-bold hover:bg-primary-50 transition-colors flex items-center justify-center gap-2"
                >
                    <Plus size={20} />
                    Agregar Ejercicio
                </button>
              )}

              {/* Delete Day Button (Footer) */}
              <div className="flex justify-end pt-8 opacity-60 hover:opacity-100 transition-opacity">
                  <button 
                    onClick={() => handleDeleteDay(activeDayId)}
                    className="flex items-center gap-2 text-red-400 text-sm font-medium hover:text-red-600 py-2 px-4 hover:bg-red-50 rounded-lg transition-colors"
                  >
                      <Trash2 size={16} />
                      Eliminar {activeDay.name}
                  </button>
              </div>

            </div>
          ) : (
            <div className="flex flex-col items-center justify-center h-full text-slate-400 mt-20">
                <p>No hay días en la rutina</p>
                <button onClick={handleAddDay} className="mt-4 text-primary-600 font-bold hover:underline">
                    Crear primer día
                </button>
            </div>
          )}
        </div>
      </main>

      {/* --- MODALS --- */}

      {/* Chart Overlay */}
      {chartExercise && (
        <ProgressChart exercise={chartExercise} onClose={() => setChartExercise(null)} />
      )}

      {/* Add Exercise Modal */}
      {isAddingExercise && (
          <div className="fixed inset-0 z-50 bg-black/50 backdrop-blur-sm flex items-center justify-center p-4">
              <div className="bg-white w-full max-w-2xl h-[80vh] rounded-2xl shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95">
                  <div className="p-4 border-b border-slate-100 flex items-center justify-between">
                      <div className="relative flex-1 mr-4">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
                        <input 
                            type="text"
                            autoFocus
                            placeholder="Buscar ejercicio..."
                            className="w-full pl-10 pr-4 py-3 bg-slate-50 rounded-xl outline-none focus:ring-2 focus:ring-primary-100"
                            value={exerciseSearch}
                            onChange={(e) => setExerciseSearch(e.target.value)}
                        />
                      </div>
                      <button onClick={() => setIsAddingExercise(false)} className="p-2 bg-slate-100 rounded-full"><X size={20} /></button>
                  </div>
                  <div className="flex-1 overflow-y-auto p-4">
                      <div className="grid grid-cols-1 gap-2">
                        {filteredCatalog.map(ex => (
                            <button 
                                key={ex.id}
                                onClick={() => handleAddExercise(ex.id)}
                                className="flex items-center p-4 hover:bg-primary-50 rounded-xl text-left group transition-colors border border-transparent hover:border-primary-100"
                            >
                                <div className="w-16 h-16 bg-slate-100 rounded-lg flex items-center justify-center mr-4 overflow-hidden shrink-0 border border-slate-200">
                                    {ex.videoUrl ? (
                                        <img src={ex.videoUrl} alt="" className="w-full h-full object-cover" />
                                    ) : (
                                        <Plus size={24} className="text-slate-400" />
                                    )}
                                </div>
                                <div>
                                    <h4 className="font-bold text-slate-800">{ex.name}</h4>
                                    <span className="text-xs text-slate-400 uppercase font-semibold">{ex.category}</span>
                                </div>
                            </button>
                        ))}
                        {filteredCatalog.length === 0 && (
                            <div className="text-center text-slate-400 mt-10">No se encontraron ejercicios</div>
                        )}
                      </div>
                  </div>
              </div>
          </div>
      )}

      {/* Weekly View Modal */}
      {showWeeklyView && (
          <div className="fixed inset-0 z-50 bg-black/50 backdrop-blur-sm flex items-center justify-center p-6">
              <div className="bg-white w-full max-w-5xl rounded-3xl shadow-2xl p-8 animate-in zoom-in-95 relative max-h-[90vh] overflow-y-auto">
                  <div className="flex justify-between items-center mb-8">
                      <h2 className="text-3xl font-bold text-slate-900">Vista Semanal</h2>
                      <button onClick={() => setShowWeeklyView(false)} className="p-2 bg-slate-100 rounded-full hover:bg-slate-200">
                         <X size={24} />
                      </button>
                  </div>

                  <div className="grid grid-cols-2 md:grid-cols-3 gap-6">
                      {patient.routine.days.map(day => (
                          <div key={day.id} className="relative bg-slate-50 rounded-2xl p-5 border border-slate-200 group">
                              {/* Delete Day Button in Modal */}
                              <button 
                                onClick={(e) => {
                                    e.stopPropagation();
                                    handleDeleteDay(day.id);
                                }}
                                className="absolute top-4 right-4 text-slate-300 hover:text-red-500 hover:bg-red-50 p-1.5 rounded-lg transition-all"
                                title="Eliminar día"
                              >
                                  <Trash2 size={18} />
                              </button>

                              <h3 className="font-bold text-lg text-slate-800 mb-4 border-b border-slate-200 pb-2 flex justify-between pr-8">
                                  {day.name}
                                  <span className="text-slate-400 text-sm font-normal pt-1">{day.exercises.length} ejs</span>
                              </h3>
                              <ul className="space-y-3">
                                  {day.exercises.map(ex => (
                                      <li key={ex.id} className="flex items-start gap-2 text-sm text-slate-600">
                                          <div className={`mt-1.5 w-1.5 h-1.5 rounded-full ${ex.isDone ? 'bg-kine' : 'bg-slate-300'}`}></div>
                                          <span className={ex.isDone ? 'line-through opacity-50' : ''}>{ex.definition.name}</span>
                                      </li>
                                  ))}
                                  {day.exercises.length === 0 && <li className="text-slate-400 text-sm italic">Día de descanso</li>}
                              </ul>
                          </div>
                      ))}
                      {/* Add Day Card Placeholder */}
                      <button 
                          onClick={() => {
                              handleAddDay();
                              setShowWeeklyView(false);
                          }}
                          className="border-2 border-dashed border-slate-200 rounded-2xl flex flex-col items-center justify-center text-slate-400 hover:border-primary-300 hover:text-primary-600 hover:bg-primary-50 transition-all min-h-[200px]"
                      >
                          <Plus size={32} />
                          <span className="font-bold mt-2">Agregar Día</span>
                      </button>
                  </div>
              </div>
          </div>
      )}

    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Patient, RoutineDay, RoutineExercise } from '../types';
import { EXERCISES } from '../constants';
import { ExerciseCard } from './ExerciseCard';
import { ProgressChart } from './ProgressChart';
import { AlertCircle, FileText, Plus, Search, X, LayoutGrid, Trash2 } from 'lucide-react';

interface PatientDetailProps {
  patient: Patient;
  onUpdatePatient: (updated: Patient) => void;
}

export const PatientDetail: React.FC<PatientDetailProps> = ({
  patient,
  onUpdatePatient,
}) => {
  const [activeDayId, setActiveDayId] = useState<string>(
    patient.routine.days[0]?.id || ''
  );
  const [showHistory, setShowHistory] = useState<boolean>(false);
  const [showWeeklyView, setShowWeeklyView] = useState<boolean>(false);
  const [chartExercise, setChartExercise] = useState<RoutineExercise | null>(null);
  const [isAddingExercise, setIsAddingExercise] = useState(false);
  const [exerciseSearch, setExerciseSearch] = useState('');

  // Local state for editable notes
  const [notes, setNotes] = useState(patient.history[0] || '');

  // Sync notes when patient changes
  useEffect(() => {
    setNotes(patient.history[0] || '');
  }, [patient.id]);

  // Ensure activeDayId is valid if days change
  useEffect(() => {
     // If activeDayId is invalid (deleted) or empty, and we have days, pick the first one.
     if (patient.routine.days.length > 0) {
         const dayExists = patient.routine.days.find(d => d.id === activeDayId);
         if (!dayExists) {
             setActiveDayId(patient.routine.days[0].id);
         }
     } else {
         // No days left
         if (activeDayId !== '') setActiveDayId('');
     }
  }, [patient.routine.days, activeDayId]);

  const activeDay = patient.routine.days.find((d) => d.id === activeDayId);

  // --- Handlers (IMMUTABLE UPDATES) ---

  const handleSaveNotes = () => {
      const newHistory = [...patient.history];
      if (newHistory.length === 0) {
          newHistory.push(notes);
      } else {
          newHistory[0] = notes;
      }
      onUpdatePatient({ ...patient, history: newHistory });
  };

  const handleAddDay = () => {
      const dayCount = patient.routine.days.length + 1;
      const newDay: RoutineDay = {
        id: `day-${Date.now()}`,
        name: `Día ${dayCount}`,
        exercises: []
      };

      const newPatient = {
          ...patient,
          routine: {
              ...patient.routine,
              days: [...patient.routine.days, newDay]
          }
      };

      onUpdatePatient(newPatient);
      // Immediately set active to the new day
      setActiveDayId(newDay.id);
  };

  const handleDeleteDay = (dayId: string) => {
    if (!window.confirm("¿Estás seguro de que quieres eliminar este día y todos sus ejercicios?")) {
        return;
    }

    const updatedDays = patient.routine.days.filter(d => d.id !== dayId);

    const newPatient = {
        ...patient,
        routine: {
            ...patient.routine,
            days: updatedDays
        }
    };

    // If we deleted the currently active day, logic in useEffect or here needs to switch tabs.
    // Doing it here is faster for UI response.
    if (activeDayId === dayId) {
        setActiveDayId(updatedDays.length > 0 ? updatedDays[0].id : '');
    }

    onUpdatePatient(newPatient);
  };

  const handleExerciseUpdate = (exerciseId: string, updates: Partial<RoutineExercise>) => {
    const dayIndex = patient.routine.days.findIndex(d => d.id === activeDayId);
    if (dayIndex === -1) return;

    // Deep copy days and exercises to avoid mutation
    const newDays = [...patient.routine.days];
    const newExercises = [...newDays[dayIndex].exercises];

    const exIndex = newExercises.findIndex(e => e.id === exerciseId);
    if (exIndex === -1) return;

    newExercises[exIndex] = {
        ...newExercises[exIndex],
        ...updates
    };

    newDays[dayIndex] = {
        ...newDays[dayIndex],
        exercises: newExercises
    };

    onUpdatePatient({
        ...patient,
        routine: {
            ...patient.routine,
            days: newDays
        }
    });
  };

  const handleRemoveExercise = (exerciseId: string) => {
      const dayIndex = patient.routine.days.findIndex(d => d.id === activeDayId);
      if (dayIndex === -1) return;

      const newDays = [...patient.routine.days];
      newDays[dayIndex] = {
          ...newDays[dayIndex],
          exercises: newDays[dayIndex].exercises.filter(e => e.id !== exerciseId)
      };

      onUpdatePatient({
          ...patient,
          routine: {
              ...patient.routine,
              days: newDays
          }
      });
  };

  const handleAddExercise = (defId: string) => {
      const definition = EXERCISES.find(e => e.id === defId);
      if(!definition) return;

      const dayIndex = patient.routine.days.findIndex(d => d.id === activeDayId);
      if (dayIndex === -1) return;

      const newExercise: RoutineExercise = {
          id: `re-${Date.now()}`,
          definitionId: definition.id,
          definition: definition,
          targetSets: 3,
          targetReps: 10,
          targetLoad: 0,
          isDone: false,
          history: []
      };

      const newDays = [...patient.routine.days];
      newDays[dayIndex] = {
          ...newDays[dayIndex],
          exercises: [...newDays[dayIndex].exercises, newExercise]
      };

      onUpdatePatient({
          ...patient,
          routine: {
              ...patient.routine,
              days: newDays
          }
      });

      setIsAddingExercise(false);
      setExerciseSearch('');
  };

  const filteredCatalog = EXERCISES.filter(ex => 
    ex.name.toLowerCase().includes(exerciseSearch.toLowerCase()) || 
    ex.category.toLowerCase().includes(exerciseSearch.toLowerCase())
  );

  return (
    <div className="flex-1 h-screen flex flex-col bg-slate-50 overflow-hidden relative">

      {/* 1. TOP HEADER: Patient Info & Context */}
      <header className="bg-white border-b border-slate-200 px-6 py-4 flex items-center justify-between shadow-sm shrink-0 z-20">
        <div className="flex items-center gap-4">
          <div className="flex flex-col">
            <h2 className="text-2xl font-bold text-slate-900 leading-none">
              {patient.firstName} {patient.lastName}
            </h2>
            <div className="flex items-center gap-2 mt-1">
                <span className="text-sm font-medium text-slate-500">{patient.condition}</span>
                <span className="w-1 h-1 bg-slate-300 rounded-full"></span>
                <span className="text-sm text-slate-400">{patient.age} años</span>
            </div>
          </div>
        </div>

        {/* Action Buttons */}
        <div className="flex gap-2">
            <button 
                onClick={() => setShowWeeklyView(true)}
                className="flex items-center gap-2 px-4 py-2 rounded-lg font-medium transition-colors bg-white border border-slate-200 text-slate-600 hover:bg-slate-50"
            >
                <LayoutGrid size={18} />
                <span>Vista Semanal</span>
            </button>
            <button 
                onClick={() => setShowHistory(!showHistory)}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg font-medium transition-colors ${showHistory ? 'bg-slate-800 text-white' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'}`}
            >
                <FileText size={18} />
                <span>{showHistory ? 'Ocultar Ficha' : 'Ver Ficha'}</span>
            </button>
        </div>
      </header>

      {/* 2. HISTORY DRAWER (Collapsible) */}
      {showHistory && (
          <div className="bg-slate-800 text-slate-200 px-8 py-6 shadow-inner shrink-0 animate-in slide-in-from-top-5 border-b border-slate-700">
              <div className="grid grid-cols-1 md:grid-cols-3 gap-8 max-w-5xl">
                  <div className="md:col-span-1">
                       <h4 className="text-slate-400 text-xs uppercase font-bold mb-2">Datos Clínicos</h4>
                       <div className="space-y-4">
                            <div>
                                <h5 className="text-slate-500 text-xs font-bold">Última Visita</h5>
                                <p className="text-sm font-mono bg-slate-700 w-fit px-2 py-1 rounded mt-1">{patient.lastVisit}</p>
                            </div>
                            <div>
                                <h5 className="text-slate-500 text-xs font-bold">Alertas</h5>
                                <div className="flex items-start gap-2 text-amber-400 text-sm mt-1">
                                    <AlertCircle size={16} className="mt-0.5 shrink-0" />
                                    <span>Controlar dolor.</span>
                                </div>
                            </div>
                       </div>
                  </div>
                  <div className="md:col-span-2">
                      <div className="flex justify-between items-center mb-2">
                        <h4 className="text-slate-400 text-xs uppercase font-bold">Observaciones / Evolución</h4>
                        <span className="text-xs text-slate-500 italic">Se guarda automáticamente</span>
                      </div>
                      <textarea 
                        className="w-full h-32 bg-slate-700 text-slate-200 p-4 rounded-xl border border-slate-600 focus:ring-2 focus:ring-primary-500 outline-none resize-none leading-relaxed"
                        value={notes}
                        onChange={(e) => setNotes(e.target.value)}
                        onBlur={handleSaveNotes}
                        placeholder="Escribe aquí las observaciones clínicas..."
                      />
                  </div>
              </div>
          </div>
      )}

      {/* 3. DAY SELECTOR (Tabs) */}
      <div className="bg-white border-b border-slate-200 px-6 flex gap-1 pt-4 overflow-x-auto no-scrollbar shrink-0">
        {patient.routine.days.map((day) => (
          <button
            key={day.id}
            onClick={() => setActiveDayId(day.id)}
            className={`px-6 py-3 rounded-t-xl font-bold text-sm tracking-wide transition-all border-t border-x ${
              activeDayId === day.id
                ? 'bg-slate-50 border-slate-200 text-primary-600 border-b-slate-50 -mb-px z-10'
                : 'bg-white border-transparent text-slate-400 hover:bg-slate-50 hover:text-slate-600'
            }`}
          >
            {day.name}
          </button>
        ))}
        {/* Add Day Button */}
        <button 
            onClick={handleAddDay}
            className="px-4 py-3 text-slate-300 hover:text-primary-600 hover:bg-slate-50 rounded-t-xl transition-all flex items-center gap-1 group"
            title="Agregar día"
        >
            <Plus size={20} className="group-hover:scale-110 transition-transform" />
        </button>
      </div>

      {/* 4. MAIN ROUTINE AREA */}
      <main className="flex-1 overflow-y-auto p-6 md:p-8 scroll-smooth">
        <div className="max-w-3xl mx-auto pb-20">

          {activeDay ? (
            <div className="space-y-4">
              {activeDay.exercises.length > 0 ? (
                  activeDay.exercises.map((exercise) => (
                    <ExerciseCard
                      key={exercise.id}
                      exercise={exercise}
                      onUpdate={handleExerciseUpdate}
                      onShowHistory={(ex) => setChartExercise(ex)}
                      onDelete={handleRemoveExercise}
                    />
                  ))
              ) : (
                  <div className="text-center py-10 text-slate-400">
                      <p className="mb-4">No hay ejercicios en este día</p>
                      <button 
                        onClick={() => setIsAddingExercise(true)}
                        className="bg-primary-50 text-primary-600 px-6 py-3 rounded-xl font-bold hover:bg-primary-100 transition-colors"
                      >
                          Agregar primer ejercicio
                      </button>
                  </div>
              )}

              {/* Add Exercise Button (Big at bottom) */}
              {activeDay.exercises.length > 0 && (
                <button 
                    onClick={() => setIsAddingExercise(true)}
                    className="w-full py-4 rounded-2xl border-2 border-dashed border-primary-200 text-primary-600 font-bold hover:bg-primary-50 transition-colors flex items-center justify-center gap-2"
                >
                    <Plus size={20} />
                    Agregar Ejercicio
                </button>
              )}

              {/* Delete Day Button (Footer) */}
              <div className="flex justify-end pt-8 opacity-60 hover:opacity-100 transition-opacity">
                  <button 
                    onClick={() => handleDeleteDay(activeDayId)}
                    className="flex items-center gap-2 text-red-400 text-sm font-medium hover:text-red-600 py-2 px-4 hover:bg-red-50 rounded-lg transition-colors"
                  >
                      <Trash2 size={16} />
                      Eliminar {activeDay.name}
                  </button>
              </div>

            </div>
          ) : (
            <div className="flex flex-col items-center justify-center h-full text-slate-400 mt-20">
                <p>No hay días en la rutina</p>
                <button onClick={handleAddDay} className="mt-4 text-primary-600 font-bold hover:underline">
                    Crear primer día
                </button>
            </div>
          )}
        </div>
      </main>

      {/* --- MODALS --- */}

      {/* Chart Overlay */}
      {chartExercise && (
        <ProgressChart exercise={chartExercise} onClose={() => setChartExercise(null)} />
      )}

      {/* Add Exercise Modal */}
      {isAddingExercise && (
          <div className="fixed inset-0 z-50 bg-black/50 backdrop-blur-sm flex items-center justify-center p-4">
              <div className="bg-white w-full max-w-2xl h-[80vh] rounded-2xl shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95">
                  <div className="p-4 border-b border-slate-100 flex items-center justify-between">
                      <div className="relative flex-1 mr-4">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
                        <input 
                            type="text"
                            autoFocus
                            placeholder="Buscar ejercicio..."
                            className="w-full pl-10 pr-4 py-3 bg-slate-50 rounded-xl outline-none focus:ring-2 focus:ring-primary-100"
                            value={exerciseSearch}
                            onChange={(e) => setExerciseSearch(e.target.value)}
                        />
                      </div>
                      <button onClick={() => setIsAddingExercise(false)} className="p-2 bg-slate-100 rounded-full"><X size={20} /></button>
                  </div>
                  <div className="flex-1 overflow-y-auto p-4">
                      <div className="grid grid-cols-1 gap-2">
                        {filteredCatalog.map(ex => (
                            <button 
                                key={ex.id}
                                onClick={() => handleAddExercise(ex.id)}
                                className="flex items-center p-4 hover:bg-primary-50 rounded-xl text-left group transition-colors border border-transparent hover:border-primary-100"
                            >
                                <div className="w-16 h-16 bg-slate-100 rounded-lg flex items-center justify-center mr-4 overflow-hidden shrink-0 border border-slate-200">
                                    {ex.videoUrl ? (
                                        <img src={ex.videoUrl} alt="" className="w-full h-full object-cover" />
                                    ) : (
                                        <Plus size={24} className="text-slate-400" />
                                    )}
                                </div>
                                <div>
                                    <h4 className="font-bold text-slate-800">{ex.name}</h4>
                                    <span className="text-xs text-slate-400 uppercase font-semibold">{ex.category}</span>
                                </div>
                            </button>
                        ))}
                        {filteredCatalog.length === 0 && (
                            <div className="text-center text-slate-400 mt-10">No se encontraron ejercicios</div>
                        )}
                      </div>
                  </div>
              </div>
          </div>
      )}

      {/* Weekly View Modal */}
      {showWeeklyView && (
          <div className="fixed inset-0 z-50 bg-black/50 backdrop-blur-sm flex items-center justify-center p-6">
              <div className="bg-white w-full max-w-5xl rounded-3xl shadow-2xl p-8 animate-in zoom-in-95 relative max-h-[90vh] overflow-y-auto">
                  <div className="flex justify-between items-center mb-8">
                      <h2 className="text-3xl font-bold text-slate-900">Vista Semanal</h2>
                      <button onClick={() => setShowWeeklyView(false)} className="p-2 bg-slate-100 rounded-full hover:bg-slate-200">
                         <X size={24} />
                      </button>
                  </div>

                  <div className="grid grid-cols-2 md:grid-cols-3 gap-6">
                      {patient.routine.days.map(day => (
                          <div key={day.id} className="relative bg-slate-50 rounded-2xl p-5 border border-slate-200 group">
                              {/* Delete Day Button in Modal */}
                              <button 
                                onClick={(e) => {
                                    e.stopPropagation();
                                    handleDeleteDay(day.id);
                                }}
                                className="absolute top-4 right-4 text-slate-300 hover:text-red-500 hover:bg-red-50 p-1.5 rounded-lg transition-all"
                                title="Eliminar día"
                              >
                                  <Trash2 size={18} />
                              </button>

                              <h3 className="font-bold text-lg text-slate-800 mb-4 border-b border-slate-200 pb-2 flex justify-between pr-8">
                                  {day.name}
                                  <span className="text-slate-400 text-sm font-normal pt-1">{day.exercises.length} ejs</span>
                              </h3>
                              <ul className="space-y-3">
                                  {day.exercises.map(ex => (
                                      <li key={ex.id} className="flex items-start gap-2 text-sm text-slate-600">
                                          <div className={`mt-1.5 w-1.5 h-1.5 rounded-full ${ex.isDone ? 'bg-kine' : 'bg-slate-300'}`}></div>
                                          <span className={ex.isDone ? 'line-through opacity-50' : ''}>{ex.definition.name}</span>
                                      </li>
                                  ))}
                                  {day.exercises.length === 0 && <li className="text-slate-400 text-sm italic">Día de descanso</li>}
                              </ul>
                          </div>
                      ))}
                      {/* Add Day Card Placeholder */}
                      <button 
                          onClick={() => {
                              handleAddDay();
                              setShowWeeklyView(false);
                          }}
                          className="border-2 border-dashed border-slate-200 rounded-2xl flex flex-col items-center justify-center text-slate-400 hover:border-primary-300 hover:text-primary-600 hover:bg-primary-50 transition-all min-h-[200px]"
                      >
