                  </div>
              </div>
          </div>
      )}

    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Patient, RoutineDay, RoutineExercise } from '../types';
import { EXERCISES } from '../constants';
import { ExerciseCard } from './ExerciseCard';
import { ProgressChart } from './ProgressChart';
import { AlertCircle, FileText, Plus, Search, X, LayoutGrid, Trash2 } from 'lucide-react';

interface PatientDetailProps {
  patient: Patient;
  onUpdatePatient: (updated: Patient) => void;
}

export const PatientDetail: React.FC<PatientDetailProps> = ({
  patient,
  onUpdatePatient,
}) => {
  const [activeDayId, setActiveDayId] = useState<string>(
    patient.routine.days[0]?.id || ''
  );
  const [showHistory, setShowHistory] = useState<boolean>(false);
  const [showWeeklyView, setShowWeeklyView] = useState<boolean>(false);
  const [chartExercise, setChartExercise] = useState<RoutineExercise | null>(null);
  const [isAddingExercise, setIsAddingExercise] = useState(false);
  const [exerciseSearch, setExerciseSearch] = useState('');

  // Local state for editable notes
  const [notes, setNotes] = useState(patient.history[0] || '');

  // Sync notes when patient changes
  useEffect(() => {
    setNotes(patient.history[0] || '');
  }, [patient.id]);

  // Ensure activeDayId is valid if days change
  useEffect(() => {
     if (patient.routine.days.length > 0) {
         const dayExists = patient.routine.days.find(d => d.id === activeDayId);
         if (!dayExists) {
             setActiveDayId(patient.routine.days[0].id);
         }
     } else {
         if (activeDayId !== '') setActiveDayId('');
     }
  }, [patient.routine.days, activeDayId]);

  // Determine active day index for display
  const activeDayIndex = patient.routine.days.findIndex(d => d.id === activeDayId);
  const activeDay = patient.routine.days[activeDayIndex];

  // --- Handlers (IMMUTABLE UPDATES) ---

  const handleSaveNotes = () => {
      const newHistory = [...patient.history];
      if (newHistory.length === 0) {
          newHistory.push(notes);
      } else {
          newHistory[0] = notes;
      }
      onUpdatePatient({ ...patient, history: newHistory });
  };

  const handleAddDay = () => {
      const dayCount = patient.routine.days.length + 1;
      const newDay: RoutineDay = {
        id: `day-${Date.now()}`,
        name: `Día ${dayCount}`, // Internal name, UI uses index
        exercises: []
      };

      const newPatient = {
          ...patient,
          routine: {
              ...patient.routine,
              days: [...patient.routine.days, newDay]
          }
      };

      onUpdatePatient(newPatient);
      setActiveDayId(newDay.id);
  };

  const handleDeleteDay = (dayId: string) => {
    if (!window.confirm("¿Estás seguro de que quieres eliminar este día?")) {
        return;
    }

    const updatedDays = patient.routine.days.filter(d => d.id !== dayId);

    const newPatient = {
        ...patient,
        routine: {
            ...patient.routine,
            days: updatedDays
        }
    };

    if (activeDayId === dayId) {
        setActiveDayId(updatedDays.length > 0 ? updatedDays[0].id : '');
    }

    onUpdatePatient(newPatient);
  };

  const handleExerciseUpdate = (exerciseId: string, updates: Partial<RoutineExercise>) => {
    if (activeDayIndex === -1) return;

    const newDays = [...patient.routine.days];
    const newExercises = [...newDays[activeDayIndex].exercises];

    const exIndex = newExercises.findIndex(e => e.id === exerciseId);
    if (exIndex === -1) return;

    newExercises[exIndex] = {
        ...newExercises[exIndex],
        ...updates
    };

    newDays[activeDayIndex] = {
        ...newDays[activeDayIndex],
        exercises: newExercises
    };

    onUpdatePatient({
        ...patient,
        routine: {
            ...patient.routine,
            days: newDays
        }
    });
  };

  const handleRemoveExercise = (exerciseId: string) => {
      if (activeDayIndex === -1) return;

      const newDays = [...patient.routine.days];
      newDays[activeDayIndex] = {
          ...newDays[activeDayIndex],
          exercises: newDays[activeDayIndex].exercises.filter(e => e.id !== exerciseId)
      };

      onUpdatePatient({
          ...patient,
          routine: {
              ...patient.routine,
              days: newDays
          }
      });
  };

  const handleAddExercise = (defId: string) => {
      const definition = EXERCISES.find(e => e.id === defId);
      if(!definition) return;

      if (activeDayIndex === -1) return;

      const newExercise: RoutineExercise = {
          id: `re-${Date.now()}`,
          definitionId: definition.id,
          definition: definition,
          targetSets: 3,
          targetReps: 10,
          targetLoad: 0,
          isDone: false,
          history: []
      };

      const newDays = [...patient.routine.days];
      newDays[activeDayIndex] = {
          ...newDays[activeDayIndex],
          exercises: [...newDays[activeDayIndex].exercises, newExercise]
      };

      onUpdatePatient({
          ...patient,
          routine: {
              ...patient.routine,
              days: newDays
          }
      });

      setIsAddingExercise(false);
      setExerciseSearch('');
  };

  const filteredCatalog = EXERCISES.filter(ex => 
    ex.name.toLowerCase().includes(exerciseSearch.toLowerCase()) || 
    ex.category.toLowerCase().includes(exerciseSearch.toLowerCase())
  );

  return (
    <div className="flex-1 h-screen flex flex-col bg-slate-50 overflow-hidden relative">

      {/* 1. TOP HEADER */}
      <header className="bg-white border-b border-slate-200 px-6 py-4 flex items-center justify-between shadow-sm shrink-0 z-20">
        <div className="flex items-center gap-4">
          <div className="flex flex-col">
            <h2 className="text-2xl font-bold text-slate-900 leading-none">
              {patient.firstName} {patient.lastName}
            </h2>
            <div className="flex items-center gap-2 mt-1">
                <span className="text-sm font-medium text-slate-500">{patient.condition}</span>
                <span className="w-1 h-1 bg-slate-300 rounded-full"></span>
                <span className="text-sm text-slate-400">{patient.age} años</span>
            </div>
          </div>
        </div>

        <div className="flex gap-2">
            <button 
                onClick={() => setShowWeeklyView(true)}
                className="flex items-center gap-2 px-4 py-2 rounded-lg font-medium transition-colors bg-white border border-slate-200 text-slate-600 hover:bg-slate-50"
            >
                <LayoutGrid size={18} />
                <span>Vista Semanal</span>
            </button>
            <button 
                onClick={() => setShowHistory(!showHistory)}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg font-medium transition-colors ${showHistory ? 'bg-slate-800 text-white' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'}`}
            >
                <FileText size={18} />
                <span>{showHistory ? 'Ocultar Ficha' : 'Ver Ficha'}</span>
            </button>
        </div>
      </header>

      {/* 2. HISTORY DRAWER */}
      {showHistory && (
          <div className="bg-slate-800 text-slate-200 px-8 py-6 shadow-inner shrink-0 animate-in slide-in-from-top-5 border-b border-slate-700">
              <div className="grid grid-cols-1 md:grid-cols-3 gap-8 max-w-5xl">
                  <div className="md:col-span-1">
                       <h4 className="text-slate-400 text-xs uppercase font-bold mb-2">Datos Clínicos</h4>
                       <div className="space-y-4">
                            <div>
                                <h5 className="text-slate-500 text-xs font-bold">Última Visita</h5>
                                <p className="text-sm font-mono bg-slate-700 w-fit px-2 py-1 rounded mt-1">{patient.lastVisit}</p>
                            </div>
                            <div>
                                <h5 className="text-slate-500 text-xs font-bold">Alertas</h5>
                                <div className="flex items-start gap-2 text-amber-400 text-sm mt-1">
                                    <AlertCircle size={16} className="mt-0.5 shrink-0" />
                                    <span>Controlar dolor.</span>
                                </div>
                            </div>
                       </div>
                  </div>
                  <div className="md:col-span-2">
                      <div className="flex justify-between items-center mb-2">
                        <h4 className="text-slate-400 text-xs uppercase font-bold">Observaciones / Evolución</h4>
                        <span className="text-xs text-slate-500 italic">Se guarda automáticamente</span>
                      </div>
                      <textarea 
                        className="w-full h-32 bg-slate-700 text-slate-200 p-4 rounded-xl border border-slate-600 focus:ring-2 focus:ring-primary-500 outline-none resize-none leading-relaxed"
                        value={notes}
                        onChange={(e) => setNotes(e.target.value)}
                        onBlur={handleSaveNotes}
                        placeholder="Escribe aquí las observaciones clínicas..."
                      />
                  </div>
              </div>
          </div>
      )}

      {/* 3. DAY SELECTOR (Tabs) */}
      <div className="bg-white border-b border-slate-200 px-6 flex gap-1 pt-4 overflow-x-auto no-scrollbar shrink-0">
        {patient.routine.days.map((day, index) => (
          <button
            key={day.id}
            onClick={() => setActiveDayId(day.id)}
            className={`px-6 py-3 rounded-t-xl font-bold text-sm tracking-wide transition-all border-t border-x ${
              activeDayId === day.id
                ? 'bg-slate-50 border-slate-200 text-primary-600 border-b-slate-50 -mb-px z-10'
                : 'bg-white border-transparent text-slate-400 hover:bg-slate-50 hover:text-slate-600'
            }`}
          >
            Día {index + 1}
          </button>
        ))}
        {/* Add Day Button */}
        <button 
            onClick={handleAddDay}
            className="px-4 py-3 text-slate-300 hover:text-primary-600 hover:bg-slate-50 rounded-t-xl transition-all flex items-center gap-1 group"
            title="Agregar día"
        >
            <Plus size={20} className="group-hover:scale-110 transition-transform" />
        </button>
      </div>

      {/* 4. MAIN ROUTINE AREA */}
      <main className="flex-1 overflow-y-auto p-6 md:p-8 scroll-smooth">
        <div className="max-w-3xl mx-auto pb-20">

          {activeDay ? (
            <div className="space-y-4">
              {activeDay.exercises.length > 0 ? (
                  activeDay.exercises.map((exercise) => (
                    <ExerciseCard
                      key={exercise.id}
                      exercise={exercise}
                      onUpdate={handleExerciseUpdate}
                      onShowHistory={(ex) => setChartExercise(ex)}
                      onDelete={handleRemoveExercise}
                    />
                  ))
              ) : (
                  <div className="text-center py-10 text-slate-400">
                      <p className="mb-4">No hay ejercicios en el Día {activeDayIndex + 1}</p>
                      <button 
                        onClick={() => setIsAddingExercise(true)}
                        className="bg-primary-50 text-primary-600 px-6 py-3 rounded-xl font-bold hover:bg-primary-100 transition-colors"
                      >
                          Agregar primer ejercicio
                      </button>
                  </div>
              )}

              {/* Add Exercise Button */}
              {activeDay.exercises.length > 0 && (
                <button 
                    onClick={() => setIsAddingExercise(true)}
                    className="w-full py-4 rounded-2xl border-2 border-dashed border-primary-200 text-primary-600 font-bold hover:bg-primary-50 transition-colors flex items-center justify-center gap-2"
                >
                    <Plus size={20} />
                    Agregar Ejercicio
                </button>
              )}

              {/* Delete Day Button (Footer) */}
              <div className="flex justify-end pt-8 opacity-60 hover:opacity-100 transition-opacity">
                  <button 
                    onClick={() => handleDeleteDay(activeDayId)}
                    className="flex items-center gap-2 text-red-400 text-sm font-medium hover:text-red-600 py-2 px-4 hover:bg-red-50 rounded-lg transition-colors"
                  >
                      <Trash2 size={16} />
                      Eliminar Día {activeDayIndex + 1}
                  </button>
              </div>

            </div>
          ) : (
            <div className="flex flex-col items-center justify-center h-full text-slate-400 mt-20">
                <p>No hay días en la rutina</p>
                <button onClick={handleAddDay} className="mt-4 text-primary-600 font-bold hover:underline">
                    Crear primer día
                </button>
            </div>
          )}
        </div>
      </main>

      {/* --- MODALS --- */}

      {/* Chart Overlay */}
      {chartExercise && (
        <ProgressChart exercise={chartExercise} onClose={() => setChartExercise(null)} />
      )}

      {/* Add Exercise Modal */}
      {isAddingExercise && (
          <div className="fixed inset-0 z-50 bg-black/50 backdrop-blur-sm flex items-center justify-center p-4">
              <div className="bg-white w-full max-w-2xl h-[80vh] rounded-2xl shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95">
                  <div className="p-4 border-b border-slate-100 flex items-center justify-between">
                      <div className="relative flex-1 mr-4">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
                        <input 
                            type="text"
                            autoFocus
                            placeholder="Buscar ejercicio..."
                            className="w-full pl-10 pr-4 py-3 bg-slate-50 rounded-xl outline-none focus:ring-2 focus:ring-primary-100"
                            value={exerciseSearch}
                            onChange={(e) => setExerciseSearch(e.target.value)}
                        />
                      </div>
                      <button onClick={() => setIsAddingExercise(false)} className="p-2 bg-slate-100 rounded-full"><X size={20} /></button>
                  </div>
                  <div className="flex-1 overflow-y-auto p-4">
                      <div className="grid grid-cols-1 gap-2">
                        {filteredCatalog.map(ex => (
                            <button 
                                key={ex.id}
                                onClick={() => handleAddExercise(ex.id)}
                                className="flex items-center p-4 hover:bg-primary-50 rounded-xl text-left group transition-colors border border-transparent hover:border-primary-100"
                            >
                                <div className="w-16 h-16 bg-slate-100 rounded-lg flex items-center justify-center mr-4 overflow-hidden shrink-0 border border-slate-200">
                                    {ex.videoUrl ? (
                                        <img src={ex.videoUrl} alt="" className="w-full h-full object-cover" />
                                    ) : (
                                        <Plus size={24} className="text-slate-400" />
                                    )}
                                </div>
                                <div>
                                    <h4 className="font-bold text-slate-800">{ex.name}</h4>
                                    <span className="text-xs text-slate-400 uppercase font-semibold">{ex.category}</span>
                                </div>
                            </button>
                        ))}
                      </div>
                  </div>
              </div>
          </div>
      )}

      {/* Weekly View Modal */}
      {showWeeklyView && (
          <div className="fixed inset-0 z-50 bg-black/50 backdrop-blur-sm flex items-center justify-center p-6">
              <div className="bg-white w-full max-w-5xl rounded-3xl shadow-2xl p-8 animate-in zoom-in-95 relative max-h-[90vh] overflow-y-auto">
                  <div className="flex justify-between items-center mb-8">
                      <h2 className="text-3xl font-bold text-slate-900">Vista Semanal</h2>
                      <button onClick={() => setShowWeeklyView(false)} className="p-2 bg-slate-100 rounded-full hover:bg-slate-200">
                         <X size={24} />
                      </button>
                  </div>

                  <div className="grid grid-cols-2 md:grid-cols-3 gap-6">
                      {patient.routine.days.map((day, index) => (
                          <div key={day.id} className="relative bg-slate-50 rounded-2xl p-5 border border-slate-200 group">
                              <button 
                                onClick={(e) => {
                                    e.stopPropagation();
                                    handleDeleteDay(day.id);
                                }}
                                className="absolute top-4 right-4 text-slate-300 hover:text-red-500 hover:bg-red-50 p-1.5 rounded-lg transition-all"
                                title="Eliminar día"
                              >
                                  <Trash2 size={18} />
                              </button>

                              <h3 className="font-bold text-lg text-slate-800 mb-4 border-b border-slate-200 pb-2 flex justify-between pr-8">
                                  Día {index + 1}
                                  <span className="text-slate-400 text-sm font-normal pt-1">{day.exercises.length} ejs</span>
                              </h3>
                              <ul className="space-y-3">
                                  {day.exercises.map(ex => (
                                      <li key={ex.id} className="flex items-start gap-2 text-sm text-slate-600">
                                          <div className={`mt-1.5 w-1.5 h-1.5 rounded-full ${ex.isDone ? 'bg-kine' : 'bg-slate-300'}`}></div>
                                          <span className={ex.isDone ? 'line-through opacity-50' : ''}>{ex.definition.name}</span>
                                      </li>
                                  ))}
                                  {day.exercises.length === 0 && <li className="text-slate-400 text-sm italic">Día de descanso</li>}
                              </ul>
                          </div>
                      ))}
                      <button 
                          onClick={() => {
                              handleAddDay();
                              setShowWeeklyView(false);
                          }}
                          className="border-2 border-dashed border-slate-200 rounded-2xl flex flex-col items-center justify-center text-slate-400 hover:border-primary-300 hover:text-primary-600 hover:bg-primary-50 transition-all min-h-[200px]"
                      >
                          <Plus size={32} />
                          <span className="font-bold mt-2">Agregar Día</span>
                      </button>
                  </div>
              </div>
          </div>
      )}

    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Sidebar } from './components/Sidebar';
import { PatientList } from './components/PatientList';
import { PatientDetail } from './components/PatientDetail';
import { MOCK_PATIENTS } from './constants';
import { Patient, ViewState } from './types';

const App: React.FC = () => {
  // --- Global State ---
  // Initialize from LocalStorage to persist changes (fixes "Trial version" feeling)
  const [patients, setPatients] = useState<Patient[]>(() => {
    try {
        const saved = localStorage.getItem('kineflow_patients');
        return saved ? JSON.parse(saved) : MOCK_PATIENTS;
    } catch (e) {
        console.error("Failed to load patients", e);
        return MOCK_PATIENTS;
    }
  });

  // "Active Patients" are those open in the dock (Sidebar)
  const [activePatientIds, setActivePatientIds] = useState<string[]>([]);

  const [selectedPatientId, setSelectedPatientId] = useState<string | null>(null);
  const [view, setView] = useState<ViewState>('HOME');

  // Derived state
  const activePatients = activePatientIds
    .map(id => patients.find(p => p.id === id))
    .filter((p): p is Patient => !!p);

  const currentPatient = patients.find(p => p.id === selectedPatientId);

  // --- Auto-Save ---
  useEffect(() => {
    localStorage.setItem('kineflow_patients', JSON.stringify(patients));
  }, [patients]);

  // --- Actions ---

  const handleSelectPatient = (patient: Patient) => {
    // 1. Add to active dock if not present
    if (!activePatientIds.includes(patient.id)) {
      setActivePatientIds(prev => [patient.id, ...prev]);
    }
    // 2. Set as selected
    setSelectedPatientId(patient.id);
    // 3. Change View
    setView('PATIENT_DETAIL');
  };

  const handleAddPatient = (newPatient: Patient) => {
      setPatients(prev => [newPatient, ...prev]);
      handleSelectPatient(newPatient); // Auto open
  };

  const handleSidebarSelect = (patientId: string) => {
    setSelectedPatientId(patientId);
    setView('PATIENT_DETAIL');
  };

  const handleRemoveActive = (patientId: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setActivePatientIds(prev => prev.filter(id => id !== patientId));

    // If we removed the currently selected one, switch to home or another
    if (selectedPatientId === patientId) {
        setSelectedPatientId(null);
        setView('HOME');
    }
  };

  const handleGoHome = () => {
    setView('HOME');
    setSelectedPatientId(null);
  };

  const handleUpdatePatient = (updatedPatient: Patient) => {
      setPatients(prev => prev.map(p => p.id === updatedPatient.id ? updatedPatient : p));
  };

  return (
    <div className="flex w-full h-screen bg-slate-50 font-sans text-slate-900">

      {/* 1. Sidebar Dock (Always Visible) */}
      <Sidebar 
        activePatients={activePatients}
        selectedPatientId={selectedPatientId}
        onSelectPatient={handleSidebarSelect}
        onRemoveActive={handleRemoveActive}
        onGoHome={handleGoHome}
      />

      {/* 2. Main Content Area */}
      <div className="flex-1 flex flex-col h-full overflow-hidden">
        {view === 'HOME' && (
            <PatientList 
                patients={patients} 
                onSelectPatient={handleSelectPatient} 
                onAddPatient={handleAddPatient}
            />
        )}

        {view === 'PATIENT_DETAIL' && currentPatient && (
            <PatientDetail 
                patient={currentPatient}
                onUpdatePatient={handleUpdatePatient}
            />
        )}
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Patient, RoutineDay, RoutineExercise } from '../types';
import { EXERCISES } from '../constants';
import { ExerciseCard } from './ExerciseCard';
import { ProgressChart } from './ProgressChart';
import { AlertCircle, FileText, Plus, Search, X, LayoutGrid, Trash2 } from 'lucide-react';

interface PatientDetailProps {
  patient: Patient;
  onUpdatePatient: (updated: Patient) => void;
}

export const PatientDetail: React.FC<PatientDetailProps> = ({
  patient,
  onUpdatePatient,
}) => {
  const [activeDayId, setActiveDayId] = useState<string>(
    patient.routine.days[0]?.id || ''
  );
  const [showHistory, setShowHistory] = useState<boolean>(false);
  const [showWeeklyView, setShowWeeklyView] = useState<boolean>(false);
  const [chartExercise, setChartExercise] = useState<RoutineExercise | null>(null);
  const [isAddingExercise, setIsAddingExercise] = useState(false);
  const [exerciseSearch, setExerciseSearch] = useState('');

  // Local state for editable notes
  const [notes, setNotes] = useState(patient.history[0] || '');

  // Sync notes when patient changes
  useEffect(() => {
    setNotes(patient.history[0] || '');
  }, [patient.id]);

  // Ensure activeDayId is valid if days change (e.g. deletion from parent or external update)
  useEffect(() => {
     if (patient.routine.days.length > 0) {
         const dayExists = patient.routine.days.find(d => d.id === activeDayId);
         if (!dayExists) {
             // If active day no longer exists, default to the first one
             setActiveDayId(patient.routine.days[0].id);
         }
     } else {
         if (activeDayId !== '') setActiveDayId('');
     }
  }, [patient.routine.days, activeDayId]);

  // Determine active day index for display
  const activeDayIndex = patient.routine.days.findIndex(d => d.id === activeDayId);
  const activeDay = patient.routine.days[activeDayIndex];

  // --- Handlers (IMMUTABLE UPDATES) ---

  const handleSaveNotes = () => {
      const newHistory = [...patient.history];
      if (newHistory.length === 0) {
          newHistory.push(notes);
      } else {
          newHistory[0] = notes;
      }
      onUpdatePatient({ ...patient, history: newHistory });
  };

  const handleAddDay = () => {
      const newDay: RoutineDay = {
        id: `day-${Date.now()}`,
        name: `Día Nuevo`, // Name is managed by index in UI
        exercises: []
      };

      const newPatient = {
          ...patient,
          routine: {
              ...patient.routine,
              days: [...patient.routine.days, newDay]
          }
      };

      onUpdatePatient(newPatient);
      // Automatically switch to the new day
      setActiveDayId(newDay.id);
  };

  const handleDeleteDay = (dayId: string) => {
    // Simple confirm
    if (!window.confirm("¿Eliminar este día de la rutina?")) {
        return;
    }

    const updatedDays = patient.routine.days.filter(d => d.id !== dayId);

    const newPatient = {
        ...patient,
        routine: {
            ...patient.routine,
            days: updatedDays
        }
    };

    // If we are deleting the currently active day, determine the new active day immediately
    if (activeDayId === dayId) {
        const newActiveId = updatedDays.length > 0 ? updatedDays[0].id : '';
        setActiveDayId(newActiveId);
    }

    onUpdatePatient(newPatient);
  };

  const handleExerciseUpdate = (exerciseId: string, updates: Partial<RoutineExercise>) => {
    if (activeDayIndex === -1) return;

    const newDays = [...patient.routine.days];
    const newExercises = [...newDays[activeDayIndex].exercises];

    const exIndex = newExercises.findIndex(e => e.id === exerciseId);
    if (exIndex === -1) return;

    newExercises[exIndex] = {
        ...newExercises[exIndex],
        ...updates
    };

    newDays[activeDayIndex] = {
        ...newDays[activeDayIndex],
        exercises: newExercises
    };

    onUpdatePatient({
        ...patient,
        routine: {
            ...patient.routine,
            days: newDays
        }
    });
  };

  const handleRemoveExercise = (exerciseId: string) => {
      if (activeDayIndex === -1) return;

      const newDays = [...patient.routine.days];
      newDays[activeDayIndex] = {
          ...newDays[activeDayIndex],
          exercises: newDays[activeDayIndex].exercises.filter(e => e.id !== exerciseId)
      };

      onUpdatePatient({
          ...patient,
          routine: {
              ...patient.routine,
              days: newDays
          }
      });
  };

  const handleAddExercise = (defId: string) => {
      const definition = EXERCISES.find(e => e.id === defId);
      if(!definition) return;

      if (activeDayIndex === -1) return;

      const newExercise: RoutineExercise = {
          id: `re-${Date.now()}`,
          definitionId: definition.id,
          definition: definition,
          targetSets: 3,
          targetReps: 10,
          targetLoad: 0,
          isDone: false,
          history: []
      };

      const newDays = [...patient.routine.days];
      newDays[activeDayIndex] = {
          ...newDays[activeDayIndex],
          exercises: [...newDays[activeDayIndex].exercises, newExercise]
      };

      onUpdatePatient({
          ...patient,
          routine: {
              ...patient.routine,
              days: newDays
          }
      });

      setIsAddingExercise(false);
      setExerciseSearch('');
  };

  const filteredCatalog = EXERCISES.filter(ex => 
    ex.name.toLowerCase().includes(exerciseSearch.toLowerCase()) || 
    ex.category.toLowerCase().includes(exerciseSearch.toLowerCase())
  );

  return (
    <div className="flex-1 h-screen flex flex-col bg-slate-50 overflow-hidden relative">

      {/* 1. TOP HEADER */}
      <header className="bg-white border-b border-slate-200 px-6 py-4 flex items-center justify-between shadow-sm shrink-0 z-20">
        <div className="flex items-center gap-4">
          <div className="flex flex-col">
            <h2 className="text-2xl font-bold text-slate-900 leading-none">
              {patient.firstName} {patient.lastName}
            </h2>
            <div className="flex items-center gap-2 mt-1">
                <span className="text-sm font-medium text-slate-500">{patient.condition}</span>
                <span className="w-1 h-1 bg-slate-300 rounded-full"></span>
                <span className="text-sm text-slate-400">{patient.age} años</span>
            </div>
          </div>
        </div>

        <div className="flex gap-2">
            <button 
                onClick={() => setShowWeeklyView(true)}
                className="flex items-center gap-2 px-4 py-2 rounded-lg font-medium transition-colors bg-white border border-slate-200 text-slate-600 hover:bg-slate-50"
            >
                <LayoutGrid size={18} />
                <span>Vista Semanal</span>
            </button>
            <button 
                onClick={() => setShowHistory(!showHistory)}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg font-medium transition-colors ${showHistory ? 'bg-slate-800 text-white' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'}`}
            >
                <FileText size={18} />
                <span>{showHistory ? 'Ocultar Ficha' : 'Ver Ficha'}</span>
            </button>
        </div>
      </header>

      {/* 2. HISTORY DRAWER */}
      {showHistory && (
          <div className="bg-slate-800 text-slate-200 px-8 py-6 shadow-inner shrink-0 animate-in slide-in-from-top-5 border-b border-slate-700">
              <div className="grid grid-cols-1 md:grid-cols-3 gap-8 max-w-5xl">
                  <div className="md:col-span-1">
                       <h4 className="text-slate-400 text-xs uppercase font-bold mb-2">Datos Clínicos</h4>
                       <div className="space-y-4">
                            <div>
                                <h5 className="text-slate-500 text-xs font-bold">Última Visita</h5>
                                <p className="text-sm font-mono bg-slate-700 w-fit px-2 py-1 rounded mt-1">{patient.lastVisit}</p>
                            </div>
                            <div>
                                <h5 className="text-slate-500 text-xs font-bold">Alertas</h5>
                                <div className="flex items-start gap-2 text-amber-400 text-sm mt-1">
                                    <AlertCircle size={16} className="mt-0.5 shrink-0" />
                                    <span>Controlar dolor.</span>
                                </div>
                            </div>
                       </div>
                  </div>
                  <div className="md:col-span-2">
                      <div className="flex justify-between items-center mb-2">
                        <h4 className="text-slate-400 text-xs uppercase font-bold">Observaciones / Evolución</h4>
                        <span className="text-xs text-slate-500 italic">Se guarda automáticamente</span>
                      </div>
                      <textarea 
                        className="w-full h-32 bg-slate-700 text-slate-200 p-4 rounded-xl border border-slate-600 focus:ring-2 focus:ring-primary-500 outline-none resize-none leading-relaxed"
                        value={notes}
                        onChange={(e) => setNotes(e.target.value)}
                        onBlur={handleSaveNotes}
                        placeholder="Escribe aquí las observaciones clínicas..."
                      />
                  </div>
              </div>
          </div>
      )}

      {/* 3. DAY SELECTOR (Tabs) */}
      <div className="bg-white border-b border-slate-200 px-6 flex gap-1 pt-4 overflow-x-auto no-scrollbar shrink-0">
        {patient.routine.days.map((day, index) => (
          <button
            key={day.id}
            onClick={() => setActiveDayId(day.id)}
            className={`px-6 py-3 rounded-t-xl font-bold text-sm tracking-wide transition-all border-t border-x ${
              activeDayId === day.id
                ? 'bg-slate-50 border-slate-200 text-primary-600 border-b-slate-50 -mb-px z-10'
                : 'bg-white border-transparent text-slate-400 hover:bg-slate-50 hover:text-slate-600'
            }`}
          >
            Día {index + 1}
          </button>
        ))}
        {/* Add Day Button */}
        <button 
            onClick={handleAddDay}
            className="px-4 py-3 text-slate-300 hover:text-primary-600 hover:bg-slate-50 rounded-t-xl transition-all flex items-center gap-1 group"
            title="Agregar día"
        >
            <Plus size={20} className="group-hover:scale-110 transition-transform" />
        </button>
      </div>

      {/* 4. MAIN ROUTINE AREA */}
      <main className="flex-1 overflow-y-auto p-6 md:p-8 scroll-smooth">
        <div className="max-w-3xl mx-auto pb-20">

          {activeDay ? (
            <div className="space-y-4">
              {activeDay.exercises.length > 0 ? (
                  activeDay.exercises.map((exercise) => (
                    <ExerciseCard
                      key={exercise.id}
                      exercise={exercise}
                      onUpdate={handleExerciseUpdate}
                      onShowHistory={(ex) => setChartExercise(ex)}
                      onDelete={handleRemoveExercise}
                    />
                  ))
              ) : (
                  <div className="text-center py-10 text-slate-400">
                      <p className="mb-4">No hay ejercicios en el Día {activeDayIndex + 1}</p>
                      <button 
                        onClick={() => setIsAddingExercise(true)}
                        className="bg-primary-50 text-primary-600 px-6 py-3 rounded-xl font-bold hover:bg-primary-100 transition-colors"
                      >
                          Agregar primer ejercicio
                      </button>
                  </div>
              )}

              {/* Add Exercise Button */}
              {activeDay.exercises.length > 0 && (
                <button 
                    onClick={() => setIsAddingExercise(true)}
                    className="w-full py-4 rounded-2xl border-2 border-dashed border-primary-200 text-primary-600 font-bold hover:bg-primary-50 transition-colors flex items-center justify-center gap-2"
                >
                    <Plus size={20} />
                    Agregar Ejercicio
                </button>
              )}

              {/* Delete Day Button (Footer) - NO OPACITY for better touch interaction */}
              <div className="flex justify-end pt-8">
                  <button 
                    onClick={() => handleDeleteDay(activeDayId)}
                    className="flex items-center gap-2 text-red-500 text-sm font-medium hover:text-red-700 py-3 px-4 bg-red-50 hover:bg-red-100 rounded-lg transition-colors border border-red-100"
                  >
                      <Trash2 size={16} />
                      Eliminar Día {activeDayIndex + 1}
                  </button>
              </div>

            </div>
          ) : (
            <div className="flex flex-col items-center justify-center h-full text-slate-400 mt-20">
                <p>No hay días en la rutina</p>
                <button onClick={handleAddDay} className="mt-4 text-primary-600 font-bold hover:underline">
                    Crear primer día
                </button>
            </div>
          )}
        </div>
      </main>

      {/* --- MODALS --- */}

      {/* Chart Overlay */}
      {chartExercise && (
        <ProgressChart exercise={chartExercise} onClose={() => setChartExercise(null)} />
      )}

      {/* Add Exercise Modal */}
      {isAddingExercise && (
          <div className="fixed inset-0 z-50 bg-black/50 backdrop-blur-sm flex items-center justify-center p-4">
              <div className="bg-white w-full max-w-2xl h-[80vh] rounded-2xl shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95">
                  <div className="p-4 border-b border-slate-100 flex items-center justify-between">
                      <div className="relative flex-1 mr-4">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
                        <input 
                            type="text"
                            autoFocus
                            placeholder="Buscar ejercicio..."
                            className="w-full pl-10 pr-4 py-3 bg-slate-50 rounded-xl outline-none focus:ring-2 focus:ring-primary-100"
                            value={exerciseSearch}
                            onChange={(e) => setExerciseSearch(e.target.value)}
                        />
                      </div>
                      <button onClick={() => setIsAddingExercise(false)} className="p-2 bg-slate-100 rounded-full"><X size={20} /></button>
                  </div>
                  <div className="flex-1 overflow-y-auto p-4">
                      <div className="grid grid-cols-1 gap-2">
                        {filteredCatalog.map(ex => (
                            <button 
                                key={ex.id}
                                onClick={() => handleAddExercise(ex.id)}
                                className="flex items-center p-4 hover:bg-primary-50 rounded-xl text-left group transition-colors border border-transparent hover:border-primary-100"
                            >
                                <div className="w-16 h-16 bg-slate-100 rounded-lg flex items-center justify-center mr-4 overflow-hidden shrink-0 border border-slate-200">
                                    {ex.videoUrl ? (
                                        <img src={ex.videoUrl} alt="" className="w-full h-full object-cover" />
                                    ) : (
                                        <Plus size={24} className="text-slate-400" />
                                    )}
                                </div>
                                <div>
                                    <h4 className="font-bold text-slate-800">{ex.name}</h4>
                                    <span className="text-xs text-slate-400 uppercase font-semibold">{ex.category}</span>
                                </div>
                            </button>
                        ))}
                      </div>
                  </div>
              </div>
          </div>
      )}

      {/* Weekly View Modal */}
      {showWeeklyView && (
          <div className="fixed inset-0 z-50 bg-black/50 backdrop-blur-sm flex items-center justify-center p-6">
              <div className="bg-white w-full max-w-5xl rounded-3xl shadow-2xl p-8 animate-in zoom-in-95 relative max-h-[90vh] overflow-y-auto">
                  <div className="flex justify-between items-center mb-8">
                      <h2 className="text-3xl font-bold text-slate-900">Vista Semanal</h2>
                      <button onClick={() => setShowWeeklyView(false)} className="p-2 bg-slate-100 rounded-full hover:bg-slate-200">
                         <X size={24} />
                      </button>
                  </div>

                  <div className="grid grid-cols-2 md:grid-cols-3 gap-6">
                      {patient.routine.days.map((day, index) => (
                          <div key={day.id} className="relative bg-slate-50 rounded-2xl p-5 border border-slate-200 group">
                              <button 
                                onClick={(e) => {
                                    e.stopPropagation();
                                    handleDeleteDay(day.id);
                                }}
                                className="absolute top-4 right-4 text-red-400 hover:text-red-600 bg-red-50 hover:bg-red-100 p-2 rounded-lg transition-all"
                                title="Eliminar día"
                              >
                                  <Trash2 size={18} />
                              </button>

                              <h3 className="font-bold text-lg text-slate-800 mb-4 border-b border-slate-200 pb-2 flex justify-between pr-8">
                                  Día {index + 1}
                                  <span className="text-slate-400 text-sm font-normal pt-1">{day.exercises.length} ejs</span>
                              </h3>
                              <ul className="space-y-3">
                                  {day.exercises.map(ex => (
                                      <li key={ex.id} className="flex items-start gap-2 text-sm text-slate-600">
                                          <div className={`mt-1.5 w-1.5 h-1.5 rounded-full ${ex.isDone ? 'bg-kine' : 'bg-slate-300'}`}></div>
                                          <span className={ex.isDone ? 'line-through opacity-50' : ''}>{ex.definition.name}</span>
                                      </li>
                                  ))}
                                  {day.exercises.length === 0 && <li className="text-slate-400 text-sm italic">Día de descanso</li>}
                              </ul>
                          </div>
                      ))}
                      <button 
                          onClick={() => {
                              handleAddDay();
                              setShowWeeklyView(false);
                          }}
                          className="border-2 border-dashed border-slate-200 rounded-2xl flex flex-col items-center justify-center text-slate-400 hover:border-primary-300 hover:text-primary-600 hover:bg-primary-50 transition-all min-h-[200px]"
                      >
                          <Plus size={32} />
                          <span className="font-bold mt-2">Agregar Día</span>
                      </button>
                  </div>
              </div>
          </div>
      )}

    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Patient, RoutineDay, RoutineExercise, Stage } from '../types';
import { EXERCISES } from '../constants';
import { ExerciseCard } from './ExerciseCard';
import { ProgressChart } from './ProgressChart';
import { AlertCircle, FileText, Plus, Search, X, LayoutGrid, Trash2, Settings, CheckSquare, Square } from 'lucide-react';

interface PatientDetailProps {
  patient: Patient;
  onUpdatePatient: (updated: Patient) => void;
}

export const PatientDetail: React.FC<PatientDetailProps> = ({
  patient,
  onUpdatePatient,
}) => {
  const [activeDayId, setActiveDayId] = useState<string>(
    patient.routine.days[0]?.id || ''
  );
  const [showHistory, setShowHistory] = useState<boolean>(false);
  const [showRoutineEditor, setShowRoutineEditor] = useState<boolean>(false);

  // States for Modals
  const [chartExercise, setChartExercise] = useState<RoutineExercise | null>(null);

  // Adding Exercise States
  const [isAddingExercise, setIsAddingExercise] = useState(false); // Single add mode
  const [targetDayIdForAdd, setTargetDayIdForAdd] = useState<string | null>(null); // Which day are we adding to?
  const [exerciseSearch, setExerciseSearch] = useState('');
  const [selectedExerciseIds, setSelectedExerciseIds] = useState<string[]>([]); // For multi-select

  // Local state for editable notes
  const [notes, setNotes] = useState(patient.history[0] || '');

  // Sync notes when patient changes
  useEffect(() => {
    setNotes(patient.history[0] || '');
  }, [patient.id]);

  // Auto-open Editor if routine is empty (Onboarding flow)
  useEffect(() => {
      const hasExercises = patient.routine.days.some(d => d.exercises.length > 0);
      if (!hasExercises && patient.routine.days.length <= 1) {
          setShowRoutineEditor(true);
      }
  }, [patient.id]);

  // Ensure activeDayId is valid
  useEffect(() => {
     if (patient.routine.days.length > 0) {
         const dayExists = patient.routine.days.find(d => d.id === activeDayId);
         if (!dayExists) {
             setActiveDayId(patient.routine.days[0].id);
         }
     } else {
         if (activeDayId !== '') setActiveDayId('');
     }
  }, [patient.routine.days, activeDayId]);

  const activeDayIndex = patient.routine.days.findIndex(d => d.id === activeDayId);
  const activeDay = patient.routine.days[activeDayIndex];

  // --- HANDLERS ---

  const handleSaveNotes = () => {
      const newHistory = [...patient.history];
      if (newHistory.length === 0) {
          newHistory.push(notes);
      } else {
          newHistory[0] = notes;
      }
      onUpdatePatient({ ...patient, history: newHistory });
  };

  const handleToggleStage = () => {
      const newStage = patient.routine.stage === Stage.KINESIOLOGY ? Stage.GYM : Stage.KINESIOLOGY;
      onUpdatePatient({
          ...patient,
          routine: { ...patient.routine, stage: newStage }
      });
  };

  // --- ROUTINE STRUCTURE HANDLERS ---

  const handleUpdateDayCount = (delta: number) => {
      const currentCount = patient.routine.days.length;
      const newCount = Math.max(1, Math.min(7, currentCount + delta));

      if (newCount === currentCount) return;

      let newDays = [...patient.routine.days];

      if (newCount > currentCount) {
          // Add Days
          for (let i = currentCount; i < newCount; i++) {
              newDays.push({
                  id: `day-${Date.now()}-${i}`,
                  name: `Día ${i + 1}`,
                  exercises: []
              });
          }
      } else {
          // Remove Days (from end)
          if (newDays[newDays.length - 1].exercises.length > 0) {
              if (!window.confirm("Al reducir los días se eliminarán los ejercicios del último día. ¿Continuar?")) {
                  return;
              }
          }
          newDays = newDays.slice(0, newCount);
      }

      onUpdatePatient({
          ...patient,
          routine: { ...patient.routine, days: newDays }
      });
  };

  const handleDeleteDay = (dayId: string) => {
    if (!window.confirm("¿Estás seguro de que quieres eliminar este día?")) return;
    const updatedDays = patient.routine.days.filter(d => d.id !== dayId);

    // If we deleted the last day, ensure there's at least one empty day or handle logic
    if (updatedDays.length === 0) {
         updatedDays.push({ id: `day-${Date.now()}`, name: 'Día 1', exercises: [] });
    }

    onUpdatePatient({
        ...patient,
        routine: { ...patient.routine, days: updatedDays }
    });

    if (activeDayId === dayId) {
        setActiveDayId(updatedDays[0].id);
    }
  };

  // --- EXERCISE HANDLERS ---

  const handleExerciseUpdate = (exerciseId: string, updates: Partial<RoutineExercise>) => {
    if (activeDayIndex === -1) return;

    // We need to find which day this exercise belongs to if we are not in the main view
    // But since this is passed to ExerciseCard in main view, activeDayIndex is correct.
    // For safety in modal (if we used it there), we would search.

    const newDays = [...patient.routine.days];
    const newExercises = [...newDays[activeDayIndex].exercises];
    const exIndex = newExercises.findIndex(e => e.id === exerciseId);
    if (exIndex === -1) return;

    newExercises[exIndex] = { ...newExercises[exIndex], ...updates };
    newDays[activeDayIndex] = { ...newDays[activeDayIndex], exercises: newExercises };

    onUpdatePatient({
        ...patient,
        routine: { ...patient.routine, days: newDays }
    });
  };

  const handleRemoveExercise = (dayId: string, exerciseId: string) => {
      const dayIndex = patient.routine.days.findIndex(d => d.id === dayId);
      if (dayIndex === -1) return;

      const newDays = [...patient.routine.days];
      newDays[dayIndex] = {
          ...newDays[dayIndex],
          exercises: newDays[dayIndex].exercises.filter(e => e.id !== exerciseId)
      };

      onUpdatePatient({
          ...patient,
          routine: { ...patient.routine, days: newDays }
      });
  };

  // --- ADD EXERCISE LOGIC (Single & Multi) ---

  const openAddModal = (dayId: string) => {
      setTargetDayIdForAdd(dayId);
      setSelectedExerciseIds([]);
      setExerciseSearch('');
      setIsAddingExercise(true);
  };

  const toggleExerciseSelection = (defId: string) => {
      setSelectedExerciseIds(prev => 
        prev.includes(defId) ? prev.filter(id => id !== defId) : [...prev, defId]
      );
  };

  const handleConfirmAddExercises = () => {
      if (!targetDayIdForAdd) return;
      const dayIndex = patient.routine.days.findIndex(d => d.id === targetDayIdForAdd);
      if (dayIndex === -1) return;

      // Create exercise instances
      const newExercises: RoutineExercise[] = selectedExerciseIds.map(defId => {
          const def = EXERCISES.find(e => e.id === defId)!;
          return {
              id: `re-${Date.now()}-${Math.random()}`,
              definitionId: def.id,
              definition: def,
              targetSets: 3,
              targetReps: 10,
              targetLoad: 0,
              isDone: false,
              history: []
          };
      });

      const newDays = [...patient.routine.days];
      newDays[dayIndex] = {
          ...newDays[dayIndex],
          exercises: [...newDays[dayIndex].exercises, ...newExercises]
      };

      onUpdatePatient({
          ...patient,
          routine: { ...patient.routine, days: newDays }
      });

      setIsAddingExercise(false);
      setSelectedExerciseIds([]);
  };

  // Legacy single add (from main view button)
  const handleSingleAdd = (defId: string) => {
      // If we are just clicking on an item without using checkboxes, treat as single add
      toggleExerciseSelection(defId);
  };

  const filteredCatalog = EXERCISES.filter(ex => 
    ex.name.toLowerCase().includes(exerciseSearch.toLowerCase()) || 
    ex.category.toLowerCase().includes(exerciseSearch.toLowerCase())
  );

  return (
    <div className="flex-1 h-screen flex flex-col bg-slate-50 overflow-hidden relative">

      {/* 1. TOP HEADER */}
      <header className="bg-white border-b border-slate-200 px-6 py-4 flex items-center justify-between shadow-sm shrink-0 z-20">
        <div className="flex items-center gap-4">
          <div className="flex flex-col">
            <h2 className="text-2xl font-bold text-slate-900 leading-none">
              {patient.firstName} {patient.lastName}
            </h2>
            <div className="flex items-center gap-2 mt-2">
                {/* Clickable Stage Badge */}
                <button 
                    onClick={handleToggleStage}
                    className={`px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wider transition-all border ${
                        patient.routine.stage === Stage.KINESIOLOGY 
                        ? 'bg-kine/10 text-kine border-kine/20 hover:bg-kine/20' 
                        : 'bg-gym/10 text-gym border-gym/20 hover:bg-gym/20'
                    }`}
                    title="Clic para cambiar etapa"
                >
                    {patient.routine.stage} ↺
                </button>
                <span className="w-1 h-1 bg-slate-300 rounded-full"></span>
                <span className="text-sm text-slate-400">{patient.age} años</span>
            </div>
          </div>
        </div>

        <div className="flex gap-2">
            <button 
                onClick={() => setShowRoutineEditor(true)}
                className="flex items-center gap-2 px-4 py-2 rounded-lg font-bold transition-colors bg-primary-600 text-white shadow-md shadow-primary-200 hover:bg-primary-700"
            >
                <Settings size={18} />
                <span>Editar Rutina</span>
            </button>
            <button 
                onClick={() => setShowHistory(!showHistory)}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg font-medium transition-colors ${showHistory ? 'bg-slate-800 text-white' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'}`}
            >
                <FileText size={18} />
                <span>{showHistory ? 'Ocultar Ficha' : 'Ver Ficha'}</span>
            </button>
        </div>
      </header>

      {/* 2. HISTORY DRAWER */}
      {showHistory && (
          <div className="bg-slate-800 text-slate-200 px-8 py-6 shadow-inner shrink-0 animate-in slide-in-from-top-5 border-b border-slate-700">
              <div className="grid grid-cols-1 md:grid-cols-3 gap-8 max-w-5xl">
                  <div className="md:col-span-1">
                       <h4 className="text-slate-400 text-xs uppercase font-bold mb-2">Datos Clínicos</h4>
                       <div className="space-y-4">
                            <div>
                                <h5 className="text-slate-500 text-xs font-bold">Última Visita</h5>
                                <p className="text-sm font-mono bg-slate-700 w-fit px-2 py-1 rounded mt-1">{patient.lastVisit}</p>
                            </div>
                            <div>
                                <h5 className="text-slate-500 text-xs font-bold">Alertas</h5>
                                <div className="flex items-start gap-2 text-amber-400 text-sm mt-1">
                                    <AlertCircle size={16} className="mt-0.5 shrink-0" />
                                    <span>Controlar dolor.</span>
                                </div>
                            </div>
                       </div>
                  </div>
                  <div className="md:col-span-2">
                      <div className="flex justify-between items-center mb-2">
                        <h4 className="text-slate-400 text-xs uppercase font-bold">Observaciones / Evolución</h4>
                        <span className="text-xs text-slate-500 italic">Se guarda automáticamente</span>
                      </div>
                      <textarea 
                        className="w-full h-32 bg-slate-700 text-slate-200 p-4 rounded-xl border border-slate-600 focus:ring-2 focus:ring-primary-500 outline-none resize-none leading-relaxed"
                        value={notes}
                        onChange={(e) => setNotes(e.target.value)}
                        onBlur={handleSaveNotes}
                        placeholder="Escribe aquí las observaciones clínicas..."
                      />
                  </div>
              </div>
          </div>
      )}

      {/* 3. DAY SELECTOR (Tabs) */}
      <div className="bg-white border-b border-slate-200 px-6 flex gap-1 pt-4 overflow-x-auto no-scrollbar shrink-0">
        {patient.routine.days.map((day, index) => (
          <button
            key={day.id}
            onClick={() => setActiveDayId(day.id)}
            className={`px-6 py-3 rounded-t-xl font-bold text-sm tracking-wide transition-all border-t border-x ${
              activeDayId === day.id
                ? 'bg-slate-50 border-slate-200 text-primary-600 border-b-slate-50 -mb-px z-10'
                : 'bg-white border-transparent text-slate-400 hover:bg-slate-50 hover:text-slate-600'
            }`}
          >
            Día {index + 1}
          </button>
        ))}
      </div>

      {/* 4. MAIN ROUTINE AREA */}
      <main className="flex-1 overflow-y-auto p-6 md:p-8 scroll-smooth">
        <div className="max-w-3xl mx-auto pb-20">

          {activeDay ? (
            <div className="space-y-4">
              {activeDay.exercises.length > 0 ? (
                  activeDay.exercises.map((exercise) => (
                    <ExerciseCard
                      key={exercise.id}
                      exercise={exercise}
                      onUpdate={handleExerciseUpdate}
                      onShowHistory={(ex) => setChartExercise(ex)}
                      onDelete={(eid) => handleRemoveExercise(activeDayId, eid)}
                    />
                  ))
              ) : (
                  <div className="text-center py-10 text-slate-400">
                      <p className="mb-4">No hay ejercicios en el Día {activeDayIndex + 1}</p>
                      <button 
                        onClick={() => openAddModal(activeDayId)}
                        className="bg-primary-50 text-primary-600 px-6 py-3 rounded-xl font-bold hover:bg-primary-100 transition-colors"
                      >
                          Agregar primer ejercicio
                      </button>
                  </div>
              )}

              {/* Add Exercise Button (Legacy/Quick Add) */}
              {activeDay.exercises.length > 0 && (
                <button 
                    onClick={() => openAddModal(activeDayId)}
                    className="w-full py-4 rounded-2xl border-2 border-dashed border-primary-200 text-primary-600 font-bold hover:bg-primary-50 transition-colors flex items-center justify-center gap-2"
                >
                    <Plus size={20} />
                    Agregar Ejercicio
                </button>
              )}
            </div>
          ) : (
            <div className="flex flex-col items-center justify-center h-full text-slate-400 mt-20">
                <p>No hay días en la rutina</p>
                <button onClick={() => setShowRoutineEditor(true)} className="mt-4 text-primary-600 font-bold hover:underline">
                    Configurar Rutina
                </button>
            </div>
          )}
        </div>
      </main>

      {/* --- MODALS --- */}

      {/* Chart Overlay */}
      {chartExercise && (
        <ProgressChart exercise={chartExercise} onClose={() => setChartExercise(null)} />
      )}

      {/* CATALOG / ADD EXERCISE MODAL (Supports Multi-Select) */}
      {isAddingExercise && (
          <div className="fixed inset-0 z-[60] bg-black/50 backdrop-blur-sm flex items-center justify-center p-4">
              <div className="bg-white w-full max-w-2xl h-[85vh] rounded-2xl shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95">
                  <div className="p-4 border-b border-slate-100 flex items-center justify-between">
                      <div className="relative flex-1 mr-4">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
                        <input 
                            type="text"
                            autoFocus
                            placeholder="Buscar ejercicio..."
                            className="w-full pl-10 pr-4 py-3 bg-slate-50 rounded-xl outline-none focus:ring-2 focus:ring-primary-100"
                            value={exerciseSearch}
                            onChange={(e) => setExerciseSearch(e.target.value)}
                        />
                      </div>
                      <button onClick={() => setIsAddingExercise(false)} className="p-2 bg-slate-100 rounded-full"><X size={20} /></button>
                  </div>

                  {/* List */}
                  <div className="flex-1 overflow-y-auto p-4">
                      <div className="grid grid-cols-1 gap-2">
                        {filteredCatalog.map(ex => {
                            const isSelected = selectedExerciseIds.includes(ex.id);
                            return (
                                <button 
                                    key={ex.id}
                                    onClick={() => toggleExerciseSelection(ex.id)}
                                    className={`flex items-center p-4 rounded-xl text-left group transition-all border ${
                                        isSelected 
                                        ? 'bg-primary-50 border-primary-300 ring-1 ring-primary-300' 
                                        : 'bg-white border-transparent hover:border-slate-200 hover:bg-slate-50'
                                    }`}
                                >
                                    {/* Checkbox Visual */}
                                    <div className={`mr-4 transition-colors ${isSelected ? 'text-primary-600' : 'text-slate-300'}`}>
                                        {isSelected ? <CheckSquare size={24} /> : <Square size={24} />}
                                    </div>

                                    <div className="w-16 h-16 bg-slate-100 rounded-lg flex items-center justify-center mr-4 overflow-hidden shrink-0 border border-slate-200">
                                        {ex.videoUrl ? (
                                            <img src={ex.videoUrl} alt="" className="w-full h-full object-cover" />
                                        ) : (
                                            <Plus size={24} className="text-slate-400" />
                                        )}
                                    </div>
                                    <div>
                                        <h4 className="font-bold text-slate-800">{ex.name}</h4>
                                        <span className="text-xs text-slate-400 uppercase font-semibold">{ex.category}</span>
                                    </div>
                                </button>
                            );
                        })}
                      </div>
                  </div>

                  {/* Bottom Action Bar */}
                  <div className="p-4 border-t border-slate-100 bg-slate-50 flex justify-between items-center">
                        <div className="text-slate-500 text-sm font-medium">
                            {selectedExerciseIds.length} seleccionados
                        </div>
                        <button 
                            disabled={selectedExerciseIds.length === 0}
                            onClick={handleConfirmAddExercises}
                            className="bg-primary-600 disabled:bg-slate-300 disabled:text-slate-500 text-white px-8 py-3 rounded-xl font-bold shadow-lg shadow-primary-200 disabled:shadow-none transition-all active:scale-95"
                        >
                            Agregar Selección
                        </button>
                  </div>
              </div>
          </div>
      )}

      {/* ROUTINE EDITOR (Replaces Weekly View) */}
      {showRoutineEditor && (
          <div className="fixed inset-0 z-50 bg-slate-100/90 backdrop-blur-md flex items-center justify-center p-6">
              <div className="bg-white w-full h-full rounded-3xl shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95">

                  {/* Editor Header */}
                  <div className="px-8 py-6 border-b border-slate-200 flex justify-between items-center bg-white">
                      <div>
                          <h2 className="text-3xl font-bold text-slate-900">Editor de Rutina</h2>
                          <p className="text-slate-500">Configura los días y los ejercicios</p>
                      </div>

                      <div className="flex items-center gap-8">
                          {/* Days Counter */}
                          <div className="flex flex-col items-center">
                              <span className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Días por semana</span>
                              <div className="flex items-center bg-slate-100 rounded-lg p-1">
                                  <button onClick={() => handleUpdateDayCount(-1)} className="w-10 h-10 flex items-center justify-center bg-white rounded-md shadow-sm text-slate-600 font-bold hover:bg-red-50 hover:text-red-500 active:scale-95 transition-all">-</button>
                                  <span className="w-12 text-center font-bold text-xl text-slate-800">{patient.routine.days.length}</span>
                                  <button onClick={() => handleUpdateDayCount(1)} className="w-10 h-10 flex items-center justify-center bg-white rounded-md shadow-sm text-slate-600 font-bold hover:bg-primary-50 hover:text-primary-600 active:scale-95 transition-all">+</button>
                              </div>
                          </div>

                          {/* Stage Toggle in Editor */}
                          <div className="flex flex-col items-center">
                              <span className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Etapa</span>
                              <button 
                                onClick={handleToggleStage}
                                className={`px-4 py-2.5 rounded-xl font-bold border transition-all ${
                                    patient.routine.stage === Stage.KINESIOLOGY 
                                    ? 'bg-kine text-white border-kine' 
                                    : 'bg-gym text-white border-gym'
                                }`}
                              >
                                  {patient.routine.stage}
                              </button>
                          </div>

                          <div className="w-px h-10 bg-slate-200 mx-2"></div>

                          <button onClick={() => setShowRoutineEditor(false)} className="p-3 bg-slate-100 rounded-full hover:bg-slate-200">
                             <X size={24} />
                          </button>
                      </div>
                  </div>

                  {/* Editor Grid */}
                  <div className="flex-1 overflow-x-auto overflow-y-hidden p-6 bg-slate-50">
                      <div className="flex gap-6 h-full min-w-max">
                          {patient.routine.days.map((day, index) => (
                              <div key={day.id} className="w-80 flex flex-col bg-white rounded-2xl border border-slate-200 shadow-sm">
                                  {/* Day Header */}
                                  <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-slate-50/50 rounded-t-2xl">
                                      <h3 className="font-bold text-lg text-slate-800">Día {index + 1}</h3>
                                      <span className="text-xs font-bold bg-slate-200 text-slate-600 px-2 py-1 rounded-md">
                                          {day.exercises.length} ejs
                                      </span>
                                  </div>

                                  {/* Exercises List */}
                                  <div className="flex-1 overflow-y-auto p-3 space-y-2">
                                      {day.exercises.map(ex => (
                                          <div key={ex.id} className="bg-white border border-slate-100 p-3 rounded-xl flex items-start gap-3 shadow-sm group">
                                              {ex.definition.videoUrl && (
                                                  <img src={ex.definition.videoUrl} className="w-10 h-10 rounded-lg object-cover bg-slate-100" alt="" />
                                              )}
                                              <div className="flex-1 min-w-0">
                                                  <div className="text-sm font-bold text-slate-800 truncate">{ex.definition.name}</div>
                                                  <div className="text-xs text-slate-400">{ex.targetSets}x{ex.targetReps} • {ex.targetLoad}kg</div>
                                              </div>
                                              <button 
                                                onClick={() => handleRemoveExercise(day.id, ex.id)}
                                                className="text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity"
                                              >
                                                  <X size={16} />
                                              </button>
                                          </div>
                                      ))}
                                      {day.exercises.length === 0 && (
                                          <div className="text-center py-10 text-slate-300 italic text-sm">Sin ejercicios</div>
                                      )}
                                  </div>

                                  {/* Add Button */}
                                  <div className="p-3 border-t border-slate-100">
                                      <button 
                                        onClick={() => openAddModal(day.id)}
                                        className="w-full py-3 rounded-xl border-2 border-dashed border-slate-200 text-slate-500 font-bold hover:border-primary-300 hover:text-primary-600 hover:bg-primary-50 transition-all flex items-center justify-center gap-2 text-sm"
                                      >
                                          <Plus size={16} />
                                          Seleccionar Ejercicios
                                      </button>
                                  </div>
                              </div>
                          ))}
                      </div>
                  </div>
              </div>
          </div>
      )}

    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Patient, RoutineDay, RoutineExercise, Stage } from '../types';
import { EXERCISES } from '../constants';
import { ExerciseCard } from './ExerciseCard';
import { ProgressChart } from './ProgressChart';
import { AlertCircle, FileText, Plus, Search, X, LayoutGrid, Trash2, Settings, CheckSquare, Square } from 'lucide-react';

interface PatientDetailProps {
  patient: Patient;
  onUpdatePatient: (updated: Patient) => void;
}

export const PatientDetail: React.FC<PatientDetailProps> = ({
  patient,
  onUpdatePatient,
}) => {
  const [activeDayId, setActiveDayId] = useState<string>(
    patient.routine.days[0]?.id || ''
  );
  const [showHistory, setShowHistory] = useState<boolean>(false);
  const [showRoutineEditor, setShowRoutineEditor] = useState<boolean>(false);

  // States for Modals
  const [chartExercise, setChartExercise] = useState<RoutineExercise | null>(null);

  // Adding Exercise States
  const [isAddingExercise, setIsAddingExercise] = useState(false); // Single add mode
  const [targetDayIdForAdd, setTargetDayIdForAdd] = useState<string | null>(null); // Which day are we adding to?
  const [exerciseSearch, setExerciseSearch] = useState('');
  const [selectedExerciseIds, setSelectedExerciseIds] = useState<string[]>([]); // For multi-select

  // Local state for editable notes
  const [notes, setNotes] = useState(patient.history[0] || '');

  // Sync notes when patient changes
  useEffect(() => {
    setNotes(patient.history[0] || '');
  }, [patient.id]);

  // Auto-open Editor if routine is empty (Onboarding flow)
  useEffect(() => {
      const hasExercises = patient.routine.days.some(d => d.exercises.length > 0);
      if (!hasExercises && patient.routine.days.length <= 1) {
          setShowRoutineEditor(true);
      }
  }, [patient.id]);

  // Ensure activeDayId is valid
  useEffect(() => {
     if (patient.routine.days.length > 0) {
         const dayExists = patient.routine.days.find(d => d.id === activeDayId);
         if (!dayExists) {
             setActiveDayId(patient.routine.days[0].id);
         }
     } else {
         if (activeDayId !== '') setActiveDayId('');
     }
  }, [patient.routine.days, activeDayId]);

  const activeDayIndex = patient.routine.days.findIndex(d => d.id === activeDayId);
  const activeDay = patient.routine.days[activeDayIndex];

  // --- HANDLERS ---

  const handleSaveNotes = () => {
      const newHistory = [...patient.history];
      if (newHistory.length === 0) {
          newHistory.push(notes);
      } else {
          newHistory[0] = notes;
      }
      onUpdatePatient({ ...patient, history: newHistory });
  };

  const handleToggleStage = () => {
      const newStage = patient.routine.stage === Stage.KINESIOLOGY ? Stage.GYM : Stage.KINESIOLOGY;
      onUpdatePatient({
          ...patient,
          routine: { ...patient.routine, stage: newStage }
      });
  };

  // --- ROUTINE STRUCTURE HANDLERS ---

  const handleUpdateDayCount = (delta: number) => {
      const currentCount = patient.routine.days.length;
      const newCount = Math.max(1, Math.min(7, currentCount + delta));

      if (newCount === currentCount) return;

      let newDays = [...patient.routine.days];

      if (newCount > currentCount) {
          // Add Days
          for (let i = currentCount; i < newCount; i++) {
              newDays.push({
                  id: `day-${Date.now()}-${i}`,
                  name: `Día ${i + 1}`,
                  exercises: []
              });
          }
      } else {
          // Remove Days (from end)
          if (newDays[newDays.length - 1].exercises.length > 0) {
              if (!window.confirm("Al reducir los días se eliminarán los ejercicios del último día. ¿Continuar?")) {
                  return;
              }
          }
          newDays = newDays.slice(0, newCount);
      }

      onUpdatePatient({
          ...patient,
          routine: { ...patient.routine, days: newDays }
      });
  };

  const handleDeleteDay = (dayId: string) => {
    if (!window.confirm("¿Estás seguro de que quieres eliminar este día?")) return;
    const updatedDays = patient.routine.days.filter(d => d.id !== dayId);

    // If we deleted the last day, ensure there's at least one empty day or handle logic
    if (updatedDays.length === 0) {
         updatedDays.push({ id: `day-${Date.now()}`, name: 'Día 1', exercises: [] });
    }

    onUpdatePatient({
        ...patient,
        routine: { ...patient.routine, days: updatedDays }
    });

    if (activeDayId === dayId) {
        setActiveDayId(updatedDays[0].id);
    }
  };

  // --- EXERCISE HANDLERS ---

  const handleExerciseUpdate = (exerciseId: string, updates: Partial<RoutineExercise>) => {
    if (activeDayIndex === -1) return;

    // We need to find which day this exercise belongs to if we are not in the main view
    // But since this is passed to ExerciseCard in main view, activeDayIndex is correct.
    // For safety in modal (if we used it there), we would search.

    const newDays = [...patient.routine.days];
    const newExercises = [...newDays[activeDayIndex].exercises];
    const exIndex = newExercises.findIndex(e => e.id === exerciseId);
    if (exIndex === -1) return;

    newExercises[exIndex] = { ...newExercises[exIndex], ...updates };
    newDays[activeDayIndex] = { ...newDays[activeDayIndex], exercises: newExercises };

    onUpdatePatient({
        ...patient,
        routine: { ...patient.routine, days: newDays }
    });
  };

  const handleRemoveExercise = (dayId: string, exerciseId: string) => {
      const dayIndex = patient.routine.days.findIndex(d => d.id === dayId);
      if (dayIndex === -1) return;

      const newDays = [...patient.routine.days];
      newDays[dayIndex] = {
          ...newDays[dayIndex],
          exercises: newDays[dayIndex].exercises.filter(e => e.id !== exerciseId)
      };

      onUpdatePatient({
          ...patient,
          routine: { ...patient.routine, days: newDays }
      });
  };

  // --- ADD EXERCISE LOGIC (Single & Multi) ---

  const openAddModal = (dayId: string) => {
      setTargetDayIdForAdd(dayId);
      setSelectedExerciseIds([]);
      setExerciseSearch('');
      setIsAddingExercise(true);
  };

  const toggleExerciseSelection = (defId: string) => {
      setSelectedExerciseIds(prev => 
        prev.includes(defId) ? prev.filter(id => id !== defId) : [...prev, defId]
      );
  };

  const handleConfirmAddExercises = () => {
      if (!targetDayIdForAdd) return;
      const dayIndex = patient.routine.days.findIndex(d => d.id === targetDayIdForAdd);
      if (dayIndex === -1) return;

      // Create exercise instances
      const newExercises: RoutineExercise[] = selectedExerciseIds.map(defId => {
          const def = EXERCISES.find(e => e.id === defId)!;
          return {
              id: `re-${Date.now()}-${Math.random()}`,
              definitionId: def.id,
              definition: def,
              targetSets: 3,
              targetReps: 10,
              targetLoad: 0,
              isDone: false,
              history: []
          };
      });

      const newDays = [...patient.routine.days];
      newDays[dayIndex] = {
          ...newDays[dayIndex],
          exercises: [...newDays[dayIndex].exercises, ...newExercises]
      };

      onUpdatePatient({
          ...patient,
          routine: { ...patient.routine, days: newDays }
      });

      setIsAddingExercise(false);
      setSelectedExerciseIds([]);
  };

  // Legacy single add (from main view button)
  const handleSingleAdd = (defId: string) => {
      // If we are just clicking on an item without using checkboxes, treat as single add
      toggleExerciseSelection(defId);
  };

  const filteredCatalog = EXERCISES.filter(ex => 
    ex.name.toLowerCase().includes(exerciseSearch.toLowerCase()) || 
    ex.category.toLowerCase().includes(exerciseSearch.toLowerCase())
  );

  return (
    <div className="flex-1 h-screen flex flex-col bg-slate-50 overflow-hidden relative">

      {/* 1. TOP HEADER */}
      <header className="bg-white border-b border-slate-200 px-6 py-4 flex items-center justify-between shadow-sm shrink-0 z-20">
        <div className="flex items-center gap-4">
          <div className="flex flex-col">
            <h2 className="text-2xl font-bold text-slate-900 leading-none">
              {patient.firstName} {patient.lastName}
            </h2>
            <div className="flex items-center gap-2 mt-2">
                {/* Static Stage Badge (Read-only here) */}
                <span 
                    className={`px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wider border ${
                        patient.routine.stage === Stage.KINESIOLOGY 
                        ? 'bg-kine/10 text-kine border-kine/20' 
                        : 'bg-gym/10 text-gym border-gym/20'
                    }`}
                >
                    {patient.routine.stage}
                </span>
                <span className="w-1 h-1 bg-slate-300 rounded-full"></span>
                <span className="text-sm text-slate-400">{patient.age} años</span>
            </div>
          </div>
        </div>

        <div className="flex gap-2">
            <button 
                onClick={() => setShowRoutineEditor(true)}
                className="flex items-center gap-2 px-4 py-2 rounded-lg font-bold transition-colors bg-primary-600 text-white shadow-md shadow-primary-200 hover:bg-primary-700"
            >
                <Settings size={18} />
                <span>Editar Rutina</span>
            </button>
            <button 
                onClick={() => setShowHistory(!showHistory)}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg font-medium transition-colors ${showHistory ? 'bg-slate-800 text-white' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'}`}
            >
                <FileText size={18} />
                <span>{showHistory ? 'Ocultar Ficha' : 'Ver Ficha'}</span>
            </button>
        </div>
      </header>

      {/* 2. HISTORY DRAWER */}
      {showHistory && (
          <div className="bg-slate-800 text-slate-200 px-8 py-6 shadow-inner shrink-0 animate-in slide-in-from-top-5 border-b border-slate-700">
              <div className="grid grid-cols-1 md:grid-cols-3 gap-8 max-w-5xl">
                  <div className="md:col-span-1">
                       <h4 className="text-slate-400 text-xs uppercase font-bold mb-2">Datos Clínicos</h4>
                       <div className="space-y-4">
                            <div>
                                <h5 className="text-slate-500 text-xs font-bold">Última Visita</h5>
                                <p className="text-sm font-mono bg-slate-700 w-fit px-2 py-1 rounded mt-1">{patient.lastVisit}</p>
                            </div>
                            <div>
                                <h5 className="text-slate-500 text-xs font-bold">Alertas</h5>
                                <div className="flex items-start gap-2 text-amber-400 text-sm mt-1">
                                    <AlertCircle size={16} className="mt-0.5 shrink-0" />
                                    <span>Controlar dolor.</span>
                                </div>
                            </div>
                       </div>
                  </div>
                  <div className="md:col-span-2">
                      <div className="flex justify-between items-center mb-2">
                        <h4 className="text-slate-400 text-xs uppercase font-bold">Observaciones / Evolución</h4>
                        <span className="text-xs text-slate-500 italic">Se guarda automáticamente</span>
                      </div>
                      <textarea 
                        className="w-full h-32 bg-slate-700 text-slate-200 p-4 rounded-xl border border-slate-600 focus:ring-2 focus:ring-primary-500 outline-none resize-none leading-relaxed"
                        value={notes}
                        onChange={(e) => setNotes(e.target.value)}
                        onBlur={handleSaveNotes}
                        placeholder="Escribe aquí las observaciones clínicas..."
                      />
                  </div>
              </div>
          </div>
      )}

      {/* 3. DAY SELECTOR (Tabs) */}
      <div className="bg-white border-b border-slate-200 px-6 flex gap-1 pt-4 overflow-x-auto no-scrollbar shrink-0">
        {patient.routine.days.map((day, index) => (
          <button
            key={day.id}
            onClick={() => setActiveDayId(day.id)}
            className={`px-6 py-3 rounded-t-xl font-bold text-sm tracking-wide transition-all border-t border-x ${
              activeDayId === day.id
                ? 'bg-slate-50 border-slate-200 text-primary-600 border-b-slate-50 -mb-px z-10'
                : 'bg-white border-transparent text-slate-400 hover:bg-slate-50 hover:text-slate-600'
            }`}
          >
            Día {index + 1}
          </button>
        ))}
      </div>

      {/* 4. MAIN ROUTINE AREA */}
      <main className="flex-1 overflow-y-auto p-6 md:p-8 scroll-smooth">
        <div className="max-w-3xl mx-auto pb-20">

          {activeDay ? (
            <div className="space-y-4">
              {activeDay.exercises.length > 0 ? (
                  activeDay.exercises.map((exercise) => (
                    <ExerciseCard
                      key={exercise.id}
                      exercise={exercise}
                      onUpdate={handleExerciseUpdate}
                      onShowHistory={(ex) => setChartExercise(ex)}
                      onDelete={(eid) => handleRemoveExercise(activeDayId, eid)}
                    />
                  ))
              ) : (
                  <div className="text-center py-10 text-slate-400">
                      <p className="mb-4">No hay ejercicios en el Día {activeDayIndex + 1}</p>
                      <button 
                        onClick={() => openAddModal(activeDayId)}
                        className="bg-primary-50 text-primary-600 px-6 py-3 rounded-xl font-bold hover:bg-primary-100 transition-colors"
                      >
                          Agregar primer ejercicio
                      </button>
                  </div>
              )}

              {/* Add Exercise Button (Legacy/Quick Add) */}
              {activeDay.exercises.length > 0 && (
                <button 
                    onClick={() => openAddModal(activeDayId)}
                    className="w-full py-4 rounded-2xl border-2 border-dashed border-primary-200 text-primary-600 font-bold hover:bg-primary-50 transition-colors flex items-center justify-center gap-2"
                >
                    <Plus size={20} />
                    Agregar Ejercicio
                </button>
              )}
            </div>
          ) : (
            <div className="flex flex-col items-center justify-center h-full text-slate-400 mt-20">
                <p>No hay días en la rutina</p>
                <button onClick={() => setShowRoutineEditor(true)} className="mt-4 text-primary-600 font-bold hover:underline">
                    Configurar Rutina
                </button>
            </div>
          )}
        </div>
      </main>

      {/* --- MODALS --- */}

      {/* Chart Overlay */}
      {chartExercise && (
        <ProgressChart exercise={chartExercise} onClose={() => setChartExercise(null)} />
      )}

      {/* CATALOG / ADD EXERCISE MODAL (Supports Multi-Select) */}
      {isAddingExercise && (
          <div className="fixed inset-0 z-[60] bg-black/50 backdrop-blur-sm flex items-center justify-center p-4">
              <div className="bg-white w-full max-w-2xl h-[85vh] rounded-2xl shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95">
                  <div className="p-4 border-b border-slate-100 flex items-center justify-between">
                      <div className="relative flex-1 mr-4">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
                        <input 
                            type="text"
                            autoFocus
                            placeholder="Buscar ejercicio..."
                            className="w-full pl-10 pr-4 py-3 bg-slate-50 rounded-xl outline-none focus:ring-2 focus:ring-primary-100"
                            value={exerciseSearch}
                            onChange={(e) => setExerciseSearch(e.target.value)}
                        />
                      </div>
                      <button onClick={() => setIsAddingExercise(false)} className="p-2 bg-slate-100 rounded-full"><X size={20} /></button>
                  </div>

                  {/* List */}
                  <div className="flex-1 overflow-y-auto p-4">
                      <div className="grid grid-cols-1 gap-2">
                        {filteredCatalog.map(ex => {
                            const isSelected = selectedExerciseIds.includes(ex.id);
                            return (
                                <button 
                                    key={ex.id}
                                    onClick={() => toggleExerciseSelection(ex.id)}
                                    className={`flex items-center p-4 rounded-xl text-left group transition-all border ${
                                        isSelected 
                                        ? 'bg-primary-50 border-primary-300 ring-1 ring-primary-300' 
                                        : 'bg-white border-transparent hover:border-slate-200 hover:bg-slate-50'
                                    }`}
                                >
                                    {/* Checkbox Visual */}
                                    <div className={`mr-4 transition-colors ${isSelected ? 'text-primary-600' : 'text-slate-300'}`}>
                                        {isSelected ? <CheckSquare size={24} /> : <Square size={24} />}
                                    </div>

                                    <div className="w-16 h-16 bg-slate-100 rounded-lg flex items-center justify-center mr-4 overflow-hidden shrink-0 border border-slate-200">
                                        {ex.videoUrl ? (
                                            <img src={ex.videoUrl} alt="" className="w-full h-full object-cover" />
                                        ) : (
                                            <Plus size={24} className="text-slate-400" />
                                        )}
                                    </div>
                                    <div>
                                        <h4 className="font-bold text-slate-800">{ex.name}</h4>
                                        <span className="text-xs text-slate-400 uppercase font-semibold">{ex.category}</span>
                                    </div>
                                </button>
                            );
                        })}
                      </div>
                  </div>

                  {/* Bottom Action Bar */}
                  <div className="p-4 border-t border-slate-100 bg-slate-50 flex justify-between items-center">
                        <div className="text-slate-500 text-sm font-medium">
                            {selectedExerciseIds.length} seleccionados
                        </div>
                        <button 
                            disabled={selectedExerciseIds.length === 0}
                            onClick={handleConfirmAddExercises}
                            className="bg-primary-600 disabled:bg-slate-300 disabled:text-slate-500 text-white px-8 py-3 rounded-xl font-bold shadow-lg shadow-primary-200 disabled:shadow-none transition-all active:scale-95"
                        >
                            Agregar Selección
                        </button>
                  </div>
              </div>
          </div>
      )}

      {/* ROUTINE EDITOR (Replaces Weekly View) */}
      {showRoutineEditor && (
          <div className="fixed inset-0 z-50 bg-slate-100/90 backdrop-blur-md flex items-center justify-center p-6">
              <div className="bg-white w-full h-full rounded-3xl shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95">

                  {/* Editor Header */}
                  <div className="px-8 py-6 border-b border-slate-200 flex justify-between items-center bg-white">
                      <div>
                          <h2 className="text-3xl font-bold text-slate-900">Editor de Rutina</h2>
                          <p className="text-slate-500">Configura los días y los ejercicios</p>
                      </div>

                      <div className="flex items-center gap-8">
                          {/* Days Counter */}
                          <div className="flex flex-col items-center">
                              <span className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Días por semana</span>
                              <div className="flex items-center bg-slate-100 rounded-lg p-1">
                                  <button onClick={() => handleUpdateDayCount(-1)} className="w-10 h-10 flex items-center justify-center bg-white rounded-md shadow-sm text-slate-600 font-bold hover:bg-red-50 hover:text-red-500 active:scale-95 transition-all">-</button>
                                  <span className="w-12 text-center font-bold text-xl text-slate-800">{patient.routine.days.length}</span>
                                  <button onClick={() => handleUpdateDayCount(1)} className="w-10 h-10 flex items-center justify-center bg-white rounded-md shadow-sm text-slate-600 font-bold hover:bg-primary-50 hover:text-primary-600 active:scale-95 transition-all">+</button>
                              </div>
                          </div>

                          {/* Stage Toggle in Editor */}
                          <div className="flex flex-col items-center">
                              <span className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Etapa</span>
                              <button 
                                onClick={handleToggleStage}
                                className={`px-4 py-2.5 rounded-xl font-bold border transition-all ${
                                    patient.routine.stage === Stage.KINESIOLOGY 
                                    ? 'bg-kine text-white border-kine' 
                                    : 'bg-gym text-white border-gym'
                                }`}
                              >
                                  {patient.routine.stage}
                              </button>
                          </div>

                          <div className="w-px h-10 bg-slate-200 mx-2"></div>

                          <button onClick={() => setShowRoutineEditor(false)} className="p-3 bg-slate-100 rounded-full hover:bg-slate-200">
                             <X size={24} />
                          </button>
                      </div>
                  </div>

                  {/* Editor Grid */}
                  <div className="flex-1 overflow-x-auto overflow-y-hidden p-6 bg-slate-50">
                      <div className="flex gap-6 h-full min-w-max">
                          {patient.routine.days.map((day, index) => (
                              <div key={day.id} className="w-80 flex flex-col bg-white rounded-2xl border border-slate-200 shadow-sm">
                                  {/* Day Header */}
                                  <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-slate-50/50 rounded-t-2xl">
                                      <h3 className="font-bold text-lg text-slate-800">Día {index + 1}</h3>
                                      <span className="text-xs font-bold bg-slate-200 text-slate-600 px-2 py-1 rounded-md">
                                          {day.exercises.length} ejs
                                      </span>
                                  </div>

                                  {/* Exercises List */}
                                  <div className="flex-1 overflow-y-auto p-3 space-y-2">
                                      {day.exercises.map(ex => (
                                          <div key={ex.id} className="bg-white border border-slate-100 p-3 rounded-xl flex items-start gap-3 shadow-sm group">
                                              {ex.definition.videoUrl && (
                                                  <img src={ex.definition.videoUrl} className="w-10 h-10 rounded-lg object-cover bg-slate-100" alt="" />
                                              )}
                                              <div className="flex-1 min-w-0">
                                                  <div className="text-sm font-bold text-slate-800 truncate">{ex.definition.name}</div>
                                                  <div className="text-xs text-slate-400">{ex.targetSets}x{ex.targetReps} • {ex.targetLoad}kg</div>
                                              </div>
                                              <button 
                                                onClick={() => handleRemoveExercise(day.id, ex.id)}
                                                className="text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity"
                                              >
                                                  <X size={16} />
                                              </button>
                                          </div>
                                      ))}
                                      {day.exercises.length === 0 && (
                                          <div className="text-center py-10 text-slate-300 italic text-sm">Sin ejercicios</div>
                                      )}
                                  </div>

                                  {/* Add Button */}
                                  <div className="p-3 border-t border-slate-100">
                                      <button 
                                        onClick={() => openAddModal(day.id)}
                                        className="w-full py-3 rounded-xl border-2 border-dashed border-slate-200 text-slate-500 font-bold hover:border-primary-300 hover:text-primary-600 hover:bg-primary-50 transition-all flex items-center justify-center gap-2 text-sm"
                                      >
                                          <Plus size={16} />
                                          Seleccionar Ejercicios
                                      </button>
                                  </div>
                              </div>
                          ))}
                      </div>
                  </div>
              </div>
          </div>
      )}

    </div>
  );
};

import React, { useState } from 'react';
import { RoutineExercise } from '../types';
import { PlayCircle, CheckCircle, Circle, Minus, Plus, TrendingUp, Trash2, Maximize2, X } from 'lucide-react';

interface ExerciseCardProps {
  exercise: RoutineExercise;
  onUpdate: (id: string, updates: Partial<RoutineExercise>) => void;
  onShowHistory: (exercise: RoutineExercise) => void;
  onDelete: (id: string) => void;
}

export const ExerciseCard: React.FC<ExerciseCardProps> = ({
  exercise,
  onUpdate,
  onShowHistory,
  onDelete,
}) => {
  const { definition, targetSets, targetReps, targetLoad, currentRpe, isDone } = exercise;
  const [isZoomed, setIsZoomed] = useState(false);

  // --- Handlers ---

  // 1. SETS (Now editable with steppers)
  const adjustSets = (amount: number, e: React.MouseEvent) => {
    e.stopPropagation();
    const newSets = Math.max(1, targetSets + amount);
    onUpdate(exercise.id, { targetSets: newSets });
  };

  // 2. REPS
  const adjustReps = (amount: number, e: React.MouseEvent) => {
    e.stopPropagation();
    const newReps = Math.max(1, targetReps + amount);
    onUpdate(exercise.id, { targetReps: newReps });
  };

  // 3. LOAD (Buttons for integers, Input for decimals)
  const adjustLoad = (amount: number, e: React.MouseEvent) => {
    e.stopPropagation();
    // Simple logic: Buttons jump by 1kg for speed.
    // Floating point math safety: round to 2 decimal places.
    let newLoad = targetLoad + amount;
    newLoad = Math.round(newLoad * 100) / 100; 
    newLoad = Math.max(0, newLoad);
    onUpdate(exercise.id, { targetLoad: newLoad });
  };

  const handleLoadInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = parseFloat(e.target.value);
    onUpdate(exercise.id, { targetLoad: isNaN(val) ? 0 : val });
  };

  const toggleDone = () => {
    onUpdate(exercise.id, { isDone: !isDone });
  };

  return (
    <>
      <div
        className={`bg-white rounded-2xl p-5 shadow-sm border transition-all duration-300 relative group ${
          isDone ? 'border-slate-100 opacity-60 bg-slate-50' : 'border-slate-200 hover:shadow-md'
        }`}
      >
        <div className="flex items-start gap-4">
          {/* Checkbox (Big touch target) */}
          <button
            onClick={toggleDone}
            className={`shrink-0 mt-1 transition-colors ${
              isDone ? 'text-kine' : 'text-slate-300 hover:text-primary-400'
            }`}
          >
            {isDone ? <CheckCircle size={32} fill="currentColor" className="text-white" /> : <Circle size={32} />}
          </button>

          {/* GIF Thumbnail (Clickable for Zoom) */}
          {definition.videoUrl && (
              <button 
                onClick={() => setIsZoomed(true)}
                className="w-24 h-24 bg-slate-100 rounded-xl overflow-hidden shrink-0 border border-slate-200 hidden sm:block relative group/image cursor-zoom-in"
              >
                  <img src={definition.videoUrl} alt={definition.name} className="w-full h-full object-cover mix-blend-multiply" />
                  <div className="absolute inset-0 bg-black/0 group-hover/image:bg-black/10 transition-colors flex items-center justify-center">
                    <Maximize2 className="text-white opacity-0 group-hover/image:opacity-100 drop-shadow-md transition-opacity" size={24} />
                  </div>
              </button>
          )}

          <div className="flex-1 space-y-4">
            {/* Header */}
            <div className="flex justify-between items-start pr-8">
              <div>
                <h4 className={`font-bold text-lg leading-tight ${isDone ? 'text-slate-500 line-through' : 'text-slate-900'}`}>
                  {definition.name}
                </h4>
                <span className="text-xs text-slate-400 uppercase font-semibold">{definition.category}</span>
              </div>

              <div className="flex gap-2">
                  <button 
                      onClick={() => onShowHistory(exercise)}
                      className="p-2 text-primary-600 bg-primary-50 rounded-lg hover:bg-primary-100"
                      title="Ver progreso"
                  >
                      <TrendingUp size={20} />
                  </button>
              </div>
            </div>

            {/* Controls Grid */}
            <div className={`grid grid-cols-12 gap-2 md:gap-4 ${isDone ? 'pointer-events-none' : ''}`}>

              {/* Sets & Reps */}
              <div className="col-span-6 md:col-span-5 flex flex-col justify-center">
                <div className="text-xs text-slate-400 font-bold mb-1">SERIES x REPS</div>
                <div className="flex items-center gap-2">

                  {/* SETS Stepper */}
                  <div className="flex items-center bg-slate-100 rounded-lg p-0.5">
                      <button onClick={(e) => adjustSets(-1, e)} className="p-1.5 bg-white rounded-md shadow-sm active:scale-95 text-slate-600"><Minus size={14}/></button>
                      <span className="w-8 text-center font-bold text-lg text-slate-800">{targetSets}</span>
                      <button onClick={(e) => adjustSets(1, e)} className="p-1.5 bg-white rounded-md shadow-sm active:scale-95 text-slate-600"><Plus size={14}/></button>
                  </div>

                  <span className="text-slate-300 text-sm">x</span>

                  {/* REPS Stepper */}
                  <div className="flex items-center bg-slate-100 rounded-lg p-0.5">
                      <button onClick={(e) => adjustReps(-1, e)} className="p-1.5 bg-white rounded-md shadow-sm active:scale-95 text-slate-600"><Minus size={14}/></button>
                      <span className="w-9 text-center font-bold text-lg text-slate-800">{targetReps}</span>
