import React, { useState, useEffect, useMemo } from 'react';
import { Patient, RoutineDay, RoutineExercise, Stage } from '../types';
import { EXERCISES } from '../constants';
import { ExerciseCard } from './ExerciseCard';
import { ProgressChart } from './ProgressChart';
import { AlertCircle, FileText, Plus, Search, X, LayoutGrid, Trash2, Settings, CheckSquare, Square, Calendar, List, Layout } from 'lucide-react';

interface PatientDetailProps {
  patient: Patient;
  onUpdatePatient: (updated: Patient) => void;
}

type ViewMode = 'daily' | 'weekly' | 'monthly';

export const PatientDetail: React.FC<PatientDetailProps> = ({
  patient,
  onUpdatePatient,
}) => {
  const [activeDayId, setActiveDayId] = useState<string>(
    patient.routine.days[0]?.id || ''
  );
  const [viewMode, setViewMode] = useState<ViewMode>('daily');
  const [showHistory, setShowHistory] = useState<boolean>(false);
  const [showRoutineEditor, setShowRoutineEditor] = useState<boolean>(false);

  // States for Modals
  const [chartExercise, setChartExercise] = useState<RoutineExercise | null>(null);

  // Adding Exercise States
  const [isAddingExercise, setIsAddingExercise] = useState(false); // Single add mode
  const [targetDayIdForAdd, setTargetDayIdForAdd] = useState<string | null>(null); // Which day are we adding to?
  const [exerciseSearch, setExerciseSearch] = useState('');
  const [selectedExerciseIds, setSelectedExerciseIds] = useState<string[]>([]); // For multi-select

  // Local state for editable notes
  const [notes, setNotes] = useState(patient.history[0] || '');

  // Sync notes when patient changes
  useEffect(() => {
    setNotes(patient.history[0] || '');
  }, [patient.id]);

  // Auto-open Editor if routine is empty (Onboarding flow)
  useEffect(() => {
      const hasExercises = patient.routine.days.some(d => d.exercises.length > 0);
      if (!hasExercises && patient.routine.days.length <= 1) {
          setShowRoutineEditor(true);
      }
  }, [patient.id]);

  // Ensure activeDayId is valid
  useEffect(() => {
     if (patient.routine.days.length > 0) {
         const dayExists = patient.routine.days.find(d => d.id === activeDayId);
         if (!dayExists) {
             setActiveDayId(patient.routine.days[0].id);
         }
     } else {
         if (activeDayId !== '') setActiveDayId('');
     }
  }, [patient.routine.days, activeDayId]);

  const activeDayIndex = patient.routine.days.findIndex(d => d.id === activeDayId);
  const activeDay = patient.routine.days[activeDayIndex];

  // --- HANDLERS ---

  const handleDayTabClick = (dayId: string) => {
      setActiveDayId(dayId);
      setViewMode('daily');
  };

  const handleSaveNotes = () => {
      const newHistory = [...patient.history];
      if (newHistory.length === 0) {
          newHistory.push(notes);
      } else {
          newHistory[0] = notes;
      }
      onUpdatePatient({ ...patient, history: newHistory });
  };

  const handleToggleStage = () => {
      const newStage = patient.routine.stage === Stage.KINESIOLOGY ? Stage.GYM : Stage.KINESIOLOGY;
      onUpdatePatient({
          ...patient,
          routine: { ...patient.routine, stage: newStage }
      });
  };

  // --- ROUTINE STRUCTURE HANDLERS ---

  const handleUpdateDayCount = (delta: number) => {
      const currentCount = patient.routine.days.length;
      const newCount = Math.max(1, Math.min(7, currentCount + delta));

      if (newCount === currentCount) return;

      let newDays = [...patient.routine.days];

      if (newCount > currentCount) {
          // Add Days
          for (let i = currentCount; i < newCount; i++) {
              newDays.push({
                  id: `day-${Date.now()}-${i}`,
                  name: `Día ${i + 1}`,
                  exercises: []
              });
          }
      } else {
          // Remove Days (from end)
          if (newDays[newDays.length - 1].exercises.length > 0) {
              if (!window.confirm("Al reducir los días se eliminarán los ejercicios del último día. ¿Continuar?")) {
                  return;
              }
          }
          newDays = newDays.slice(0, newCount);
      }

      onUpdatePatient({
          ...patient,
          routine: { ...patient.routine, days: newDays }
      });
  };

  const handleDeleteDay = (dayId: string) => {
    if (!window.confirm("¿Estás seguro de que quieres eliminar este día?")) return;
    const updatedDays = patient.routine.days.filter(d => d.id !== dayId);

    // If we deleted the last day, ensure there's at least one empty day or handle logic
    if (updatedDays.length === 0) {
         updatedDays.push({ id: `day-${Date.now()}`, name: 'Día 1', exercises: [] });
    }

    onUpdatePatient({
        ...patient,
        routine: { ...patient.routine, days: updatedDays }
    });

    if (activeDayId === dayId) {
        setActiveDayId(updatedDays[0].id);
    }
  };

  // --- EXERCISE HANDLERS ---

  const handleExerciseUpdate = (exerciseId: string, updates: Partial<RoutineExercise>) => {
    if (activeDayIndex === -1) return;

    // We need to find which day this exercise belongs to if we are not in the main view
    // But since this is passed to ExerciseCard in main view, activeDayIndex is correct.
    // For safety in modal (if we used it there), we would search.

    const newDays = [...patient.routine.days];
    const newExercises = [...newDays[activeDayIndex].exercises];
    const exIndex = newExercises.findIndex(e => e.id === exerciseId);
    if (exIndex === -1) return;

    newExercises[exIndex] = { ...newExercises[exIndex], ...updates };
    newDays[activeDayIndex] = { ...newDays[activeDayIndex], exercises: newExercises };

    onUpdatePatient({
        ...patient,
        routine: { ...patient.routine, days: newDays }
    });
  };

  const handleRemoveExercise = (dayId: string, exerciseId: string) => {
      const dayIndex = patient.routine.days.findIndex(d => d.id === dayId);
      if (dayIndex === -1) return;

      const newDays = [...patient.routine.days];
      newDays[dayIndex] = {
          ...newDays[dayIndex],
          exercises: newDays[dayIndex].exercises.filter(e => e.id !== exerciseId)
      };

      onUpdatePatient({
          ...patient,
          routine: { ...patient.routine, days: newDays }
      });
  };

  // --- ADD EXERCISE LOGIC (Single & Multi) ---

  const openAddModal = (dayId: string) => {
      setTargetDayIdForAdd(dayId);
      setSelectedExerciseIds([]);
      setExerciseSearch('');
      setIsAddingExercise(true);
  };

  const toggleExerciseSelection = (defId: string) => {
      setSelectedExerciseIds(prev => 
        prev.includes(defId) ? prev.filter(id => id !== defId) : [...prev, defId]
      );
  };

  const handleConfirmAddExercises = () => {
      if (!targetDayIdForAdd) return;
      const dayIndex = patient.routine.days.findIndex(d => d.id === targetDayIdForAdd);
      if (dayIndex === -1) return;

      // Create exercise instances
      const newExercises: RoutineExercise[] = selectedExerciseIds.map(defId => {
          const def = EXERCISES.find(e => e.id === defId)!;
          return {
              id: `re-${Date.now()}-${Math.random()}`,
              definitionId: def.id,
              definition: def,
              targetSets: 3,
              targetReps: 10,
              targetLoad: 0,
              isDone: false,
              history: []
          };
      });

      const newDays = [...patient.routine.days];
      newDays[dayIndex] = {
          ...newDays[dayIndex],
          exercises: [...newDays[dayIndex].exercises, ...newExercises]
      };

      onUpdatePatient({
          ...patient,
          routine: { ...patient.routine, days: newDays }
      });

      setIsAddingExercise(false);
      setSelectedExerciseIds([]);
  };

  const filteredCatalog = EXERCISES.filter(ex => 
    ex.name.toLowerCase().includes(exerciseSearch.toLowerCase()) || 
    ex.category.toLowerCase().includes(exerciseSearch.toLowerCase())
  );

  // --- CALENDAR LOGIC (For Monthly View) ---
  const calendarData = useMemo(() => {
    // Gather all dates from all exercise histories
    const activeDates = new Set<string>();
    patient.routine.days.forEach(day => {
        day.exercises.forEach(ex => {
            if (ex.history) {
                ex.history.forEach(log => {
                    activeDates.add(log.date); // format YYYY-MM-DD
                });
            }
        });
    });

    const today = new Date();
    const currentYear = today.getFullYear();
    const currentMonth = today.getMonth(); // 0-indexed
    const daysInMonth = new Date(currentYear, currentMonth + 1, 0).getDate();

    const days = [];
    for (let i = 1; i <= daysInMonth; i++) {
        const dateStr = `${currentYear}-${String(currentMonth + 1).padStart(2, '0')}-${String(i).padStart(2, '0')}`;
        days.push({
            day: i,
            date: dateStr,
            hasActivity: activeDates.has(dateStr),
            isToday: i === today.getDate()
        });
    }
    return days;
  }, [patient]);

  return (
    <div className="flex-1 h-screen flex flex-col bg-slate-50 overflow-hidden relative">

      {/* 1. TOP HEADER */}
      <header className="bg-white border-b border-slate-200 px-6 py-4 flex items-center justify-between shadow-sm shrink-0 z-20">
        <div className="flex items-center gap-4">
          <div className="flex flex-col">
            <h2 className="text-2xl font-bold text-slate-900 leading-none">
              {patient.firstName} {patient.lastName}
            </h2>
            <div className="flex items-center gap-2 mt-2">
                {/* Static Stage Badge (Read-only here) */}
                <span 
                    className={`px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wider border ${
                        patient.routine.stage === Stage.KINESIOLOGY 
                        ? 'bg-kine/10 text-kine border-kine/20' 
                        : 'bg-gym/10 text-gym border-gym/20'
                    }`}
                >
                    {patient.routine.stage}
                </span>
                <span className="w-1 h-1 bg-slate-300 rounded-full"></span>
                <span className="text-sm text-slate-400">{patient.age} años</span>
            </div>
          </div>
        </div>

        <div className="flex gap-2">
            <button 
                onClick={() => setShowRoutineEditor(true)}
                className="flex items-center gap-2 px-4 py-2 rounded-lg font-bold transition-colors bg-primary-600 text-white shadow-md shadow-primary-200 hover:bg-primary-700"
            >
                <Settings size={18} />
                <span>Editar Rutina</span>
            </button>
            <button 
                onClick={() => setShowHistory(!showHistory)}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg font-medium transition-colors ${showHistory ? 'bg-slate-800 text-white' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'}`}
            >
                <FileText size={18} />
                <span>{showHistory ? 'Ocultar Ficha' : 'Ver Ficha'}</span>
            </button>
        </div>
      </header>

      {/* 2. HISTORY DRAWER */}
      {showHistory && (
          <div className="bg-slate-800 text-slate-200 px-8 py-6 shadow-inner shrink-0 animate-in slide-in-from-top-5 border-b border-slate-700">
