  if (loading) {
      return (
          <div className="h-screen w-full flex flex-col items-center justify-center bg-slate-50">
              <Loader2 className="animate-spin text-primary-600 mb-4" size={48} />
              <h2 className="text-xl font-bold text-slate-800">Iniciando KineFlow...</h2>
          </div>
      );
  }

  const activePatients = activePatientIds
    .map(id => patients.find(p => p.id === id))
    .filter((p): p is Patient => !!p);

  const currentPatient = patients.find(p => p.id === selectedPatientId);

  return (
    <div className="flex w-full h-screen bg-slate-50 font-sans text-slate-900">

      {/* DB Error Notification */}
      {dbError && (
          <div className="fixed bottom-20 left-1/2 -translate-x-1/2 z-[100] bg-red-600 text-white px-6 py-3 rounded-full shadow-2xl flex items-center gap-3 animate-bounce">
              <AlertTriangle size={20} />
              <span className="font-bold text-sm">{dbError}</span>
              <button onClick={() => setDbError(null)} className="ml-2 hover:text-red-200">
                  <X size={16} />
              </button>
          </div>
      )}

      {/* Configuration Assistant Badge */}
      {!isConfigValid && (
          <button 
            onClick={() => setShowSetupModal(true)}
            className="fixed top-4 right-4 z-[100] bg-white border-2 border-amber-200 p-4 rounded-2xl shadow-xl flex items-center gap-4 hover:border-amber-400 hover:scale-[1.02] transition-all text-left animate-in slide-in-from-right-10"
          >
              <div className="bg-amber-100 p-2 rounded-xl">
                <AlertTriangle className="text-amber-600" size={24} />
              </div>
              <div>
                  <p className="text-slate-900 font-bold text-sm">Modo Demostración</p>
                  <p className="text-slate-500 text-xs font-medium">Click para conectar con tu Firebase</p>
              </div>
          </button>
      )}

      {/* Setup Modal */}
      {showSetupModal && (
          <div className="fixed inset-0 z-[200] bg-slate-900/60 backdrop-blur-md flex items-center justify-center p-4">
              <div className="bg-white w-full max-w-lg rounded-3xl shadow-2xl overflow-hidden animate-in zoom-in-95">
                  <div className="p-6 border-b border-slate-100 flex justify-between items-center">
                      <h3 className="text-xl font-bold text-slate-900">Configuración de Firebase</h3>
                      <button onClick={() => setShowSetupModal(false)} className="p-2 hover:bg-slate-100 rounded-full transition-colors">
                          <X size={20} className="text-slate-400" />
                      </button>
                  </div>
                  <div className="p-8 space-y-6">
                      <div className="flex items-start gap-4">
                          <div className="bg-primary-50 p-2 rounded-lg text-primary-600 shrink-0">
                              <Terminal size={20} />
                          </div>
                          <div>
                              <p className="font-bold text-slate-800">Variables de Entorno</p>
                              <p className="text-sm text-slate-500 mt-1">
                                Debes configurar estas variables en tu entorno para activar la base de datos real:
                              </p>
                          </div>
                      </div>

                      <div className="bg-slate-900 rounded-xl p-4 font-mono text-xs text-emerald-400 space-y-1 overflow-x-auto">
                          <p>VITE_FIREBASE_API_KEY=tu_api_key</p>
                          <p>VITE_FIREBASE_PROJECT_ID=tu_project_id</p>
                          <p>VITE_FIREBASE_APP_ID=tu_app_id</p>
                          <p>VITE_FIREBASE_AUTH_DOMAIN=...</p>
                      </div>

                      <div className="space-y-3">
                          <div className="flex items-center gap-3 text-sm text-slate-600">
                              <CheckCircle2 size={16} className="text-emerald-500" />
                              <span>Obtén las claves en <b>Project Settings</b> de Firebase.</span>
                          </div>
                          <div className="flex items-center gap-3 text-sm text-slate-600">
                              <CheckCircle2 size={16} className="text-emerald-500" />
                              <span>Configura las variables y reinicia la app.</span>
                          </div>
                      </div>

                      <a 
                        href="https://console.firebase.google.com/" 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="flex items-center justify-center gap-2 w-full bg-slate-100 text-slate-700 py-3 rounded-xl font-bold hover:bg-slate-200 transition-colors"
                      >
                          Ir a la Consola de Firebase
                          <ExternalLink size={16} />
                      </a>
                  </div>
              </div>
          </div>
      )}

      <div className="flex flex-col relative">
          <Sidebar 
            activePatients={activePatients}
            selectedPatientId={selectedPatientId}
            onSelectPatient={handleSidebarSelect}
            onRemoveActive={handleRemoveActive}
            onGoHome={handleGoHome}
          />
          <div className="absolute bottom-4 left-1/2 -translate-x-1/2 flex flex-col items-center gap-1 z-50">
              {isOnline && isConfigValid ? (
                  <div className="bg-emerald-100 text-emerald-600 p-2 rounded-full shadow-sm" title="Sincronizado con Firebase">
                      <Cloud size={16} />
                  </div>
              ) : (
                  <div className="bg-amber-100 text-amber-600 p-2 rounded-full shadow-sm" title={!isConfigValid ? "Usando datos locales (Demo)" : "Modo Offline"}>
                      <CloudOff size={16} />
                  </div>
              )}
          </div>
      </div>

      <div className="flex-1 flex flex-col h-full overflow-hidden">
        {view === 'HOME' && (
            <PatientList 
                patients={patients} 
                onSelectPatient={handleSelectPatient} 
                onAddPatient={handleAddPatient}
            />
        )}

        {view === 'PATIENT_DETAIL' && currentPatient && (
            <PatientDetail 
                patient={currentPatient}
                onUpdatePatient={handleUpdatePatient}
            />
        )}
      </div>
    </div>
  );
};

export default App;

