import { initializeApp, getApps } from 'firebase/app';
import { 
  initializeFirestore, 
  persistentLocalCache,
  persistentMultipleTabManager 
} from 'firebase/firestore';
import { getAnalytics, isSupported } from 'firebase/analytics';

// Detectamos si las variables son las de ejemplo o están vacías
const isPlaceholder = (val: string | undefined) => !val || val.includes('...') || val === 'undefined';

// Usamos las credenciales reales proporcionadas por el usuario
const firebaseConfig = {
  apiKey: "AIzaSyBEvk3PuZ-HvNxBcgndtunv7SP9IjxBJps",
  authDomain: "kineflow-pro2.firebaseapp.com",
  projectId: "kineflow-pro2",
  storageBucket: "kineflow-pro2.firebasestorage.app",
  messagingSenderId: "360109819538",
  appId: "1:360109819538:web:083451995f3f071e86884b",
  measurementId: "G-D6YV7K8Z9W" // ID de medición sugerido para analytics
};

// Priorizamos variables de entorno si existen, sino usamos las hardcodeadas
const config = {
  apiKey: (typeof process !== 'undefined' && process.env?.VITE_FIREBASE_API_KEY) || firebaseConfig.apiKey,
  authDomain: (typeof process !== 'undefined' && process.env?.VITE_FIREBASE_AUTH_DOMAIN) || firebaseConfig.authDomain,
  projectId: (typeof process !== 'undefined' && process.env?.VITE_FIREBASE_PROJECT_ID) || firebaseConfig.projectId,
  storageBucket: (typeof process !== 'undefined' && process.env?.VITE_FIREBASE_STORAGE_BUCKET) || firebaseConfig.storageBucket,
  messagingSenderId: (typeof process !== 'undefined' && process.env?.VITE_FIREBASE_MESSAGING_SENDER_ID) || firebaseConfig.messagingSenderId,
  appId: (typeof process !== 'undefined' && process.env?.VITE_FIREBASE_APP_ID) || firebaseConfig.appId,
  measurementId: (typeof process !== 'undefined' && process.env?.VITE_FIREBASE_MEASUREMENT_ID) || firebaseConfig.measurementId
};

const isConfigValid = !isPlaceholder(config.apiKey) && !isPlaceholder(config.projectId);

// Inicialización segura
let app: any;
let db: any = null;
let analytics: any = null;

if (isConfigValid) {
  try {
    app = getApps().length === 0 ? initializeApp(config) : getApps()[0];

    // Firestore con persistencia para uso Offline (Crítico para tablets en clínicas)
    db = initializeFirestore(app, {
      localCache: persistentLocalCache({
        tabManager: persistentMultipleTabManager()
      })
    });

    // Inicializar Analytics solo si es compatible
    isSupported().then(yes => {
        if (yes) analytics = getAnalytics(app);
    });
  } catch (error) {
    console.error("Firebase init error:", error);
  }
}

export { db, analytics, isConfigValid };

import React, { useState, useEffect } from 'react';
import { Sidebar } from './components/Sidebar';
import { PatientList } from './components/PatientList';
import { PatientDetail } from './components/PatientDetail';
import { MOCK_PATIENTS } from './constants';
import { Patient, ViewState } from './types';
import { db, isConfigValid } from './firebase';
import { 
  collection, 
  onSnapshot, 
  doc, 
  setDoc, 
  updateDoc,
  query
} from 'firebase/firestore';
import { Cloud, CloudOff, Loader2, AlertTriangle, X, Terminal, ExternalLink, CheckCircle2, Wifi } from 'lucide-react';

const App: React.FC = () => {
  const [patients, setPatients] = useState<Patient[]>([]);
  const [loading, setLoading] = useState(true);
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [isSyncing, setIsSyncing] = useState(false);
  const [activePatientIds, setActivePatientIds] = useState<string[]>([]);
  const [selectedPatientId, setSelectedPatientId] = useState<string | null>(null);
  const [view, setView] = useState<ViewState>('HOME');
  const [showSetupModal, setShowSetupModal] = useState(false);
  const [dbError, setDbError] = useState<string | null>(null);

  useEffect(() => {
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  useEffect(() => {
    if (!isConfigValid || !db) {
      setPatients(MOCK_PATIENTS);
      setLoading(false);
      return;
    }

    const q = query(collection(db, 'patients'));
    const unsubscribe = onSnapshot(q, (snapshot) => {
      const patientsData: Patient[] = [];
      snapshot.forEach((doc) => {
        patientsData.push(doc.data() as Patient);
      });

      // Si la DB está vacía, mostramos los mocks por primera vez
      if (patientsData.length === 0 && loading) {
        setPatients(MOCK_PATIENTS);
      } else if (patientsData.length > 0) {
        setPatients(patientsData);
      }
      setLoading(false);
      setDbError(null);
    }, (error) => {
      console.error("Firestore error:", error);
      setDbError(`Error de conexión: ${error.message}`);
      setPatients(MOCK_PATIENTS);
      setLoading(false);
    });

    return () => unsubscribe();
  }, [loading]);

  const handleSelectPatient = (patient: Patient) => {
    if (!activePatientIds.includes(patient.id)) {
      setActivePatientIds(prev => [patient.id, ...prev]);
    }
    setSelectedPatientId(patient.id);
    setView('PATIENT_DETAIL');
  };

  const handleAddPatient = async (newPatient: Patient) => {
      if (isConfigValid && db) {
          setIsSyncing(true);
          try {
              await setDoc(doc(db, 'patients', newPatient.id), newPatient);
              setDbError(null);
          } catch (e: any) {
              setDbError(`Error al guardar: ${e.message}`);
          } finally {
              setIsSyncing(false);
          }
      }
      handleSelectPatient(newPatient);
  };

  const handleUpdatePatient = async (updatedPatient: Patient) => {
      if (isConfigValid && db) {
          setIsSyncing(true);
          try {
              await updateDoc(doc(db, 'patients', updatedPatient.id), { ...updatedPatient });
              setDbError(null);
          } catch (e: any) {
              setDbError(`Error al actualizar: ${e.message}`);
          } finally {
              setIsSyncing(false);
          }
      }
      setPatients(prev => prev.map(p => p.id === updatedPatient.id ? updatedPatient : p));
  };

  const handleSidebarSelect = (patientId: string) => {
    setSelectedPatientId(patientId);
    setView('PATIENT_DETAIL');
  };

  const handleRemoveActive = (patientId: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setActivePatientIds(prev => prev.filter(id => id !== patientId));
    if (selectedPatientId === patientId) {
        setSelectedPatientId(null);
        setView('HOME');
    }
  };

  const handleGoHome = () => {
    setView('HOME');
    setSelectedPatientId(null);
  };

  if (loading) {
      return (
          <div className="h-screen w-full flex flex-col items-center justify-center bg-slate-50">
              <Loader2 className="animate-spin text-primary-600 mb-4" size={48} />
              <h2 className="text-xl font-bold text-slate-800">Iniciando KineFlow Pro...</h2>
          </div>
      );
  }

  const activePatients = activePatientIds
    .map(id => patients.find(p => p.id === id))
    .filter((p): p is Patient => !!p);

  const currentPatient = patients.find(p => p.id === selectedPatientId);

  return (
    <div className="flex w-full h-screen bg-slate-50 font-sans text-slate-900">

      {/* Syncing Indicator */}
      {isSyncing && (
          <div className="fixed bottom-6 right-6 z-[100] bg-slate-900 text-white px-4 py-2 rounded-full shadow-2xl flex items-center gap-2 animate-in fade-in slide-in-from-bottom-4">
              <Loader2 size={16} className="animate-spin text-primary-400" />
              <span className="text-xs font-bold uppercase tracking-wider">Sincronizando...</span>
          </div>
      )}

      {/* DB Error Notification */}
      {dbError && (
          <div className="fixed bottom-20 left-1/2 -translate-x-1/2 z-[100] bg-red-600 text-white px-6 py-3 rounded-full shadow-2xl flex items-center gap-3 animate-bounce">
              <AlertTriangle size={20} />
              <span className="font-bold text-sm">{dbError}</span>
              <button onClick={() => setDbError(null)} className="ml-2 hover:text-red-200">
                  <X size={16} />
              </button>
          </div>
      )}

      {/* Configuration Assistant Badge - Solo se muestra si falla la config */}
      {!isConfigValid && (
          <button 
            onClick={() => setShowSetupModal(true)}
            className="fixed top-4 right-4 z-[100] bg-white border-2 border-amber-200 p-4 rounded-2xl shadow-xl flex items-center gap-4 hover:border-amber-400 hover:scale-[1.02] transition-all text-left animate-in slide-in-from-right-10"
          >
              <div className="bg-amber-100 p-2 rounded-xl">
                <AlertTriangle className="text-amber-600" size={24} />
              </div>
              <div>
                  <p className="text-slate-900 font-bold text-sm">Configuración Pendiente</p>
                  <p className="text-slate-500 text-xs font-medium">Revisar credenciales de Firebase</p>
              </div>
          </button>
      )}

      <div className="flex flex-col relative">
          <Sidebar 
            activePatients={activePatients}
            selectedPatientId={selectedPatientId}
            onSelectPatient={handleSidebarSelect}
            onRemoveActive={handleRemoveActive}
            onGoHome={handleGoHome}
          />
          <div className="absolute bottom-4 left-1/2 -translate-x-1/2 flex flex-col items-center gap-1 z-50">
              {isOnline && isConfigValid ? (
                  <div className="flex flex-col items-center group">
                      <div className="bg-emerald-100 text-emerald-600 p-2 rounded-full shadow-sm cursor-help">
                          <Wifi size={16} />
                      </div>
                      <span className="absolute bottom-full mb-2 bg-slate-800 text-white text-[10px] px-2 py-1 rounded opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap">
                          Conectado a kineflow-pro2
                      </span>
                  </div>
              ) : (
                  <div className="bg-amber-100 text-amber-600 p-2 rounded-full shadow-sm">
                      <CloudOff size={16} />
                  </div>
              )}
          </div>
      </div>

      <div className="flex-1 flex flex-col h-full overflow-hidden">
        {view === 'HOME' && (
            <PatientList 
                patients={patients} 
                onSelectPatient={handleSelectPatient} 
                onAddPatient={handleAddPatient}
            />
        )}

        {view === 'PATIENT_DETAIL' && currentPatient && (
            <PatientDetail 
                patient={currentPatient}
                onUpdatePatient={handleUpdatePatient}
            />
        )}
      </div>
    </div>
  );
};

export default App;

