import React, { useState } from 'react';
import { Patient, Stage } from '../types';
import { Search, Clock, ChevronRight, UserPlus, X, Settings2, Trash2, User } from 'lucide-react';

interface PatientListProps {
  patients: Patient[];
  onSelectPatient: (patient: Patient) => void;
  onAddPatient: (patient: Patient) => void;
  onUpdatePatient: (patient: Patient) => void;
  onDeletePatient: (patientId: string) => void;
}

export const PatientList: React.FC<PatientListProps> = ({
  patients,
  onSelectPatient,
  onAddPatient,
  onUpdatePatient,
  onDeletePatient
}) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [modalState, setModalState] = useState<{ show: boolean, editingPatient: Patient | null }>({
    show: false,
    editingPatient: null
  });

  // Form State
  const [formData, setFormData] = useState({
    firstName: '',
    lastName: '',
    condition: '',
    age: 30,
    stage: Stage.KINESIOLOGY
  });

  const filteredPatients = patients.filter((p) => {
    const fullName = `${p.firstName} ${p.lastName}`.toLowerCase();
    return fullName.includes(searchTerm.toLowerCase());
  });

  const recentPatients = patients.slice(0, 3);

  const openModal = (patient: Patient | null = null) => {
    if (patient) {
      setFormData({
        firstName: patient.firstName,
        lastName: patient.lastName,
        condition: patient.condition,
        age: patient.age,
        stage: patient.routine.stage
      });
      setModalState({ show: true, editingPatient: patient });
    } else {
      setFormData({
        firstName: '',
        lastName: '',
        condition: '',
        age: 30,
        stage: Stage.KINESIOLOGY
      });
      setModalState({ show: true, editingPatient: null });
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.firstName || !formData.lastName) return;

    if (modalState.editingPatient) {
      // Update existing
      onUpdatePatient({
        ...modalState.editingPatient,
        firstName: formData.firstName,
        lastName: formData.lastName,
        age: formData.age,
        condition: formData.condition,
        routine: {
          ...modalState.editingPatient.routine,
          stage: formData.stage
        }
      });
    } else {
      // Create new
      const newPatient: Patient = {
        id: `p-${Date.now()}`,
        firstName: formData.firstName,
        lastName: formData.lastName,
        age: formData.age,
        condition: formData.condition || 'Sin diagnóstico',
        photoUrl: `https://ui-avatars.com/api/?name=${formData.firstName}+${formData.lastName}&background=random`,
        lastVisit: new Date().toISOString().split('T')[0],
        history: [],
        routine: {
          id: `r-${Date.now()}`,
          stage: formData.stage,
          days: [
            { id: `d1-${Date.now()}`, name: 'Día 1', exercises: [] },
            { id: `d2-${Date.now()}`, name: 'Día 2', exercises: [] }
          ]
        }
      };
      onAddPatient(newPatient);
    }
    setModalState({ show: false, editingPatient: null });
  };

  const handleDelete = () => {
    if (!modalState.editingPatient) return;
    if (window.confirm(`¿Estás seguro de que deseas eliminar a ${modalState.editingPatient.firstName}? Esta acción no se puede deshacer.`)) {
      onDeletePatient(modalState.editingPatient.id);
      setModalState({ show: false, editingPatient: null });
    }
  };

  return (
    <div className="flex-1 h-screen overflow-y-auto bg-slate-50 p-6 md:p-8 relative">
      <div className="max-w-4xl mx-auto space-y-8">

        {/* Header & Search */}
        <div className="space-y-4">
          <div className="flex justify-between items-center">
            <h1 className="text-3xl font-bold text-slate-900">Pacientes</h1>
            <button 
                onClick={() => openModal()}
                className="bg-primary-600 text-white px-5 py-3 rounded-xl font-bold flex items-center gap-2 shadow-lg shadow-primary-200 hover:bg-primary-700 active:scale-95 transition-all"
            >
                <UserPlus size={20} />
                Nuevo Paciente
            </button>
          </div>

          <div className="relative">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={24} />
            <input
              type="text"
              placeholder="Buscar paciente por nombre..."
              className="w-full h-16 pl-14 pr-6 rounded-2xl border-none shadow-sm text-lg focus:ring-4 focus:ring-primary-100"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
        </div>

        {/* Recent Patients */}
        {!searchTerm && (
          <div className="space-y-4">
            <div className="flex items-center gap-2 text-slate-500 font-semibold uppercase text-sm tracking-wider">
              <Clock size={16} />
              <span>Recientes</span>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              {recentPatients.map((patient) => (
                <button
                  key={patient.id}
                  onClick={() => onSelectPatient(patient)}
                  className="bg-white p-4 rounded-xl shadow-sm border border-slate-100 flex items-center gap-4 hover:shadow-md transition-shadow text-left group"
                >
                  <img
                    src={patient.photoUrl}
                    alt={patient.firstName}
                    className="w-14 h-14 rounded-full object-cover"
                  />
                  <div className="flex-1 min-w-0">
                    <h3 className="font-bold text-slate-800 text-lg truncate">
                      {patient.firstName}
                    </h3>
                    <p className="text-slate-500 text-sm truncate">{patient.condition}</p>
                  </div>
                </button>
              ))}
            </div>
          </div>
        )}

        {/* All Patients List */}
        <div className="space-y-4 pb-10">
          <div className="flex items-center gap-2 text-slate-500 font-semibold uppercase text-sm tracking-wider">
            <User size={16} />
            <span>Todos los pacientes</span>
          </div>

          <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
            {filteredPatients.length > 0 ? (
              filteredPatients.map((patient, index) => (
                <div
                  key={patient.id}
                  className={`flex items-center p-5 cursor-pointer hover:bg-slate-50 transition-colors group ${
                    index !== filteredPatients.length - 1 ? 'border-b border-slate-100' : ''
                  }`}
                  onClick={() => onSelectPatient(patient)}
                >
                  <img
                    src={patient.photoUrl}
                    alt={patient.firstName}
                    className="w-12 h-12 rounded-full object-cover mr-4"
                  />
                  <div className="flex-1">
                    <h3 className="font-bold text-slate-800 text-lg">
                      {patient.firstName} {patient.lastName}
                    </h3>
                    <div className="flex items-center gap-2 mt-1">
                        <span className={`px-2 py-0.5 rounded-full text-xs font-bold ${
