import React, { useState, useEffect } from 'react';
import { Sidebar } from './components/Sidebar';
import { PatientList } from './components/PatientList';
import { PatientDetail } from './components/PatientDetail';
import { MOCK_PATIENTS } from './constants';
import { Patient, ViewState } from './types';
import { db, isConfigValid } from './firebase';
import { 
  collection, 
  onSnapshot, 
  doc, 
  setDoc, 
  updateDoc,
  deleteDoc,
  query
} from 'firebase/firestore';
import { Loader2, AlertTriangle, X, Wifi, CloudOff } from 'lucide-react';

const App: React.FC = () => {
  const [patients, setPatients] = useState<Patient[]>([]);
  const [loading, setLoading] = useState(true);
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [isSyncing, setIsSyncing] = useState(false);
  const [activePatientIds, setActivePatientIds] = useState<string[]>([]);
  const [selectedPatientId, setSelectedPatientId] = useState<string | null>(null);
  const [view, setView] = useState<ViewState>('HOME');
  const [dbError, setDbError] = useState<string | null>(null);

  useEffect(() => {
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  useEffect(() => {
    if (!isConfigValid || !db) {
      setPatients(MOCK_PATIENTS);
      setLoading(false);
      return;
    }

    const q = query(collection(db, 'patients'));
    const unsubscribe = onSnapshot(q, (snapshot) => {
      const patientsData: Patient[] = [];
      snapshot.forEach((doc) => {
        patientsData.push(doc.data() as Patient);
      });

      if (patientsData.length === 0 && loading) {
        setPatients(MOCK_PATIENTS);
      } else if (patientsData.length > 0) {
        setPatients(patientsData);
      }
      setLoading(false);
      setDbError(null);
    }, (error) => {
      console.error("Firestore error:", error);
      setDbError(`Error de conexión: ${error.message}`);
      setPatients(MOCK_PATIENTS);
      setLoading(false);
    });

    return () => unsubscribe();
  }, [loading]);

  const handleSelectPatient = (patient: Patient) => {
    if (!activePatientIds.includes(patient.id)) {
      setActivePatientIds(prev => [patient.id, ...prev]);
    }
    setSelectedPatientId(patient.id);
    setView('PATIENT_DETAIL');
  };

  const handleAddPatient = async (newPatient: Patient) => {
      if (isConfigValid && db) {
          setIsSyncing(true);
          try {
              await setDoc(doc(db, 'patients', newPatient.id), newPatient);
          } catch (e: any) {
              setDbError(`Error al guardar: ${e.message}`);
          } finally {
              setIsSyncing(false);
          }
      }
      handleSelectPatient(newPatient);
  };

  const handleUpdatePatient = async (updatedPatient: Patient) => {
      if (isConfigValid && db) {
          setIsSyncing(true);
          try {
              await updateDoc(doc(db, 'patients', updatedPatient.id), { ...updatedPatient });
          } catch (e: any) {
              setDbError(`Error al actualizar: ${e.message}`);
          } finally {
              setIsSyncing(false);
          }
      }
      setPatients(prev => prev.map(p => p.id === updatedPatient.id ? updatedPatient : p));
  };

  const handleDeletePatient = async (patientId: string) => {
    if (isConfigValid && db) {
      setIsSyncing(true);
      try {
        await deleteDoc(doc(db, 'patients', patientId));
        setActivePatientIds(prev => prev.filter(id => id !== patientId));
        if (selectedPatientId === patientId) {
          setView('HOME');
          setSelectedPatientId(null);
        }
      } catch (e: any) {
        setDbError(`Error al eliminar: ${e.message}`);
      } finally {
        setIsSyncing(false);
      }
    } else {
      setPatients(prev => prev.filter(p => p.id !== patientId));
      setActivePatientIds(prev => prev.filter(id => id !== patientId));
      if (selectedPatientId === patientId) {
        setView('HOME');
        setSelectedPatientId(null);
      }
    }
  };

  const handleSidebarSelect = (patientId: string) => {
    setSelectedPatientId(patientId);
    setView('PATIENT_DETAIL');
  };

  const handleRemoveActive = (patientId: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setActivePatientIds(prev => prev.filter(id => id !== patientId));
    if (selectedPatientId === patientId) {
        setSelectedPatientId(null);
        setView('HOME');
    }
  };

  const handleGoHome = () => {
    setView('HOME');
    setSelectedPatientId(null);
  };

  if (loading) {
      return (
          <div className="h-[100dvh] w-full flex flex-col items-center justify-center bg-slate-50">
              <Loader2 className="animate-spin text-primary-600 mb-4" size={48} />
              <h2 className="text-xl font-bold text-slate-800">Iniciando KineFlow Pro...</h2>
          </div>
      );
  }

  const activePatients = activePatientIds
    .map(id => patients.find(p => p.id === id))
    .filter((p): p is Patient => !!p);

  const currentPatient = patients.find(p => p.id === selectedPatientId);

  return (
    <div className="flex w-full h-[100dvh] bg-slate-50 font-sans text-slate-900 overflow-hidden">

      {/* 1. Connection Indicator (Bottom Left, within sidebar horizontal zone) */}
      <div className="fixed bottom-10 left-8 z-[100] pointer-events-none">
        {isOnline && isConfigValid ? (
          <div className="bg-emerald-500 text-white p-2.5 rounded-full shadow-lg border-2 border-white ring-4 ring-emerald-50 animate-in fade-in slide-in-from-bottom-2 duration-500">
            <Wifi size={18} />
          </div>
        ) : (
          <div className="bg-amber-500 text-white p-2.5 rounded-full shadow-lg border-2 border-white ring-4 ring-amber-50 animate-bounce">
            <CloudOff size={18} />
          </div>
        )}
      </div>

      {/* 2. Syncing Indicator (Bottom Right) */}
      {isSyncing && (
          <div className="fixed bottom-10 right-10 z-[100] bg-slate-900 text-white px-5 py-3 rounded-full shadow-2xl flex items-center gap-3 animate-in fade-in slide-in-from-bottom-4">
              <Loader2 size={18} className="animate-spin text-primary-400" />
              <span className="text-sm font-bold uppercase tracking-widest">Sincronizando</span>
          </div>
      )}

      {/* DB Error Notification */}
      {dbError && (
          <div className="fixed top-6 left-1/2 -translate-x-1/2 z-[100] bg-red-600 text-white px-6 py-3 rounded-full shadow-2xl flex items-center gap-3 animate-in bounce-in">
              <AlertTriangle size={20} />
              <span className="font-bold text-sm">{dbError}</span>
              <button onClick={() => setDbError(null)} className="ml-2 hover:text-red-200">
                  <X size={16} />
              </button>
          </div>
      )}

      <div className="flex shrink-0">
          <Sidebar 
            activePatients={activePatients}
            selectedPatientId={selectedPatientId}
            onSelectPatient={handleSidebarSelect}
            onRemoveActive={handleRemoveActive}
            onGoHome={handleGoHome}
          />
      </div>

      <div className="flex-1 flex flex-col h-full overflow-hidden">
        {view === 'HOME' && (
            <PatientList 
                patients={patients} 
                onSelectPatient={handleSelectPatient} 
                onAddPatient={handleAddPatient}
                onUpdatePatient={handleUpdatePatient}
                onDeletePatient={handleDeletePatient}
            />
        )}

        {view === 'PATIENT_DETAIL' && currentPatient && (
            <PatientDetail 
                patient={currentPatient}
                onUpdatePatient={handleUpdatePatient}
            />
        )}
      </div>
    </div>
  );
};

export default App;

