import React, { useState } from 'react';
import { Patient, Stage } from '../types';
import { Search, Clock, ChevronRight, UserPlus, X, Settings2, Trash2, User } from 'lucide-react';

interface PatientListProps {
  patients: Patient[];
  onSelectPatient: (patient: Patient) => void;
  onAddPatient: (patient: Patient) => void;
  onUpdatePatient: (patient: Patient) => void;
  onDeletePatient: (patientId: string) => void;
}

export const PatientList: React.FC<PatientListProps> = ({
  patients,
  onSelectPatient,
  onAddPatient,
  onUpdatePatient,
  onDeletePatient
}) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [modalState, setModalState] = useState<{ show: boolean, editingPatient: Patient | null }>({
    show: false,
    editingPatient: null
  });

  const [formData, setFormData] = useState({
    firstName: '',
    lastName: '',
    condition: '',
    age: 30,
    stage: Stage.KINESIOLOGY
  });

  const filteredPatients = patients.filter((p) => {
    const fullName = `${p.firstName} ${p.lastName}`.toLowerCase();
    return fullName.includes(searchTerm.toLowerCase());
  });

  const recentPatients = patients.slice(0, 3);

  const openModal = (patient: Patient | null = null) => {
    if (patient) {
      setFormData({
        firstName: patient.firstName,
        lastName: patient.lastName,
        condition: patient.condition,
        age: patient.age,
        stage: patient.routine.stage
      });
      setModalState({ show: true, editingPatient: patient });
    } else {
      setFormData({
        firstName: '',
        lastName: '',
        condition: '',
        age: 30,
        stage: Stage.KINESIOLOGY
      });
      setModalState({ show: true, editingPatient: null });
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.firstName || !formData.lastName) return;

    if (modalState.editingPatient) {
      onUpdatePatient({
        ...modalState.editingPatient,
        firstName: formData.firstName,
        lastName: formData.lastName,
        age: formData.age,
        condition: formData.condition,
        routine: {
          ...modalState.editingPatient.routine,
          stage: formData.stage
        }
      });
    } else {
      const newPatient: Patient = {
        id: `p-${Date.now()}`,
        firstName: formData.firstName,
        lastName: formData.lastName,
        age: formData.age,
        condition: formData.condition || 'Sin diagnóstico',
        photoUrl: `https://ui-avatars.com/api/?name=${formData.firstName}+${formData.lastName}&background=random`,
        lastVisit: new Date().toISOString().split('T')[0],
        history: [],
        routine: {
          id: `r-${Date.now()}`,
          stage: formData.stage,
          days: [
            { id: `d1-${Date.now()}`, name: 'Día 1', exercises: [] },
            { id: `d2-${Date.now()}`, name: 'Día 2', exercises: [] }
          ]
        }
      };
      onAddPatient(newPatient);
    }
    setModalState({ show: false, editingPatient: null });
  };

  const handleDelete = () => {
    if (!modalState.editingPatient) return;
    if (window.confirm(`¿Estás seguro de que deseas eliminar a ${modalState.editingPatient.firstName}?`)) {
      onDeletePatient(modalState.editingPatient.id);
      setModalState({ show: false, editingPatient: null });
    }
  };

  return (
    <div className="flex-1 h-screen overflow-y-auto bg-slate-50 p-4 md:p-8 relative">
      <div className="max-w-4xl mx-auto space-y-6 md:space-y-8">

        {/* Header & Search */}
        <div className="space-y-4">
          <div className="flex justify-between items-center gap-4">
            <h1 className="text-2xl md:text-3xl font-bold text-slate-900">Pacientes</h1>
            <button 
                onClick={() => openModal()}
                className="bg-primary-600 text-white px-4 py-2.5 md:px-5 md:py-3 rounded-xl font-bold flex items-center gap-2 shadow-lg hover:bg-primary-700 active:scale-95 transition-all text-sm"
            >
                <UserPlus size={18} />
                <span className="hidden xs:inline">Nuevo Paciente</span>
                <span className="xs:hidden">Nuevo</span>
            </button>
          </div>

          <div className="relative">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
            <input
              type="text"
              placeholder="Buscar paciente..."
              className="w-full h-14 md:h-16 pl-12 pr-6 rounded-2xl border-none shadow-sm text-base md:text-lg focus:ring-4 focus:ring-primary-100"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
        </div>

        {/* Recent Patients */}
        {!searchTerm && recentPatients.length > 0 && (
          <div className="space-y-3">
            <div className="flex items-center gap-2 text-slate-500 font-semibold uppercase text-[10px] tracking-wider">
