import React, { useState, useEffect, useMemo } from 'react';
import { Patient, RoutineDay, RoutineExercise, Stage } from '../types';
import { EXERCISES } from '../constants';
import { ExerciseCard } from './ExerciseCard';
import { ProgressChart } from './ProgressChart';
import { AlertCircle, FileText, Plus, Search, X, LayoutGrid, Trash2, Settings, CheckSquare, Square, Calendar, List, Layout } from 'lucide-react';

interface PatientDetailProps {
  patient: Patient;
  onUpdatePatient: (updated: Patient) => void;
}

type ViewMode = 'daily' | 'weekly' | 'monthly';

export const PatientDetail: React.FC<PatientDetailProps> = ({
  patient,
  onUpdatePatient,
}) => {
  const [activeDayId, setActiveDayId] = useState<string>(
    patient.routine.days[0]?.id || ''
  );
  const [viewMode, setViewMode] = useState<ViewMode>('daily');
  const [showHistory, setShowHistory] = useState<boolean>(false);
  const [showRoutineEditor, setShowRoutineEditor] = useState<boolean>(false);
  const [chartExercise, setChartExercise] = useState<RoutineExercise | null>(null);
  const [isAddingExercise, setIsAddingExercise] = useState(false);
  const [targetDayIdForAdd, setTargetDayIdForAdd] = useState<string | null>(null);
  const [exerciseSearch, setExerciseSearch] = useState('');
  const [selectedExerciseIds, setSelectedExerciseIds] = useState<string[]>([]);
  const [notes, setNotes] = useState(patient.history[0] || '');

  useEffect(() => {
    setNotes(patient.history[0] || '');
  }, [patient.id]);

  useEffect(() => {
      const hasExercises = patient.routine.days.some(d => d.exercises.length > 0);
      if (!hasExercises && patient.routine.days.length <= 1) {
          setShowRoutineEditor(true);
      }
  }, [patient.id]);

  useEffect(() => {
     if (patient.routine.days.length > 0) {
         const dayExists = patient.routine.days.find(d => d.id === activeDayId);
         if (!dayExists) {
             setActiveDayId(patient.routine.days[0].id);
         }
     } else {
         if (activeDayId !== '') setActiveDayId('');
     }
  }, [patient.routine.days, activeDayId]);

  const activeDayIndex = patient.routine.days.findIndex(d => d.id === activeDayId);
  const activeDay = patient.routine.days[activeDayIndex];

  const handleDayTabClick = (dayId: string) => {
      setActiveDayId(dayId);
      setViewMode('daily');
  };

  const handleSaveNotes = () => {
      const newHistory = [...patient.history];
      if (newHistory.length === 0) {
          newHistory.push(notes);
      } else {
          newHistory[0] = notes;
      }
      onUpdatePatient({ ...patient, history: newHistory });
  };

  const handleToggleStage = () => {
      const newStage = patient.routine.stage === Stage.KINESIOLOGY ? Stage.GYM : Stage.KINESIOLOGY;
      onUpdatePatient({
          ...patient,
          routine: { ...patient.routine, stage: newStage }
      });
  };

  const handleUpdateDayCount = (delta: number) => {
      const currentCount = patient.routine.days.length;
      const newCount = Math.max(1, Math.min(7, currentCount + delta));
      if (newCount === currentCount) return;
      let newDays = [...patient.routine.days];
      if (newCount > currentCount) {
          for (let i = currentCount; i < newCount; i++) {
              newDays.push({ id: `day-${Date.now()}-${i}`, name: `Día ${i + 1}`, exercises: [] });
          }
      } else {
          if (newDays[newDays.length - 1].exercises.length > 0) {
              if (!window.confirm("Al reducir los días se eliminarán los ejercicios del último día. ¿Continuar?")) return;
          }
          newDays = newDays.slice(0, newCount);
      }
      onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  const handleExerciseUpdate = (exerciseId: string, updates: Partial<RoutineExercise>) => {
    if (activeDayIndex === -1) return;
    const newDays = [...patient.routine.days];
    const newExercises = [...newDays[activeDayIndex].exercises];
    const exIndex = newExercises.findIndex(e => e.id === exerciseId);
    if (exIndex === -1) return;
    newExercises[exIndex] = { ...newExercises[exIndex], ...updates };
    newDays[activeDayIndex] = { ...newDays[activeDayIndex], exercises: newExercises };
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  const handleRemoveExercise = (dayId: string, exerciseId: string) => {
      const dayIndex = patient.routine.days.findIndex(d => d.id === dayId);
      if (dayIndex === -1) return;
      const newDays = [...patient.routine.days];
      newDays[dayIndex] = { ...newDays[dayIndex], exercises: newDays[dayIndex].exercises.filter(e => e.id !== exerciseId) };
      onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  const openAddModal = (dayId: string) => {
      setTargetDayIdForAdd(dayId);
      setSelectedExerciseIds([]);
      setExerciseSearch('');
      setIsAddingExercise(true);
  };

  const toggleExerciseSelection = (defId: string) => {
      setSelectedExerciseIds(prev => prev.includes(defId) ? prev.filter(id => id !== defId) : [...prev, defId]);
  };

  const handleConfirmAddExercises = () => {
      if (!targetDayIdForAdd) return;
      const dayIndex = patient.routine.days.findIndex(d => d.id === targetDayIdForAdd);
      if (dayIndex === -1) return;
      const newExercises: RoutineExercise[] = selectedExerciseIds.map(defId => {
          const def = EXERCISES.find(e => e.id === defId)!;
          return { id: `re-${Date.now()}-${Math.random()}`, definitionId: def.id, definition: def, targetSets: 3, targetReps: 10, targetLoad: 0, isDone: false, history: [] };
      });
      const newDays = [...patient.routine.days];
      newDays[dayIndex] = { ...newDays[dayIndex], exercises: [...newDays[dayIndex].exercises, ...newExercises] };
      onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
      setIsAddingExercise(false);
      setSelectedExerciseIds([]);
  };

  const filteredCatalog = EXERCISES.filter(ex => ex.name.toLowerCase().includes(exerciseSearch.toLowerCase()) || ex.category.toLowerCase().includes(exerciseSearch.toLowerCase()));

  const calendarData = useMemo(() => {
    const activeDates = new Set<string>();
    patient.routine.days.forEach(day => day.exercises.forEach(ex => ex.history && ex.history.forEach(log => activeDates.add(log.date))));
    const today = new Date();
    const currentYear = today.getFullYear();
    const currentMonth = today.getMonth();
    const daysInMonth = new Date(currentYear, currentMonth + 1, 0).getDate();
    const days = [];
    for (let i = 1; i <= daysInMonth; i++) {
        const dateStr = `${currentYear}-${String(currentMonth + 1).padStart(2, '0')}-${String(i).padStart(2, '0')}`;
        days.push({ day: i, date: dateStr, hasActivity: activeDates.has(dateStr), isToday: i === today.getDate() });
    }
    return days;
  }, [patient]);

  return (
    <div className="flex-1 h-screen flex flex-col bg-slate-50 overflow-hidden relative">
      <header className="bg-white border-b border-slate-200 px-4 md:px-6 py-3 md:py-4 flex items-center justify-between shadow-sm shrink-0 z-20">
        <div className="flex flex-col min-w-0">
          <h2 className="text-xl md:text-2xl font-bold text-slate-900 leading-none truncate">
            {patient.firstName} {patient.lastName}
          </h2>
          <div className="flex items-center gap-2 mt-1.5 md:mt-2">
              <span className={`px-2 md:px-3 py-0.5 md:py-1 rounded-full text-[10px] font-bold uppercase border ${patient.routine.stage === Stage.KINESIOLOGY ? 'bg-kine/10 text-kine border-kine/20' : 'bg-gym/10 text-gym border-gym/20'}`}>
                  {patient.routine.stage}
              </span>
              <span className="text-[10px] md:text-sm text-slate-400 truncate hidden xs:inline">• {patient.condition}</span>
          </div>
        </div>
        <div className="flex gap-1.5 md:gap-2 shrink-0">
            <button onClick={() => setShowRoutineEditor(true)} className="p-2 md:px-4 md:py-2 bg-primary-600 text-white rounded-lg font-bold shadow-md hover:bg-primary-700 transition-colors">
                <Settings size={18} />
                <span className="hidden md:inline ml-2">Editar Rutina</span>
            </button>
            <button onClick={() => setShowHistory(!showHistory)} className={`p-2 md:px-4 md:py-2 rounded-lg font-bold transition-colors ${showHistory ? 'bg-slate-800 text-white' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'}`}>
                <FileText size={18} />
                <span className="hidden md:inline ml-2">{showHistory ? 'Ocultar' : 'Ficha'}</span>
            </button>
        </div>
      </header>

      {showHistory && (
          <div className="bg-slate-800 text-slate-200 px-4 md:px-8 py-4 md:py-6 shadow-inner shrink-0 animate-in slide-in-from-top-5 border-b border-slate-700 overflow-y-auto max-h-[40vh]">
              <div className="grid grid-cols-1 md:grid-cols-3 gap-6 max-w-5xl">
                  <div className="space-y-4">
                       <h4 className="text-slate-400 text-[10px] md:text-xs uppercase font-bold mb-1">Datos Clínicos</h4>
                       <div className="flex items-center gap-3">
                            <h5 className="text-slate-500 text-[10px] md:text-xs font-bold uppercase">Última Visita:</h5>
                            <span className="text-xs font-mono bg-slate-700 px-2 py-0.5 rounded">{patient.lastVisit}</span>
                       </div>
                  </div>
                  <div className="md:col-span-2">
                      <div className="flex justify-between items-center mb-2">
                        <h4 className="text-slate-400 text-[10px] md:text-xs uppercase font-bold tracking-wider">Evolución</h4>
                      </div>
                      <textarea className="w-full h-24 md:h-32 bg-slate-700 text-slate-200 p-3 md:p-4 rounded-xl border border-slate-600 focus:ring-2 focus:ring-primary-500 outline-none resize-none text-sm md:text-base" value={notes} onChange={(e) => setNotes(e.target.value)} onBlur={handleSaveNotes} placeholder="Observaciones..." />
                  </div>
              </div>
          </div>
      )}

      <div className="bg-white border-b border-slate-200 px-4 md:px-6 flex justify-between pt-2 md:pt-4 shrink-0 overflow-x-auto no-scrollbar">
          <div className="flex gap-1">
            {patient.routine.days.map((day, index) => (
              <button key={day.id} onClick={() => handleDayTabClick(day.id)} className={`px-4 md:px-6 py-2 md:py-3 rounded-t-xl font-bold text-xs md:text-sm tracking-wide transition-all border-t border-x min-w-[80px] md:min-w-[100px] ${activeDayId === day.id && viewMode === 'daily' ? 'bg-slate-50 border-slate-200 text-primary-600 border-b-slate-50 -mb-px z-10' : 'bg-white border-transparent text-slate-400 hover:bg-slate-50'}`}>
                Día {index + 1}
              </button>
            ))}
          </div>
          <div className="flex items-center gap-1 pb-1 md:pb-2 pl-4 border-l border-slate-100 ml-2 shrink-0">
              <button onClick={() => setViewMode('weekly')} className={`p-1.5 md:px-3 md:py-1.5 rounded-lg text-[10px] font-bold uppercase tracking-wider transition-colors ${viewMode === 'weekly' ? 'bg-primary-100 text-primary-700' : 'text-slate-400'}`}>
                  <LayoutGrid size={14} className="md:w-4 md:h-4" />
              </button>
              <button onClick={() => setViewMode('monthly')} className={`p-1.5 md:px-3 md:py-1.5 rounded-lg text-[10px] font-bold uppercase tracking-wider transition-colors ${viewMode === 'monthly' ? 'bg-primary-100 text-primary-700' : 'text-slate-400'}`}>
                  <Calendar size={14} className="md:w-4 md:h-4" />
              </button>
          </div>
      </div>

      <main className="flex-1 overflow-y-auto p-4 md:p-8">
        <div className="max-w-4xl mx-auto pb-24">
          {viewMode === 'daily' && (
              activeDay ? (
                <div className="space-y-3 md:space-y-4 max-w-2xl mx-auto">
                  {activeDay.exercises.length > 0 ? (
                      activeDay.exercises.map((exercise) => (
                        <ExerciseCard key={exercise.id} exercise={exercise} onUpdate={handleExerciseUpdate} onShowHistory={(ex) => setChartExercise(ex)} onDelete={(eid) => handleRemoveExercise(activeDayId, eid)} />
                      ))
                  ) : (
                      <div className="text-center py-10 text-slate-400 flex flex-col items-center">
                          <p className="mb-4 text-sm font-medium">No hay ejercicios aún</p>
                          <button onClick={() => openAddModal(activeDayId)} className="bg-primary-600 text-white px-6 py-3 rounded-xl font-bold shadow-md">
                              Agregar Ejercicio
                          </button>
                      </div>
                  )}
                  {activeDay.exercises.length > 0 && (
                    <button onClick={() => openAddModal(activeDayId)} className="w-full py-3.5 rounded-2xl border-2 border-dashed border-primary-200 text-primary-600 font-bold text-sm hover:bg-primary-50 transition-colors flex items-center justify-center gap-2">
                        <Plus size={18} />
                        Agregar Ejercicio
                    </button>
                  )}
                </div>
              ) : null
          )}

          {viewMode === 'weekly' && (
             <div className="grid grid-cols-1 xs:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-6 animate-in fade-in slide-in-from-bottom-2">
                 {patient.routine.days.map((day, idx) => (
                     <div key={day.id} className="bg-white rounded-2xl border border-slate-200 shadow-sm p-4 flex flex-col h-full min-h-[160px]">
                         <div className="flex justify-between items-center mb-3 pb-2 border-b border-slate-100">
                             <h3 className="font-bold text-base text-slate-800">Día {idx + 1}</h3>
                             <span className="text-[10px] bg-slate-100 text-slate-500 px-2 py-0.5 rounded font-bold uppercase">{day.exercises.length} Ej</span>
                         </div>
                         <div className="space-y-2 flex-1 overflow-hidden">
                             {day.exercises.slice(0, 4).map(ex => (
                                 <div key={ex.id} className="flex items-center gap-2 text-[10px] md:text-xs">
                                     <div className="w-1.5 h-1.5 rounded-full bg-primary-500 shrink-0"></div>
                                     <p className="font-bold text-slate-600 truncate">{ex.definition.name}</p>
                                 </div>
                             ))}
                             {day.exercises.length > 4 && <p className="text-[10px] text-slate-400 ml-3">+{day.exercises.length - 4} más...</p>}
                             {day.exercises.length === 0 && <p className="text-slate-300 italic text-xs text-center py-4">Descanso</p>}
                         </div>
                         <button onClick={() => handleDayTabClick(day.id)} className="mt-3 w-full py-2 bg-slate-50 text-slate-600 font-bold rounded-lg text-xs hover:bg-slate-100">
                             Abrir Día
                         </button>
                     </div>
                 ))}
             </div>
          )}

          {viewMode === 'monthly' && (
              <div className="animate-in fade-in slide-in-from-bottom-2">
                  <div className="bg-white rounded-3xl border border-slate-200 shadow-sm p-4 md:p-8 max-w-xl mx-auto">
                      <div className="flex justify-between items-center mb-6">
                          <h3 className="text-lg md:text-xl font-bold text-slate-900">Asistencia</h3>
                          <div className="text-[10px] md:text-xs font-bold text-slate-500 bg-slate-100 px-3 py-1 rounded-lg uppercase tracking-wider">
                              {new Date().toLocaleString('es-ES', { month: 'long' })}
                          </div>
                      </div>
                      <div className="grid grid-cols-7 gap-1 md:gap-3 mb-2">
                          {['D', 'L', 'M', 'M', 'J', 'V', 'S'].map(d => (
                              <div key={d} className="text-center text-[10px] font-bold text-slate-400 uppercase">{d}</div>
                          ))}
                      </div>
                      <div className="grid grid-cols-7 gap-1 md:gap-3">
                          {Array.from({ length: new Date(new Date().getFullYear(), new Date().getMonth(), 1).getDay() }).map((_, i) => (<div key={`empty-${i}`} />))}
                          {calendarData.map((d) => (
                              <div key={d.day} className={`aspect-square rounded-lg flex flex-col items-center justify-center relative border transition-all ${d.isToday ? 'border-primary-500 bg-primary-50' : 'border-slate-100 bg-slate-50'}`}>
                                  <span className={`text-xs font-bold ${d.isToday ? 'text-primary-700' : 'text-slate-500'}`}>{d.day}</span>
                                  {d.hasActivity && <div className="absolute bottom-1 w-1 h-1 rounded-full bg-kine"></div>}
                              </div>
                          ))}
                      </div>
                  </div>
              </div>
          )}
        </div>
      </main>

      {/* MODALS OPTIMIZED FOR ALL ORIENTATIONS */}
      {chartExercise && <ProgressChart exercise={chartExercise} onClose={() => setChartExercise(null)} />}

      {isAddingExercise && (
          <div className="fixed inset-0 z-[120] bg-black/50 backdrop-blur-sm flex items-center justify-center p-4">
              <div className="bg-white w-full max-w-xl h-[85vh] rounded-2xl shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95">
                  <div className="p-4 border-b border-slate-100 flex items-center justify-between shrink-0">
                      <div className="relative flex-1 mr-4">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                        <input type="text" autoFocus placeholder="Buscar..." className="w-full pl-9 pr-4 py-2 bg-slate-50 rounded-xl outline-none text-sm" value={exerciseSearch} onChange={(e) => setExerciseSearch(e.target.value)} />
                      </div>
                      <button onClick={() => setIsAddingExercise(false)} className="p-1.5 bg-slate-100 rounded-full shrink-0"><X size={18} /></button>
                  </div>
                  <div className="flex-1 overflow-y-auto p-4 space-y-2 no-scrollbar">
                      {filteredCatalog.map(ex => {
                          const isSelected = selectedExerciseIds.includes(ex.id);
                          return (
                              <button key={ex.id} onClick={() => toggleExerciseSelection(ex.id)} className={`flex items-center p-3 rounded-xl text-left border transition-all ${isSelected ? 'bg-primary-50 border-primary-300 ring-1 ring-primary-300' : 'bg-white border-transparent hover:bg-slate-50'}`}>
                                  <div className={`mr-3 shrink-0 ${isSelected ? 'text-primary-600' : 'text-slate-300'}`}>
                                      {isSelected ? <CheckSquare size={20} /> : <Square size={20} />}
                                  </div>
                                  <div className="w-12 h-12 bg-slate-100 rounded-lg flex items-center justify-center mr-3 overflow-hidden shrink-0">
                                      {ex.videoUrl ? <img src={ex.videoUrl} className="w-full h-full object-cover" /> : <Plus size={18} />}
                                  </div>
                                  <div className="min-w-0">
                                      <h4 className="font-bold text-slate-800 text-sm truncate">{ex.name}</h4>
                                      <span className="text-[10px] text-slate-400 uppercase font-bold">{ex.category}</span>
                                  </div>
                              </button>
                          );
                      })}
                  </div>
                  <div className="p-4 border-t border-slate-100 bg-slate-50 flex justify-between items-center shrink-0">
                        <span className="text-slate-500 text-xs font-bold">{selectedExerciseIds.length} seleccionados</span>
                        <button disabled={selectedExerciseIds.length === 0} onClick={handleConfirmAddExercises} className="bg-primary-600 disabled:bg-slate-300 text-white px-6 py-2.5 rounded-xl font-bold text-sm shadow-md active:scale-95 transition-all">
                            Agregar
                        </button>
                  </div>
              </div>
          </div>
      )}

      {showRoutineEditor && (
          <div className="fixed inset-0 z-[110] bg-slate-100/95 backdrop-blur-md flex items-center justify-center p-4">
              <div className="bg-white w-full h-full max-h-[95vh] rounded-3xl shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95">
                  <div className="px-6 py-4 border-b border-slate-200 flex justify-between items-center bg-white shrink-0">
                      <div className="min-w-0">
                          <h2 className="text-xl md:text-2xl font-bold text-slate-900 truncate">Configurar Rutina</h2>
                      </div>
                      <div className="flex items-center gap-4 shrink-0">
                          <div className="hidden xs:flex flex-col items-center">
                              <span className="text-[8px] font-bold text-slate-400 uppercase mb-0.5">Días</span>
                              <div className="flex items-center bg-slate-100 rounded-lg p-0.5">
                                  <button onClick={() => handleUpdateDayCount(-1)} className="w-7 h-7 flex items-center justify-center bg-white rounded-md shadow-sm text-slate-600 font-bold">-</button>
                                  <span className="w-8 text-center font-bold text-sm">{patient.routine.days.length}</span>
                                  <button onClick={() => handleUpdateDayCount(1)} className="w-7 h-7 flex items-center justify-center bg-white rounded-md shadow-sm text-slate-600 font-bold">+</button>
                              </div>
                          </div>
                          <button onClick={() => setShowRoutineEditor(false)} className="p-2 bg-slate-100 rounded-full hover:bg-slate-200 transition-colors">
                             <X size={20} />
                          </button>
                      </div>
                  </div>
                  <div className="flex-1 overflow-x-auto overflow-y-hidden p-4 md:p-6 bg-slate-50">
                      <div className="flex gap-4 md:gap-6 h-full min-w-max pb-4">
                          {patient.routine.days.map((day, index) => (
                              <div key={day.id} className="w-64 md:w-80 flex flex-col bg-white rounded-2xl border border-slate-200 shadow-sm">
                                  <div className="p-3 border-b border-slate-100 flex justify-between items-center bg-slate-50/50 rounded-t-2xl shrink-0">
                                      <h3 className="font-bold text-sm md:text-base">Día {index + 1}</h3>
                                      <span className="text-[10px] font-bold bg-slate-200 text-slate-600 px-2 py-0.5 rounded">
                                          {day.exercises.length}
                                      </span>
                                  </div>
                                  <div className="flex-1 overflow-y-auto p-2.5 space-y-2 no-scrollbar">
                                      {day.exercises.map(ex => (
                                          <div key={ex.id} className="bg-white border border-slate-100 p-2.5 rounded-xl flex items-center gap-2 shadow-sm group">
                                              <div className="flex-1 min-w-0">
                                                  <div className="text-xs font-bold text-slate-800 truncate">{ex.definition.name}</div>
                                                  <div className="text-[10px] text-slate-400">{ex.targetSets}x{ex.targetReps} • {ex.targetLoad}kg</div>
                                              </div>
                                              <button onClick={() => handleRemoveExercise(day.id, ex.id)} className="text-slate-300 hover:text-red-500 transition-colors p-1 shrink-0">
                                                  <Trash2 size={14} />
                                              </button>
                                          </div>
                                      ))}
                                      {day.exercises.length === 0 && <div className="text-center py-10 text-slate-300 italic text-[10px]">Sin ejercicios</div>}
                                  </div>
                                  <div className="p-2.5 border-t border-slate-100 shrink-0">
                                      <button onClick={() => openAddModal(day.id)} className="w-full py-2.5 rounded-xl border-2 border-dashed border-slate-200 text-slate-500 font-bold hover:border-primary-300 hover:text-primary-600 hover:bg-primary-50 transition-all flex items-center justify-center gap-2 text-xs">
                                          <Plus size={14} />
                                          Agregar
                                      </button>
                                  </div>
                              </div>
                          ))}
                      </div>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { RoutineExercise } from '../types';
import { PlayCircle, CheckCircle, Circle, Minus, Plus, TrendingUp, Trash2, Maximize2, X } from 'lucide-react';

interface ExerciseCardProps {
  exercise: RoutineExercise;
  onUpdate: (id: string, updates: Partial<RoutineExercise>) => void;
  onShowHistory: (exercise: RoutineExercise) => void;
  onDelete: (id: string) => void;
}

export const ExerciseCard: React.FC<ExerciseCardProps> = ({
  exercise,
  onUpdate,
  onShowHistory,
  onDelete,
}) => {
  const { definition, targetSets, targetReps, targetLoad, currentRpe, isDone } = exercise;
  const [isZoomed, setIsZoomed] = useState(false);

  const adjustSets = (amount: number, e: React.MouseEvent) => {
    e.stopPropagation();
    const newSets = Math.max(1, targetSets + amount);
    onUpdate(exercise.id, { targetSets: newSets });
  };

  const adjustReps = (amount: number, e: React.MouseEvent) => {
    e.stopPropagation();
    const newReps = Math.max(1, targetReps + amount);
    onUpdate(exercise.id, { targetReps: newReps });
  };

  const adjustLoad = (amount: number, e: React.MouseEvent) => {
    e.stopPropagation();
    let newLoad = targetLoad + amount;
    newLoad = Math.round(newLoad * 100) / 100; 
    newLoad = Math.max(0, newLoad);
    onUpdate(exercise.id, { targetLoad: newLoad });
  };

  const handleLoadInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = parseFloat(e.target.value);
    onUpdate(exercise.id, { targetLoad: isNaN(val) ? 0 : val });
  };

  const toggleDone = () => {
    onUpdate(exercise.id, { isDone: !isDone });
  };

  return (
    <>
      <div
        className={`bg-white rounded-2xl p-4 md:p-5 shadow-sm border transition-all duration-300 relative group ${
          isDone ? 'border-slate-100 opacity-60 bg-slate-50' : 'border-slate-200 hover:shadow-md'
        }`}
      >
        <div className="flex items-start gap-3 md:gap-4">
          <button
            onClick={toggleDone}
            className={`shrink-0 mt-1 transition-colors ${
              isDone ? 'text-kine' : 'text-slate-300 hover:text-primary-400'
            }`}
          >
            {isDone ? <CheckCircle size={28} className="md:w-8 md:h-8" fill="currentColor" /> : <Circle size={28} className="md:w-8 md:h-8" />}
          </button>

          {/* Miniatura del GIF - Ahora siempre visible y responsive */}
          {definition.videoUrl && (
              <button 
                onClick={() => setIsZoomed(true)}
                className="w-14 h-14 sm:w-20 sm:h-20 md:w-24 md:h-24 bg-slate-100 rounded-xl overflow-hidden shrink-0 border border-slate-200 relative cursor-zoom-in active:scale-95 transition-transform"
              >
                  <img 
                    src={definition.videoUrl} 
                    alt={definition.name} 
                    className="w-full h-full object-cover" 
                    loading="lazy"
                  />
                  <div className="absolute inset-0 bg-black/5 flex items-center justify-center opacity-0 hover:opacity-100 transition-opacity">
                      <Maximize2 size={16} className="text-white drop-shadow-md" />
                  </div>
              </button>
          )}

          <div className="flex-1 space-y-3 md:space-y-4 min-w-0">
            <div className="flex justify-between items-start pr-6">
              <div className="min-w-0">
                <h4 className={`font-bold text-base md:text-lg leading-tight truncate ${isDone ? 'text-slate-500 line-through' : 'text-slate-900'}`}>
                  {definition.name}
                </h4>
                <span className="text-[10px] text-slate-400 uppercase font-bold tracking-wider">{definition.category}</span>
              </div>

              <button 
                  onClick={() => onShowHistory(exercise)}
                  className="p-1.5 text-primary-600 bg-primary-50 rounded-lg hover:bg-primary-100 shrink-0 ml-1"
              >
                  <TrendingUp size={18} />
              </button>
            </div>

            {/* Controles del Ejercicio */}
            <div className={`grid grid-cols-12 gap-3 md:gap-4 ${isDone ? 'pointer-events-none' : ''}`}>

              {/* Series x Reps */}
              <div className="col-span-12 sm:col-span-6 md:col-span-5 flex flex-col justify-center">
                <div className="text-[10px] text-slate-400 font-bold mb-1 uppercase">Series x Reps</div>
                <div className="flex items-center gap-1.5">
                  <div className="flex items-center bg-slate-100 rounded-lg p-0.5">
                      <button onClick={(e) => adjustSets(-1, e)} className="p-1 md:p-1.5 bg-white rounded-md shadow-sm active:scale-95 text-slate-600"><Minus size={12}/></button>
                      <span className="w-6 md:w-8 text-center font-bold text-base md:text-lg text-slate-800">{targetSets}</span>
                      <button onClick={(e) => adjustSets(1, e)} className="p-1 md:p-1.5 bg-white rounded-md shadow-sm active:scale-95 text-slate-600"><Plus size={12}/></button>
                  </div>
                  <span className="text-slate-300 text-xs">x</span>
                  <div className="flex items-center bg-slate-100 rounded-lg p-0.5">
                      <button onClick={(e) => adjustReps(-1, e)} className="p-1 md:p-1.5 bg-white rounded-md shadow-sm active:scale-95 text-slate-600"><Minus size={12}/></button>
                      <span className="w-7 md:w-9 text-center font-bold text-base md:text-lg text-slate-800">{targetReps}</span>
                      <button onClick={(e) => adjustReps(1, e)} className="p-1 md:p-1.5 bg-white rounded-md shadow-sm active:scale-95 text-slate-600"><Plus size={12}/></button>
                  </div>
                </div>
              </div>

              {/* Carga (KG) */}
