import React, { useState } from 'react';
import { RoutineExercise } from '../types';
import { CheckCircle, Circle, Minus, Plus, TrendingUp, Trash2, Maximize2, X } from 'lucide-react';

interface ExerciseCardProps {
  exercise: RoutineExercise;
  onUpdate: (id: string, updates: Partial<RoutineExercise>) => void;
  onShowHistory: (exercise: RoutineExercise) => void;
  onDelete: (id: string) => void;
}

export const ExerciseCard: React.FC<ExerciseCardProps> = ({
  exercise,
  onUpdate,
  onShowHistory,
  onDelete,
}) => {
  const { definition, targetSets, targetReps, targetLoad, currentRpe, isDone } = exercise;
  const [isZoomed, setIsZoomed] = useState(false);

  const adjustSets = (amount: number, e: React.MouseEvent) => {
    e.stopPropagation();
    onUpdate(exercise.id, { targetSets: Math.max(1, targetSets + amount) });
  };

  const adjustReps = (amount: number, e: React.MouseEvent) => {
    e.stopPropagation();
    onUpdate(exercise.id, { targetReps: Math.max(1, targetReps + amount) });
  };

  const adjustLoad = (amount: number, e: React.MouseEvent) => {
    e.stopPropagation();
    let newLoad = Math.max(0, Math.round((targetLoad + amount) * 100) / 100);
    onUpdate(exercise.id, { targetLoad: newLoad });
  };

  const toggleDone = () => onUpdate(exercise.id, { isDone: !isDone });

  return (
    <>
      <div className={`bg-white rounded-2xl p-4 md:p-5 shadow-sm border transition-all duration-300 relative ${
          isDone ? 'border-slate-100 opacity-60 bg-slate-50' : 'border-slate-200 hover:shadow-md'
      }`}>
        <div className="flex items-start gap-3">
          <button onClick={toggleDone} className={`shrink-0 mt-1 ${isDone ? 'text-kine' : 'text-slate-300'}`}>
            {isDone ? <CheckCircle size={28} fill="currentColor" /> : <Circle size={28} />}
          </button>

          {/* Miniatura GIF - Siempre visible */}
          {definition.videoUrl && (
            <button 
              onClick={() => setIsZoomed(true)}
              className="w-14 h-14 sm:w-20 sm:h-20 bg-slate-100 rounded-xl overflow-hidden shrink-0 border border-slate-200 relative group cursor-zoom-in"
            >
              <img src={definition.videoUrl} alt={definition.name} className="w-full h-full object-cover" />
              <div className="absolute inset-0 bg-black/10 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity">
                <Maximize2 size={16} className="text-white" />
              </div>
            </button>
          )}

          <div className="flex-1 min-w-0">
            <div className="flex justify-between items-start mb-3 pr-6">
              <div className="min-w-0">
                <h4 className={`font-bold text-base truncate ${isDone ? 'text-slate-500 line-through' : 'text-slate-900'}`}>
                  {definition.name}
                </h4>
                <p className="text-[10px] text-slate-400 uppercase font-bold tracking-wider">{definition.category}</p>
              </div>
              <button onClick={() => onShowHistory(exercise)} className="p-1.5 text-primary-600 bg-primary-50 rounded-lg shrink-0">
                <TrendingUp size={16} />
              </button>
            </div>

            {/* Controles Adaptables */}
            <div className="grid grid-cols-12 gap-y-3 gap-x-2">
              <div className="col-span-12 sm:col-span-6 flex flex-col justify-center">
                <p className="text-[9px] text-slate-400 font-bold uppercase mb-1">Series x Reps</p>
                <div className="flex items-center gap-1">
                  <div className="flex items-center bg-slate-100 rounded-lg p-0.5">
                    <button onClick={(e) => adjustSets(-1, e)} className="p-1 bg-white rounded shadow-sm"><Minus size={12}/></button>
                    <span className="w-6 text-center font-bold text-sm">{targetSets}</span>
                    <button onClick={(e) => adjustSets(1, e)} className="p-1 bg-white rounded shadow-sm"><Plus size={12}/></button>
                  </div>
                  <span className="text-slate-300 text-xs">x</span>
                  <div className="flex items-center bg-slate-100 rounded-lg p-0.5">
                    <button onClick={(e) => adjustReps(-1, e)} className="p-1 bg-white rounded shadow-sm"><Minus size={12}/></button>
                    <span className="w-7 text-center font-bold text-sm">{targetReps}</span>
                    <button onClick={(e) => adjustReps(1, e)} className="p-1 bg-white rounded shadow-sm"><Plus size={12}/></button>
                  </div>
                </div>
              </div>

              <div className="col-span-6 sm:col-span-3 border-l border-slate-100 pl-2">
                <p className="text-[9px] text-slate-400 font-bold uppercase mb-1">Carga (kg)</p>
                <div className="flex items-center bg-slate-100 rounded-lg p-0.5 w-full max-w-[100px]">
                  <button onClick={(e) => adjustLoad(-0.5, e)} className="p-1 bg-white rounded shadow-sm"><Minus size={12}/></button>
                  <input 
                    type="number" 
                    value={targetLoad} 
                    onChange={e => onUpdate(exercise.id, { targetLoad: parseFloat(e.target.value) || 0 })}
                    className="w-full text-center font-bold text-sm bg-transparent outline-none"
                  />
                  <button onClick={(e) => adjustLoad(0.5, e)} className="p-1 bg-white rounded shadow-sm"><Plus size={12}/></button>
                </div>
              </div>

              <div className="col-span-6 sm:col-span-3 border-l border-slate-100 pl-2">
                <p className="text-[9px] text-slate-400 font-bold uppercase mb-1">Esfuerzo</p>
                <select 
                  className="bg-slate-100 font-bold text-sm rounded-lg w-full p-1.5 outline-none"
                  value={currentRpe || ""}
                  onChange={e => onUpdate(exercise.id, { currentRpe: Number(e.target.value) })}
                >
                  <option value="">-</option>
                  {[...Array(10)].map((_, i) => <option key={i+1} value={i+1}>{i+1}</option>)}
                </select>
              </div>
            </div>
          </div>
        </div>

        <button onClick={() => onDelete(exercise.id)} className="absolute top-3 right-3 p-1.5 text-slate-200 hover:text-red-500 transition-colors">
          <Trash2 size={16} />
        </button>
      </div>

      {/* MODAL ZOOM - CIERRE AL TOCAR FUERA */}
      {isZoomed && definition.videoUrl && (
        <div 
          className="fixed inset-0 z-[200] bg-black/90 backdrop-blur-md flex items-center justify-center p-4 cursor-pointer"
          onClick={() => setIsZoomed(false)} // CIERRA AL TOCAR EL FONDO
        >
          <div 
            className="relative bg-white rounded-3xl overflow-hidden shadow-2xl max-w-2xl w-full animate-in zoom-in-95 cursor-default"
            onClick={e => e.stopPropagation()} // EVITA CIERRE AL TOCAR EL CONTENIDO
          >
            <button 
              onClick={() => setIsZoomed(false)} 
              className="absolute top-4 right-4 z-10 p-2 bg-black/10 hover:bg-black/20 rounded-full transition-colors"
            >
              <X size={24} />
            </button>
            <div className="aspect-video bg-slate-50 flex items-center justify-center">
              <img src={definition.videoUrl} alt={definition.name} className="max-w-full max-h-full object-contain" />
            </div>
            <div className="p-6">
              <h2 className="text-2xl font-bold text-slate-900">{definition.name}</h2>
              <p className="text-slate-500 uppercase font-bold text-xs tracking-widest mt-1">{definition.category}</p>
            </div>
          </div>
        </div>
      )}
    </>
  );
};

export enum Stage {
  KINESIOLOGY = 'Kinesiología',
  GYM = 'Gimnasio',
}

export enum UserRole {
  ADMIN = 'Recepción',
  KINE = 'Kinesiólogo',
  PATIENT = 'Paciente',
}

export interface ExerciseLog {
  date: string;
  load: number;
  reps: number;
  rpe: number;
}

export interface ExerciseDefinition {
  id: string;
  name: string;
  category: string;
  videoUrl?: string;
}

export interface RoutineExercise {
  id: string;
  definitionId: string;
  definition: ExerciseDefinition;
  targetSets: number;
  targetReps: number;
  targetLoad: number;
  currentRpe?: number;
  notes?: string;
  isDone: boolean;
  history: ExerciseLog[];
}

export interface RoutineDay {
  id: string;
  name: string;
  exercises: RoutineExercise[];
}

export interface Routine {
  id: string;
  stage: Stage;
  days: RoutineDay[];
}

export interface Patient {
  id: string;
  clinicId: string; // Para identificar a qué consultorio pertenece
  firstName: string;
  lastName: string;
  age: number;
  condition: string;
  photoUrl: string;
  lastVisit: string;
  routine: Routine;
  history: string[];
}

