import React, { useState } from 'react';
import { Patient, Stage } from '../types';
import { Search, Clock, ChevronRight, UserPlus, X, Settings2, Trash2, User } from 'lucide-react';

interface PatientListProps {
  patients: Patient[];
  clinicId: string;
  onSelectPatient: (patient: Patient) => void;
  onAddPatient: (patient: Patient) => void;
  onUpdatePatient: (patient: Patient) => void;
  onDeletePatient: (patientId: string) => void;
}

export const PatientList: React.FC<PatientListProps> = ({
  patients,
  clinicId,
  onSelectPatient,
  onAddPatient,
  onUpdatePatient,
  onDeletePatient
}) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [modalState, setModalState] = useState<{ show: boolean, editingPatient: Patient | null }>({
    show: false,
    editingPatient: null
  });

  const [formData, setFormData] = useState({
    firstName: '',
    lastName: '',
    condition: '',
    age: 30,
    stage: Stage.KINESIOLOGY
  });

  const filteredPatients = patients.filter((p) => {
    const fullName = `${p.firstName} ${p.lastName}`.toLowerCase();
    return fullName.includes(searchTerm.toLowerCase());
  });

  const recentPatients = patients.slice(0, 3);

  const openModal = (patient: Patient | null = null) => {
    if (patient) {
      setFormData({
        firstName: patient.firstName,
        lastName: patient.lastName,
        condition: patient.condition,
        age: patient.age,
        stage: patient.routine.stage
      });
      setModalState({ show: true, editingPatient: patient });
    } else {
      setFormData({
        firstName: '',
        lastName: '',
        condition: '',
        age: 30,
        stage: Stage.KINESIOLOGY
      });
      setModalState({ show: true, editingPatient: null });
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.firstName || !formData.lastName) return;

    if (modalState.editingPatient) {
      onUpdatePatient({
        ...modalState.editingPatient,
        firstName: formData.firstName,
        lastName: formData.lastName,
        age: formData.age,
        condition: formData.condition,
        routine: {
          ...modalState.editingPatient.routine,
          stage: formData.stage
        }
      });
    } else {
      // Fix: Construct newPatient with the required clinicId from props
      const newPatient: Patient = {
        id: `p-${Date.now()}`,
        clinicId: clinicId,
        firstName: formData.firstName,
        lastName: formData.lastName,
        age: formData.age,
        condition: formData.condition || 'Sin diagnóstico',
        photoUrl: `https://ui-avatars.com/api/?name=${formData.firstName}+${formData.lastName}&background=random`,
        lastVisit: new Date().toISOString().split('T')[0],
        history: [],
        routine: {
          id: `r-${Date.now()}`,
          stage: formData.stage,
          days: [
            { id: `d1-${Date.now()}`, name: 'Día 1', exercises: [] },
            { id: `d2-${Date.now()}`, name: 'Día 2', exercises: [] }
          ]
        }
      };
      onAddPatient(newPatient);
    }
    setModalState({ show: false, editingPatient: null });
  };

  const handleDelete = () => {
    if (!modalState.editingPatient) return;
    if (window.confirm(`¿Estás seguro de que deseas eliminar a ${modalState.editingPatient.firstName}?`)) {
      onDeletePatient(modalState.editingPatient.id);
      setModalState({ show: false, editingPatient: null });
    }
  };

  return (
    <div className="flex-1 h-screen overflow-y-auto bg-slate-50 p-4 md:p-8 relative">
      <div className="max-w-4xl mx-auto space-y-6 md:space-y-8">

        {/* Header & Search */}
        <div className="space-y-4">
          <div className="flex justify-between items-center gap-4">
            <h1 className="text-2xl md:text-3xl font-bold text-slate-900">Pacientes</h1>
            <button 
                onClick={() => openModal()}
                className="bg-primary-600 text-white px-4 py-2.5 md:px-5 md:py-3 rounded-xl font-bold flex items-center gap-2 shadow-lg hover:bg-primary-700 active:scale-95 transition-all text-sm"
            >
                <UserPlus size={18} />
                <span className="hidden xs:inline">Nuevo Paciente</span>
                <span className="xs:hidden">Nuevo</span>
            </button>
          </div>

          <div className="relative">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
            <input
              type="text"
              placeholder="Buscar paciente..."
              className="w-full h-14 md:h-16 pl-12 pr-6 rounded-2xl border-none shadow-sm text-base md:text-lg focus:ring-4 focus:ring-primary-100"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
        </div>

        {/* Recent Patients */}
        {!searchTerm && recentPatients.length > 0 && (
          <div className="space-y-3">
            <div className="flex items-center gap-2 text-slate-500 font-semibold uppercase text-[10px] tracking-wider">
              <Clock size={14} />
              <span>Recientes</span>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-3 md:gap-4">
              {recentPatients.map((patient) => (
                <button
                  key={patient.id}
                  onClick={() => onSelectPatient(patient)}
                  className="bg-white p-3 md:p-4 rounded-xl shadow-sm border border-slate-100 flex items-center gap-3 hover:shadow-md transition-shadow text-left"
                >
                  <img
                    src={patient.photoUrl}
                    alt={patient.firstName}
                    className="w-10 h-10 md:w-14 md:h-14 rounded-full object-cover"
                  />
                  <div className="flex-1 min-w-0">
                    <h3 className="font-bold text-slate-800 text-base md:text-lg truncate">
                      {patient.firstName}
                    </h3>
                    <p className="text-slate-500 text-xs truncate">{patient.condition}</p>
                  </div>
                </button>
              ))}
            </div>
          </div>
        )}

        {/* All Patients List */}
        <div className="space-y-3 pb-20">
          <div className="flex items-center gap-2 text-slate-500 font-semibold uppercase text-[10px] tracking-wider">
            <User size={14} />
            <span>Todos los pacientes</span>
          </div>

          <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
            {filteredPatients.length > 0 ? (
              filteredPatients.map((patient, index) => (
                <div
                  key={patient.id}
                  className={`flex items-center p-4 md:p-5 cursor-pointer hover:bg-slate-50 transition-colors group ${
                    index !== filteredPatients.length - 1 ? 'border-b border-slate-100' : ''
                  }`}
                  onClick={() => onSelectPatient(patient)}
                >
                  <img
                    src={patient.photoUrl}
                    alt={patient.firstName}
                    className="w-10 h-10 md:w-12 md:h-12 rounded-full object-cover mr-4"
                  />
                  <div className="flex-1 min-w-0">
                    <h3 className="font-bold text-slate-800 text-base md:text-lg truncate">
                      {patient.firstName} {patient.lastName}
                    </h3>
                    <div className="flex items-center gap-2 mt-0.5">
                        <span className={`px-2 py-0.5 rounded-full text-[10px] font-bold ${
                            patient.routine.stage === Stage.KINESIOLOGY ? 'bg-kine/10 text-kine' : 'bg-gym/10 text-gym'
                        }`}>
                            {patient.routine.stage}
                        </span>
                        <span className="text-slate-400 text-xs truncate">• {patient.condition}</span>
                    </div>
                  </div>

                  <div className="flex items-center gap-1 md:gap-2">
                    <button 
                      onClick={(e) => {
                        e.stopPropagation();
                        openModal(patient);
                      }}
                      className="p-2 md:p-3 text-slate-400 hover:text-primary-600 hover:bg-primary-50 rounded-xl transition-all"
                    >
                      <Settings2 size={18} />
                    </button>
                    <ChevronRight className="text-slate-300" size={20} />
                  </div>
                </div>
              ))
            ) : (
              <div className="p-10 text-center text-slate-400 italic">
                No se encontraron pacientes
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Patient Modal (Improved for Landscape/Mobile) */}
      {modalState.show && (
        <div className="fixed inset-0 z-[100] bg-black/50 backdrop-blur-sm flex items-center justify-center p-4 overflow-hidden">
             <div className="bg-white w-full max-w-md rounded-2xl shadow-2xl animate-in zoom-in-95 flex flex-col max-h-[90vh]">
                 <div className="flex justify-between items-center p-5 border-b border-slate-100 shrink-0">
                     <h2 className="text-xl font-bold text-slate-900">
                        {modalState.editingPatient ? 'Editar Perfil' : 'Nuevo Paciente'}
                     </h2>
                     <button onClick={() => setModalState({ show: false, editingPatient: null })} className="p-2 bg-slate-100 rounded-full hover:bg-slate-200 transition-colors">
                         <X size={18} />
                     </button>
                 </div>

                 <form onSubmit={handleSubmit} className="p-5 space-y-4 overflow-y-auto no-scrollbar">
                     <div className="grid grid-cols-2 gap-3">
                         <div>
                             <label className="block text-[10px] font-bold text-slate-500 mb-1 uppercase tracking-wider">Nombre</label>
                             <input 
                                type="text" 
                                className="w-full p-2.5 bg-slate-50 rounded-xl border border-slate-200 focus:ring-2 focus:ring-primary-500 outline-none"
                                placeholder="Ej: Ana"
                                required
                                value={formData.firstName}
                                onChange={e => setFormData({...formData, firstName: e.target.value})}
                             />
                         </div>
                         <div>
                             <label className="block text-[10px] font-bold text-slate-500 mb-1 uppercase tracking-wider">Apellido</label>
                             <input 
                                type="text" 
                                className="w-full p-2.5 bg-slate-50 rounded-xl border border-slate-200 focus:ring-2 focus:ring-primary-500 outline-none"
                                placeholder="Ej: Garcia"
                                required
                                value={formData.lastName}
                                onChange={e => setFormData({...formData, lastName: e.target.value})}
                             />
                         </div>
                     </div>

                     <div className="grid grid-cols-3 gap-3">
                        <div className="col-span-1">
                            <label className="block text-[10px] font-bold text-slate-500 mb-1 uppercase tracking-wider">Edad</label>
                            <input 
                                type="number" 
                                className="w-full p-2.5 bg-slate-50 rounded-xl border border-slate-200 focus:ring-2 focus:ring-primary-500 outline-none"
                                value={formData.age}
                                onChange={e => setFormData({...formData, age: parseInt(e.target.value)})}
                            />
                        </div>
                        <div className="col-span-2">
                            <label className="block text-[10px] font-bold text-slate-500 mb-1 uppercase tracking-wider">Diagnóstico</label>
                            <input 
                                type="text" 
                                className="w-full p-2.5 bg-slate-50 rounded-xl border border-slate-200 focus:ring-2 focus:ring-primary-500 outline-none"
                                placeholder="Ej: Esguince Tobillo"
                                value={formData.condition}
                                onChange={e => setFormData({...formData, condition: e.target.value})}
                             />
                        </div>
                     </div>

                     <div>
                         <label className="block text-[10px] font-bold text-slate-500 mb-1 uppercase tracking-wider">Etapa</label>
                         <div className="flex gap-2">
                             {[Stage.KINESIOLOGY, Stage.GYM].map(stage => (
                                 <button
                                    key={stage}
                                    type="button"
                                    onClick={() => setFormData({...formData, stage})}
                                    className={`flex-1 py-2.5 rounded-xl border font-bold text-xs transition-all ${
                                        formData.stage === stage 
                                        ? 'bg-primary-50 border-primary-500 text-primary-700' 
                                        : 'bg-white border-slate-200 text-slate-400'
                                    }`}
                                 >
                                     {stage}
                                 </button>
                             ))}
                         </div>
                     </div>

                     <div className="pt-4 space-y-3">
                        <button 
                            type="submit"
                            className="w-full bg-primary-600 text-white font-bold py-3.5 rounded-xl shadow-lg hover:bg-primary-700 active:scale-95 transition-all text-sm"
                        >
                            {modalState.editingPatient ? 'Guardar Cambios' : 'Crear Paciente'}
                        </button>

                        {modalState.editingPatient && (
                            <button 
                                type="button"
                                onClick={handleDelete}
                                className="w-full flex items-center justify-center gap-2 text-red-500 font-bold py-2 rounded-xl hover:bg-red-50 transition-all text-sm"
                            >
                                <Trash2 size={16} />
                                Eliminar Paciente
                            </button>
                        )}
                     </div>
                 </form>
             </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Sidebar } from './components/Sidebar';
import { PatientList } from './components/PatientList';
import { PatientDetail } from './components/PatientDetail';
import { MOCK_PATIENTS } from './constants';
import { Patient, ViewState, UserRole } from './types';
import { db, isConfigValid } from './firebase';
import { 
  collection, 
  onSnapshot, 
  doc, 
  setDoc, 
  updateDoc,
  deleteDoc,
  query,
  where
} from 'firebase/firestore';
import { Loader2, AlertTriangle, X, Wifi, CloudOff, Download, ShieldCheck, Building2 } from 'lucide-react';

const App: React.FC = () => {
  const [patients, setPatients] = useState<Patient[]>([]);
  const [loading, setLoading] = useState(true);
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [isSyncing, setIsSyncing] = useState(false);
  const [activePatientIds, setActivePatientIds] = useState<string[]>([]);
  const [selectedPatientId, setSelectedPatientId] = useState<string | null>(null);

  // Multi-tenant States
  const [view, setView] = useState<ViewState>('GATEWAY');
  const [currentRole, setCurrentRole] = useState<UserRole>(UserRole.KINE);
  const [currentClinicId, setCurrentClinicId] = useState<string>('clinic_1');

  const [dbError, setDbError] = useState<string | null>(null);
  const [installPrompt, setInstallPrompt] = useState<any>(null);

  useEffect(() => {
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);
    const handleBeforeInstall = (e: any) => {
        e.preventDefault();
        setInstallPrompt(e);
    };
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    window.addEventListener('beforeinstallprompt', handleBeforeInstall);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
      window.removeEventListener('beforeinstallprompt', handleBeforeInstall);
    };
  }, []);

  useEffect(() => {
    if (view === 'GATEWAY') return;

    if (!isConfigValid || !db) {
      // Filter mock patients by clinic
      const filteredMocks = MOCK_PATIENTS.map(p => ({ ...p, clinicId: p.id === 'p1' ? 'clinic_1' : 'clinic_2' }))
                                        .filter(p => p.clinicId === currentClinicId);
      setPatients(filteredMocks);
      setLoading(false);
      return;
    }

    // Filtrar por clínica en la query de Firestore
    const q = query(collection(db, 'patients'), where('clinicId', '==', currentClinicId));

    const unsubscribe = onSnapshot(q, (snapshot) => {
      const patientsData: Patient[] = [];
      snapshot.forEach((doc) => {
        patientsData.push(doc.data() as Patient);
      });

      setPatients(patientsData);
      setLoading(false);
      setDbError(null);
    }, (error) => {
      setDbError(`Error de conexión: ${error.message}`);
      setLoading(false);
    });

    return () => unsubscribe();
  }, [currentClinicId, view]);

  const handleSelectPatient = (patient: Patient) => {
    if (!activePatientIds.includes(patient.id)) {
      setActivePatientIds(prev => [patient.id, ...prev]);
    }
    setSelectedPatientId(patient.id);
    setView('PATIENT_DETAIL');
  };

  const handleUpdatePatient = async (updatedPatient: Patient) => {
      if (isConfigValid && db) {
          setIsSyncing(true);
          try {
              await updateDoc(doc(db, 'patients', updatedPatient.id), { ...updatedPatient });
          } catch (e: any) {
              setDbError(`Error al actualizar: ${e.message}`);
          } finally {
              setIsSyncing(false);
          }
      }
      setPatients(prev => prev.map(p => p.id === updatedPatient.id ? updatedPatient : p));
  };

  const handleGoHome = () => {
    if (currentRole === UserRole.PATIENT) return;
    setView('HOME');
    setSelectedPatientId(null);
  };

  if (view === 'GATEWAY') {
      return (
          <div className="h-[100dvh] w-full flex items-center justify-center bg-slate-900 p-6 overflow-hidden">
              <div className="w-full max-w-md space-y-8 animate-in fade-in zoom-in-95 duration-500">
                  <div className="text-center space-y-2">
                      <div className="inline-flex p-4 bg-primary-600 rounded-3xl shadow-2xl shadow-primary-500/20 mb-4">
                          <Building2 className="text-white" size={40} />
                      </div>
                      <h1 className="text-4xl font-black text-white tracking-tight">KineFlow <span className="text-primary-500">Pro</span></h1>
                      <p className="text-slate-400 font-medium">Selecciona tu consultorio y perfil</p>
                  </div>

                  <div className="bg-white/10 backdrop-blur-xl p-8 rounded-[2.5rem] border border-white/10 space-y-6">
                      <div className="space-y-4">
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Consultorio</label>
                          <div className="grid grid-cols-2 gap-3">
                              <button 
                                onClick={() => setCurrentClinicId('clinic_1')}
                                className={`py-4 rounded-2xl font-bold transition-all border-2 ${currentClinicId === 'clinic_1' ? 'bg-primary-600 border-primary-500 text-white' : 'bg-white/5 border-transparent text-slate-300 hover:bg-white/10'}`}
                              >
                                Sport Center
                              </button>
                              <button 
                                onClick={() => setCurrentClinicId('clinic_2')}
                                className={`py-4 rounded-2xl font-bold transition-all border-2 ${currentClinicId === 'clinic_2' ? 'bg-primary-600 border-primary-500 text-white' : 'bg-white/5 border-transparent text-slate-300 hover:bg-white/10'}`}
                              >
                                Kine Salud
                              </button>
                          </div>
                      </div>

                      <div className="space-y-4">
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Tu Rol</label>
                          <div className="space-y-2">
                              {[UserRole.ADMIN, UserRole.KINE, UserRole.PATIENT].map(role => (
                                  <button 
                                    key={role}
                                    onClick={() => setCurrentRole(role)}
                                    className={`w-full py-4 px-6 rounded-2xl font-bold flex items-center justify-between transition-all border-2 ${currentRole === role ? 'bg-white border-white text-slate-900 shadow-xl' : 'bg-white/5 border-transparent text-slate-400 hover:bg-white/10'}`}
                                  >
                                    {role}
                                    {currentRole === role && <ShieldCheck size={20} className="text-primary-600" />}
                                  </button>
                              ))}
                          </div>
                      </div>

                      <button 
                        onClick={() => {
                            if (currentRole === UserRole.PATIENT) {
                                // For simulation, select the first patient of the clinic
                                const patient = MOCK_PATIENTS.find(p => p.id === (currentClinicId === 'clinic_1' ? 'p1' : 'p2'));
                                if (patient) handleSelectPatient(patient);
                                else setView('HOME');
                            } else {
                                setView('HOME');
                            }
                        }}
                        className="w-full bg-primary-600 hover:bg-primary-500 text-white py-5 rounded-2xl font-black text-lg shadow-2xl shadow-primary-600/30 transition-all active:scale-95 mt-4"
                      >
                          Ingresar al Sistema
                      </button>
                  </div>

                  <p className="text-center text-slate-500 text-xs font-medium">
                      Multi-tenant Architecture Ready • v1.0.4
                  </p>
              </div>
          </div>
      );
  }

  const activePatients = activePatientIds
    .map(id => patients.find(p => p.id === id))
    .filter((p): p is Patient => !!p);

  const currentPatient = patients.find(p => p.id === selectedPatientId);

  return (
    <div className="flex w-full h-[100dvh] bg-slate-50 font-sans text-slate-900 overflow-hidden">

      {currentRole !== UserRole.PATIENT && (
        <div className="flex shrink-0">
            <Sidebar 
                activePatients={activePatients}
                selectedPatientId={selectedPatientId}
                onSelectPatient={(id) => { setSelectedPatientId(id); setView('PATIENT_DETAIL'); }}
                onRemoveActive={(id, e) => {
                    e.stopPropagation();
                    setActivePatientIds(prev => prev.filter(p => p !== id));
                    if (selectedPatientId === id) { setSelectedPatientId(null); setView('HOME'); }
                }}
                onGoHome={handleGoHome}
            />
        </div>
      )}

      <div className="flex-1 flex flex-col h-full overflow-hidden">
        {view === 'HOME' && (
            <PatientList 
                patients={patients} 
                clinicId={currentClinicId}
                onSelectPatient={handleSelectPatient} 
                onAddPatient={(p) => setPatients([...patients, { ...p, clinicId: currentClinicId }])}
                onUpdatePatient={handleUpdatePatient}
                onDeletePatient={(id) => setPatients(patients.filter(p => p.id !== id))}
            />
        )}

        {view === 'PATIENT_DETAIL' && currentPatient && (
            <PatientDetail 
                patient={currentPatient}
                role={currentRole}
                onUpdatePatient={handleUpdatePatient}
            />
        )}
      </div>

      {/* Role Badge */}
      <div className="fixed top-4 right-4 z-[150] bg-slate-900/80 backdrop-blur-md text-white px-3 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest flex items-center gap-2 border border-white/10 shadow-xl">
          <div className="w-2 h-2 rounded-full bg-primary-500 animate-pulse"></div>
          {currentRole} • {currentClinicId === 'clinic_1' ? 'Sport Center' : 'Kine Salud'}
          <button onClick={() => setView('GATEWAY')} className="ml-2 hover:text-primary-400">
              <X size={12} />
          </button>
      </div>
    </div>
  );
};

