import React, { useState } from 'react';
import { Patient, Stage } from '../types';
import { Search, Clock, ChevronRight, UserPlus, X, Settings2, Trash2, User } from 'lucide-react';

interface PatientListProps {
  patients: Patient[];
  onSelectPatient: (patient: Patient) => void;
  onAddPatient: (patient: Patient) => void;
  onUpdatePatient: (patient: Patient) => void;
  onDeletePatient: (patientId: string) => void;
}

export const PatientList: React.FC<PatientListProps> = ({
  patients,
  onSelectPatient,
  onAddPatient,
  onUpdatePatient,
  onDeletePatient
}) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [modalState, setModalState] = useState<{ show: boolean, editingPatient: Patient | null }>({
    show: false,
    editingPatient: null
  });

  const [formData, setFormData] = useState({
    firstName: '',
    lastName: '',
    condition: '',
    age: 30,
    stage: Stage.KINESIOLOGY
  });

  const filteredPatients = patients.filter((p) => {
    const fullName = `${p.firstName} ${p.lastName}`.toLowerCase();
    return fullName.includes(searchTerm.toLowerCase());
  });

  const openModal = (patient: Patient | null = null) => {
    if (patient) {
      setFormData({
        firstName: patient.firstName,
        lastName: patient.lastName,
        condition: patient.condition,
        age: patient.age,
        stage: patient.routine.stage
      });
      setModalState({ show: true, editingPatient: patient });
    } else {
      setFormData({ firstName: '', lastName: '', condition: '', age: 30, stage: Stage.KINESIOLOGY });
      setModalState({ show: true, editingPatient: null });
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.firstName || !formData.lastName) return;

    if (modalState.editingPatient) {
      onUpdatePatient({
        ...modalState.editingPatient,
        firstName: formData.firstName,
        lastName: formData.lastName,
        age: formData.age,
        condition: formData.condition,
        routine: { ...modalState.editingPatient.routine, stage: formData.stage }
      });
    } else {
      const newPatient: Patient = {
        id: `p-${Date.now()}`,
        firstName: formData.firstName,
        lastName: formData.lastName,
        age: formData.age,
        condition: formData.condition || 'Sin diagnóstico',
        photoUrl: `https://ui-avatars.com/api/?name=${formData.firstName}+${formData.lastName}&background=random`,
        lastVisit: new Date().toISOString().split('T')[0],
        history: [],
        routine: {
          id: `r-${Date.now()}`,
          stage: formData.stage,
          days: [{ id: `d1-${Date.now()}`, name: 'Día 1', exercises: [] }]
        }
      };
      onAddPatient(newPatient);
    }
    setModalState({ show: false, editingPatient: null });
  };

  const handleDelete = () => {
    if (!modalState.editingPatient) return;
    if (window.confirm(`¿Estás seguro de que deseas eliminar a ${modalState.editingPatient.firstName}?`)) {
      onDeletePatient(modalState.editingPatient.id);
      setModalState({ show: false, editingPatient: null });
    }
  };

  return (
    <div className="flex-1 h-screen overflow-y-auto bg-slate-50 p-4 md:p-8 relative">
      <div className="max-w-4xl mx-auto space-y-6 md:space-y-8">
        <div className="space-y-4">
          <div className="flex justify-between items-center gap-4">
            <h1 className="text-2xl md:text-3xl font-bold text-slate-900">Pacientes</h1>
            <button onClick={() => openModal()} className="bg-primary-600 text-white px-4 py-2.5 rounded-xl font-bold flex items-center gap-2 shadow-lg hover:bg-primary-700 active:scale-95 transition-all text-sm">
                <UserPlus size={18} />
                <span>Nuevo Paciente</span>
            </button>
          </div>
          <div className="relative">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
            <input
              type="text"
              placeholder="Buscar paciente..."
              className="w-full h-14 pl-12 pr-6 rounded-2xl border-none shadow-sm text-base focus:ring-4 focus:ring-primary-100"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
        </div>

        <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
          {filteredPatients.map((patient, index) => (
            <div key={patient.id} className={`flex items-center p-4 cursor-pointer hover:bg-slate-50 transition-colors ${index !== filteredPatients.length - 1 ? 'border-b border-slate-100' : ''}`} onClick={() => onSelectPatient(patient)}>
              <img src={patient.photoUrl} className="w-10 h-10 rounded-full object-cover mr-4" />
              <div className="flex-1 min-w-0">
                <h3 className="font-bold text-slate-800 truncate">{patient.firstName} {patient.lastName}</h3>
                <p className="text-slate-400 text-xs truncate">{patient.condition}</p>
              </div>
              <div className="flex items-center gap-2">
                <button onClick={(e) => { e.stopPropagation(); openModal(patient); }} className="p-2 text-slate-400 hover:text-primary-600"><Settings2 size={18} /></button>
                <ChevronRight className="text-slate-300" size={20} />
              </div>
            </div>
          ))}
        </div>
      </div>

      {modalState.show && (
        <div className="fixed inset-0 z-[100] bg-black/50 flex items-center justify-center p-4">
             <div className="bg-white w-full max-w-md rounded-2xl p-6 space-y-4">
                 <div className="flex justify-between items-center">
                     <h2 className="text-xl font-bold">{modalState.editingPatient ? 'Editar' : 'Nuevo'}</h2>
                     <button onClick={() => setModalState({ show: false, editingPatient: null })}><X size={20} /></button>
                 </div>
                 <form onSubmit={handleSubmit} className="space-y-4">
                     <input type="text" placeholder="Nombre" required className="w-full p-3 bg-slate-50 rounded-xl" value={formData.firstName} onChange={e => setFormData({...formData, firstName: e.target.value})} />
                     <input type="text" placeholder="Apellido" required className="w-full p-3 bg-slate-50 rounded-xl" value={formData.lastName} onChange={e => setFormData({...formData, lastName: e.target.value})} />
                     <input type="text" placeholder="Diagnóstico" className="w-full p-3 bg-slate-50 rounded-xl" value={formData.condition} onChange={e => setFormData({...formData, condition: e.target.value})} />
                     <button type="submit" className="w-full bg-primary-600 text-white font-bold py-3 rounded-xl">Guardar</button>
                     {modalState.editingPatient && <button type="button" onClick={handleDelete} className="w-full text-red-500 font-bold py-2">Eliminar</button>}
                 </form>
             </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Sidebar } from './components/Sidebar';
import { PatientList } from './components/PatientList';
import { PatientDetail } from './components/PatientDetail';
import { MOCK_PATIENTS } from './constants';
import { Patient, ViewState, UserRole } from './types';
import { db, isConfigValid } from './firebase';
import { 
  collection, 
  onSnapshot, 
  doc, 
  updateDoc,
  query
} from 'firebase/firestore';
import { X } from 'lucide-react';

const App: React.FC = () => {
  const [patients, setPatients] = useState<Patient[]>([]);
  const [loading, setLoading] = useState(true);
  const [activePatientIds, setActivePatientIds] = useState<string[]>([]);
  const [selectedPatientId, setSelectedPatientId] = useState<string | null>(null);
  const [view, setView] = useState<ViewState>('HOME');
  const [currentRole, setCurrentRole] = useState<UserRole>(UserRole.KINE);

  useEffect(() => {
    if (!isConfigValid || !db) {
      setPatients(MOCK_PATIENTS);
      setLoading(false);
      return;
    }

    const q = query(collection(db, 'patients'));
    const unsubscribe = onSnapshot(q, (snapshot) => {
      const patientsData: Patient[] = [];
      snapshot.forEach((doc) => {
        patientsData.push(doc.data() as Patient);
      });
      setPatients(patientsData.length > 0 ? patientsData : MOCK_PATIENTS);
      setLoading(false);
    }, () => {
      setPatients(MOCK_PATIENTS);
      setLoading(false);
    });

    return () => unsubscribe();
  }, []);

  const handleSelectPatient = (patient: Patient) => {
    if (!activePatientIds.includes(patient.id)) {
      setActivePatientIds(prev => [patient.id, ...prev]);
    }
    setSelectedPatientId(patient.id);
    setView('PATIENT_DETAIL');
  };

  const handleUpdatePatient = async (updatedPatient: Patient) => {
      if (isConfigValid && db) {
          try {
              await updateDoc(doc(db, 'patients', updatedPatient.id), { ...updatedPatient });
          } catch (e) {}
      }
      setPatients(prev => prev.map(p => p.id === updatedPatient.id ? updatedPatient : p));
  };

  const handleGoHome = () => {
    setView('HOME');
    setSelectedPatientId(null);
  };

  const activePatients = activePatientIds
    .map(id => patients.find(p => p.id === id))
    .filter((p): p is Patient => !!p);

  const currentPatient = patients.find(p => p.id === selectedPatientId);

  return (
    <div className="flex w-full h-[100dvh] bg-slate-50 font-sans text-slate-900 overflow-hidden">
      <Sidebar 
          activePatients={activePatients}
          selectedPatientId={selectedPatientId}
          onSelectPatient={(id) => { setSelectedPatientId(id); setView('PATIENT_DETAIL'); }}
          onRemoveActive={(id, e) => {
              e.stopPropagation();
              setActivePatientIds(prev => prev.filter(p => p !== id));
              if (selectedPatientId === id) { setSelectedPatientId(null); setView('HOME'); }
          }}
          onGoHome={handleGoHome}
      />

      <div className="flex-1 flex flex-col h-full overflow-hidden">
        {view === 'HOME' ? (
            <PatientList 
                patients={patients} 
                onSelectPatient={handleSelectPatient} 
                onAddPatient={(p) => setPatients([...patients, p])}
                onUpdatePatient={handleUpdatePatient}
                onDeletePatient={(id) => setPatients(patients.filter(p => p.id !== id))}
            />
        ) : currentPatient && (
            <PatientDetail 
                patient={currentPatient}
                role={currentRole}
                onUpdatePatient={handleUpdatePatient}
            />
        )}
      </div>

      {/* Role Switcher para pruebas rápidas */}
      <div className="fixed bottom-4 right-4 z-[150] bg-slate-900 text-white px-3 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest flex items-center gap-2 border border-white/10 shadow-xl">
          <select 
            className="bg-transparent outline-none cursor-pointer"
            value={currentRole}
            onChange={(e) => setCurrentRole(e.target.value as UserRole)}
          >
              <option value={UserRole.KINE} className="text-black">Kinesiólogo</option>
              <option value={UserRole.ADMIN} className="text-black">Recepción</option>
              <option value={UserRole.PATIENT} className="text-black">Paciente</option>
          </select>
      </div>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { RoutineExercise, UserRole } from '../types';
import { CheckCircle, Circle, Minus, Plus, TrendingUp, Trash2, Maximize2, X } from 'lucide-react';

interface ExerciseCardProps {
  exercise: RoutineExercise;
  role: UserRole;
  onUpdate: (id: string, updates: Partial<RoutineExercise>) => void;
  onShowHistory: (exercise: RoutineExercise) => void;
  onDelete: (id: string) => void;
}

export const ExerciseCard: React.FC<ExerciseCardProps> = ({
  exercise,
  role,
  onUpdate,
  onShowHistory,
  onDelete,
}) => {
  const { definition, targetSets, targetReps, targetLoad, currentRpe, isDone } = exercise;
  const [isZoomed, setIsZoomed] = useState(false);

  const isReadOnly = role === UserRole.PATIENT || role === UserRole.ADMIN;

  // Función para calcular el color según el esfuerzo (1 verde -> 10 rojo)
  const getRpeStyle = (rpe: number | undefined) => {
    if (!rpe) return { backgroundColor: '#f1f5f9', color: '#94a3b8', borderColor: '#e2e8f0' };

    // Mapeo de 1 (120 - Verde) a 10 (0 - Rojo)
    const hue = Math.max(0, 120 - (rpe - 1) * (120 / 9));
    return {
      backgroundColor: `hsl(${hue}, 85%, 94%)`,
      color: `hsl(${hue}, 90%, 25%)`,
      borderColor: `hsl(${hue}, 70%, 80%)`,
    };
  };

  const rpeStyle = getRpeStyle(currentRpe);

  const adjustSets = (amount: number, e: React.MouseEvent) => {
    if (isReadOnly) return;
    e.stopPropagation();
    onUpdate(exercise.id, { targetSets: Math.max(1, targetSets + amount) });
  };

  const adjustReps = (amount: number, e: React.MouseEvent) => {
    if (isReadOnly) return;
    e.stopPropagation();
    onUpdate(exercise.id, { targetReps: Math.max(1, targetReps + amount) });
  };

  const adjustLoad = (amount: number, e: React.MouseEvent) => {
    if (isReadOnly) return;
    e.stopPropagation();
    let newLoad = Math.max(0, Math.round((targetLoad + amount) * 100) / 100);
    onUpdate(exercise.id, { targetLoad: newLoad });
  };

  const toggleDone = () => onUpdate(exercise.id, { isDone: !isDone });

  return (
    <>
      <div className={`bg-white rounded-2xl p-4 shadow-sm border transition-all duration-300 relative ${
          isDone ? 'border-slate-100 opacity-60 bg-slate-50' : 'border-slate-200 hover:shadow-md'
      }`}>
        <div className="flex items-start gap-3">
          <button 
            onClick={toggleDone} 
            disabled={role === UserRole.ADMIN}
            className={`shrink-0 mt-1 ${isDone ? 'text-kine' : 'text-slate-300'} ${role === UserRole.ADMIN ? 'opacity-50' : ''}`}
          >
            {isDone ? <CheckCircle size={28} fill="currentColor" /> : <Circle size={28} />}
          </button>

          {definition.videoUrl && (
            <button 
              onClick={() => setIsZoomed(true)}
              className="w-16 h-16 sm:w-20 sm:h-20 bg-slate-100 rounded-xl overflow-hidden shrink-0 border border-slate-200 relative group cursor-zoom-in block"
            >
              <img 
                src={definition.videoUrl} 
                alt={definition.name} 
                className="w-full h-full object-cover block"
                style={{ display: 'block' }} 
              />
              <div className="absolute inset-0 bg-black/10 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity">
                <Maximize2 size={16} className="text-white" />
              </div>
            </button>
          )}

          <div className="flex-1 min-w-0">
            <div className="flex justify-between items-start mb-2 pr-6">
              <div className="min-w-0">
                <h4 className={`font-bold text-base truncate ${isDone ? 'text-slate-500 line-through' : 'text-slate-900'}`}>
                  {definition.name}
                </h4>
                <p className="text-[10px] text-slate-400 uppercase font-bold tracking-wider">{definition.category}</p>
              </div>
              {role === UserRole.KINE && (
                <button onClick={() => onShowHistory(exercise)} className="p-1.5 text-primary-600 bg-primary-50 rounded-lg shrink-0">
                  <TrendingUp size={16} />
                </button>
              )}
            </div>

            <div className="grid grid-cols-12 gap-y-3 gap-x-2">
              <div className="col-span-12 sm:col-span-6 flex flex-col justify-center">
                <p className="text-[9px] text-slate-400 font-bold uppercase mb-1">Series x Reps</p>
                <div className="flex items-center gap-1">
                  <div className={`flex items-center rounded-lg p-0.5 ${isReadOnly ? 'bg-slate-50' : 'bg-slate-100'}`}>
                    {!isReadOnly && <button onClick={(e) => adjustSets(-1, e)} className="p-1 bg-white rounded shadow-sm"><Minus size={12}/></button>}
                    <span className="w-8 text-center font-bold text-sm">{targetSets}</span>
                    {!isReadOnly && <button onClick={(e) => adjustSets(1, e)} className="p-1 bg-white rounded shadow-sm"><Plus size={12}/></button>}
                  </div>
                  <span className="text-slate-300 text-xs">x</span>
                  <div className={`flex items-center rounded-lg p-0.5 ${isReadOnly ? 'bg-slate-50' : 'bg-slate-100'}`}>
                    {!isReadOnly && <button onClick={(e) => adjustReps(-1, e)} className="p-1 bg-white rounded shadow-sm"><Minus size={12}/></button>}
                    <span className="w-9 text-center font-bold text-sm">{targetReps}</span>
                    {!isReadOnly && <button onClick={(e) => adjustReps(1, e)} className="p-1 bg-white rounded shadow-sm"><Plus size={12}/></button>}
                  </div>
                </div>
              </div>

              <div className="col-span-6 sm:col-span-3 border-l border-slate-100 pl-2">
                <p className="text-[9px] text-slate-400 font-bold uppercase mb-1">Carga (kg)</p>
                <div className={`flex items-center rounded-lg p-0.5 w-full max-w-[100px] ${isReadOnly ? 'bg-slate-50' : 'bg-slate-100'}`}>
                  {!isReadOnly && <button onClick={(e) => adjustLoad(-0.5, e)} className="p-1 bg-white rounded shadow-sm"><Minus size={12}/></button>}
                  <span className="w-full text-center font-bold text-sm">{targetLoad}</span>
                  {!isReadOnly && <button onClick={(e) => adjustLoad(0.5, e)} className="p-1 bg-white rounded shadow-sm"><Plus size={12}/></button>}
