/**
 * Calcula el color dinámico para la escala RPE (1-10)
 * 1 = Verde (120°), 10 = Rojo (0°)
 */
export const getRpeStyle = (rpe: number | undefined) => {
  if (!rpe) return { backgroundColor: '#f1f5f9', color: '#94a3b8', borderColor: '#e2e8f0' };

  // Mapeo de 1 (120 - Verde) a 10 (0 - Rojo)
  const hue = Math.max(0, 120 - (rpe - 1) * (120 / 9));
  return {
    backgroundColor: `hsl(${hue}, 85%, 94%)`,
    color: `hsl(${hue}, 90%, 25%)`,
    borderColor: `hsl(${hue}, 70%, 80%)`,
  };
};

export const formatDate = (dateStr: string) => {
  return new Date(dateStr).toLocaleDateString('es-AR', {
    day: '2-digit',
    month: '2-digit',
    year: '2-digit'
  });
};

