import { useState, useEffect } from 'react';
import { db, isConfigValid } from '../firebase';
import { collection, onSnapshot, doc, updateDoc, deleteDoc, setDoc, query } from 'firebase/firestore';
import { Patient } from '../types';
import { MOCK_PATIENTS } from '../constants';

export const usePatients = () => {
  const [patients, setPatients] = useState<Patient[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!isConfigValid || !db) {
      setPatients(MOCK_PATIENTS);
      setLoading(false);
      return;
    }

    const q = query(collection(db, 'patients'));
    const unsubscribe = onSnapshot(q, (snapshot) => {
      const patientsData: Patient[] = [];
      snapshot.forEach((doc) => {
        patientsData.push(doc.data() as Patient);
      });
      // Solo actualizamos si hay datos, si no, mantenemos mocks para desarrollo inicial
      setPatients(patientsData.length > 0 ? patientsData : MOCK_PATIENTS);
      setLoading(false);
    }, (error) => {
      console.error("Firestore Error:", error);
      setPatients(MOCK_PATIENTS);
      setLoading(false);
    });

    return () => unsubscribe();
  }, []);

  const addPatient = async (patient: Patient) => {
    if (isConfigValid && db) {
      await setDoc(doc(db, 'patients', patient.id), patient);
    } else {
      // Fallback solo si no hay firebase
      setPatients(prev => [...prev, patient]);
    }
  };

  const updatePatient = async (updatedPatient: Patient) => {
    if (isConfigValid && db) {
      try {
        await updateDoc(doc(db, 'patients', updatedPatient.id), { ...updatedPatient });
      } catch (e) {
        console.error("Error updating patient:", e);
      }
    } else {
      setPatients(prev => prev.map(p => p.id === updatedPatient.id ? updatedPatient : p));
    }
  };

  const deletePatient = async (patientId: string) => {
    if (isConfigValid && db) {
      await deleteDoc(doc(db, 'patients', patientId));
    } else {
      setPatients(prev => prev.filter(p => p.id !== patientId));
    }
  };

  return { patients, loading, addPatient, updatePatient, deletePatient };
};

