              <div className="flex items-center gap-2">
                <button onClick={(e) => { e.stopPropagation(); openModal(patient); }} className="p-2 text-slate-400 hover:text-primary-600"><Settings2 size={18} /></button>
                <ChevronRight className="text-slate-300" size={20} />
              </div>
            </div>
          ))}
          {filteredPatients.length === 0 && <div className="p-8 text-center text-slate-400 italic">No se encontraron pacientes</div>}
        </div>
      </div>

      {modalState.show && (
        <div className="fixed inset-0 z-[100] bg-black/50 backdrop-blur-sm flex items-center justify-center p-4">
             <div className="bg-white w-full max-w-md rounded-3xl p-6 space-y-6 shadow-2xl animate-in zoom-in-95">
                 <div className="flex justify-between items-center">
                     <h2 className="text-xl font-bold text-slate-900">{modalState.editingPatient ? 'Editar Paciente' : 'Nuevo Paciente'}</h2>
                     <button onClick={() => setModalState({ show: false, editingPatient: null })} className="p-2 hover:bg-slate-100 rounded-full transition-colors"><X size={20} /></button>
                 </div>

                 <form onSubmit={handleSubmit} className="space-y-4">
                     <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-1">
                            <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">Nombre</label>
                            <input type="text" required className="w-full p-3 bg-slate-50 rounded-xl outline-none focus:ring-2 focus:ring-primary-500" value={formData.firstName} onChange={e => setFormData({...formData, firstName: e.target.value})} />
                        </div>
                        <div className="space-y-1">
                            <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">Apellido</label>
                            <input type="text" required className="w-full p-3 bg-slate-50 rounded-xl outline-none focus:ring-2 focus:ring-primary-500" value={formData.lastName} onChange={e => setFormData({...formData, lastName: e.target.value})} />
                        </div>
                     </div>

                     <div className="grid grid-cols-3 gap-4">
                        <div className="col-span-1 space-y-1">
                            <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">Edad</label>
                            <input type="number" required className="w-full p-3 bg-slate-50 rounded-xl outline-none focus:ring-2 focus:ring-primary-500" value={formData.age} onChange={e => setFormData({...formData, age: Number(e.target.value)})} />
                        </div>
                        <div className="col-span-2 space-y-1">
                            <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">Etapa Inicial</label>
                            <select className="w-full p-3 bg-slate-50 rounded-xl outline-none focus:ring-2 focus:ring-primary-500" value={formData.stage} onChange={e => setFormData({...formData, stage: e.target.value as Stage})}>
                                <option value={Stage.KINESIOLOGY}>Kinesiología</option>
                                <option value={Stage.GYM}>Gimnasio</option>
                            </select>
                        </div>
                     </div>

                     <div className="space-y-1">
                        <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">Diagnóstico / Motivo</label>
                        <input type="text" className="w-full p-3 bg-slate-50 rounded-xl outline-none focus:ring-2 focus:ring-primary-500" value={formData.condition} onChange={e => setFormData({...formData, condition: e.target.value})} />
                     </div>

                     <div className="pt-4 flex flex-col gap-3">
                        <button type="submit" className="w-full bg-primary-600 text-white font-bold py-4 rounded-2xl shadow-lg shadow-primary-200 hover:bg-primary-700 transition-colors">
                            {modalState.editingPatient ? 'Actualizar Datos' : 'Crear Paciente'}
                        </button>
                        {modalState.editingPatient && (
                            <button type="button" onClick={() => { if(window.confirm('¿Eliminar paciente?')) { onDeletePatient(modalState.editingPatient!.id); setModalState({show:false, editingPatient:null}); } }} className="w-full text-red-500 font-bold py-2 hover:bg-red-50 rounded-xl transition-colors">
                                Eliminar Paciente
                            </button>
                        )}
                     </div>
                 </form>
             </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Patient, RoutineExercise, Stage, UserRole } from '../types';
import { EXERCISES } from '../constants';
import { ExerciseCard } from './ExerciseCard';
import { ProgressChart } from './ProgressChart';
import { FileText, Plus, Search, X, LayoutGrid, Settings, CheckSquare, Square, Calendar } from 'lucide-react';

interface PatientDetailProps {
  patient: Patient;
  role: UserRole;
  onUpdatePatient: (updated: Patient) => void;
}

export const PatientDetail: React.FC<PatientDetailProps> = ({
  patient,
  role,
  onUpdatePatient,
}) => {
  const [activeDayId, setActiveDayId] = useState<string>(patient.routine.days[0]?.id || '');
  const [viewMode, setViewMode] = useState<'daily' | 'weekly' | 'monthly'>('daily');
  const [showHistory, setShowHistory] = useState<boolean>(false);
  const [showRoutineEditor, setShowRoutineEditor] = useState<boolean>(false);
  const [chartExercise, setChartExercise] = useState<RoutineExercise | null>(null);
  const [isAddingExercise, setIsAddingExercise] = useState(false);
  const [exerciseSearch, setExerciseSearch] = useState('');
  const [selectedExerciseIds, setSelectedExerciseIds] = useState<string[]>([]);
  const [notes, setNotes] = useState(patient.history[0] || '');

  const isKine = role === UserRole.KINE;
  const isReadOnly = role === UserRole.PATIENT || role === UserRole.ADMIN;

  useEffect(() => {
    if (patient.routine.days.length > 0 && !activeDayId) {
        setActiveDayId(patient.routine.days[0].id);
    }
  }, [patient]);

  const activeDay = patient.routine.days.find(d => d.id === activeDayId);

  const handleExerciseUpdate = (exerciseId: string, updates: Partial<RoutineExercise>) => {
    const newDays = patient.routine.days.map(day => ({
        ...day,
        exercises: day.exercises.map(ex => ex.id === exerciseId ? { ...ex, ...updates } : ex)
    }));
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  const handleRemoveExercise = (exerciseId: string) => {
    if (isReadOnly) return;
    const newDays = patient.routine.days.map(day => ({
        ...day,
        exercises: day.exercises.filter(ex => ex.id !== exerciseId)
    }));
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  const handleUpdateStage = (newStage: Stage) => {
    onUpdatePatient({ ...patient, routine: { ...patient.routine, stage: newStage } });
    setShowRoutineEditor(false);
  };

  return (
    <div className="flex-1 h-screen flex flex-col bg-slate-50 overflow-hidden relative">
      <header className="bg-white border-b border-slate-200 px-6 py-4 flex items-center justify-between shadow-sm shrink-0 z-20">
        <div className="flex flex-col min-w-0">
          <h2 className="text-xl md:text-2xl font-bold text-slate-900 leading-none truncate">
            {patient.firstName} {patient.lastName}
          </h2>
          <div className="flex items-center gap-2 mt-2">
              <span className={`px-2 py-0.5 rounded-full text-[10px] font-bold uppercase border ${patient.routine.stage === Stage.KINESIOLOGY ? 'bg-kine/10 text-kine border-kine/20' : 'bg-gym/10 text-gym border-gym/20'}`}>
                  {patient.routine.stage}
              </span>
              <span className="text-[10px] text-slate-400 truncate hidden xs:inline">• {patient.condition} • {patient.age} años</span>
          </div>
        </div>
        <div className="flex gap-2">
            {isKine && (
                <button onClick={() => setShowRoutineEditor(true)} className="p-2 md:px-4 md:py-2 bg-primary-600 text-white rounded-lg font-bold shadow-md hover:bg-primary-700 transition-colors flex items-center">
                    <Settings size={18} />
                    <span className="hidden md:inline ml-2 text-sm">Editar Etapa</span>
                </button>
            )}
            <button onClick={() => setShowHistory(!showHistory)} className={`p-2 md:px-4 md:py-2 rounded-lg font-bold transition-colors flex items-center ${showHistory ? 'bg-slate-800 text-white' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'}`}>
                <FileText size={18} />
                <span className="hidden md:inline ml-2 text-sm">{showHistory ? 'Cerrar Ficha' : 'Ficha'}</span>
            </button>
        </div>
      </header>

      {showHistory && (
          <div className="bg-slate-800 text-slate-200 px-6 py-6 shadow-inner shrink-0 border-b border-slate-700 overflow-y-auto max-h-[40vh]">
              <div className="grid grid-cols-1 md:grid-cols-3 gap-6 max-w-5xl mx-auto">
                  <div>
                       <h4 className="text-slate-400 text-[10px] uppercase font-bold mb-2">Datos Clínicos</h4>
                       <p className="text-xs">Última Visita: <span className="font-mono text-primary-400">{patient.lastVisit}</span></p>
                       <p className="text-xs mt-1">Edad: {patient.age} años</p>
                  </div>
                  <div className="md:col-span-2">
                      <h4 className="text-slate-400 text-[10px] uppercase font-bold mb-2">Evolución / Notas</h4>
                      <textarea 
                        readOnly={isReadOnly}
                        className="w-full h-24 bg-slate-700 text-slate-200 p-4 rounded-xl border border-slate-600 focus:ring-2 focus:ring-primary-500 outline-none resize-none" 
                        value={notes} 
                        onChange={(e) => setNotes(e.target.value)} 
                        placeholder="Sin notas de evolución..." 
                      />
                  </div>
              </div>
          </div>
      )}

      {showRoutineEditor && (
        <div className="fixed inset-0 z-[300] bg-black/50 backdrop-blur-sm flex items-center justify-center p-4">
            <div className="bg-white rounded-3xl p-6 w-full max-w-sm space-y-4 shadow-2xl">
                <div className="flex justify-between items-center">
                    <h3 className="font-bold text-lg">Cambiar Etapa</h3>
                    <button onClick={() => setShowRoutineEditor(false)}><X size={20}/></button>
                </div>
                <div className="grid grid-cols-1 gap-3">
                    <button onClick={() => handleUpdateStage(Stage.KINESIOLOGY)} className={`p-4 rounded-2xl border-2 font-bold transition-all ${patient.routine.stage === Stage.KINESIOLOGY ? 'border-kine bg-kine/5 text-kine' : 'border-slate-100 text-slate-400 hover:border-slate-200'}`}>Kinesiología</button>
                    <button onClick={() => handleUpdateStage(Stage.GYM)} className={`p-4 rounded-2xl border-2 font-bold transition-all ${patient.routine.stage === Stage.GYM ? 'border-gym bg-gym/5 text-gym' : 'border-slate-100 text-slate-400 hover:border-slate-200'}`}>Gimnasio</button>
                </div>
            </div>
        </div>
      )}

      <div className="bg-white border-b border-slate-200 px-6 flex justify-between pt-4 shrink-0 overflow-x-auto no-scrollbar">
          <div className="flex gap-1">
            {patient.routine.days.map((day, idx) => (
              <button key={day.id} onClick={() => {setActiveDayId(day.id); setViewMode('daily');}} className={`px-6 py-3 rounded-t-xl font-bold text-sm transition-all border-t border-x ${activeDayId === day.id && viewMode === 'daily' ? 'bg-slate-50 border-slate-200 text-primary-600' : 'bg-white border-transparent text-slate-400'}`}>
                Día {idx + 1}
              </button>
            ))}
          </div>
          <div className="flex items-center gap-2 pb-2 pl-4 border-l ml-2">
              <button onClick={() => setViewMode('weekly')} className={`p-2 rounded-lg ${viewMode === 'weekly' ? 'bg-primary-100 text-primary-700' : 'text-slate-400'}`}><LayoutGrid size={16}/></button>
              <button onClick={() => setViewMode('monthly')} className={`p-2 rounded-lg ${viewMode === 'monthly' ? 'bg-primary-100 text-primary-700' : 'text-slate-400'}`}><Calendar size={16}/></button>
          </div>
      </div>

      <main className="flex-1 overflow-y-auto p-4 md:p-8">
        <div className="max-w-3xl mx-auto pb-24">
          {viewMode === 'daily' && activeDay && (
              <div className="space-y-4">
                  {activeDay.exercises.map(ex => (
                      <ExerciseCard 
                        key={ex.id} 
                        exercise={ex} 
                        role={role}
                        onUpdate={handleExerciseUpdate} 
                        onShowHistory={(e) => setChartExercise(e)} 
                        onDelete={handleRemoveExercise} 
                      />
                  ))}
                  {isKine && (
                      <button onClick={() => setIsAddingExercise(true)} className="w-full py-4 rounded-2xl border-2 border-dashed border-primary-200 text-primary-600 font-bold flex items-center justify-center gap-2 hover:bg-primary-50 transition-colors">
                          <Plus size={18} /> Agregar Ejercicio
                      </button>
                  )}
              </div>
          )}
        </div>
      </main>

      {chartExercise && <ProgressChart exercise={chartExercise} onClose={() => setChartExercise(null)} />}

      {isAddingExercise && (
          <div className="fixed inset-0 z-[250] bg-black/60 backdrop-blur-sm flex items-center justify-center p-4">
              <div className="bg-white w-full max-w-lg h-[80vh] rounded-3xl shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95">
                  <div className="p-4 border-b flex items-center justify-between">
                      <div className="relative flex-1 mr-4">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                        <input type="text" placeholder="Buscar ejercicio..." className="w-full pl-10 pr-4 py-2.5 bg-slate-50 rounded-xl outline-none" value={exerciseSearch} onChange={e => setExerciseSearch(e.target.value)} />
                      </div>
                      <button onClick={() => { setIsAddingExercise(false); setSelectedExerciseIds([]); }} className="p-2 bg-slate-100 rounded-full"><X size={20}/></button>
                  </div>
                  <div className="flex-1 overflow-y-auto p-4 space-y-2 no-scrollbar">
                      {EXERCISES.filter(ex => ex.name.toLowerCase().includes(exerciseSearch.toLowerCase())).map(ex => {
                          const isSelected = selectedExerciseIds.includes(ex.id);
                          return (
                              <button key={ex.id} onClick={() => setSelectedExerciseIds(prev => isSelected ? prev.filter(i => i !== ex.id) : [...prev, ex.id])} className={`w-full flex items-center p-3 rounded-2xl border transition-all ${isSelected ? 'bg-primary-50 border-primary-400' : 'bg-white border-transparent hover:bg-slate-50'}`}>
                                  {isSelected ? <CheckSquare size={20} className="text-primary-600 mr-3"/> : <Square size={20} className="text-slate-300 mr-3"/>}
                                  <img src={ex.videoUrl} className="w-12 h-12 rounded-lg object-cover mr-3" />
                                  <div className="text-left">
                                      <p className="font-bold text-slate-800 text-sm">{ex.name}</p>
                                      <span className="text-[10px] text-slate-400 uppercase font-bold">{ex.category}</span>
                                  </div>
                              </button>
                          );
                      })}
                  </div>
                  <div className="p-4 bg-slate-50 border-t flex justify-between items-center">
                        <span className="text-xs font-bold text-slate-500">{selectedExerciseIds.length} seleccionados</span>
                        <button 
                            disabled={selectedExerciseIds.length === 0}
                            className="bg-primary-600 text-white px-8 py-3 rounded-xl font-bold disabled:opacity-50"
                            onClick={() => {
                                const newExs: RoutineExercise[] = selectedExerciseIds.map(id => ({
                                    id: `re-${Date.now()}-${id}`,
                                    definitionId: id,
                                    definition: EXERCISES.find(e => e.id === id)!,
                                    targetSets: 3, targetReps: 12, targetLoad: 0, isDone: false, history: []
                                }));
                                const newDays = patient.routine.days.map(d => d.id === activeDayId ? { ...d, exercises: [...d.exercises, ...newExs] } : d);
                                onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
                                setIsAddingExercise(false);
                                setSelectedExerciseIds([]);
                            }}
                        >
                            Agregar
                        </button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

// Added React import to solve "Cannot find namespace 'React'" errors.
import React, { useState } from 'react';
import { Patient, Stage } from '../types';
import { Search, ChevronRight, UserPlus, X, Settings2 } from 'lucide-react';

interface PatientListProps {
  patients: Patient[];
  onSelectPatient: (patient: Patient) => void;
  onAddPatient: (patient: Patient) => void;
  onUpdatePatient: (patient: Patient) => void;
  onDeletePatient: (patientId: string) => void;
}

export const PatientList: React.FC<PatientListProps> = ({
  patients,
  onSelectPatient,
  onAddPatient,
  onUpdatePatient,
  onDeletePatient
}) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [modalState, setModalState] = useState<{ show: boolean, editingPatient: Patient | null }>({
    show: false,
    editingPatient: null
  });

  const [formData, setFormData] = useState({
    firstName: '',
    lastName: '',
    condition: '',
    age: 30,
    stage: Stage.KINESIOLOGY
  });

  const filteredPatients = patients.filter((p) => {
    const fullName = `${p.firstName} ${p.lastName}`.toLowerCase();
    return fullName.includes(searchTerm.toLowerCase());
  });

  const openModal = (patient: Patient | null = null) => {
    if (patient) {
      setFormData({
        firstName: patient.firstName,
        lastName: patient.lastName,
        condition: patient.condition,
        age: patient.age,
        stage: patient.routine.stage
      });
      setModalState({ show: true, editingPatient: patient });
    } else {
      setFormData({ firstName: '', lastName: '', condition: '', age: 30, stage: Stage.KINESIOLOGY });
      setModalState({ show: true, editingPatient: null });
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.firstName || !formData.lastName) return;

    if (modalState.editingPatient) {
      onUpdatePatient({
        ...modalState.editingPatient,
        firstName: formData.firstName,
        lastName: formData.lastName,
        age: formData.age,
        condition: formData.condition,
        routine: { ...modalState.editingPatient.routine, stage: formData.stage }
      });
    } else {
      const newPatient: Patient = {
        id: `p-${Date.now()}`,
        firstName: formData.firstName,
        lastName: formData.lastName,
        age: formData.age,
        condition: formData.condition || 'Sin diagnóstico',
        photoUrl: `https://ui-avatars.com/api/?name=${formData.firstName}+${formData.lastName}&background=random`,
        lastVisit: new Date().toISOString().split('T')[0],
        history: [],
        routine: {
          id: `r-${Date.now()}`,
          stage: formData.stage,
          days: [{ id: `d1-${Date.now()}`, name: 'Día 1', exercises: [] }]
        }
      };
      onAddPatient(newPatient);
    }
    setModalState({ show: false, editingPatient: null });
  };

  return (
    <div className="flex-1 h-screen overflow-y-auto bg-slate-50 p-4 md:p-8">
      <div className="max-w-4xl mx-auto space-y-6">
        <div className="flex justify-between items-center gap-4">
          <h1 className="text-2xl md:text-3xl font-bold text-slate-900">Pacientes</h1>
          <button onClick={() => openModal()} className="bg-primary-600 text-white px-4 py-2.5 rounded-xl font-bold flex items-center gap-2 shadow-lg hover:bg-primary-700 transition-all text-sm">
            <UserPlus size={18} />
            <span className="hidden xs:inline">Nuevo Paciente</span>
          </button>
        </div>

        <div className="relative">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
          <input
            type="text"
            placeholder="Buscar por nombre..."
            className="w-full h-14 pl-12 pr-6 rounded-2xl border-none shadow-sm text-base focus:ring-4 focus:ring-primary-100"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
          {filteredPatients.map((patient, index) => (
            <div key={patient.id} className={`flex items-center p-4 cursor-pointer hover:bg-slate-50 transition-colors ${index !== filteredPatients.length - 1 ? 'border-b border-slate-100' : ''}`} onClick={() => onSelectPatient(patient)}>
              <img src={patient.photoUrl} className="w-10 h-10 rounded-full object-cover mr-4" />
              <div className="flex-1 min-w-0">
                <h3 className="font-bold text-slate-800 truncate">{patient.firstName} {patient.lastName}</h3>
                <p className="text-slate-400 text-xs truncate">{patient.condition}</p>
              </div>
              <div className="flex items-center gap-2">
                <button onClick={(e) => { e.stopPropagation(); openModal(patient); }} className="p-2 text-slate-400 hover:text-primary-600"><Settings2 size={18} /></button>
                <ChevronRight className="text-slate-300" size={20} />
              </div>
            </div>
          ))}
          {filteredPatients.length === 0 && <div className="p-8 text-center text-slate-400 italic">No se encontraron pacientes</div>}
        </div>
      </div>

      {modalState.show && (
        <div className="fixed inset-0 z-[100] bg-black/50 backdrop-blur-sm flex items-center justify-center p-4">
             <div className="bg-white w-full max-w-md rounded-3xl p-6 space-y-6 shadow-2xl animate-in zoom-in-95">
                 <div className="flex justify-between items-center">
                     <h2 className="text-xl font-bold text-slate-900">{modalState.editingPatient ? 'Editar Paciente' : 'Nuevo Paciente'}</h2>
                     <button onClick={() => setModalState({ show: false, editingPatient: null })} className="p-2 hover:bg-slate-100 rounded-full transition-colors"><X size={20} /></button>
                 </div>

                 <form onSubmit={handleSubmit} className="space-y-4">
                     <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-1">
                            <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">Nombre</label>
                            <input type="text" required className="w-full p-3 bg-slate-50 rounded-xl outline-none focus:ring-2 focus:ring-primary-500" value={formData.firstName} onChange={e => setFormData({...formData, firstName: e.target.value})} />
                        </div>
                        <div className="space-y-1">
                            <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">Apellido</label>
                            <input type="text" required className="w-full p-3 bg-slate-50 rounded-xl outline-none focus:ring-2 focus:ring-primary-500" value={formData.lastName} onChange={e => setFormData({...formData, lastName: e.target.value})} />
                        </div>
                     </div>

                     <div className="grid grid-cols-3 gap-4">
                        <div className="col-span-1 space-y-1">
                            <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">Edad</label>
                            <input type="number" required className="w-full p-3 bg-slate-50 rounded-xl outline-none focus:ring-2 focus:ring-primary-500" value={formData.age} onChange={e => setFormData({...formData, age: Number(e.target.value)})} />
                        </div>
                        <div className="col-span-2 space-y-1">
                            <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">Etapa Inicial</label>
                            <select className="w-full p-3 bg-slate-50 rounded-xl outline-none focus:ring-2 focus:ring-primary-500" value={formData.stage} onChange={e => setFormData({...formData, stage: e.target.value as Stage})}>
                                <option value={Stage.KINESIOLOGY}>Kinesiología</option>
                                <option value={Stage.GYM}>Gimnasio</option>
                            </select>
                        </div>
                     </div>

                     <div className="space-y-1">
                        <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">Diagnóstico / Motivo</label>
                        <input type="text" className="w-full p-3 bg-slate-50 rounded-xl outline-none focus:ring-2 focus:ring-primary-500" value={formData.condition} onChange={e => setFormData({...formData, condition: e.target.value})} />
                     </div>

                     <div className="pt-4 flex flex-col gap-3">
                        <button type="submit" className="w-full bg-primary-600 text-white font-bold py-4 rounded-2xl shadow-lg shadow-primary-200 hover:bg-primary-700 transition-colors">
                            {modalState.editingPatient ? 'Actualizar Datos' : 'Crear Paciente'}
                        </button>
                        {modalState.editingPatient && (
                            <button type="button" onClick={() => { if(window.confirm('¿Eliminar paciente?')) { onDeletePatient(modalState.editingPatient!.id); setModalState({show:false, editingPatient:null}); } }} className="w-full text-red-500 font-bold py-2 hover:bg-red-50 rounded-xl transition-colors">
                                Eliminar Paciente
                            </button>
                        )}
                     </div>
                 </form>
             </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Patient, RoutineExercise, Stage, UserRole, RoutineDay } from '../types';
import { EXERCISES } from '../constants';
import { ExerciseCard } from './ExerciseCard';
import { ProgressChart } from './ProgressChart';
import { FileText, Plus, Search, X, LayoutGrid, Settings, CheckSquare, Square, Calendar, Trash2, Edit3, Save } from 'lucide-react';

interface PatientDetailProps {
  patient: Patient;
  role: UserRole;
  onUpdatePatient: (updated: Patient) => void;
}

export const PatientDetail: React.FC<PatientDetailProps> = ({
  patient,
  role,
  onUpdatePatient,
}) => {
  const [activeDayId, setActiveDayId] = useState<string>(patient.routine.days[0]?.id || '');
  const [viewMode, setViewMode] = useState<'daily' | 'weekly' | 'monthly'>('daily');
  const [showHistory, setShowHistory] = useState<boolean>(false);
  const [showRoutineEditor, setShowRoutineEditor] = useState<boolean>(false);
  const [chartExercise, setChartExercise] = useState<RoutineExercise | null>(null);
  const [isAddingExercise, setIsAddingExercise] = useState(false);
  const [exerciseSearch, setExerciseSearch] = useState('');
  const [selectedExerciseIds, setSelectedExerciseIds] = useState<string[]>([]);
  const [notes, setNotes] = useState(patient.history[0] || '');

  const isKine = role === UserRole.KINE;
  const isReadOnly = role === UserRole.PATIENT || role === UserRole.ADMIN;

  useEffect(() => {
    if (patient.routine.days.length > 0 && (!activeDayId || !patient.routine.days.find(d => d.id === activeDayId))) {
        setActiveDayId(patient.routine.days[0].id);
    }
  }, [patient, activeDayId]);

  const activeDay = patient.routine.days.find(d => d.id === activeDayId);

  // --- Manejo de Ejercicios ---
  const handleExerciseUpdate = (exerciseId: string, updates: Partial<RoutineExercise>) => {
    const newDays = patient.routine.days.map(day => ({
        ...day,
        exercises: day.exercises.map(ex => ex.id === exerciseId ? { ...ex, ...updates } : ex)
    }));
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  const handleRemoveExercise = (exerciseId: string) => {
    if (isReadOnly) return;
    const newDays = patient.routine.days.map(day => ({
        ...day,
        exercises: day.exercises.filter(ex => ex.id !== exerciseId)
    }));
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  // --- Manejo de Días y Estructura ---
  const handleUpdateStage = (newStage: Stage) => {
    onUpdatePatient({ ...patient, routine: { ...patient.routine, stage: newStage } });
  };

  const handleAddDay = () => {
    const newDay: RoutineDay = {
      id: `day-${Date.now()}`,
      name: `Día ${patient.routine.days.length + 1}`,
      exercises: []
    };
    onUpdatePatient({ 
      ...patient, 
      routine: { ...patient.routine, days: [...patient.routine.days, newDay] } 
    });
  };

  const handleRemoveDay = (dayId: string) => {
    if (patient.routine.days.length <= 1) return; // No permitir borrar el último día
    const newDays = patient.routine.days.filter(d => d.id !== dayId);
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  const handleRenameDay = (dayId: string, newName: string) => {
    const newDays = patient.routine.days.map(d => d.id === dayId ? { ...d, name: newName } : d);
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  return (
    <div className="flex-1 h-screen flex flex-col bg-slate-50 overflow-hidden relative">
      <header className="bg-white border-b border-slate-200 px-6 py-4 flex items-center justify-between shadow-sm shrink-0 z-20">
        <div className="flex flex-col min-w-0">
          <h2 className="text-xl md:text-2xl font-bold text-slate-900 leading-none truncate">
            {patient.firstName} {patient.lastName}
          </h2>
          <div className="flex items-center gap-2 mt-2">
              <span className={`px-2 py-0.5 rounded-full text-[10px] font-bold uppercase border ${patient.routine.stage === Stage.KINESIOLOGY ? 'bg-kine/10 text-kine border-kine/20' : 'bg-gym/10 text-gym border-gym/20'}`}>
                  {patient.routine.stage}
              </span>
              <span className="text-[10px] text-slate-400 truncate hidden xs:inline">• {patient.condition} • {patient.age} años</span>
          </div>
        </div>
        <div className="flex gap-2">
            {isKine && (
                <button onClick={() => setShowRoutineEditor(true)} className="p-2 md:px-4 md:py-2 bg-primary-600 text-white rounded-lg font-bold shadow-md hover:bg-primary-700 transition-colors flex items-center">
                    <Settings size={18} />
                    <span className="hidden md:inline ml-2 text-sm">Configurar Rutina</span>
                </button>
            )}
            <button onClick={() => setShowHistory(!showHistory)} className={`p-2 md:px-4 md:py-2 rounded-lg font-bold transition-colors flex items-center ${showHistory ? 'bg-slate-800 text-white' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'}`}>
                <FileText size={18} />
                <span className="hidden md:inline ml-2 text-sm">{showHistory ? 'Cerrar Ficha' : 'Ficha'}</span>
            </button>
        </div>
      </header>

      {/* Panel de Evolución / Notas */}
      {showHistory && (
          <div className="bg-slate-800 text-slate-200 px-6 py-6 shadow-inner shrink-0 border-b border-slate-700 overflow-y-auto max-h-[40vh]">
              <div className="grid grid-cols-1 md:grid-cols-3 gap-6 max-w-5xl mx-auto">
                  <div>
                       <h4 className="text-slate-400 text-[10px] uppercase font-bold mb-2">Datos Clínicos</h4>
                       <p className="text-xs">Última Visita: <span className="font-mono text-primary-400">{patient.lastVisit}</span></p>
                       <p className="text-xs mt-1">Edad: {patient.age} años</p>
                  </div>
                  <div className="md:col-span-2">
                      <h4 className="text-slate-400 text-[10px] uppercase font-bold mb-2">Evolución / Notas</h4>
                      <textarea 
                        readOnly={isReadOnly}
                        className="w-full h-24 bg-slate-700 text-slate-200 p-4 rounded-xl border border-slate-600 focus:ring-2 focus:ring-primary-500 outline-none resize-none" 
                        value={notes} 
                        onChange={(e) => setNotes(e.target.value)} 
                        placeholder="Sin notas de evolución..." 
                      />
                  </div>
              </div>
          </div>
      )}

      {/* MODAL: Editor de Rutina Completo */}
      {showRoutineEditor && (
        <div className="fixed inset-0 z-[300] bg-black/50 backdrop-blur-sm flex items-center justify-center p-4">
            <div className="bg-white rounded-3xl p-6 w-full max-w-md space-y-6 shadow-2xl animate-in zoom-in-95">
                <div className="flex justify-between items-center">
                    <h3 className="font-bold text-xl text-slate-900">Configuración de Rutina</h3>
                    <button onClick={() => setShowRoutineEditor(false)} className="p-2 hover:bg-slate-100 rounded-full"><X size={20}/></button>
                </div>

                {/* Selector de Etapa */}
                <div className="space-y-3">
                    <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Etapa Actual</label>
                    <div className="grid grid-cols-2 gap-3">
                        <button onClick={() => handleUpdateStage(Stage.KINESIOLOGY)} className={`p-3 rounded-xl border-2 font-bold text-sm transition-all ${patient.routine.stage === Stage.KINESIOLOGY ? 'border-kine bg-kine/5 text-kine' : 'border-slate-100 text-slate-400'}`}>Kinesiología</button>
                        <button onClick={() => handleUpdateStage(Stage.GYM)} className={`p-3 rounded-xl border-2 font-bold text-sm transition-all ${patient.routine.stage === Stage.GYM ? 'border-gym bg-gym/5 text-gym' : 'border-slate-100 text-slate-400'}`}>Gimnasio</button>
                    </div>
                </div>

                {/* Lista de Días */}
                <div className="space-y-3">
                    <div className="flex justify-between items-center">
                        <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Días de Entrenamiento</label>
                        <button onClick={handleAddDay} className="text-primary-600 font-bold text-xs flex items-center gap-1 hover:underline"><Plus size={14}/> Agregar Día</button>
                    </div>
                    <div className="max-h-60 overflow-y-auto space-y-2 pr-2 no-scrollbar">
                        {patient.routine.days.map((day, idx) => (
                            <div key={day.id} className="flex items-center gap-2 p-2 bg-slate-50 rounded-xl border border-slate-100">
                                <input 
                                    className="flex-1 bg-transparent border-none font-bold text-sm text-slate-700 focus:ring-0 px-2"
                                    value={day.name}
                                    onChange={(e) => handleRenameDay(day.id, e.target.value)}
                                />
                                <button 
                                    onClick={() => handleRemoveDay(day.id)} 
                                    className={`p-2 text-slate-300 hover:text-red-500 transition-colors ${patient.routine.days.length <= 1 ? 'hidden' : ''}`}
                                >
                                    <Trash2 size={16}/>
                                </button>
                            </div>
                        ))}
                    </div>
                </div>

                <button onClick={() => setShowRoutineEditor(false)} className="w-full bg-slate-900 text-white font-bold py-4 rounded-2xl hover:bg-slate-800 transition-colors">
                    Guardar Cambios
                </button>
            </div>
        </div>
      )}

      {/* Tabs de Días */}
      <div className="bg-white border-b border-slate-200 px-6 flex justify-between pt-4 shrink-0 overflow-x-auto no-scrollbar">
          <div className="flex gap-1">
            {patient.routine.days.map((day) => (
              <button key={day.id} onClick={() => {setActiveDayId(day.id); setViewMode('daily');}} className={`px-6 py-3 rounded-t-xl font-bold text-sm transition-all border-t border-x whitespace-nowrap ${activeDayId === day.id && viewMode === 'daily' ? 'bg-slate-50 border-slate-200 text-primary-600' : 'bg-white border-transparent text-slate-400'}`}>
                {day.name}
              </button>
            ))}
          </div>
          <div className="flex items-center gap-2 pb-2 pl-4 border-l ml-2">
              <button onClick={() => setViewMode('weekly')} className={`p-2 rounded-lg ${viewMode === 'weekly' ? 'bg-primary-100 text-primary-700' : 'text-slate-400'}`}><LayoutGrid size={16}/></button>
              <button onClick={() => setViewMode('monthly')} className={`p-2 rounded-lg ${viewMode === 'monthly' ? 'bg-primary-100 text-primary-700' : 'text-slate-400'}`}><Calendar size={16}/></button>
          </div>
      </div>

      <main className="flex-1 overflow-y-auto p-4 md:p-8">
        <div className="max-w-3xl mx-auto pb-24">
          {viewMode === 'daily' && activeDay && (
              <div className="space-y-4">
                  {activeDay.exercises.map(ex => (
                      <ExerciseCard 
                        key={ex.id} 
                        exercise={ex} 
                        role={role}
                        onUpdate={handleExerciseUpdate} 
                        onShowHistory={(e) => setChartExercise(e)} 
                        onDelete={handleRemoveExercise} 
                      />
                  ))}
                  {isKine && (
                      <button onClick={() => setIsAddingExercise(true)} className="w-full py-4 rounded-2xl border-2 border-dashed border-primary-200 text-primary-600 font-bold flex items-center justify-center gap-2 hover:bg-primary-50 transition-colors">
                          <Plus size={18} /> Agregar Ejercicio
                      </button>
                  )}
              </div>
          )}
        </div>
      </main>

      {chartExercise && <ProgressChart exercise={chartExercise} onClose={() => setChartExercise(null)} />}

      {/* Modal de Selección de Ejercicios */}
      {isAddingExercise && (
          <div className="fixed inset-0 z-[250] bg-black/60 backdrop-blur-sm flex items-center justify-center p-4">
              <div className="bg-white w-full max-w-lg h-[80vh] rounded-3xl shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95">
                  <div className="p-4 border-b flex items-center justify-between">
                      <div className="relative flex-1 mr-4">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                        <input type="text" placeholder="Buscar ejercicio..." className="w-full pl-10 pr-4 py-2.5 bg-slate-50 rounded-xl outline-none" value={exerciseSearch} onChange={e => setExerciseSearch(e.target.value)} />
                      </div>
                      <button onClick={() => { setIsAddingExercise(false); setSelectedExerciseIds([]); }} className="p-2 bg-slate-100 rounded-full"><X size={20}/></button>
                  </div>
                  <div className="flex-1 overflow-y-auto p-4 space-y-2 no-scrollbar">
                      {EXERCISES.filter(ex => ex.name.toLowerCase().includes(exerciseSearch.toLowerCase())).map(ex => {
                          const isSelected = selectedExerciseIds.includes(ex.id);
                          return (
                              <button key={ex.id} onClick={() => setSelectedExerciseIds(prev => isSelected ? prev.filter(i => i !== ex.id) : [...prev, ex.id])} className={`w-full flex items-center p-3 rounded-2xl border transition-all ${isSelected ? 'bg-primary-50 border-primary-400' : 'bg-white border-transparent hover:bg-slate-50'}`}>
                                  {isSelected ? <CheckSquare size={20} className="text-primary-600 mr-3"/> : <Square size={20} className="text-slate-300 mr-3"/>}
                                  <img src={ex.videoUrl} className="w-12 h-12 rounded-lg object-cover mr-3" />
                                  <div className="text-left">
                                      <p className="font-bold text-slate-800 text-sm">{ex.name}</p>
                                      <span className="text-[10px] text-slate-400 uppercase font-bold">{ex.category}</span>
                                  </div>
                              </button>
                          );
                      })}
                  </div>
                  <div className="p-4 bg-slate-50 border-t flex justify-between items-center">
                        <span className="text-xs font-bold text-slate-500">{selectedExerciseIds.length} seleccionados</span>
                        <button 
                            disabled={selectedExerciseIds.length === 0}
                            className="bg-primary-600 text-white px-8 py-3 rounded-xl font-bold disabled:opacity-50"
                            onClick={() => {
                                const newExs: RoutineExercise[] = selectedExerciseIds.map(id => ({
                                    id: `re-${Date.now()}-${id}`,
                                    definitionId: id,
                                    definition: EXERCISES.find(e => e.id === id)!,
                                    targetSets: 3, targetReps: 12, targetLoad: 0, isDone: false, history: []
                                }));
                                const newDays = patient.routine.days.map(d => d.id === activeDayId ? { ...d, exercises: [...d.exercises, ...newExs] } : d);
                                onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
                                setIsAddingExercise(false);
                                setSelectedExerciseIds([]);
                            }}
                        >
                            Agregar
                        </button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Sidebar } from './components/Sidebar';
import { PatientList } from './components/PatientList';
import { PatientDetail } from './components/PatientDetail';
import { MOCK_PATIENTS } from './constants';
import { Patient, ViewState, UserRole } from './types';
import { db, isConfigValid } from './firebase';
import { 
  collection, 
  onSnapshot, 
  doc, 
  updateDoc,
  setDoc,
  deleteDoc,
  query
} from 'firebase/firestore';

const App: React.FC = () => {
  const [patients, setPatients] = useState<Patient[]>([]);
  const [loading, setLoading] = useState(true);
  const [activePatientIds, setActivePatientIds] = useState<string[]>([]);
  const [selectedPatientId, setSelectedPatientId] = useState<string | null>(null);
  const [view, setView] = useState<ViewState>('HOME');
  const [currentRole] = useState<UserRole>(UserRole.KINE);

  // Listener en tiempo real para Firebase
  useEffect(() => {
    if (!isConfigValid || !db) {
      setPatients(MOCK_PATIENTS);
      setLoading(false);
      return;
    }

    const q = query(collection(db, 'patients'));
    const unsubscribe = onSnapshot(q, (snapshot) => {
      const patientsData: Patient[] = [];
      snapshot.forEach((doc) => {
        patientsData.push(doc.data() as Patient);
      });
      // Si no hay datos en la nube, mostramos los mocks iniciales
      setPatients(patientsData.length > 0 ? patientsData : MOCK_PATIENTS);
      setLoading(false);
    }, (error) => {
      console.error("Firestore Error:", error);
      setPatients(MOCK_PATIENTS);
      setLoading(false);
    });

    return () => unsubscribe();
  }, []);

  const handleSelectPatient = (patient: Patient) => {
    if (!activePatientIds.includes(patient.id)) {
      setActivePatientIds(prev => [patient.id, ...prev]);
    }
    setSelectedPatientId(patient.id);
    setView('PATIENT_DETAIL');
  };

  const handleAddPatient = async (newPatient: Patient) => {
    if (isConfigValid && db) {
      try {
        await setDoc(doc(db, 'patients', newPatient.id), newPatient);
      } catch (e) {
        console.error("Error adding patient:", e);
      }
    } else {
      setPatients(prev => [...prev, newPatient]);
    }
  };

  const handleUpdatePatient = async (updatedPatient: Patient) => {
    if (isConfigValid && db) {
      try {
        await updateDoc(doc(db, 'patients', updatedPatient.id), { ...updatedPatient });
      } catch (e) {
        console.error("Error updating patient:", e);
      }
    } else {
      setPatients(prev => prev.map(p => p.id === updatedPatient.id ? updatedPatient : p));
    }
  };

  const handleDeletePatient = async (patientId: string) => {
    if (isConfigValid && db) {
      try {
        await deleteDoc(doc(db, 'patients', patientId));
      } catch (e) {
        console.error("Error deleting patient:", e);
      }
    } else {
      setPatients(prev => prev.filter(p => p.id !== patientId));
    }
  };

  const handleGoHome = () => {
    setView('HOME');
    setSelectedPatientId(null);
  };

  const activePatients = activePatientIds
    .map(id => patients.find(p => p.id === id))
    .filter((p): p is Patient => !!p);

  const currentPatient = patients.find(p => p.id === selectedPatientId);

  if (loading) {
    return (
      <div className="h-screen w-full flex items-center justify-center bg-slate-50">
        <div className="flex flex-col items-center gap-4">
          <div className="w-12 h-12 border-4 border-primary-500 border-t-transparent rounded-full animate-spin"></div>
          <p className="text-slate-500 font-bold animate-pulse">Cargando KineFlow...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="flex w-full h-[100dvh] bg-slate-50 font-sans text-slate-900 overflow-hidden">
      <Sidebar 
          activePatients={activePatients}
          selectedPatientId={selectedPatientId}
          onSelectPatient={(id) => { setSelectedPatientId(id); setView('PATIENT_DETAIL'); }}
          onRemoveActive={(id, e) => {
              e.stopPropagation();
              setActivePatientIds(prev => prev.filter(p => p !== id));
              if (selectedPatientId === id) { setSelectedPatientId(null); setView('HOME'); }
          }}
          onGoHome={handleGoHome}
      />

      <div className="flex-1 flex flex-col h-full overflow-hidden">
        {view === 'HOME' ? (
            <PatientList 
                patients={patients} 
                onSelectPatient={handleSelectPatient} 
                onAddPatient={handleAddPatient}
                onUpdatePatient={handleUpdatePatient}
                onDeletePatient={handleDeletePatient}
            />
        ) : currentPatient && (
            <PatientDetail 
                patient={currentPatient}
                role={currentRole}
                onUpdatePatient={handleUpdatePatient}
            />
        )}
      </div>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Patient, Stage } from '../types';
import { Search, ChevronRight, UserPlus, X, Settings2 } from 'lucide-react';

interface PatientListProps {
  patients: Patient[];
  onSelectPatient: (patient: Patient) => void;
  onAddPatient: (patient: Patient) => void;
  onUpdatePatient: (patient: Patient) => void;
  onDeletePatient: (patientId: string) => void;
}

export const PatientList: React.FC<PatientListProps> = ({
  patients,
  onSelectPatient,
  onAddPatient,
  onUpdatePatient,
  onDeletePatient
}) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [modalState, setModalState] = useState<{ show: boolean, editingPatient: Patient | null }>({
    show: false,
    editingPatient: null
  });

  const [formData, setFormData] = useState({
    firstName: '',
    lastName: '',
    condition: '',
    age: 30,
    stage: Stage.KINESIOLOGY
  });

  const filteredPatients = patients.filter((p) => {
    const fullName = `${p.firstName} ${p.lastName}`.toLowerCase();
    return fullName.includes(searchTerm.toLowerCase());
  });

  const openModal = (patient: Patient | null = null) => {
    if (patient) {
      setFormData({
        firstName: patient.firstName,
        lastName: patient.lastName,
        condition: patient.condition,
        age: patient.age,
        stage: patient.routine.stage
      });
      setModalState({ show: true, editingPatient: patient });
    } else {
      setFormData({ firstName: '', lastName: '', condition: '', age: 30, stage: Stage.KINESIOLOGY });
      setModalState({ show: true, editingPatient: null });
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.firstName || !formData.lastName) return;

    if (modalState.editingPatient) {
      onUpdatePatient({
        ...modalState.editingPatient,
        firstName: formData.firstName,
        lastName: formData.lastName,
        age: formData.age,
        condition: formData.condition,
        routine: { ...modalState.editingPatient.routine, stage: formData.stage }
      });
    } else {
      const newPatient: Patient = {
        id: `p-${Date.now()}`,
        firstName: formData.firstName,
        lastName: formData.lastName,
        age: formData.age,
        condition: formData.condition || 'Sin diagnóstico',
        photoUrl: `https://ui-avatars.com/api/?name=${formData.firstName}+${formData.lastName}&background=random`,
        lastVisit: new Date().toISOString().split('T')[0],
        history: [],
        routine: {
          id: `r-${Date.now()}`,
          stage: formData.stage,
          days: [{ id: `d1-${Date.now()}`, name: 'Día 1', exercises: [] }]
        }
      };
      onAddPatient(newPatient);
    }
    setModalState({ show: false, editingPatient: null });
  };

  return (
    <div className="flex-1 h-screen overflow-y-auto bg-slate-50 p-4 md:p-8">
      <div className="max-w-4xl mx-auto space-y-6">
        <div className="flex justify-between items-center gap-4">
          <h1 className="text-2xl md:text-3xl font-bold text-slate-900">Pacientes</h1>
          <button onClick={() => openModal()} className="bg-primary-600 text-white px-4 py-2.5 rounded-xl font-bold flex items-center gap-2 shadow-lg hover:bg-primary-700 transition-all text-sm">
            <UserPlus size={18} />
            <span className="hidden xs:inline">Nuevo Paciente</span>
          </button>
        </div>

        <div className="relative">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
          <input
            type="text"
            placeholder="Buscar por nombre..."
            className="w-full h-14 pl-12 pr-6 rounded-2xl border-none shadow-sm text-base focus:ring-4 focus:ring-primary-100"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
          {filteredPatients.map((patient, index) => (
            <div key={patient.id} className={`flex items-center p-4 cursor-pointer hover:bg-slate-50 transition-colors ${index !== filteredPatients.length - 1 ? 'border-b border-slate-100' : ''}`} onClick={() => onSelectPatient(patient)}>
              <img src={patient.photoUrl} className="w-10 h-10 rounded-full object-cover mr-4" />
              <div className="flex-1 min-w-0">
                <h3 className="font-bold text-slate-800 truncate">{patient.firstName} {patient.lastName}</h3>
                <p className="text-slate-400 text-xs truncate">{patient.condition}</p>
              </div>
              <div className="flex items-center gap-2">
                <button onClick={(e) => { e.stopPropagation(); openModal(patient); }} className="p-2 text-slate-400 hover:text-primary-600"><Settings2 size={18} /></button>
                <ChevronRight className="text-slate-300" size={20} />
              </div>
            </div>
          ))}
          {filteredPatients.length === 0 && <div className="p-8 text-center text-slate-400 italic">No se encontraron pacientes</div>}
        </div>
      </div>

      {modalState.show && (
        <div className="fixed inset-0 z-[100] bg-black/50 backdrop-blur-sm flex items-center justify-center p-4">
             <div className="bg-white w-full max-w-md rounded-3xl p-6 space-y-6 shadow-2xl animate-in zoom-in-95">
                 <div className="flex justify-between items-center">
                     <h2 className="text-xl font-bold text-slate-900">{modalState.editingPatient ? 'Editar Paciente' : 'Nuevo Paciente'}</h2>
                     <button onClick={() => setModalState({ show: false, editingPatient: null })} className="p-2 hover:bg-slate-100 rounded-full transition-colors"><X size={20} /></button>
                 </div>

                 <form onSubmit={handleSubmit} className="space-y-4">
                     <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-1">
                            <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">Nombre</label>
                            <input type="text" required className="w-full p-3 bg-slate-50 rounded-xl outline-none focus:ring-2 focus:ring-primary-500" value={formData.firstName} onChange={e => setFormData({...formData, firstName: e.target.value})} />
                        </div>
                        <div className="space-y-1">
                            <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">Apellido</label>
                            <input type="text" required className="w-full p-3 bg-slate-50 rounded-xl outline-none focus:ring-2 focus:ring-primary-500" value={formData.lastName} onChange={e => setFormData({...formData, lastName: e.target.value})} />
                        </div>
                     </div>

                     <div className="grid grid-cols-3 gap-4">
                        <div className="col-span-1 space-y-1">
                            <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">Edad</label>
                            <input type="number" required className="w-full p-3 bg-slate-50 rounded-xl outline-none focus:ring-2 focus:ring-primary-500" value={formData.age} onChange={e => setFormData({...formData, age: Number(e.target.value)})} />
                        </div>
                        <div className="col-span-2 space-y-1">
                            <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">Etapa Inicial</label>
                            <select className="w-full p-3 bg-slate-50 rounded-xl outline-none focus:ring-2 focus:ring-primary-500" value={formData.stage} onChange={e => setFormData({...formData, stage: e.target.value as Stage})}>
                                <option value={Stage.KINESIOLOGY}>Kinesiología</option>
                                <option value={Stage.GYM}>Gimnasio</option>
                            </select>
                        </div>
                     </div>

                     <div className="space-y-1">
                        <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">Diagnóstico / Motivo</label>
                        <input type="text" className="w-full p-3 bg-slate-50 rounded-xl outline-none focus:ring-2 focus:ring-primary-500" value={formData.condition} onChange={e => setFormData({...formData, condition: e.target.value})} />
                     </div>

                     <div className="pt-4 flex flex-col gap-3">
                        <button type="submit" className="w-full bg-primary-600 text-white font-bold py-4 rounded-2xl shadow-lg shadow-primary-200 hover:bg-primary-700 transition-colors">
                            {modalState.editingPatient ? 'Actualizar Datos' : 'Crear Paciente'}
                        </button>
                        {modalState.editingPatient && (
                            <button type="button" onClick={() => { if(window.confirm('¿Eliminar paciente?')) { onDeletePatient(modalState.editingPatient!.id); setModalState({show:false, editingPatient:null}); } }} className="w-full text-red-500 font-bold py-2 hover:bg-red-50 rounded-xl transition-colors">
                                Eliminar Paciente
                            </button>
                        )}
                     </div>
                 </form>
             </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Patient, RoutineExercise, Stage, UserRole, RoutineDay } from '../types';
import { EXERCISES } from '../constants';
import { ExerciseCard } from './ExerciseCard';
import { ProgressChart } from './ProgressChart';
import { FileText, Plus, Search, X, LayoutGrid, Settings, CheckSquare, Square, Calendar, Trash2 } from 'lucide-react';

interface PatientDetailProps {
  patient: Patient;
  role: UserRole;
  onUpdatePatient: (updated: Patient) => void;
}

export const PatientDetail: React.FC<PatientDetailProps> = ({
  patient,
  role,
  onUpdatePatient,
}) => {
  const [activeDayId, setActiveDayId] = useState<string>(patient.routine.days[0]?.id || '');
  const [viewMode, setViewMode] = useState<'daily' | 'weekly' | 'monthly'>('daily');
  const [showHistory, setShowHistory] = useState<boolean>(false);
  const [showRoutineEditor, setShowRoutineEditor] = useState<boolean>(false);
  const [chartExercise, setChartExercise] = useState<RoutineExercise | null>(null);
  const [isAddingExercise, setIsAddingExercise] = useState(false);
  const [exerciseSearch, setExerciseSearch] = useState('');
  const [selectedExerciseIds, setSelectedExerciseIds] = useState<string[]>([]);
  const [notes, setNotes] = useState(patient.history[0] || '');

  const isKine = role === UserRole.KINE;
  const isReadOnly = role === UserRole.PATIENT || role === UserRole.ADMIN;

  useEffect(() => {
    // Si el día activo ya no existe (porque fue borrado), seleccionamos el primero disponible
    if (patient.routine.days.length > 0 && (!activeDayId || !patient.routine.days.find(d => d.id === activeDayId))) {
        setActiveDayId(patient.routine.days[0].id);
    }
  }, [patient, activeDayId]);

  const activeDay = patient.routine.days.find(d => d.id === activeDayId);

  // Handlers para ejercicios
  const handleExerciseUpdate = (exerciseId: string, updates: Partial<RoutineExercise>) => {
    const newDays = patient.routine.days.map(day => ({
        ...day,
        exercises: day.exercises.map(ex => ex.id === exerciseId ? { ...ex, ...updates } : ex)
    }));
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  const handleRemoveExercise = (exerciseId: string) => {
    if (isReadOnly) return;
    const newDays = patient.routine.days.map(day => ({
        ...day,
        exercises: day.exercises.filter(ex => ex.id !== exerciseId)
    }));
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  // Handlers para el Editor de Rutina (Días y Etapa)
  const handleUpdateStage = (newStage: Stage) => {
    onUpdatePatient({ ...patient, routine: { ...patient.routine, stage: newStage } });
  };

  const handleAddDay = () => {
    const newDay: RoutineDay = {
      id: `day-${Date.now()}`,
      name: `Día ${patient.routine.days.length + 1}`,
      exercises: []
    };
    onUpdatePatient({ 
      ...patient, 
      routine: { ...patient.routine, days: [...patient.routine.days, newDay] } 
    });
  };

  const handleRemoveDay = (dayId: string) => {
    if (patient.routine.days.length <= 1) return;
    const newDays = patient.routine.days.filter(d => d.id !== dayId);
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  const handleRenameDay = (dayId: string, newName: string) => {
    const newDays = patient.routine.days.map(d => d.id === dayId ? { ...d, name: newName } : d);
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  return (
    <div className="flex-1 h-screen flex flex-col bg-slate-50 overflow-hidden relative">
      <header className="bg-white border-b border-slate-200 px-6 py-4 flex items-center justify-between shadow-sm shrink-0 z-20">
        <div className="flex flex-col min-w-0">
          <h2 className="text-xl md:text-2xl font-bold text-slate-900 leading-none truncate">
            {patient.firstName} {patient.lastName}
          </h2>
          <div className="flex items-center gap-2 mt-2">
              <span className={`px-2 py-0.5 rounded-full text-[10px] font-bold uppercase border ${patient.routine.stage === Stage.KINESIOLOGY ? 'bg-kine/10 text-kine border-kine/20' : 'bg-gym/10 text-gym border-gym/20'}`}>
                  {patient.routine.stage}
              </span>
              <span className="text-[10px] text-slate-400 truncate hidden xs:inline">• {patient.condition} • {patient.age} años</span>
          </div>
        </div>
        <div className="flex gap-2">
            {isKine && (
                <button onClick={() => setShowRoutineEditor(true)} className="p-2 md:px-4 md:py-2 bg-primary-600 text-white rounded-lg font-bold shadow-md hover:bg-primary-700 transition-colors flex items-center">
                    <Settings size={18} />
                    <span className="hidden md:inline ml-2 text-sm">Editar Rutina</span>
                </button>
            )}
            <button onClick={() => setShowHistory(!showHistory)} className={`p-2 md:px-4 md:py-2 rounded-lg font-bold transition-colors flex items-center ${showHistory ? 'bg-slate-800 text-white' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'}`}>
                <FileText size={18} />
                <span className="hidden md:inline ml-2 text-sm">{showHistory ? 'Cerrar Ficha' : 'Ficha'}</span>
            </button>
        </div>
      </header>

      {showHistory && (
          <div className="bg-slate-800 text-slate-200 px-6 py-6 shadow-inner shrink-0 border-b border-slate-700 overflow-y-auto max-h-[40vh]">
              <div className="grid grid-cols-1 md:grid-cols-3 gap-6 max-w-5xl mx-auto">
                  <div>
                       <h4 className="text-slate-400 text-[10px] uppercase font-bold mb-2">Datos Clínicos</h4>
                       <p className="text-xs">Última Visita: <span className="font-mono text-primary-400">{patient.lastVisit}</span></p>
                       <p className="text-xs mt-1">Edad: {patient.age} años</p>
                  </div>
                  <div className="md:col-span-2">
                      <h4 className="text-slate-400 text-[10px] uppercase font-bold mb-2">Evolución / Notas</h4>
                      <textarea 
                        readOnly={isReadOnly}
                        className="w-full h-24 bg-slate-700 text-slate-200 p-4 rounded-xl border border-slate-600 focus:ring-2 focus:ring-primary-500 outline-none resize-none" 
                        value={notes} 
                        onChange={(e) => setNotes(e.target.value)} 
                        placeholder="Sin notas de evolución..." 
                      />
                  </div>
              </div>
          </div>
      )}

      {/* MODAL: Editor de Rutina (Etapa + Días) */}
      {showRoutineEditor && (
        <div className="fixed inset-0 z-[300] bg-black/50 backdrop-blur-sm flex items-center justify-center p-4">
            <div className="bg-white rounded-3xl p-6 w-full max-w-md space-y-6 shadow-2xl animate-in zoom-in-95">
                <div className="flex justify-between items-center">
                    <h3 className="font-bold text-xl text-slate-900">Configuración de Rutina</h3>
                    <button onClick={() => setShowRoutineEditor(false)} className="p-2 hover:bg-slate-100 rounded-full transition-colors"><X size={20}/></button>
                </div>

                <div className="space-y-3">
                    <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Etapa del Tratamiento</label>
                    <div className="grid grid-cols-2 gap-3">
                        <button onClick={() => handleUpdateStage(Stage.KINESIOLOGY)} className={`p-4 rounded-xl border-2 font-bold transition-all ${patient.routine.stage === Stage.KINESIOLOGY ? 'border-kine bg-kine/5 text-kine' : 'border-slate-100 text-slate-400'}`}>Kinesiología</button>
                        <button onClick={() => handleUpdateStage(Stage.GYM)} className={`p-4 rounded-xl border-2 font-bold transition-all ${patient.routine.stage === Stage.GYM ? 'border-gym bg-gym/5 text-gym' : 'border-slate-100 text-slate-400'}`}>Gimnasio</button>
                    </div>
                </div>

                <div className="space-y-3">
                    <div className="flex justify-between items-center">
                        <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Días de Entrenamiento</label>
                        <button onClick={handleAddDay} className="text-primary-600 font-bold text-xs flex items-center gap-1 hover:underline"><Plus size={14}/> Agregar Día</button>
                    </div>
                    <div className="max-h-64 overflow-y-auto space-y-2 pr-2 no-scrollbar">
                        {patient.routine.days.map((day) => (
                            <div key={day.id} className="flex items-center gap-2 p-2 bg-slate-50 rounded-xl border border-slate-100">
                                <input 
                                    className="flex-1 bg-transparent border-none font-bold text-sm text-slate-700 focus:ring-0 px-2"
                                    value={day.name}
                                    onChange={(e) => handleRenameDay(day.id, e.target.value)}
                                />
                                <button 
                                    onClick={() => handleRemoveDay(day.id)} 
                                    className={`p-2 text-slate-300 hover:text-red-500 transition-colors ${patient.routine.days.length <= 1 ? 'hidden' : ''}`}
                                >
                                    <Trash2 size={16}/>
                                </button>
                            </div>
                        ))}
                    </div>
                </div>

                <button onClick={() => setShowRoutineEditor(false)} className="w-full bg-slate-900 text-white font-bold py-4 rounded-2xl hover:bg-slate-800 transition-colors shadow-lg">
                    Cerrar y Guardar
                </button>
            </div>
        </div>
      )}

      {/* Tabs de Días */}
      <div className="bg-white border-b border-slate-200 px-6 flex justify-between pt-4 shrink-0 overflow-x-auto no-scrollbar">
          <div className="flex gap-1">
            {patient.routine.days.map((day) => (
              <button key={day.id} onClick={() => {setActiveDayId(day.id); setViewMode('daily');}} className={`px-6 py-3 rounded-t-xl font-bold text-sm transition-all border-t border-x whitespace-nowrap ${activeDayId === day.id && viewMode === 'daily' ? 'bg-slate-50 border-slate-200 text-primary-600' : 'bg-white border-transparent text-slate-400'}`}>
                {day.name}
              </button>
            ))}
          </div>
          <div className="flex items-center gap-2 pb-2 pl-4 border-l ml-2">
              <button onClick={() => setViewMode('weekly')} className={`p-2 rounded-lg ${viewMode === 'weekly' ? 'bg-primary-100 text-primary-700' : 'text-slate-400'}`}><LayoutGrid size={16}/></button>
              <button onClick={() => setViewMode('monthly')} className={`p-2 rounded-lg ${viewMode === 'monthly' ? 'bg-primary-100 text-primary-700' : 'text-slate-400'}`}><Calendar size={16}/></button>
          </div>
      </div>

      <main className="flex-1 overflow-y-auto p-4 md:p-8">
        <div className="max-w-3xl mx-auto pb-24">
          {viewMode === 'daily' && activeDay && (
              <div className="space-y-4">
                  {activeDay.exercises.map(ex => (
                      <ExerciseCard 
                        key={ex.id} 
                        exercise={ex} 
                        role={role}
                        onUpdate={handleExerciseUpdate} 
                        onShowHistory={(e) => setChartExercise(e)} 
                        onDelete={handleRemoveExercise} 
                      />
                  ))}
                  {isKine && (
                      <button onClick={() => setIsAddingExercise(true)} className="w-full py-4 rounded-2xl border-2 border-dashed border-primary-200 text-primary-600 font-bold flex items-center justify-center gap-2 hover:bg-primary-50 transition-colors">
                          <Plus size={18} /> Agregar Ejercicio
                      </button>
                  )}
              </div>
          )}
        </div>
      </main>

      {chartExercise && <ProgressChart exercise={chartExercise} onClose={() => setChartExercise(null)} />}

      {/* Modal de Selección de Ejercicios */}
      {isAddingExercise && (
          <div className="fixed inset-0 z-[250] bg-black/60 backdrop-blur-sm flex items-center justify-center p-4">
              <div className="bg-white w-full max-w-lg h-[80vh] rounded-3xl shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95">
                  <div className="p-4 border-b flex items-center justify-between">
                      <div className="relative flex-1 mr-4">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                        <input type="text" placeholder="Buscar ejercicio..." className="w-full pl-10 pr-4 py-2.5 bg-slate-50 rounded-xl outline-none" value={exerciseSearch} onChange={e => setExerciseSearch(e.target.value)} />
                      </div>
                      <button onClick={() => { setIsAddingExercise(false); setSelectedExerciseIds([]); }} className="p-2 bg-slate-100 rounded-full"><X size={20}/></button>
                  </div>
                  <div className="flex-1 overflow-y-auto p-4 space-y-2 no-scrollbar">
                      {EXERCISES.filter(ex => ex.name.toLowerCase().includes(exerciseSearch.toLowerCase())).map(ex => {
                          const isSelected = selectedExerciseIds.includes(ex.id);
                          return (
                              <button key={ex.id} onClick={() => setSelectedExerciseIds(prev => isSelected ? prev.filter(i => i !== ex.id) : [...prev, ex.id])} className={`w-full flex items-center p-3 rounded-2xl border transition-all ${isSelected ? 'bg-primary-50 border-primary-400' : 'bg-white border-transparent hover:bg-slate-50'}`}>
                                  {isSelected ? <CheckSquare size={20} className="text-primary-600 mr-3"/> : <Square size={20} className="text-slate-300 mr-3"/>}
                                  <img src={ex.videoUrl} className="w-12 h-12 rounded-lg object-cover mr-3" />
                                  <div className="text-left">
                                      <p className="font-bold text-slate-800 text-sm">{ex.name}</p>
                                      <span className="text-[10px] text-slate-400 uppercase font-bold">{ex.category}</span>
                                  </div>
                              </button>
                          );
                      })}
                  </div>
                  <div className="p-4 bg-slate-50 border-t flex justify-between items-center">
                        <span className="text-xs font-bold text-slate-500">{selectedExerciseIds.length} seleccionados</span>
                        <button 
                            disabled={selectedExerciseIds.length === 0}
                            className="bg-primary-600 text-white px-8 py-3 rounded-xl font-bold disabled:opacity-50 transition-all active:scale-95"
                            onClick={() => {
                                const newExs: RoutineExercise[] = selectedExerciseIds.map(id => ({
                                    id: `re-${Date.now()}-${id}`,
                                    definitionId: id,
                                    definition: EXERCISES.find(e => e.id === id)!,
                                    targetSets: 3, targetReps: 12, targetLoad: 0, isDone: false, history: []
                                }));
                                const newDays = patient.routine.days.map(d => d.id === activeDayId ? { ...d, exercises: [...d.exercises, ...newExs] } : d);
                                onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
                                setIsAddingExercise(false);
                                setSelectedExerciseIds([]);
                            }}
                        >
                            Agregar a Rutina
                        </button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Sidebar } from './components/Sidebar';
import { PatientList } from './components/PatientList';
import { PatientDetail } from './components/PatientDetail';
import { MOCK_PATIENTS } from './constants';
import { Patient, ViewState, UserRole } from './types';
import { db, isConfigValid } from './firebase';
import { 
  collection, 
  onSnapshot, 
  doc, 
  updateDoc,
  setDoc,
  deleteDoc,
  query
} from 'firebase/firestore';

const App: React.FC = () => {
  const [patients, setPatients] = useState<Patient[]>([]);
  const [loading, setLoading] = useState(true);
  const [activePatientIds, setActivePatientIds] = useState<string[]>([]);
  const [selectedPatientId, setSelectedPatientId] = useState<string | null>(null);
  const [view, setView] = useState<ViewState>('HOME');
  const [currentRole] = useState<UserRole>(UserRole.KINE);

  useEffect(() => {
    if (!isConfigValid || !db) {
      setPatients(MOCK_PATIENTS);
      setLoading(false);
      return;
    }

    const q = query(collection(db, 'patients'));
    const unsubscribe = onSnapshot(q, (snapshot) => {
      const patientsData: Patient[] = [];
      snapshot.forEach((doc) => {
        patientsData.push(doc.data() as Patient);
      });
      // Importante: No duplicamos si ya hay datos, pero mantenemos mocks si está vacío
      setPatients(patientsData.length > 0 ? patientsData : MOCK_PATIENTS);
      setLoading(false);
    }, (error) => {
      console.error("Firestore Error:", error);
      setPatients(MOCK_PATIENTS);
      setLoading(false);
    });

    return () => unsubscribe();
  }, []);

  const handleSelectPatient = (patient: Patient) => {
    if (!activePatientIds.includes(patient.id)) {
      setActivePatientIds(prev => [patient.id, ...prev]);
    }
    setSelectedPatientId(patient.id);
    setView('PATIENT_DETAIL');
  };

  const handleAddPatient = async (newPatient: Patient) => {
    if (isConfigValid && db) {
      try {
        // Al usar setDoc con onSnapshot, NO necesitamos actualizar el estado local manualmente.
        // Evita el bug de duplicidad.
        await setDoc(doc(db, 'patients', newPatient.id), newPatient);
      } catch (e) {
        console.error("Error adding patient:", e);
      }
    } else {
      setPatients(prev => [...prev, newPatient]);
    }
  };

  const handleUpdatePatient = async (updatedPatient: Patient) => {
    if (isConfigValid && db) {
      try {
        await updateDoc(doc(db, 'patients', updatedPatient.id), { ...updatedPatient });
      } catch (e) {
        console.error("Error updating patient:", e);
      }
    } else {
      setPatients(prev => prev.map(p => p.id === updatedPatient.id ? updatedPatient : p));
    }
  };

  const handleDeletePatient = async (patientId: string) => {
    if (isConfigValid && db) {
      try {
        await deleteDoc(doc(db, 'patients', patientId));
      } catch (e) {
        console.error("Error deleting patient:", e);
      }
    } else {
      setPatients(prev => prev.filter(p => p.id !== patientId));
    }
  };

  const handleGoHome = () => {
    setView('HOME');
    setSelectedPatientId(null);
  };

  const activePatients = activePatientIds
    .map(id => patients.find(p => p.id === id))
    .filter((p): p is Patient => !!p);

  const currentPatient = patients.find(p => p.id === selectedPatientId);

  if (loading) {
    return (
      <div className="h-[100dvh] w-full flex items-center justify-center bg-slate-50">
        <div className="flex flex-col items-center gap-4">
          <div className="w-12 h-12 border-4 border-primary-500 border-t-transparent rounded-full animate-spin"></div>
          <p className="text-slate-500 font-bold animate-pulse">Iniciando KineFlow...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="flex w-full h-[100dvh] bg-slate-50 font-sans text-slate-900 overflow-hidden">
      <Sidebar 
          activePatients={activePatients}
          selectedPatientId={selectedPatientId}
          onSelectPatient={(id) => { setSelectedPatientId(id); setView('PATIENT_DETAIL'); }}
          onRemoveActive={(id, e) => {
              e.stopPropagation();
              setActivePatientIds(prev => prev.filter(p => p !== id));
              if (selectedPatientId === id) { setSelectedPatientId(null); setView('HOME'); }
          }}
          onGoHome={handleGoHome}
      />

      <div className="flex-1 flex flex-col h-full overflow-hidden relative">
        {view === 'HOME' ? (
            <PatientList 
                patients={patients} 
                onSelectPatient={handleSelectPatient} 
                onAddPatient={handleAddPatient}
                onUpdatePatient={handleUpdatePatient}
                onDeletePatient={handleDeletePatient}
            />
        ) : currentPatient && (
            <PatientDetail 
                patient={currentPatient}
                role={currentRole}
                onUpdatePatient={handleUpdatePatient}
            />
        )}
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Patient, RoutineExercise, Stage, UserRole, RoutineDay } from '../types';
import { EXERCISES } from '../constants';
import { ExerciseCard } from './ExerciseCard';
import { ProgressChart } from './ProgressChart';
import { FileText, Plus, Search, X, LayoutGrid, Settings, CheckSquare, Square, Calendar, Trash2 } from 'lucide-react';

interface PatientDetailProps {
  patient: Patient;
  role: UserRole;
  onUpdatePatient: (updated: Patient) => void;
}

export const PatientDetail: React.FC<PatientDetailProps> = ({
  patient,
  role,
  onUpdatePatient,
}) => {
  const [activeDayId, setActiveDayId] = useState<string>(patient.routine.days[0]?.id || '');
  const [viewMode, setViewMode] = useState<'daily' | 'weekly' | 'monthly'>('daily');
  const [showHistory, setShowHistory] = useState<boolean>(false);
  const [showRoutineEditor, setShowRoutineEditor] = useState<boolean>(false);
  const [chartExercise, setChartExercise] = useState<RoutineExercise | null>(null);
  const [isAddingExercise, setIsAddingExercise] = useState(false);
  const [exerciseSearch, setExerciseSearch] = useState('');
  const [selectedExerciseIds, setSelectedExerciseIds] = useState<string[]>([]);
  const [notes, setNotes] = useState(patient.history[0] || '');

  const isKine = role === UserRole.KINE;
  const isReadOnly = role === UserRole.PATIENT || role === UserRole.ADMIN;

  useEffect(() => {
    if (patient.routine.days.length > 0 && (!activeDayId || !patient.routine.days.find(d => d.id === activeDayId))) {
        setActiveDayId(patient.routine.days[0].id);
    }
  }, [patient, activeDayId]);

  const activeDay = patient.routine.days.find(d => d.id === activeDayId);

  const handleExerciseUpdate = (exerciseId: string, updates: Partial<RoutineExercise>) => {
    const newDays = patient.routine.days.map(day => ({
        ...day,
        exercises: day.exercises.map(ex => ex.id === exerciseId ? { ...ex, ...updates } : ex)
    }));
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  const handleRemoveExercise = (exerciseId: string) => {
    if (isReadOnly) return;
    const newDays = patient.routine.days.map(day => ({
        ...day,
        exercises: day.exercises.filter(ex => ex.id !== exerciseId)
    }));
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  const handleUpdateStage = (newStage: Stage) => {
    onUpdatePatient({ ...patient, routine: { ...patient.routine, stage: newStage } });
  };

  const handleAddDay = () => {
    const newDay: RoutineDay = {
      id: `day-${Date.now()}`,
      name: `Día ${patient.routine.days.length + 1}`,
      exercises: []
    };
    onUpdatePatient({ 
      ...patient, 
      routine: { ...patient.routine, days: [...patient.routine.days, newDay] } 
    });
  };

  const handleRemoveDay = (dayId: string) => {
    if (patient.routine.days.length <= 1) return;
    const newDays = patient.routine.days.filter(d => d.id !== dayId);
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  const handleRenameDay = (dayId: string, newName: string) => {
    const newDays = patient.routine.days.map(d => d.id === dayId ? { ...d, name: newName } : d);
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  return (
    <div className="flex-1 h-full flex flex-col bg-slate-50 overflow-hidden relative">
      {/* Header con Safe Area support */}
      <header className="bg-white border-b border-slate-200 px-4 md:px-6 py-4 flex items-center justify-between shadow-sm shrink-0 z-20 pt-[calc(1rem+var(--sat))]">
        <div className="flex flex-col min-w-0">
          <h2 className="text-xl font-bold text-slate-900 leading-none truncate">
            {patient.firstName} {patient.lastName}
          </h2>
          <div className="flex items-center gap-2 mt-2">
              <span className={`px-2 py-0.5 rounded-full text-[10px] font-bold uppercase border ${patient.routine.stage === Stage.KINESIOLOGY ? 'bg-kine/10 text-kine border-kine/20' : 'bg-gym/10 text-gym border-gym/20'}`}>
                  {patient.routine.stage}
              </span>
              <span className="text-[10px] text-slate-400 truncate hidden xs:inline">• {patient.condition} • {patient.age} años</span>
          </div>
        </div>
        <div className="flex gap-2">
            {isKine && (
                <button onClick={() => setShowRoutineEditor(true)} className="p-2 md:px-4 md:py-2 bg-primary-600 text-white rounded-lg font-bold shadow-md hover:bg-primary-700 transition-all flex items-center shrink-0">
                    <Settings size={18} />
                    <span className="hidden md:inline ml-2 text-sm">Editar Rutina</span>
                </button>
            )}
            <button onClick={() => setShowHistory(!showHistory)} className={`p-2 md:px-4 md:py-2 rounded-lg font-bold transition-colors flex items-center shrink-0 ${showHistory ? 'bg-slate-800 text-white' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'}`}>
                <FileText size={18} />
                <span className="hidden md:inline ml-2 text-sm">{showHistory ? 'Cerrar' : 'Ficha'}</span>
            </button>
        </div>
      </header>

      {/* Panel de Evolución */}
      {showHistory && (
          <div className="bg-slate-800 text-slate-200 px-6 py-6 shadow-inner shrink-0 border-b border-slate-700 overflow-y-auto max-h-[35vh]">
              <div className="grid grid-cols-1 md:grid-cols-3 gap-6 max-w-5xl mx-auto">
                  <div className="space-y-1">
                       <h4 className="text-slate-400 text-[10px] uppercase font-bold mb-2">Datos Clínicos</h4>
                       <p className="text-xs">Última Visita: <span className="font-mono text-primary-400">{patient.lastVisit}</span></p>
                       <p className="text-xs">Edad: {patient.age} años</p>
                  </div>
                  <div className="md:col-span-2">
                      <h4 className="text-slate-400 text-[10px] uppercase font-bold mb-2">Evolución / Notas</h4>
                      <textarea 
                        readOnly={isReadOnly}
                        className="w-full h-24 bg-slate-700 text-slate-200 p-3 rounded-xl border border-slate-600 focus:ring-2 focus:ring-primary-500 outline-none resize-none text-sm" 
                        value={notes} 
                        onChange={(e) => setNotes(e.target.value)} 
                        placeholder="Escriba aquí la evolución..." 
                      />
                  </div>
              </div>
          </div>
      )}

      {/* Editor de Rutina Modal */}
      {showRoutineEditor && (
        <div className="fixed inset-0 z-[300] bg-black/50 backdrop-blur-sm flex items-center justify-center p-4">
            <div className="bg-white rounded-3xl p-6 w-full max-w-md space-y-6 shadow-2xl animate-in zoom-in-95">
                <div className="flex justify-between items-center">
                    <h3 className="font-bold text-xl text-slate-900">Configurar Rutina</h3>
                    <button onClick={() => setShowRoutineEditor(false)} className="p-2 hover:bg-slate-100 rounded-full"><X size={20}/></button>
                </div>

                <div className="space-y-3">
                    <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Etapa</label>
                    <div className="grid grid-cols-2 gap-3">
                        <button onClick={() => handleUpdateStage(Stage.KINESIOLOGY)} className={`p-4 rounded-xl border-2 font-bold transition-all ${patient.routine.stage === Stage.KINESIOLOGY ? 'border-kine bg-kine/5 text-kine' : 'border-slate-100 text-slate-400'}`}>Kinesiología</button>
                        <button onClick={() => handleUpdateStage(Stage.GYM)} className={`p-4 rounded-xl border-2 font-bold transition-all ${patient.routine.stage === Stage.GYM ? 'border-gym bg-gym/5 text-gym' : 'border-slate-100 text-slate-400'}`}>Gimnasio</button>
                    </div>
                </div>

                <div className="space-y-3">
                    <div className="flex justify-between items-center">
                        <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Días de Entrenamiento</label>
                        <button onClick={handleAddDay} className="text-primary-600 font-bold text-xs flex items-center gap-1"><Plus size={14}/> Nuevo Día</button>
                    </div>
                    <div className="max-h-52 overflow-y-auto space-y-2 pr-2 no-scrollbar">
                        {patient.routine.days.map((day) => (
                            <div key={day.id} className="flex items-center gap-2 p-2 bg-slate-50 rounded-xl border border-slate-100">
                                <input 
                                    className="flex-1 bg-transparent border-none font-bold text-sm text-slate-700 focus:ring-0 px-2"
                                    value={day.name}
                                    onChange={(e) => handleRenameDay(day.id, e.target.value)}
                                />
                                <button onClick={() => handleRemoveDay(day.id)} className={`p-2 text-slate-300 hover:text-red-500 ${patient.routine.days.length <= 1 ? 'hidden' : ''}`}><Trash2 size={16}/></button>
                            </div>
                        ))}
                    </div>
                </div>

                <button onClick={() => setShowRoutineEditor(false)} className="w-full bg-slate-900 text-white font-bold py-4 rounded-2xl hover:bg-slate-800 transition-colors">
                    Guardar y Cerrar
                </button>
            </div>
        </div>
      )}

      {/* Tabs de Días (Scrollable horizontal) */}
      <div className="bg-white border-b border-slate-200 px-4 md:px-6 flex justify-between pt-4 shrink-0 overflow-x-auto no-scrollbar">
          <div className="flex gap-1">
            {patient.routine.days.map((day) => (
              <button key={day.id} onClick={() => {setActiveDayId(day.id); setViewMode('daily');}} className={`px-6 py-3 rounded-t-xl font-bold text-sm transition-all border-t border-x whitespace-nowrap ${activeDayId === day.id && viewMode === 'daily' ? 'bg-slate-50 border-slate-200 text-primary-600' : 'bg-white border-transparent text-slate-400'}`}>
                {day.name}
              </button>
            ))}
          </div>
          <div className="flex items-center gap-2 pb-2 pl-4 border-l ml-2 shrink-0">
              <button onClick={() => setViewMode('weekly')} className={`p-2 rounded-lg ${viewMode === 'weekly' ? 'bg-primary-100 text-primary-700' : 'text-slate-400'}`}><LayoutGrid size={16}/></button>
              <button onClick={() => setViewMode('monthly')} className={`p-2 rounded-lg ${viewMode === 'monthly' ? 'bg-primary-100 text-primary-700' : 'text-slate-400'}`}><Calendar size={16}/></button>
          </div>
      </div>

      <main className="flex-1 overflow-y-auto p-4 md:p-8 no-scrollbar">
        <div className="max-w-3xl mx-auto pb-32">
          {viewMode === 'daily' && activeDay && (
              <div className="space-y-4">
                  {activeDay.exercises.map(ex => (
                      <ExerciseCard 
                        key={ex.id} 
                        exercise={ex} 
                        role={role}
                        onUpdate={handleExerciseUpdate} 
                        onShowHistory={(e) => setChartExercise(e)} 
                        onDelete={handleRemoveExercise} 
                      />
                  ))}
                  {isKine && (
                      <button onClick={() => setIsAddingExercise(true)} className="w-full py-6 rounded-3xl border-2 border-dashed border-slate-200 text-slate-400 font-bold flex items-center justify-center gap-2 hover:border-primary-300 hover:text-primary-500 hover:bg-primary-50 transition-all">
                          <Plus size={20} /> Agregar Ejercicio
                      </button>
                  )}
              </div>
          )}
        </div>
      </main>

      {chartExercise && <ProgressChart exercise={chartExercise} onClose={() => setChartExercise(null)} />}

      {/* Modal Agregar Ejercicio */}
      {isAddingExercise && (
          <div className="fixed inset-0 z-[250] bg-black/60 backdrop-blur-sm flex items-center justify-center p-4">
              <div className="bg-white w-full max-w-lg h-[80vh] rounded-3xl shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95">
                  <div className="p-4 border-b flex items-center justify-between">
                      <div className="relative flex-1 mr-4">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                        <input type="text" placeholder="Buscar ejercicio..." className="w-full pl-10 pr-4 py-2.5 bg-slate-50 rounded-xl outline-none" value={exerciseSearch} onChange={e => setExerciseSearch(e.target.value)} />
                      </div>
                      <button onClick={() => { setIsAddingExercise(false); setSelectedExerciseIds([]); }} className="p-2 bg-slate-100 rounded-full"><X size={20}/></button>
                  </div>
                  <div className="flex-1 overflow-y-auto p-4 space-y-2 no-scrollbar">
                      {EXERCISES.filter(ex => ex.name.toLowerCase().includes(exerciseSearch.toLowerCase())).map(ex => {
                          const isSelected = selectedExerciseIds.includes(ex.id);
                          return (
                              <button key={ex.id} onClick={() => setSelectedExerciseIds(prev => isSelected ? prev.filter(i => i !== ex.id) : [...prev, ex.id])} className={`w-full flex items-center p-3 rounded-2xl border transition-all ${isSelected ? 'bg-primary-50 border-primary-400' : 'bg-white border-transparent hover:bg-slate-50'}`}>
                                  {isSelected ? <CheckSquare size={20} className="text-primary-600 mr-3"/> : <Square size={20} className="text-slate-300 mr-3"/>}
                                  <img src={ex.videoUrl} className="w-12 h-12 rounded-lg object-cover mr-3" />
                                  <div className="text-left">
                                      <p className="font-bold text-slate-800 text-sm">{ex.name}</p>
                                      <span className="text-[10px] text-slate-400 uppercase font-bold">{ex.category}</span>
                                  </div>
                              </button>
                          );
                      })}
                  </div>
                  <div className="p-4 bg-slate-50 border-t flex justify-between items-center pb-[calc(1rem+var(--sab))]">
                        <span className="text-xs font-bold text-slate-500">{selectedExerciseIds.length} seleccionados</span>
                        <button 
                            disabled={selectedExerciseIds.length === 0}
                            className="bg-primary-600 text-white px-8 py-3 rounded-xl font-bold disabled:opacity-50 transition-all active:scale-95"
                            onClick={() => {
                                const newExs: RoutineExercise[] = selectedExerciseIds.map(id => ({
                                    id: `re-${Date.now()}-${id}`,
                                    definitionId: id,
                                    definition: EXERCISES.find(e => e.id === id)!,
                                    targetSets: 3, targetReps: 12, targetLoad: 0, isDone: false, history: []
                                }));
                                const newDays = patient.routine.days.map(d => d.id === activeDayId ? { ...d, exercises: [...d.exercises, ...newExs] } : d);
                                onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
                                setIsAddingExercise(false);
                                setSelectedExerciseIds([]);
                            }}
                        >
                            Confirmar
                        </button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

