import React, { useState, useEffect } from 'react';
import { Sidebar } from './components/Sidebar';
import { PatientList } from './components/PatientList';
import { PatientDetail } from './components/PatientDetail';
import { MOCK_PATIENTS } from './constants';
import { Patient, ViewState, UserRole } from './types';
import { db, isConfigValid } from './firebase';
import { 
  collection, 
  onSnapshot, 
  doc, 
  updateDoc,
  setDoc,
  deleteDoc,
  query
} from 'firebase/firestore';

const App: React.FC = () => {
  const [patients, setPatients] = useState<Patient[]>([]);
  const [loading, setLoading] = useState(true);
  const [activePatientIds, setActivePatientIds] = useState<string[]>([]);
  const [selectedPatientId, setSelectedPatientId] = useState<string | null>(null);
  const [view, setView] = useState<ViewState>('HOME');
  const [currentRole] = useState<UserRole>(UserRole.KINE);

  useEffect(() => {
    if (!isConfigValid || !db) {
      setPatients(MOCK_PATIENTS);
      setLoading(false);
      return;
    }

    const q = query(collection(db, 'patients'));
    const unsubscribe = onSnapshot(q, (snapshot) => {
      const patientsData: Patient[] = [];
      snapshot.forEach((doc) => {
        patientsData.push(doc.data() as Patient);
      });
      setPatients(patientsData.length > 0 ? patientsData : MOCK_PATIENTS);
      setLoading(false);
    }, (error) => {
      console.error("Firestore Error:", error);
      setPatients(MOCK_PATIENTS);
      setLoading(false);
    });

    return () => unsubscribe();
  }, []);

  const handleSelectPatient = (patient: Patient) => {
    if (!activePatientIds.includes(patient.id)) {
      setActivePatientIds(prev => [patient.id, ...prev]);
    }
    setSelectedPatientId(patient.id);
    setView('PATIENT_DETAIL');
  };

  const handleAddPatient = async (newPatient: Patient) => {
    if (isConfigValid && db) {
      try {
        await setDoc(doc(db, 'patients', newPatient.id), newPatient);
      } catch (e) { console.error(e); }
    } else {
      setPatients(prev => [...prev, newPatient]);
    }
  };

  const handleUpdatePatient = async (updatedPatient: Patient) => {
    if (isConfigValid && db) {
      try {
        await updateDoc(doc(db, 'patients', updatedPatient.id), { ...updatedPatient });
      } catch (e) { console.error(e); }
    } else {
      setPatients(prev => prev.map(p => p.id === updatedPatient.id ? updatedPatient : p));
    }
  };

  const handleDeletePatient = async (patientId: string) => {
    if (isConfigValid && db) {
      try {
        await deleteDoc(doc(db, 'patients', patientId));
      } catch (e) { console.error(e); }
    } else {
      setPatients(prev => prev.filter(p => p.id !== patientId));
    }
  };

  const activePatients = activePatientIds
    .map(id => patients.find(p => p.id === id))
    .filter((p): p is Patient => !!p);

  const currentPatient = patients.find(p => p.id === selectedPatientId);

  if (loading) {
    return (
      <div className="h-screen w-full flex items-center justify-center bg-slate-50">
        <div className="flex flex-col items-center gap-4 animate-pulse">
          <div className="w-16 h-16 bg-primary-600 rounded-2xl flex items-center justify-center shadow-xl">
             <div className="w-8 h-8 border-4 border-white border-t-transparent rounded-full animate-spin"></div>
          </div>
          <p className="text-slate-400 font-bold tracking-widest text-xs uppercase">KineFlow Pro</p>
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col md:flex-row w-full h-[100dvh] bg-slate-50 overflow-hidden">
      <Sidebar 
          activePatients={activePatients}
          selectedPatientId={selectedPatientId}
          onSelectPatient={(id) => { setSelectedPatientId(id); setView('PATIENT_DETAIL'); }}
          onRemoveActive={(id, e) => {
              e.stopPropagation();
              setActivePatientIds(prev => prev.filter(p => p !== id));
              if (selectedPatientId === id) { setSelectedPatientId(null); setView('HOME'); }
          }}
          onGoHome={() => { setView('HOME'); setSelectedPatientId(null); }}
      />

      <main className="flex-1 flex flex-col h-full overflow-hidden relative">
        {view === 'HOME' ? (
            <PatientList 
                patients={patients} 
                onSelectPatient={handleSelectPatient} 
                onAddPatient={handleAddPatient}
                onUpdatePatient={handleUpdatePatient}
                onDeletePatient={handleDeletePatient}
            />
        ) : currentPatient && (
            <PatientDetail 
                patient={currentPatient}
                role={currentRole}
                onUpdatePatient={handleUpdatePatient}
            />
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Patient, RoutineExercise, Stage, UserRole, RoutineDay } from '../types';
import { EXERCISES } from '../constants';
import { ExerciseCard } from './ExerciseCard';
import { ProgressChart } from './ProgressChart';
import { 
    FileText, Plus, Search, X, LayoutGrid, Settings, 
    CheckSquare, Square, Calendar, Trash2, Edit2, ChevronDown 
} from 'lucide-react';

interface PatientDetailProps {
  patient: Patient;
  role: UserRole;
  onUpdatePatient: (updated: Patient) => void;
}

export const PatientDetail: React.FC<PatientDetailProps> = ({
  patient,
  role,
  onUpdatePatient,
}) => {
  const [activeDayId, setActiveDayId] = useState<string>(patient.routine.days[0]?.id || '');
  const [viewMode, setViewMode] = useState<'daily' | 'weekly'>('daily');
  const [showHistory, setShowHistory] = useState(false);
  const [showRoutineEditor, setShowRoutineEditor] = useState(false);
  const [chartExercise, setChartExercise] = useState<RoutineExercise | null>(null);

  // States para el Routine Studio
  const [isAddingExerciseModal, setIsAddingExerciseModal] = useState<{show: boolean, dayId: string}>({show: false, dayId: ''});
  const [exerciseSearch, setExerciseSearch] = useState('');
  const [selectedExerciseIds, setSelectedExerciseIds] = useState<string[]>([]);
  const [notes, setNotes] = useState(patient.history[0] || '');

  const isKine = role === UserRole.KINE;
  const isReadOnly = role === UserRole.PATIENT || role === UserRole.ADMIN;

  useEffect(() => {
    if (patient.routine.days.length > 0 && (!activeDayId || !patient.routine.days.find(d => d.id === activeDayId))) {
        setActiveDayId(patient.routine.days[0].id);
    }
  }, [patient, activeDayId]);

  const activeDay = patient.routine.days.find(d => d.id === activeDayId);

  // Handlers
  const handleExerciseUpdate = (exerciseId: string, updates: Partial<RoutineExercise>) => {
    const newDays = patient.routine.days.map(day => ({
        ...day,
        exercises: day.exercises.map(ex => ex.id === exerciseId ? { ...ex, ...updates } : ex)
    }));
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  const handleRemoveExercise = (dayId: string, exerciseId: string) => {
    const newDays = patient.routine.days.map(day => 
        day.id === dayId ? { ...day, exercises: day.exercises.filter(ex => ex.id !== exerciseId) } : day
    );
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  const handleUpdateStage = (newStage: Stage) => {
    onUpdatePatient({ ...patient, routine: { ...patient.routine, stage: newStage } });
  };

  const handleAddDay = () => {
    const newDay: RoutineDay = {
      id: `day-${Date.now()}`,
      name: `Día ${patient.routine.days.length + 1}`,
      exercises: []
    };
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: [...patient.routine.days, newDay] } });
  };

  const handleRemoveDay = (dayId: string) => {
    if (patient.routine.days.length <= 1) return;
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: patient.routine.days.filter(d => d.id !== dayId) } });
  };

  return (
    <div className="flex-1 h-full flex flex-col bg-slate-50 overflow-hidden relative">
      {/* Header Principal con Safe Area */}
      <header className="bg-white border-b border-slate-200 px-4 md:px-6 py-4 flex items-center justify-between shadow-sm shrink-0 z-30 pt-[calc(1rem+var(--sat))]">
        <div className="flex flex-col min-w-0">
          <h2 className="text-xl font-black text-slate-900 leading-tight truncate">
            {patient.firstName} {patient.lastName}
          </h2>
          <div className="flex items-center gap-2 mt-1">
              <span className={`px-2 py-0.5 rounded-full text-[10px] font-bold uppercase border ${patient.routine.stage === Stage.KINESIOLOGY ? 'bg-kine/10 text-kine border-kine/20' : 'bg-gym/10 text-gym border-gym/20'}`}>
                  {patient.routine.stage}
              </span>
              <span className="text-[10px] text-slate-400 font-bold">• {patient.condition}</span>
          </div>
        </div>
        <div className="flex gap-2">
            {isKine && (
                <button onClick={() => setShowRoutineEditor(true)} className="flex items-center gap-2 bg-slate-900 text-white px-4 py-2.5 rounded-xl font-bold text-sm shadow-lg hover:scale-[1.02] transition-transform">
                    <LayoutGrid size={18} />
                    <span className="hidden xs:inline">Gestionar Rutina</span>
                </button>
            )}
            <button onClick={() => setShowHistory(!showHistory)} className={`p-2.5 rounded-xl border transition-all ${showHistory ? 'bg-slate-100 border-slate-300' : 'bg-white border-slate-200 shadow-sm'}`}>
                <FileText size={20} className={showHistory ? 'text-slate-900' : 'text-slate-400'} />
            </button>
        </div>
      </header>

      {/* Panel de Evolución */}
      {showHistory && (
          <div className="bg-slate-900 text-white p-6 shadow-2xl z-20 overflow-y-auto max-h-[40vh] border-b border-slate-800">
              <div className="max-w-4xl mx-auto space-y-4">
                  <div className="flex justify-between items-center">
                    <h4 className="text-[10px] uppercase font-black text-slate-500 tracking-widest">Ficha Clínica</h4>
                    <span className="text-[10px] bg-slate-800 px-2 py-1 rounded text-primary-400 font-mono uppercase">V-ID: {patient.id.slice(0,6)}</span>
                  </div>
                  <textarea 
                    readOnly={isReadOnly}
                    className="w-full h-32 bg-slate-800 text-slate-200 p-4 rounded-2xl border border-slate-700 focus:ring-2 focus:ring-primary-500 outline-none resize-none text-sm font-medium" 
                    value={notes} 
                    onChange={(e) => setNotes(e.target.value)} 
                    placeholder="Documentar evolución actual..." 
                  />
              </div>
          </div>
      )}

      {/* GESTOR DE RUTINA (MODAL FULLSCREEN) */}
      {showRoutineEditor && (
          <div className="fixed inset-0 z-[100] bg-slate-50 flex flex-col pt-[var(--sat)] animate-in slide-in-from-bottom-10 duration-300">
              <header className="bg-white border-b border-slate-200 px-6 py-4 flex items-center justify-between shadow-sm">
                  <div>
                    <h3 className="text-xl font-black text-slate-900">Routine Master Studio</h3>
                    <p className="text-xs text-slate-400 font-bold uppercase tracking-wider">Planificación avanzada</p>
                  </div>
                  <button onClick={() => setShowRoutineEditor(false)} className="bg-slate-100 p-2.5 rounded-full hover:bg-slate-200 transition-colors">
                      <X size={24} />
                  </button>
              </header>

              <div className="flex-1 overflow-y-auto p-4 md:p-8 scroll-container">
                  <div className="max-w-4xl mx-auto space-y-10 pb-20">

                      {/* Control de Etapa */}
                      <section className="space-y-4">
                          <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] px-2">Tratamiento</h4>
                          <div className="grid grid-cols-2 gap-4">
                              <button onClick={() => handleUpdateStage(Stage.KINESIOLOGY)} className={`p-6 rounded-3xl border-4 text-left transition-all ${patient.routine.stage === Stage.KINESIOLOGY ? 'border-kine bg-kine/5' : 'border-slate-100 bg-white'}`}>
                                  <div className={`w-10 h-10 rounded-xl mb-3 flex items-center justify-center ${patient.routine.stage === Stage.KINESIOLOGY ? 'bg-kine text-white' : 'bg-slate-100 text-slate-400'}`}><Settings size={20}/></div>
                                  <p className={`font-black text-lg ${patient.routine.stage === Stage.KINESIOLOGY ? 'text-kine' : 'text-slate-400'}`}>Kinesiología</p>
                                  <p className="text-xs text-slate-400 font-medium mt-1">Control motor, dolor y movilidad.</p>
                              </button>
                              <button onClick={() => handleUpdateStage(Stage.GYM)} className={`p-6 rounded-3xl border-4 text-left transition-all ${patient.routine.stage === Stage.GYM ? 'border-gym bg-gym/5' : 'border-slate-100 bg-white'}`}>
                                  <div className={`w-10 h-10 rounded-xl mb-3 flex items-center justify-center ${patient.routine.stage === Stage.GYM ? 'bg-gym text-white' : 'bg-slate-100 text-slate-400'}`}><LayoutGrid size={20}/></div>
                                  <p className={`font-black text-lg ${patient.routine.stage === Stage.GYM ? 'text-gym' : 'text-slate-400'}`}>Gimnasio</p>
                                  <p className="text-xs text-slate-400 font-medium mt-1">Fuerza, carga progresiva e hipertrofia.</p>
                              </button>
                          </div>
                      </section>

                      {/* Control de Días y Ejercicios */}
                      <section className="space-y-4">
                          <div className="flex justify-between items-center px-2">
                              <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Estructura de Entrenamiento</h4>
                              <button onClick={handleAddDay} className="flex items-center gap-1.5 text-primary-600 font-black text-xs uppercase hover:bg-primary-50 px-3 py-1.5 rounded-lg transition-colors">
                                  <Plus size={16} /> Nuevo Día
                              </button>
                          </div>

                          <div className="space-y-6">
                              {patient.routine.days.map((day, dIdx) => (
                                  <div key={day.id} className="bg-white rounded-[2.5rem] p-6 shadow-sm border border-slate-100 space-y-4">
                                      <div className="flex items-center justify-between border-b border-slate-50 pb-4">
                                          <div className="flex items-center gap-3">
                                              <span className="w-8 h-8 rounded-full bg-slate-900 text-white flex items-center justify-center text-xs font-black">{dIdx + 1}</span>
                                              <input 
                                                className="font-black text-xl text-slate-800 bg-transparent border-none focus:ring-0 w-full"
                                                value={day.name}
                                                onChange={(e) => handleRenameDay(day.id, e.target.value)}
                                              />
                                          </div>
                                          <button onClick={() => handleRemoveDay(day.id)} className="p-2 text-slate-200 hover:text-red-500"><Trash2 size={20}/></button>
                                      </div>

                                      <div className="space-y-2">
                                          {day.exercises.map((ex, eIdx) => (
                                              <div key={ex.id} className="flex items-center justify-between p-3 bg-slate-50 rounded-2xl group hover:bg-slate-100 transition-colors">
                                                  <div className="flex items-center gap-3">
                                                      <span className="text-[10px] font-black text-slate-300 w-4">{eIdx + 1}</span>
                                                      <img src={ex.definition.videoUrl} className="w-10 h-10 rounded-lg object-cover bg-slate-200" />
                                                      <div>
                                                          <p className="font-bold text-sm text-slate-800">{ex.definition.name}</p>
                                                          <p className="text-[9px] text-slate-400 uppercase font-black">{ex.targetSets}x{ex.targetReps} • {ex.targetLoad}kg</p>
                                                      </div>
                                                  </div>
                                                  <button onClick={() => handleRemoveExercise(day.id, ex.id)} className="opacity-0 group-hover:opacity-100 p-2 text-red-400 hover:bg-red-50 rounded-xl transition-all"><Trash2 size={16}/></button>
                                              </div>
                                          ))}

                                          <button 
                                            onClick={() => setIsAddingExerciseModal({show: true, dayId: day.id})}
                                            className="w-full py-4 rounded-2xl border-2 border-dashed border-slate-100 text-slate-400 font-bold text-xs flex items-center justify-center gap-2 hover:border-primary-200 hover:text-primary-600 hover:bg-primary-50 transition-all"
                                          >
                                              <Plus size={16} /> Agregar ejercicio al {day.name}
                                          </button>
                                      </div>
                                  </div>
                              ))}
                          </div>
                      </section>
                  </div>
              </div>

              <div className="bg-white border-t border-slate-200 p-6 flex justify-center pb-[calc(1.5rem+var(--sab))]">
                  <button onClick={() => setShowRoutineEditor(false)} className="bg-primary-600 text-white w-full max-w-sm py-4 rounded-2xl font-black text-lg shadow-xl shadow-primary-200 hover:scale-105 active:scale-95 transition-all">
                      Confirmar Plan Maestro
                  </button>
              </div>
          </div>
      )}

      {/* Tabs de Días (Vista de Uso Diario) */}
      <div className="bg-white border-b border-slate-200 px-4 md:px-6 flex justify-between pt-4 shrink-0 overflow-x-auto no-scrollbar">
          <div className="flex gap-1">
            {patient.routine.days.map((day) => (
              <button key={day.id} onClick={() => {setActiveDayId(day.id); setViewMode('daily');}} className={`px-6 py-3 rounded-t-xl font-black text-xs uppercase tracking-widest transition-all border-t border-x whitespace-nowrap ${activeDayId === day.id && viewMode === 'daily' ? 'bg-slate-50 border-slate-200 text-primary-600 shadow-sm' : 'bg-white border-transparent text-slate-400 opacity-50'}`}>
                {day.name}
              </button>
            ))}
          </div>
          <div className="flex items-center gap-2 pb-2 pl-4 border-l ml-2 shrink-0">
              <button onClick={() => setViewMode('weekly')} className={`p-2.5 rounded-xl ${viewMode === 'weekly' ? 'bg-primary-100 text-primary-700' : 'text-slate-400'}`}><Calendar size={18}/></button>
          </div>
      </div>

      <main className="flex-1 overflow-y-auto p-4 md:p-8 scroll-container">
        <div className="max-w-3xl mx-auto pb-32">
          {viewMode === 'daily' && activeDay ? (
              <div className="space-y-4">
                  {activeDay.exercises.map(ex => (
                      <ExerciseCard 
                        key={ex.id} 
                        exercise={ex} 
                        role={role}
                        onUpdate={(id, up) => handleExerciseUpdate(id, up)} 
                        onShowHistory={(e) => setChartExercise(e)} 
                        onDelete={(id) => handleRemoveExercise(activeDayId, id)} 
                      />
                  ))}
                  {activeDay.exercises.length === 0 && (
                      <div className="text-center py-20 bg-white rounded-[2rem] border-2 border-dashed border-slate-200">
                          <p className="text-slate-300 font-bold uppercase text-xs tracking-widest mb-4">Día vacío</p>
                          <button onClick={() => setShowRoutineEditor(true)} className="bg-slate-900 text-white px-6 py-3 rounded-2xl font-black text-sm">Configurar ahora</button>
                      </div>
                  )}
              </div>
          ) : (
              <div className="text-center py-20 bg-white rounded-[2rem] shadow-sm">
                  <p className="text-slate-400 font-bold">Vista Semanal en desarrollo...</p>
              </div>
          )}
        </div>
      </main>

      {chartExercise && <ProgressChart exercise={chartExercise} onClose={() => setChartExercise(null)} />}

      {/* Modal Librería de Ejercicios */}
      {isAddingExerciseModal.show && (
          <div className="fixed inset-0 z-[350] bg-black/60 backdrop-blur-md flex items-center justify-center p-4">
              <div className="bg-white w-full max-w-lg h-[85vh] rounded-[3rem] shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95">
                  <div className="p-6 border-b flex items-center justify-between bg-slate-50">
                      <div className="relative flex-1 mr-4">
                        <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
                        <input type="text" placeholder="Buscar ejercicio..." className="w-full pl-12 pr-4 py-3 bg-white border border-slate-200 rounded-2xl outline-none focus:ring-4 focus:ring-primary-100 transition-all font-bold" value={exerciseSearch} onChange={e => setExerciseSearch(e.target.value)} />
                      </div>
                      <button onClick={() => { setIsAddingExerciseModal({show:false, dayId:''}); setSelectedExerciseIds([]); }} className="p-3 bg-white border border-slate-200 rounded-full hover:bg-red-50 hover:text-red-500 transition-all"><X size={20}/></button>
                  </div>
                  <div className="flex-1 overflow-y-auto p-4 space-y-2 scroll-container">
                      {EXERCISES.filter(ex => ex.name.toLowerCase().includes(exerciseSearch.toLowerCase())).map(ex => {
                          const isSelected = selectedExerciseIds.includes(ex.id);
                          return (
                              <button key={ex.id} onClick={() => setSelectedExerciseIds(prev => isSelected ? prev.filter(i => i !== ex.id) : [...prev, ex.id])} className={`w-full flex items-center p-4 rounded-[1.5rem] border-2 transition-all ${isSelected ? 'bg-primary-50 border-primary-500' : 'bg-white border-slate-50 hover:border-slate-200'}`}>
                                  {isSelected ? <CheckSquare size={24} className="text-primary-600 mr-4"/> : <Square size={24} className="text-slate-200 mr-4"/>}
                                  <img src={ex.videoUrl} className="w-14 h-14 rounded-xl object-cover mr-4 shadow-sm" />
                                  <div className="text-left">
                                      <p className="font-black text-slate-800">{ex.name}</p>
                                      <span className="text-[9px] text-slate-400 uppercase font-black tracking-wider">{ex.category}</span>
                                  </div>
                              </button>
                          );
                      })}
                  </div>
                  <div className="p-6 bg-slate-50 border-t flex justify-between items-center pb-[calc(1.5rem+var(--sab))]">
                        <div>
                            <p className="text-xs font-black text-slate-800 uppercase">{selectedExerciseIds.length} seleccionados</p>
                        </div>
                        <button 
                            disabled={selectedExerciseIds.length === 0}
                            className="bg-primary-600 text-white px-10 py-4 rounded-2xl font-black shadow-lg disabled:opacity-30 disabled:grayscale transition-all active:scale-95"
                            onClick={() => {
                                const newExs: RoutineExercise[] = selectedExerciseIds.map(id => ({
                                    id: `re-${Date.now()}-${id}`,
                                    definitionId: id,
                                    definition: EXERCISES.find(e => e.id === id)!,
                                    targetSets: 3, targetReps: 12, targetLoad: 0, isDone: false, history: []
                                }));
                                const newDays = patient.routine.days.map(d => d.id === isAddingExerciseModal.dayId ? { ...d, exercises: [...d.exercises, ...newExs] } : d);
                                onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
                                setIsAddingExerciseModal({show:false, dayId:''});
                                setSelectedExerciseIds([]);
                            }}
                        >
                            Añadir al Plan
                        </button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

