            {patient.routine.days.map((day) => (
              <button 
                key={day.id} 
                onClick={() => {setActiveDayId(day.id); setViewMode('daily');}} 
                className={`px-6 py-3 rounded-t-2xl font-black text-[10px] uppercase tracking-[0.15em] transition-all border-t border-x whitespace-nowrap ${activeDayId === day.id && viewMode === 'daily' ? 'bg-slate-50 border-slate-200 text-primary-600 shadow-[0_-4px_10px_-5px_rgba(0,0,0,0.05)]' : 'bg-white border-transparent text-slate-400 opacity-60'}`}
              >
                {day.name}
              </button>
            ))}
          </div>
          <div className="flex items-center gap-2 pb-2 pl-4 border-l ml-2 shrink-0">
              <button 
                onClick={() => setViewMode('weekly')} 
                className={`p-2.5 rounded-2xl transition-all ${viewMode === 'weekly' ? 'bg-primary-100 text-primary-700 shadow-inner' : 'text-slate-400 hover:bg-slate-100'}`}
