                  <div className="flex-1 overflow-y-auto p-6 space-y-3 scroll-container">
                      {EXERCISES.filter(ex => 
                        ex.name.toLowerCase().includes(exerciseSearch.toLowerCase()) || 
                        ex.category.toLowerCase().includes(exerciseSearch.toLowerCase())
                      ).map(ex => {
                          const isSelected = selectedExerciseIds.includes(ex.id);
                          return (
                              <button 
                                key={ex.id} 
                                onClick={() => setSelectedExerciseIds(prev => isSelected ? prev.filter(i => i !== ex.id) : [...prev, ex.id])} 
                                className={`w-full flex items-center p-4 rounded-3xl border-2 transition-all active:scale-[0.98] ${isSelected ? 'bg-primary-50 border-primary-500' : 'bg-white border-slate-50 hover:border-slate-200'}`}
                              >
                                  <div className={`mr-5 transition-transform ${isSelected ? 'scale-110' : ''}`}>
                                    {isSelected ? <CheckSquare size={26} className="text-primary-600"/> : <Square size={26} className="text-slate-200"/>}
                                  </div>
                                  <img src={ex.videoUrl} className="w-16 h-16 rounded-2xl object-cover mr-5 shadow-sm bg-slate-100" />
                                  <div className="text-left flex-1">
                                      <p className="font-black text-slate-800 text-base">{ex.name}</p>
                                      <span className="text-[10px] text-slate-400 uppercase font-black tracking-widest">{ex.category}</span>
                                  </div>
                              </button>
                          );
                      })}
                  </div>

                  <div className="p-8 bg-white border-t border-slate-100 flex justify-between items-center pb-[calc(2rem+var(--sab))] shadow-[0_-20px_50px_-20px_rgba(0,0,0,0.05)]">
                        <div>
                            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Seleccionados</p>
                            <p className="text-2xl font-black text-slate-900">{selectedExerciseIds.length}</p>
                        </div>
                        <button 
                            disabled={selectedExerciseIds.length === 0}
                            className="bg-primary-600 text-white px-12 py-5 rounded-[2rem] font-black shadow-2xl shadow-primary-200 disabled:opacity-20 disabled:grayscale transition-all active:scale-95 flex items-center gap-3"
                            onClick={() => {
                                const newExs: RoutineExercise[] = selectedExerciseIds.map(id => ({
                                    id: `re-${Date.now()}-${id}-${Math.random()}`,
                                    definitionId: id,
                                    definition: EXERCISES.find(e => e.id === id)!,
                                    targetSets: 3, targetReps: 12, targetLoad: 0, isDone: false, history: []
                                }));
                                const newDays = patient.routine.days.map(d => d.id === isAddingExerciseModal.dayId ? { ...d, exercises: [...d.exercises, ...newExs] } : d);
                                onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
                                setIsAddingExerciseModal({show:false, dayId:''});
                                setSelectedExerciseIds([]);
                            }}
                        >
                            Añadir al Plan <Plus size={20} />
                        </button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

