import React, { useState, useEffect } from 'react';
import { Patient, RoutineExercise, Stage, UserRole, RoutineDay } from '../types';
import { EXERCISES } from '../constants';
import { ExerciseCard } from './ExerciseCard';
import { ProgressChart } from './ProgressChart';
import { 
    FileText, Plus, Search, X, LayoutGrid, Settings, 
    CheckSquare, Square, Calendar, Trash2, Edit2, ChevronDown, Save, Copy, Activity
} from 'lucide-react';

interface PatientDetailProps {
  patient: Patient;
  role: UserRole;
  onUpdatePatient: (updated: Patient) => void;
}

export const PatientDetail: React.FC<PatientDetailProps> = ({
  patient,
  role,
  onUpdatePatient,
}) => {
  const [activeDayId, setActiveDayId] = useState<string>(patient.routine.days[0]?.id || '');
  const [viewMode, setViewMode] = useState<'daily' | 'weekly'>('daily');
  const [showHistory, setShowHistory] = useState(false);
  const [showRoutineEditor, setShowRoutineEditor] = useState(false);
  const [chartExercise, setChartExercise] = useState<RoutineExercise | null>(null);

  const [isAddingExerciseModal, setIsAddingExerciseModal] = useState<{show: boolean, dayId: string}>({show: false, dayId: ''});
  const [exerciseSearch, setExerciseSearch] = useState('');
  const [selectedExerciseIds, setSelectedExerciseIds] = useState<string[]>([]);
  const [notes, setNotes] = useState(patient.history[0] || '');

  const isKine = role === UserRole.KINE;
  const isReadOnly = role === UserRole.PATIENT || role === UserRole.ADMIN;

  useEffect(() => {
    if (patient.routine.days.length > 0 && (!activeDayId || !patient.routine.days.find(d => d.id === activeDayId))) {
        setActiveDayId(patient.routine.days[0].id);
    }
  }, [patient, activeDayId]);

  const activeDay = patient.routine.days.find(d => d.id === activeDayId);

  const handleExerciseUpdate = (exerciseId: string, updates: Partial<RoutineExercise>) => {
    const newDays = patient.routine.days.map(day => ({
        ...day,
        exercises: day.exercises.map(ex => ex.id === exerciseId ? { ...ex, ...updates } : ex)
    }));
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  const handleRemoveExercise = (dayId: string, exerciseId: string) => {
    const newDays = patient.routine.days.map(day => 
        day.id === dayId ? { ...day, exercises: day.exercises.filter(ex => ex.id !== exerciseId) } : day
    );
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  const handleUpdateStage = (newStage: Stage) => {
    onUpdatePatient({ ...patient, routine: { ...patient.routine, stage: newStage } });
  };

  const handleAddDay = () => {
    const newDay: RoutineDay = {
      id: `day-${Date.now()}`,
      name: `Día ${patient.routine.days.length + 1}`,
      exercises: []
    };
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: [...patient.routine.days, newDay] } });
  };

  const handleRemoveDay = (dayId: string) => {
    if (patient.routine.days.length <= 1) return;
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: patient.routine.days.filter(d => d.id !== dayId) } });
  };

  const handleRenameDay = (dayId: string, newName: string) => {
    const newDays = patient.routine.days.map(day => 
      day.id === dayId ? { ...day, name: newName } : day
    );
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  return (
    <div className="flex-1 h-full flex flex-col bg-slate-50 overflow-hidden relative">
      <header className="bg-white border-b border-slate-200 px-4 md:px-6 py-4 flex items-center justify-between shadow-sm shrink-0 z-30 pt-[calc(1rem+var(--sat))]">
        <div className="flex flex-col min-w-0">
          <h2 className="text-xl font-black text-slate-900 leading-tight truncate">
            {patient.firstName} {patient.lastName}
          </h2>
          <div className="flex items-center gap-2 mt-1">
              <span className={`px-2 py-0.5 rounded-full text-[10px] font-black uppercase border ${patient.routine.stage === Stage.KINESIOLOGY ? 'bg-kine/10 text-kine border-kine/20' : 'bg-gym/10 text-gym border-gym/20'}`}>
                  {patient.routine.stage}
              </span>
              <span className="text-[10px] text-slate-400 font-bold">• {patient.condition}</span>
          </div>
        </div>
        <div className="flex gap-2">
            {isKine && (
                <button 
                  onClick={() => setShowRoutineEditor(true)} 
                  className="flex items-center gap-2 bg-slate-900 text-white px-5 py-2.5 rounded-2xl font-black text-sm shadow-xl hover:scale-105 active:scale-95 transition-all"
                >
                    <Edit2 size={18} />
                    <span className="hidden sm:inline">Editar Rutina</span>
                </button>
            )}
            <button 
              onClick={() => setShowHistory(!showHistory)} 
              className={`p-2.5 rounded-2xl border transition-all ${showHistory ? 'bg-primary-50 border-primary-200 text-primary-600' : 'bg-white border-slate-200 text-slate-400 hover:bg-slate-50'}`}
            >
                <FileText size={20} />
            </button>
        </div>
      </header>

      {showHistory && (
          <div className="bg-slate-900 text-white p-6 shadow-2xl z-20 overflow-y-auto max-h-[40vh] border-b border-slate-800 animate-in slide-in-from-top duration-300">
              <div className="max-w-4xl mx-auto space-y-4">
                  <div className="flex justify-between items-center">
                    <h4 className="text-[10px] uppercase font-black text-slate-500 tracking-widest">Evolución Clínica</h4>
                    <span className="text-[10px] bg-slate-800 px-2 py-1 rounded text-primary-400 font-mono">ID: {patient.id.slice(-6)}</span>
                  </div>
                  <textarea 
                    readOnly={isReadOnly}
                    className="w-full h-32 bg-slate-800/50 text-slate-200 p-4 rounded-3xl border border-slate-700 focus:ring-2 focus:ring-primary-500 outline-none resize-none text-sm font-medium transition-all" 
                    value={notes} 
                    onChange={(e) => setNotes(e.target.value)} 
                    placeholder="Documentar sesión actual..." 
                  />
                  <div className="flex justify-end">
                    <button className="flex items-center gap-2 text-[10px] font-black uppercase text-primary-400 hover:text-primary-300 transition-colors">
                        <Save size={14} /> Guardar Nota
                    </button>
                  </div>
              </div>
          </div>
      )}

      {showRoutineEditor && (
          <div className="fixed inset-0 z-[100] bg-slate-50 flex flex-col pt-[var(--sat)] animate-in slide-in-from-bottom-10 duration-500">
              <header className="bg-white border-b border-slate-200 px-6 py-5 flex items-center justify-between shadow-sm">
                  <div>
                    <h3 className="text-2xl font-black text-slate-900 flex items-center gap-3">
                        <Edit2 className="text-primary-500" /> Routine Studio
                    </h3>
                    <p className="text-xs text-slate-400 font-bold uppercase tracking-wider">Planificación estratégica de tratamiento</p>
                  </div>
                  <button onClick={() => setShowRoutineEditor(false)} className="bg-slate-100 p-3 rounded-full hover:bg-red-50 hover:text-red-500 transition-all">
                      <X size={24} />
                  </button>
              </header>

              <div className="flex-1 overflow-y-auto p-4 md:p-8 scroll-container">
                  <div className="max-w-6xl mx-auto space-y-12 pb-32">
                      <section className="space-y-4">
                          <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-2">1. Fase de Rehabilitación</h4>
                          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                              <button 
                                onClick={() => handleUpdateStage(Stage.KINESIOLOGY)} 
                                className={`group p-6 rounded-[2rem] border-4 text-left transition-all ${patient.routine.stage === Stage.KINESIOLOGY ? 'border-kine bg-kine/5' : 'border-white bg-white hover:border-slate-100'}`}
                              >
                                  <div className={`w-12 h-12 rounded-2xl mb-4 flex items-center justify-center transition-all ${patient.routine.stage === Stage.KINESIOLOGY ? 'bg-kine text-white rotate-3 shadow-lg shadow-kine/20' : 'bg-slate-100 text-slate-400'}`}>
                                      <Settings size={24}/>
                                  </div>
                                  <p className={`font-black text-xl ${patient.routine.stage === Stage.KINESIOLOGY ? 'text-kine' : 'text-slate-400'}`}>Kinesiología</p>
                                  <p className="text-sm text-slate-400 font-medium mt-1">Enfoque en control motor, alivio de dolor y rango articular.</p>
                              </button>
                              <button 
                                onClick={() => handleUpdateStage(Stage.GYM)} 
                                className={`group p-6 rounded-[2rem] border-4 text-left transition-all ${patient.routine.stage === Stage.GYM ? 'border-gym bg-gym/5' : 'border-white bg-white hover:border-slate-100'}`}
                              >
                                  <div className={`w-12 h-12 rounded-2xl mb-4 flex items-center justify-center transition-all ${patient.routine.stage === Stage.GYM ? 'bg-gym text-white -rotate-3 shadow-lg shadow-gym/20' : 'bg-slate-100 text-slate-400'}`}>
                                      <LayoutGrid size={24}/>
                                  </div>
                                  <p className={`font-black text-xl ${patient.routine.stage === Stage.GYM ? 'text-gym' : 'text-slate-400'}`}>Gimnasio</p>
                                  <p className="text-sm text-slate-400 font-medium mt-1">Fase de fortalecimiento, hipertrofia y retorno al deporte.</p>
                              </button>
                          </div>
                      </section>

                      <section className="space-y-6">
                          <div className="flex justify-between items-center px-2">
                              <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">2. Estructura Semanal</h4>
                              <button 
                                onClick={handleAddDay} 
                                className="flex items-center gap-2 bg-primary-50 text-primary-700 px-4 py-2 rounded-xl font-black text-xs uppercase hover:bg-primary-100 transition-colors"
                              >
                                  <Plus size={16} /> Añadir Día
                              </button>
                          </div>

                          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                              {patient.routine.days.map((day, dIdx) => (
                                  <div key={day.id} className="bg-white rounded-[2.5rem] p-6 shadow-sm border border-slate-100 flex flex-col h-full">
                                      <div className="flex items-center justify-between border-b border-slate-50 pb-5 mb-5">
                                          <div className="flex items-center gap-4 flex-1">
                                              <span className="w-10 h-10 rounded-2xl bg-slate-900 text-white flex items-center justify-center text-sm font-black shadow-lg">
                                                {dIdx + 1}
                                              </span>
                                              <input 
                                                className="font-black text-xl text-slate-800 bg-transparent border-none focus:ring-0 w-full p-0"
                                                value={day.name}
                                                onChange={(e) => handleRenameDay(day.id, e.target.value)}
                                                placeholder="Nombre del día..."
                                              />
                                          </div>
                                          <div className="flex items-center gap-1">
                                            <button onClick={() => handleRemoveDay(day.id)} className="p-2 text-slate-200 hover:text-red-500 transition-colors">
                                                <Trash2 size={22}/>
                                            </button>
                                          </div>
