import React, { useState, useEffect } from 'react';
import { Patient, RoutineExercise, Stage, UserRole, RoutineDay } from '../types';
import { EXERCISES } from '../constants';
import { ExerciseCard } from './ExerciseCard';
import { ProgressChart } from './ProgressChart';
import { 
    FileText, Plus, Search, X, LayoutGrid, Settings, 
    CheckSquare, Square, Calendar, Trash2, Edit2, Save, Activity
} from 'lucide-react';

interface PatientDetailProps {
  patient: Patient;
  role: UserRole;
  onUpdatePatient: (updated: Patient) => void;
}

export const PatientDetail: React.FC<PatientDetailProps> = ({
  patient,
  role,
  onUpdatePatient,
}) => {
  const [activeDayId, setActiveDayId] = useState<string>(patient.routine.days[0]?.id || '');
  const [viewMode, setViewMode] = useState<'daily' | 'weekly'>('daily');
  const [showHistory, setShowHistory] = useState(false);
  const [showRoutineEditor, setShowRoutineEditor] = useState(false);
  const [chartExercise, setChartExercise] = useState<RoutineExercise | null>(null);

  const [isAddingExerciseModal, setIsAddingExerciseModal] = useState<{show: boolean, dayId: string}>({show: false, dayId: ''});
  const [exerciseSearch, setExerciseSearch] = useState('');
  const [selectedExerciseIds, setSelectedExerciseIds] = useState<string[]>([]);
  const [notes, setNotes] = useState(patient.history[0] || '');

  const isKine = role === UserRole.KINE;
  const isReadOnly = role === UserRole.PATIENT || role === UserRole.ADMIN;

  useEffect(() => {
    if (patient.routine.days.length > 0 && (!activeDayId || !patient.routine.days.find(d => d.id === activeDayId))) {
        setActiveDayId(patient.routine.days[0].id);
    }
  }, [patient, activeDayId]);

  const activeDay = patient.routine.days.find(d => d.id === activeDayId);

  const handleExerciseUpdate = (exerciseId: string, updates: Partial<RoutineExercise>) => {
    const newDays = patient.routine.days.map(day => ({
        ...day,
        exercises: day.exercises.map(ex => ex.id === exerciseId ? { ...ex, ...updates } : ex)
    }));
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  const handleRemoveExercise = (dayId: string, exerciseId: string) => {
    const newDays = patient.routine.days.map(day => 
        day.id === dayId ? { ...day, exercises: day.exercises.filter(ex => ex.id !== exerciseId) } : day
    );
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  const handleUpdateStage = (newStage: Stage) => {
    onUpdatePatient({ ...patient, routine: { ...patient.routine, stage: newStage } });
  };

  const handleAddDay = () => {
    const newDay: RoutineDay = {
      id: `day-${Date.now()}`,
      name: `Día ${patient.routine.days.length + 1}`,
      exercises: []
    };
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: [...patient.routine.days, newDay] } });
  };

  const handleRemoveDay = (dayId: string) => {
    if (patient.routine.days.length <= 1) return;
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: patient.routine.days.filter(d => d.id !== dayId) } });
  };

  const handleRenameDay = (dayId: string, newName: string) => {
    const newDays = patient.routine.days.map(day => 
      day.id === dayId ? { ...day, name: newName } : day
    );
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  return (
    <div className="flex-1 h-full flex flex-col bg-slate-50 overflow-hidden relative">
      <header className="bg-white border-b border-slate-200 px-4 py-3 flex items-center justify-between shadow-sm shrink-0 z-30 pt-[calc(0.75rem+var(--sat))]">
        <div className="flex flex-col min-w-0">
          <h2 className="text-lg font-black text-slate-900 leading-tight truncate">
            {patient.firstName} {patient.lastName}
          </h2>
          <div className="flex items-center gap-2 mt-0.5">
              <span className={`px-1.5 py-0.5 rounded text-[9px] font-black uppercase ${patient.routine.stage === Stage.KINESIOLOGY ? 'bg-kine/10 text-kine' : 'bg-gym/10 text-gym'}`}>
                  {patient.routine.stage}
              </span>
              <span className="text-[9px] text-slate-400 font-bold">• {patient.condition}</span>
          </div>
        </div>
        <div className="flex gap-1.5">
            {isKine && (
                <button 
                  onClick={() => setShowRoutineEditor(true)} 
                  className="flex items-center gap-2 bg-slate-900 text-white px-3 py-2 rounded-xl font-bold text-xs hover:bg-slate-800 transition-all"
                >
                    <Edit2 size={14} />
                    <span className="hidden sm:inline">Rutina</span>
                </button>
            )}
            <button 
              onClick={() => setShowHistory(!showHistory)} 
              className={`p-2 rounded-xl border transition-all ${showHistory ? 'bg-primary-50 border-primary-200 text-primary-600' : 'bg-white border-slate-200 text-slate-400 hover:bg-slate-50'}`}
            >
                <FileText size={18} />
            </button>
        </div>
      </header>

      {showHistory && (
          <div className="bg-slate-900 text-white p-4 shadow-xl z-20 overflow-y-auto max-h-[30vh] border-b border-slate-800 animate-in slide-in-from-top duration-300">
              <div className="max-w-4xl mx-auto space-y-3">
                  <div className="flex justify-between items-center">
                    <h4 className="text-[9px] uppercase font-black text-slate-500 tracking-widest">Evolución Clínica</h4>
                    <button className="text-[9px] font-black uppercase text-primary-400 flex items-center gap-1"><Save size={10}/> Guardar</button>
                  </div>
                  <textarea 
                    readOnly={isReadOnly}
                    className="w-full h-24 bg-slate-800/50 text-slate-200 p-3 rounded-xl border border-slate-700 outline-none resize-none text-xs font-medium" 
                    value={notes} 
                    onChange={(e) => setNotes(e.target.value)} 
                    placeholder="Documentar sesión..." 
                  />
              </div>
          </div>
      )}

      {showRoutineEditor && (
          <div className="fixed inset-0 z-[100] bg-slate-50 flex flex-col pt-[var(--sat)] animate-in slide-in-from-bottom-5 duration-300">
              <header className="bg-white border-b border-slate-200 px-4 py-3 flex items-center justify-between">
                  <h3 className="text-lg font-black text-slate-900 flex items-center gap-2">
                      <Edit2 size={18} className="text-primary-500" /> Studio
                  </h3>
                  <button onClick={() => setShowRoutineEditor(false)} className="p-2 hover:bg-slate-100 rounded-full transition-all">
                      <X size={20} />
                  </button>
              </header>

              <div className="flex-1 overflow-x-auto p-4 scroll-container">
                  <div className="flex items-start gap-6 h-full min-w-max pb-10">

                      {/* Lado izquierdo: Configuración General */}
                      <div className="w-64 space-y-6 shrink-0">
                          <section className="bg-white p-4 rounded-2xl border border-slate-100 shadow-sm space-y-4">
                              <h4 className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Etapa del Plan</h4>
                              <div className="space-y-2">
                                  <button 
                                    onClick={() => handleUpdateStage(Stage.KINESIOLOGY)} 
                                    className={`w-full flex items-center gap-3 p-3 rounded-xl border-2 transition-all ${patient.routine.stage === Stage.KINESIOLOGY ? 'border-kine bg-kine/5' : 'border-slate-50'}`}
                                  >
                                      <Settings size={14} className={patient.routine.stage === Stage.KINESIOLOGY ? 'text-kine' : 'text-slate-300'}/>
                                      <span className={`font-bold text-xs ${patient.routine.stage === Stage.KINESIOLOGY ? 'text-kine' : 'text-slate-500'}`}>Kinesiología</span>
                                  </button>
                                  <button 
                                    onClick={() => handleUpdateStage(Stage.GYM)} 
                                    className={`w-full flex items-center gap-3 p-3 rounded-xl border-2 transition-all ${patient.routine.stage === Stage.GYM ? 'border-gym bg-gym/5' : 'border-slate-50'}`}
                                  >
                                      <LayoutGrid size={14} className={patient.routine.stage === Stage.GYM ? 'text-gym' : 'text-slate-300'}/>
                                      <span className={`font-bold text-xs ${patient.routine.stage === Stage.GYM ? 'text-gym' : 'text-slate-500'}`}>Gimnasio</span>
                                  </button>
                              </div>
                          </section>

                          <button 
                            onClick={handleAddDay} 
                            className="w-full py-3 bg-primary-600 text-white rounded-xl font-bold text-xs uppercase flex items-center justify-center gap-2 shadow-lg"
                          >
                            <Plus size={16} /> Nuevo Día
                          </button>
                      </div>

                      {/* Lado derecho: Columnas de Días (Side-by-side) */}
                      {patient.routine.days.map((day, dIdx) => (
                          <div key={day.id} className="w-80 bg-white rounded-2xl border border-slate-100 shadow-sm flex flex-col h-full shrink-0">
                              <div className="p-4 border-b border-slate-50 flex items-center justify-between">
                                  <input 
                                    className="font-black text-sm text-slate-800 bg-transparent border-none focus:ring-0 p-0 w-32"
                                    value={day.name}
                                    onChange={(e) => handleRenameDay(day.id, e.target.value)}
                                  />
                                  <button onClick={() => handleRemoveDay(day.id)} className="text-slate-200 hover:text-red-500"><Trash2 size={16}/></button>
                              </div>

                              <div className="flex-1 overflow-y-auto p-3 space-y-2 scroll-container">
                                  {day.exercises.map((ex, eIdx) => (
                                      <div key={ex.id} className="flex items-center justify-between p-2 bg-slate-50 rounded-xl group border border-transparent hover:border-slate-200">
                                          <div className="flex items-center gap-3">
                                              <img src={ex.definition.videoUrl} className="w-8 h-8 rounded-lg object-cover bg-slate-200" />
                                              <div className="min-w-0">
                                                  <p className="font-bold text-[11px] text-slate-800 truncate leading-none">{ex.definition.name}</p>
                                                  <p className="text-[9px] text-slate-400 mt-1 uppercase font-black">{ex.targetSets}x{ex.targetReps}</p>
                                              </div>
                                          </div>
                                          <button onClick={() => handleRemoveExercise(day.id, ex.id)} className="p-1 text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100"><X size={14}/></button>
                                      </div>
                                  ))}
                              </div>

                              <button 
                                onClick={() => setIsAddingExerciseModal({show: true, dayId: day.id})}
                                className="m-3 py-3 border border-dashed border-slate-200 rounded-xl text-[10px] font-black text-slate-400 uppercase hover:bg-slate-50"
                              >
                                  + Ejercicio
                              </button>
                          </div>
                      ))}
                  </div>
              </div>
          </div>
      )}

      {/* Selector de Día (Tabs) */}
      <div className="bg-white border-b border-slate-200 px-4 flex justify-between pt-2 shrink-0">
          <div className="flex gap-1 overflow-x-auto no-scrollbar">
            {patient.routine.days.map((day) => (
              <button 
                key={day.id} 
                onClick={() => {setActiveDayId(day.id); setViewMode('daily');}} 
                className={`px-4 py-2 rounded-t-xl font-bold text-[10px] uppercase tracking-wider transition-all border-t border-x ${activeDayId === day.id && viewMode === 'daily' ? 'bg-slate-50 border-slate-200 text-primary-600' : 'bg-white border-transparent text-slate-400'}`}
              >
                {day.name}
              </button>
            ))}
          </div>
          <div className="flex items-center gap-2 pb-1 ml-4 border-l pl-3 shrink-0">
              <button 
                onClick={() => setViewMode('weekly')} 
                className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg font-black text-[9px] uppercase transition-all ${viewMode === 'weekly' ? 'bg-primary-600 text-white' : 'bg-slate-100 text-slate-500'}`}
              >
                <Calendar size={12}/> <span className="hidden xs:inline">Semana</span>
              </button>
          </div>
      </div>

      <main className="flex-1 overflow-y-auto p-4 md:p-6 scroll-container">
        <div className="max-w-4xl mx-auto h-full">
          {viewMode === 'daily' && activeDay ? (
              <div className="space-y-3 max-w-2xl mx-auto pb-20">
                  {activeDay.exercises.map(ex => (
                      <ExerciseCard 
                        key={ex.id} 
                        exercise={ex} 
                        role={role}
                        onUpdate={(id, up) => handleExerciseUpdate(id, up)} 
                        onShowHistory={(e) => setChartExercise(e)} 
                        onDelete={(id) => handleRemoveExercise(activeDayId, id)} 
                      />
                  ))}
              </div>
          ) : viewMode === 'weekly' ? (
              <div className="h-full overflow-x-auto scroll-container">
                  <div className="flex items-start gap-4 min-w-max pb-10">
                      {patient.routine.days.map((day, idx) => (
                          <div key={day.id} className="w-72 shrink-0 bg-white rounded-2xl p-4 shadow-sm border border-slate-100">
                              <div className="flex items-center gap-3 mb-4 border-b pb-2">
                                  <span className="w-6 h-6 bg-slate-900 text-white rounded-lg flex items-center justify-center text-[10px] font-black">{idx + 1}</span>
                                  <h4 className="text-sm font-black text-slate-800 truncate">{day.name}</h4>
                              </div>
                              <div className="space-y-2">
                                  {day.exercises.map(ex => (
                                      <div key={ex.id} className="flex items-center gap-3 p-2 bg-slate-50 rounded-xl border border-slate-100">
                                          <img src={ex.definition.videoUrl} className="w-10 h-10 rounded-lg object-cover" />
                                          <div className="flex-1 min-w-0">
                                              <p className="font-bold text-[10px] text-slate-800 leading-tight truncate">{ex.definition.name}</p>
                                              <p className="text-[9px] font-black text-slate-400 uppercase mt-0.5">{ex.targetSets}x{ex.targetReps} • {ex.targetLoad}kg</p>
                                          </div>
                                      </div>
                                  ))}
                                  {day.exercises.length === 0 && <p className="text-[10px] text-slate-300 italic py-4 text-center">Sin asignar</p>}
                              </div>
                          </div>
                      ))}
                  </div>
              </div>
          ) : null}
        </div>
      </main>

      {chartExercise && <ProgressChart exercise={chartExercise} onClose={() => setChartExercise(null)} />}

      {isAddingExerciseModal.show && (
          <div className="fixed inset-0 z-[350] bg-slate-900/40 backdrop-blur-sm flex items-center justify-center p-4">
              <div className="bg-white w-full max-w-lg h-[70vh] rounded-3xl shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95 duration-200">
                  <div className="p-4 border-b flex items-center gap-3">
                      <div className="relative flex-1">
                          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-300" size={16} />
                          <input 
                              type="text" 
                              placeholder="Buscar..." 
                              className="w-full pl-9 pr-4 py-2 bg-slate-50 border-none rounded-xl text-sm font-bold outline-none" 
                              value={exerciseSearch} 
                              onChange={e => setExerciseSearch(e.target.value)} 
                          />
                      </div>
                      <button onClick={() => setIsAddingExerciseModal({show:false, dayId:''})} className="p-2 text-slate-400"><X size={20}/></button>
                  </div>
                  <div className="flex-1 overflow-y-auto p-4 space-y-2 scroll-container">
                      {EXERCISES.filter(ex => ex.name.toLowerCase().includes(exerciseSearch.toLowerCase())).map(ex => {
                          const isSelected = selectedExerciseIds.includes(ex.id);
                          return (
                              <button 
                                key={ex.id} 
                                onClick={() => setSelectedExerciseIds(prev => isSelected ? prev.filter(i => i !== ex.id) : [...prev, ex.id])} 
                                className={`w-full flex items-center p-3 rounded-xl border-2 transition-all ${isSelected ? 'bg-primary-50 border-primary-500' : 'bg-white border-slate-50'}`}
                              >
                                  <div className="mr-3">{isSelected ? <CheckSquare size={18} className="text-primary-600"/> : <Square size={18} className="text-slate-200"/>}</div>
                                  <img src={ex.videoUrl} className="w-10 h-10 rounded-lg object-cover mr-3" />
                                  <div className="text-left">
                                      <p className="font-bold text-slate-800 text-xs">{ex.name}</p>
                                      <span className="text-[9px] text-slate-400 uppercase font-black">{ex.category}</span>
                                  </div>
                              </button>
                          );
                      })}
                  </div>
                  <div className="p-4 bg-white border-t">
                        <button 
                            disabled={selectedExerciseIds.length === 0}
                            className="bg-primary-600 text-white w-full py-3 rounded-xl font-bold text-sm disabled:opacity-30"
                            onClick={() => {
                                const newExs: RoutineExercise[] = selectedExerciseIds.map(id => ({
                                    id: `re-${Date.now()}-${id}`,
                                    definitionId: id,
                                    definition: EXERCISES.find(e => e.id === id)!,
                                    targetSets: 3, targetReps: 12, targetLoad: 0, isDone: false, history: []
                                }));
                                const newDays = patient.routine.days.map(d => d.id === isAddingExerciseModal.dayId ? { ...d, exercises: [...d.exercises, ...newExs] } : d);
                                onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
                                setIsAddingExerciseModal({show:false, dayId:''});
                                setSelectedExerciseIds([]);
                            }}
                        >
                            Añadir a {patient.routine.days.find(d => d.id === isAddingExerciseModal.dayId)?.name}
                        </button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

import React from 'react';
