      </div>

      <nav className="p-1.5 space-y-1">
        <button 
          onClick={onGoHome}
          title="Panel Central"
          className={`w-full flex flex-col items-center gap-1 py-3 rounded-lg transition-all ${!selectedPatientId ? 'bg-primary-50 text-primary-600' : 'text-slate-400 hover:bg-slate-50'}`}
        >
          <Home size={18} />
          <span className="text-[8px] font-black uppercase tracking-tighter">Panel</span>
