        <button onClick={onGoHome} className="group">
          <div className="w-9 h-9 bg-primary-600 rounded-xl flex items-center justify-center shadow-md group-hover:scale-110 transition-transform">
            <Activity className="text-white" size={20} />
          </div>
        </button>
      </div>

      <nav className="p-1.5 space-y-1">
        <button 
          onClick={onGoHome}
          title="Panel Central"
          className={`w-full flex flex-col items-center justify-center gap-1 py-4 rounded-xl transition-all ${!selectedPatientId ? 'bg-primary-50 text-primary-600' : 'text-slate-400 hover:bg-slate-50'}`}
        >
          <Home size={20} />
          <span className="text-[7px] font-black uppercase tracking-tighter">Panel</span>
        </button>
      </nav>

      <div className="mt-2 flex-1 overflow-y-auto scroll-container px-1.5">
        <div className="space-y-2">
          {activePatients.map((patient) => (
            <div 
              key={patient.id}
              onClick={() => onSelectPatient(patient.id)}
              title={patient.firstName}
              className={`group relative flex flex-col items-center p-1.5 rounded-xl cursor-pointer transition-all border ${selectedPatientId === patient.id ? 'bg-white border-primary-100 shadow-sm ring-2 ring-primary-50' : 'border-transparent hover:bg-slate-50'}`}
            >
              <img src={patient.photoUrl} className="w-10 h-10 rounded-lg object-cover shrink-0 shadow-sm" />
              <p className={`font-black text-[7px] truncate max-w-full uppercase mt-1 tracking-tighter text-center ${selectedPatientId === patient.id ? 'text-slate-900' : 'text-slate-400'}`}>
                {patient.firstName}
              </p>
              <button 
                onClick={(e) => onRemoveActive(patient.id, e)}
                className="absolute -top-1 -right-1 opacity-0 group-hover:opacity-100 p-0.5 bg-white shadow-md border border-slate-100 rounded-full text-red-500 transition-all hover:scale-125 z-10"
              >
                <X size={8} strokeWidth={3} />
              </button>
            </div>
          ))}
        </div>
