      <div className="p-4 border-t border-slate-50 flex justify-center items-center">
        {isOnline ? (
          <Wifi size={18} className="text-kine drop-shadow-[0_0_8px_rgba(16,185,129,0.4)]" />
        ) : (
          <WifiOff size={18} className="text-red-500 animate-pulse" />
        )}
      </div>
    </aside>
  );
};

import React, { useState, useEffect } from 'react';
import { Patient, RoutineExercise, Stage, UserRole, RoutineDay } from '../types';
import { EXERCISES } from '../constants';
import { ExerciseCard } from './ExerciseCard';
import { ProgressChart } from './ProgressChart';
import { 
    FileText, Plus, Search, X, Calendar, Trash2, Edit2, Save, Wand2,
    Activity, Minus, Layers, TrendingUp
} from 'lucide-react';

interface PatientDetailProps {
  patient: Patient;
  role: UserRole;
  onUpdatePatient: (updated: Patient) => void;
}

export const PatientDetail: React.FC<PatientDetailProps> = ({
  patient,
  role,
  onUpdatePatient,
}) => {
  const [activeDayId, setActiveDayId] = useState<string>(patient.routine.days[0]?.id || '');
  const [viewMode, setViewMode] = useState<'daily' | 'weekly' | 'monthly'>('daily');
  const [showHistory, setShowHistory] = useState(false);
  const [showRoutineEditor, setShowRoutineEditor] = useState(false);
  const [chartExercise, setChartExercise] = useState<RoutineExercise | null>(null);

  const [isAddingExerciseModal, setIsAddingExerciseModal] = useState<{show: boolean, dayId: string}>({show: false, dayId: ''});
  const [exerciseSearch, setExerciseSearch] = useState('');
  const [selectedExerciseIds, setSelectedExerciseIds] = useState<string[]>([]);
  const [notes, setNotes] = useState(patient.history[0] || '');

  const isKine = role === UserRole.KINE;
  const isReadOnly = role === UserRole.PATIENT || role === UserRole.ADMIN;

  useEffect(() => {
    if (patient.routine.days.length > 0 && (!activeDayId || !patient.routine.days.find(d => d.id === activeDayId))) {
        setActiveDayId(patient.routine.days[0].id);
    }
  }, [patient, activeDayId]);

  const activeDay = patient.routine.days.find(d => d.id === activeDayId);

  const handleExerciseUpdate = (exerciseId: string, updates: Partial<RoutineExercise>) => {
    const newDays = patient.routine.days.map(day => ({
        ...day,
        exercises: day.exercises.map(ex => ex.id === exerciseId ? { ...ex, ...updates } : ex)
    }));
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  const handleRemoveExercise = (dayId: string, exerciseId: string) => {
    const newDays = patient.routine.days.map(day => 
        day.id === dayId ? { ...day, exercises: day.exercises.filter(ex => ex.id !== exerciseId) } : day
    );
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  const handleUpdateStage = (newStage: Stage) => {
    onUpdatePatient({ ...patient, routine: { ...patient.routine, stage: newStage } });
  };

  const handleAddDay = () => {
    const newDay: RoutineDay = {
      id: `day-${Date.now()}`,
      name: `Día ${patient.routine.days.length + 1}`,
      exercises: []
    };
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: [...patient.routine.days, newDay] } });
  };

  const handleRemoveLastDay = () => {
    if (patient.routine.days.length <= 1) return;
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: patient.routine.days.slice(0, -1) } });
  };

  const handleGenerateFullWeek = (count: number) => {
    const newDays: RoutineDay[] = Array.from({ length: count }).map((_, i) => ({
      id: `day-${Date.now()}-${i}`,
      name: `Día ${i + 1}`,
      exercises: []
    }));
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  const handleRemoveDay = (dayId: string) => {
    if (patient.routine.days.length <= 1) return;
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: patient.routine.days.filter(d => d.id !== dayId) } });
  };

  const handleRenameDay = (dayId: string, newName: string) => {
    const newDays = patient.routine.days.map(day => 
      day.id === dayId ? { ...day, name: newName } : day
    );
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  return (
    <div className="flex-1 h-full flex flex-col bg-slate-50 overflow-hidden relative">
      <header className="bg-white border-b border-slate-200 px-4 py-2 flex items-center justify-between shrink-0 z-30 pt-[calc(0.25rem+var(--sat))]">
        <div className="flex flex-col min-w-0">
          <h2 className="text-xs font-black text-slate-900 leading-none truncate uppercase tracking-tighter">
            {patient.firstName} {patient.lastName}
          </h2>
          <p className="text-[7px] text-slate-400 font-black mt-0.5 uppercase truncate tracking-widest">{patient.condition}</p>
        </div>
        <div className="flex gap-1 items-center">
            <span className={`px-1.5 py-0.5 rounded text-[7px] font-black uppercase ${patient.routine.stage === Stage.KINESIOLOGY ? 'bg-kine/10 text-kine' : 'bg-gym/10 text-gym'}`}>
                {patient.routine.stage}
            </span>
            {isKine && (
                <button 
                  onClick={() => setShowRoutineEditor(true)} 
                  className="bg-slate-900 text-white px-2.5 py-1.5 rounded-lg font-bold text-[8px] uppercase hover:bg-slate-800 transition-all flex items-center gap-1"
                >
                    <Edit2 size={10} />
                    <span>Rutina</span>
                </button>
            )}
            <button 
              onClick={() => setShowHistory(!showHistory)} 
              className={`p-1.5 rounded-lg border transition-all ${showHistory ? 'bg-primary-50 border-primary-200 text-primary-600' : 'bg-white border-slate-200 text-slate-400'}`}
            >
                <FileText size={14} />
            </button>
        </div>
      </header>

      {showHistory && (
          <div className="bg-slate-900 text-white p-3 shadow-xl z-20 border-b border-slate-800 animate-in slide-in-from-top duration-200">
              <div className="max-w-4xl mx-auto flex gap-4 items-center">
                  <textarea 
                    className="flex-1 h-10 bg-slate-800/50 text-slate-200 p-2 rounded-lg border border-slate-700 outline-none resize-none text-[10px]" 
                    value={notes} 
                    onChange={(e) => setNotes(e.target.value)} 
                    placeholder="Notas clínicas..." 
                  />
                  <button className="text-[9px] font-black uppercase text-primary-400 flex items-center gap-1 p-2 bg-slate-800 rounded-lg"><Save size={12}/></button>
              </div>
          </div>
      )}

      {showRoutineEditor && (
          <div className="fixed inset-0 z-[100] bg-slate-50 flex flex-col pt-[var(--sat)] animate-in slide-in-from-bottom-5 duration-300">
              <header className="bg-white border-b border-slate-200 px-4 py-1.5 flex items-center justify-between shrink-0">
                  <div className="flex items-center gap-4">
                      <div className="flex bg-slate-100 p-0.5 rounded-lg">
                          <button 
                            onClick={() => handleUpdateStage(Stage.KINESIOLOGY)}
                            className={`px-3 py-1 rounded-md text-[8px] font-black uppercase transition-all ${patient.routine.stage === Stage.KINESIOLOGY ? 'bg-white text-kine shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
                          >
                            Kine
                          </button>
                          <button 
                            onClick={() => handleUpdateStage(Stage.GYM)}
                            className={`px-3 py-1 rounded-md text-[8px] font-black uppercase transition-all ${patient.routine.stage === Stage.GYM ? 'bg-white text-gym shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
                          >
                            Gym
                          </button>
                      </div>

                      {/* Stepper intuitivo para días */}
                      <div className="flex items-center gap-2 bg-white px-2 py-1 rounded-lg border border-slate-200">
                          <button 
                            onClick={handleRemoveLastDay} 
                            disabled={patient.routine.days.length <= 1}
                            className="text-slate-400 hover:text-red-500 disabled:opacity-20 transition-colors"
                          >
                            <Minus size={14}/>
                          </button>
                          <div className="flex flex-col items-center min-w-[30px]">
                              <span className="text-[10px] font-black leading-none">{patient.routine.days.length}</span>
                              <span className="text-[6px] font-black uppercase text-slate-300 tracking-tighter">Días</span>
                          </div>
                          <button 
                            onClick={handleAddDay} 
                            disabled={patient.routine.days.length >= 7}
                            className="text-slate-400 hover:text-primary-600 disabled:opacity-20 transition-colors"
                          >
                            <Plus size={14}/>
                          </button>
                      </div>

                      {/* Botón para generar semana típica (3 días) */}
                      <button 
                        onClick={() => handleGenerateFullWeek(3)}
                        className="p-1.5 bg-primary-50 text-primary-600 rounded-lg border border-primary-100 hover:bg-primary-100 transition-all flex items-center gap-1.5 text-[8px] font-black uppercase"
                      >
                        <Wand2 size={12} />
                        <span className="hidden sm:inline">Set 3 Días</span>
                      </button>
                  </div>

                  <button onClick={() => setShowRoutineEditor(false)} className="p-2 hover:bg-slate-100 rounded-full"><X size={18} /></button>
              </header>

              <div className="flex-1 overflow-x-auto p-4 scroll-container bg-slate-50">
                  <div className="flex items-start gap-4 h-full min-w-max pb-10">
                      {patient.routine.days.map((day, dIdx) => (
                          <div key={day.id} className="w-64 bg-white rounded-xl border border-slate-200 shadow-sm flex flex-col h-full shrink-0 group">
                              <div className="p-3 border-b border-slate-50 flex items-center justify-between">
                                  <div className="flex items-center gap-2">
                                      <span className="text-[9px] font-black text-slate-300">#{dIdx+1}</span>
                                      <input 
                                        className="font-black text-xs text-slate-800 bg-transparent border-none focus:ring-0 p-0 w-28"
                                        value={day.name}
                                        onChange={(e) => handleRenameDay(day.id, e.target.value)}
                                      />
                                  </div>
                                  <button onClick={() => handleRemoveDay(day.id)} className="text-slate-200 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all"><Trash2 size={12}/></button>
                              </div>

                              <div className="flex-1 overflow-y-auto p-2 space-y-1.5 scroll-container">
                                  {day.exercises.map((ex) => (
                                      <div key={ex.id} className="flex items-center justify-between p-2 bg-slate-50 rounded-lg border border-transparent hover:border-slate-200 transition-all">
                                          <div className="flex items-center gap-2 min-w-0">
                                              <img src={ex.definition.videoUrl} className="w-7 h-7 rounded-md object-cover bg-slate-200 shrink-0" />
                                              <div className="min-w-0">
                                                  <p className="font-bold text-[9px] text-slate-800 truncate leading-none">{ex.definition.name}</p>
                                                  <p className="text-[7px] text-slate-400 mt-1 uppercase font-black">{ex.targetSets}x{ex.targetReps}</p>
                                              </div>
                                          </div>
                                          <button onClick={() => handleRemoveExercise(day.id, ex.id)} className="p-1 text-slate-300 hover:text-red-500"><X size={10}/></button>
                                      </div>
                                  ))}
                                  <button 
                                    onClick={() => setIsAddingExerciseModal({show: true, dayId: day.id})}
                                    className="w-full py-3 border border-dashed border-slate-200 rounded-lg text-[9px] font-black text-slate-400 uppercase hover:bg-slate-50 hover:text-primary-600 hover:border-primary-200 transition-all"
                                  >
                                      + Agregar Ejercicio
                                  </button>
                              </div>
                          </div>
                      ))}

                      {/* Botón "+" intuitivo al final */}
                      <button 
                        onClick={handleAddDay}
                        disabled={patient.routine.days.length >= 7}
                        className="w-16 h-full flex flex-col items-center justify-center bg-white/40 rounded-xl border-2 border-dashed border-slate-200 text-slate-300 hover:bg-white hover:text-primary-500 hover:border-primary-300 transition-all group shrink-0 disabled:opacity-0 disabled:pointer-events-none"
                      >
                          <Plus size={24} className="group-hover:scale-125 transition-transform" />
                          <span className="text-[7px] font-black uppercase mt-2">Día</span>
                      </button>
                  </div>
              </div>
          </div>
      )}

      {/* Tabs / Selectores de vista principal */}
      <div className="bg-white border-b border-slate-200 px-4 flex justify-between shrink-0 h-10 items-end">
          <div className="flex gap-1 overflow-x-auto no-scrollbar">
            {patient.routine.days.map((day) => (
              <button 
                key={day.id} 
                onClick={() => {setActiveDayId(day.id); setViewMode('daily');}} 
                className={`px-3 py-1.5 rounded-t-lg font-bold text-[9px] uppercase tracking-wider transition-all border-t border-x ${activeDayId === day.id && viewMode === 'daily' ? 'bg-slate-50 border-slate-200 text-primary-600' : 'bg-white border-transparent text-slate-400'}`}
              >
                {day.name}
              </button>
            ))}
          </div>
          <div className="flex items-center pb-1 gap-1 border-l pl-2 ml-2 shrink-0">
              <button 
                onClick={() => setViewMode('weekly')} 
                title="Semana actual"
                className={`p-1.5 rounded-md transition-all ${viewMode === 'weekly' ? 'bg-primary-600 text-white shadow-sm' : 'bg-slate-50 text-slate-400 hover:text-slate-600'}`}
              >
                <Calendar size={14}/>
              </button>
              <button 
                onClick={() => setViewMode('monthly')} 
                title="Proyección Mensual"
                className={`p-1.5 rounded-md transition-all ${viewMode === 'monthly' ? 'bg-gym text-white shadow-sm' : 'bg-slate-50 text-slate-400 hover:text-slate-600'}`}
              >
                <Layers size={14}/>
              </button>
          </div>
      </div>

      <main className="flex-1 overflow-y-auto p-4 md:p-6 scroll-container">
        <div className="max-w-4xl mx-auto h-full">
          {viewMode === 'daily' && activeDay ? (
              <div className="space-y-2 max-w-lg mx-auto pb-20">
                  {activeDay.exercises.map(ex => (
                      <ExerciseCard 
                        key={ex.id} 
                        exercise={ex} 
                        role={role}
                        onUpdate={(id, up) => handleExerciseUpdate(id, up)} 
                        onShowHistory={(e) => setChartExercise(e)} 
                        onDelete={(id) => handleRemoveExercise(activeDayId, id)} 
                      />
                  ))}
                  {activeDay.exercises.length === 0 && (
                      <div className="text-center py-20 opacity-20">
                          <Activity size={48} className="mx-auto mb-4" />
                          <p className="font-black uppercase text-xs">Sin ejercicios asignados</p>
                      </div>
                  )}
              </div>
          ) : viewMode === 'weekly' ? (
              <div className="h-full overflow-x-auto scroll-container">
                  <div className="flex items-start gap-4 min-w-max pb-10">
                      {patient.routine.days.map((day, idx) => (
                          <div key={day.id} className="w-60 shrink-0 bg-white rounded-xl p-3 shadow-sm border border-slate-100">
                              <div className="flex items-center gap-2 mb-3 border-b pb-1.5">
                                  <span className="text-[8px] font-black text-slate-400 tracking-tighter uppercase">Día {idx + 1}</span>
                                  <h4 className="text-[10px] font-black text-slate-800 truncate uppercase">{day.name}</h4>
                              </div>
                              <div className="space-y-1">
                                  {day.exercises.map(ex => (
                                      <div key={ex.id} className="flex items-center gap-2 p-1.5 bg-slate-50 rounded-lg border border-slate-50">
                                          <img src={ex.definition.videoUrl} className="w-6 h-6 rounded-md object-cover shrink-0" />
                                          <div className="flex-1 min-w-0">
                                              <p className="font-bold text-[9px] text-slate-700 leading-tight truncate">{ex.definition.name}</p>
                                              <p className="text-[8px] font-black text-slate-400 uppercase mt-0.5">{ex.targetSets}x{ex.targetReps} • {ex.targetLoad}kg</p>
                                          </div>
                                      </div>
                                  ))}
                              </div>
                          </div>
                      ))}
                  </div>
              </div>
          ) : viewMode === 'monthly' ? (
              /* VISTA MENSUAL MEJORADA */
              <div className="space-y-10 pb-20 max-w-3xl mx-auto">
                  <div className="bg-white p-4 rounded-2xl border border-slate-200 flex items-center justify-between mb-8 shadow-sm">
                      <div className="flex items-center gap-4">
                        <div className="w-10 h-10 bg-gym/10 text-gym rounded-xl flex items-center justify-center">
                            <TrendingUp size={20} />
                        </div>
                        <div>
                            <h3 className="font-black text-sm uppercase text-slate-900 leading-none">Progresión Mensual</h3>
                            <p className="text-[9px] font-bold text-slate-400 mt-1 uppercase">Estimación de carga semanal (+5%)</p>
                        </div>
                      </div>
                  </div>

                  {[1, 2, 3, 4].map((weekNum) => (
                      <div key={weekNum} className="relative pl-6 border-l-2 border-slate-200 space-y-4">
                          <div className="absolute -left-2 top-0 w-4 h-4 bg-white border-2 border-slate-400 rounded-full flex items-center justify-center">
                              <div className="w-1.5 h-1.5 bg-slate-400 rounded-full"></div>
                          </div>

                          <div className="flex items-center gap-3 mb-2">
                              <h4 className="font-black text-[10px] uppercase tracking-widest text-slate-900 bg-slate-100 px-3 py-1 rounded-full border border-slate-200 shadow-sm">
                                  Semana {weekNum}
                              </h4>
                          </div>

                          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3">
                              {patient.routine.days.map((day, dIdx) => (
                                  <div key={`${weekNum}-${day.id}`} className="bg-white p-3 rounded-xl border border-slate-100 shadow-sm">
                                      <p className="text-[8px] font-black text-slate-400 uppercase mb-2">Día {dIdx+1}</p>
                                      <div className="space-y-1.5">
                                          {day.exercises.map(ex => {
                                              const projectedLoad = (ex.targetLoad * (1 + (weekNum - 1) * 0.05)).toFixed(1);
                                              return (
                                                <div key={`${weekNum}-${ex.id}`} className="flex justify-between items-center text-[9px] p-1.5 bg-slate-50 rounded-lg">
                                                    <span className="font-bold text-slate-600 truncate mr-2">{ex.definition.name}</span>
                                                    <span className="font-black text-primary-600 shrink-0">{projectedLoad}kg</span>
                                                </div>
                                              );
                                          })}
                                          {day.exercises.length === 0 && <p className="text-[8px] text-slate-300 italic">Sin datos</p>}
                                      </div>
                                  </div>
                              ))}
                          </div>
                      </div>
                  ))}
              </div>
          ) : null}
        </div>
      </main>

      {chartExercise && <ProgressChart exercise={chartExercise} onClose={() => setChartExercise(null)} />}

      {isAddingExerciseModal.show && (
          <div className="fixed inset-0 z-[350] bg-slate-900/40 backdrop-blur-sm flex items-center justify-center p-4">
              <div className="bg-white w-full max-w-sm h-[60vh] rounded-2xl shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95 duration-200">
                  <div className="p-3 border-b flex items-center gap-2">
                      <div className="relative flex-1">
                          <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 text-slate-300" size={14} />
                          <input 
                              type="text" 
                              placeholder="Buscar..." 
                              className="w-full pl-8 pr-3 py-1.5 bg-slate-50 border-none rounded-lg text-[10px] font-bold outline-none" 
                              value={exerciseSearch} 
                              onChange={e => setExerciseSearch(e.target.value)} 
                          />
                      </div>
                      <button onClick={() => setIsAddingExerciseModal({show:false, dayId:''})} className="p-1.5 text-slate-400 hover:bg-slate-50 rounded-lg"><X size={16}/></button>
                  </div>
                  <div className="flex-1 overflow-y-auto p-2 space-y-1 scroll-container">
                      {EXERCISES.filter(ex => ex.name.toLowerCase().includes(exerciseSearch.toLowerCase())).map(ex => {
                          const isSelected = selectedExerciseIds.includes(ex.id);
                          return (
                              <button 
                                key={ex.id} 
                                onClick={() => setSelectedExerciseIds(prev => isSelected ? prev.filter(i => i !== ex.id) : [...prev, ex.id])} 
                                className={`w-full flex items-center p-2 rounded-lg border-2 transition-all ${isSelected ? 'bg-primary-50 border-primary-400' : 'bg-white border-slate-50'}`}
                              >
                                  <div className="mr-2">{isSelected ? <CheckSquare size={14} className="text-primary-600"/> : <Square size={14} className="text-slate-200"/>}</div>
                                  <img src={ex.videoUrl} className="w-8 h-8 rounded-md object-cover mr-2" />
                                  <div className="text-left flex-1 min-w-0">
                                      <p className="font-bold text-slate-800 text-[10px] truncate leading-none">{ex.name}</p>
                                      <span className="text-[8px] text-slate-400 uppercase font-black">{ex.category}</span>
                                  </div>
                              </button>
                          );
                      })}
                  </div>
                  <div className="p-3 bg-white border-t">
                        <button 
                            disabled={selectedExerciseIds.length === 0}
                            className="bg-primary-600 text-white w-full py-2.5 rounded-lg font-bold text-xs disabled:opacity-30"
                            onClick={() => {
                                const newExs: RoutineExercise[] = selectedExerciseIds.map(id => ({
                                    id: `re-${Date.now()}-${id}`,
                                    definitionId: id,
                                    definition: EXERCISES.find(e => e.id === id)!,
                                    targetSets: 3, targetReps: 12, targetLoad: 0, isDone: false, history: []
                                }));
                                const newDays = patient.routine.days.map(d => d.id === isAddingExerciseModal.dayId ? { ...d, exercises: [...d.exercises, ...newExs] } : d);
                                onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
                                setIsAddingExerciseModal({show:false, dayId:''});
                                setSelectedExerciseIds([]);
                            }}
                        >
                            Confirmar ({selectedExerciseIds.length})
                        </button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Patient, RoutineExercise, Stage, UserRole, RoutineDay } from '../types';
import { EXERCISES } from '../constants';
import { ExerciseCard } from './ExerciseCard';
import { ProgressChart } from './ProgressChart';
import { 
    FileText, Plus, Search, X, Calendar, Trash2, Edit2, Save, Wand2,
    Activity, Minus, Layers, TrendingUp, CheckSquare, Square
} from 'lucide-react';

interface PatientDetailProps {
  patient: Patient;
  role: UserRole;
  onUpdatePatient: (updated: Patient) => void;
}

export const PatientDetail: React.FC<PatientDetailProps> = ({
  patient,
  role,
  onUpdatePatient,
}) => {
  const [activeDayId, setActiveDayId] = useState<string>(patient.routine.days[0]?.id || '');
  const [viewMode, setViewMode] = useState<'daily' | 'weekly' | 'monthly'>('daily');
  const [showHistory, setShowHistory] = useState(false);
  const [showRoutineEditor, setShowRoutineEditor] = useState(false);
  const [chartExercise, setChartExercise] = useState<RoutineExercise | null>(null);

  const [isAddingExerciseModal, setIsAddingExerciseModal] = useState<{show: boolean, dayId: string}>({show: false, dayId: ''});
  const [exerciseSearch, setExerciseSearch] = useState('');
  const [selectedExerciseIds, setSelectedExerciseIds] = useState<string[]>([]);
  const [notes, setNotes] = useState(patient.history[0] || '');

  const isKine = role === UserRole.KINE;
  const isReadOnly = role === UserRole.PATIENT || role === UserRole.ADMIN;

  useEffect(() => {
    if (patient.routine.days.length > 0 && (!activeDayId || !patient.routine.days.find(d => d.id === activeDayId))) {
        setActiveDayId(patient.routine.days[0].id);
    }
  }, [patient, activeDayId]);

  const activeDay = patient.routine.days.find(d => d.id === activeDayId);

  const handleExerciseUpdate = (exerciseId: string, updates: Partial<RoutineExercise>) => {
    const newDays = patient.routine.days.map(day => ({
        ...day,
        exercises: day.exercises.map(ex => ex.id === exerciseId ? { ...ex, ...updates } : ex)
    }));
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  const handleRemoveExercise = (dayId: string, exerciseId: string) => {
    const newDays = patient.routine.days.map(day => 
        day.id === dayId ? { ...day, exercises: day.exercises.filter(ex => ex.id !== exerciseId) } : day
    );
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  const handleUpdateStage = (newStage: Stage) => {
    onUpdatePatient({ ...patient, routine: { ...patient.routine, stage: newStage } });
  };

  const handleAddDay = () => {
    const newDay: RoutineDay = {
      id: `day-${Date.now()}`,
      name: `Día ${patient.routine.days.length + 1}`,
      exercises: []
    };
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: [...patient.routine.days, newDay] } });
  };

  const handleRemoveLastDay = () => {
    if (patient.routine.days.length <= 1) return;
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: patient.routine.days.slice(0, -1) } });
  };

  const handleGenerateFullWeek = (count: number) => {
    const newDays: RoutineDay[] = Array.from({ length: count }).map((_, i) => ({
      id: `day-${Date.now()}-${i}`,
      name: `Día ${i + 1}`,
      exercises: []
    }));
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  const handleRemoveDay = (dayId: string) => {
    if (patient.routine.days.length <= 1) return;
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: patient.routine.days.filter(d => d.id !== dayId) } });
  };

  const handleRenameDay = (dayId: string, newName: string) => {
    const newDays = patient.routine.days.map(day => 
      day.id === dayId ? { ...day, name: newName } : day
    );
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  return (
    <div className="flex-1 h-full flex flex-col bg-slate-50 overflow-hidden relative">
      <header className="bg-white border-b border-slate-200 px-4 py-2 flex items-center justify-between shrink-0 z-30 pt-[calc(0.25rem+var(--sat))]">
        <div className="flex flex-col min-w-0">
          <h2 className="text-xs font-black text-slate-900 leading-none truncate uppercase tracking-tighter">
            {patient.firstName} {patient.lastName}
          </h2>
          <p className="text-[7px] text-slate-400 font-black mt-0.5 uppercase truncate tracking-widest">{patient.condition}</p>
        </div>
        <div className="flex gap-1 items-center">
            <span className={`px-1.5 py-0.5 rounded text-[7px] font-black uppercase ${patient.routine.stage === Stage.KINESIOLOGY ? 'bg-kine/10 text-kine' : 'bg-gym/10 text-gym'}`}>
                {patient.routine.stage}
            </span>
            {isKine && (
                <button 
                  onClick={() => setShowRoutineEditor(true)} 
                  className="bg-slate-900 text-white px-2.5 py-1.5 rounded-lg font-bold text-[8px] uppercase hover:bg-slate-800 transition-all flex items-center gap-1"
                >
                    <Edit2 size={10} />
                    <span>Rutina</span>
                </button>
            )}
            <button 
              onClick={() => setShowHistory(!showHistory)} 
              className={`p-1.5 rounded-lg border transition-all ${showHistory ? 'bg-primary-50 border-primary-200 text-primary-600' : 'bg-white border-slate-200 text-slate-400'}`}
            >
                <FileText size={14} />
            </button>
        </div>
      </header>

      {showHistory && (
          <div className="bg-slate-900 text-white p-3 shadow-xl z-20 border-b border-slate-800 animate-in slide-in-from-top duration-200">
              <div className="max-w-4xl mx-auto flex gap-4 items-center">
                  <textarea 
                    className="flex-1 h-10 bg-slate-800/50 text-slate-200 p-2 rounded-lg border border-slate-700 outline-none resize-none text-[10px]" 
                    value={notes} 
                    onChange={(e) => setNotes(e.target.value)} 
                    placeholder="Notas clínicas..." 
                  />
                  <button className="text-[9px] font-black uppercase text-primary-400 flex items-center gap-1 p-2 bg-slate-800 rounded-lg"><Save size={12}/></button>
              </div>
          </div>
      )}

      {showRoutineEditor && (
          <div className="fixed inset-0 z-[100] bg-slate-50 flex flex-col pt-[var(--sat)] animate-in slide-in-from-bottom-5 duration-300">
              <header className="bg-white border-b border-slate-200 px-4 py-1.5 flex items-center justify-between shrink-0">
                  <div className="flex items-center gap-4">
                      <div className="flex bg-slate-100 p-0.5 rounded-lg">
                          <button 
                            onClick={() => handleUpdateStage(Stage.KINESIOLOGY)}
                            className={`px-3 py-1 rounded-md text-[8px] font-black uppercase transition-all ${patient.routine.stage === Stage.KINESIOLOGY ? 'bg-white text-kine shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
                          >
                            Kine
                          </button>
                          <button 
                            onClick={() => handleUpdateStage(Stage.GYM)}
                            className={`px-3 py-1 rounded-md text-[8px] font-black uppercase transition-all ${patient.routine.stage === Stage.GYM ? 'bg-white text-gym shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
                          >
                            Gym
                          </button>
                      </div>

                      {/* Stepper intuitivo para días */}
                      <div className="flex items-center gap-2 bg-white px-2 py-1 rounded-lg border border-slate-200">
                          <button 
                            onClick={handleRemoveLastDay} 
                            disabled={patient.routine.days.length <= 1}
                            className="text-slate-400 hover:text-red-500 disabled:opacity-20 transition-colors"
                          >
                            <Minus size={14}/>
                          </button>
                          <div className="flex flex-col items-center min-w-[30px]">
                              <span className="text-[10px] font-black leading-none">{patient.routine.days.length}</span>
                              <span className="text-[6px] font-black uppercase text-slate-300 tracking-tighter">Días</span>
                          </div>
                          <button 
                            onClick={handleAddDay} 
                            disabled={patient.routine.days.length >= 7}
                            className="text-slate-400 hover:text-primary-600 disabled:opacity-20 transition-colors"
                          >
                            <Plus size={14}/>
                          </button>
                      </div>

                      {/* Botón para generar semana típica (3 días) */}
                      <button 
                        onClick={() => handleGenerateFullWeek(3)}
                        className="p-1.5 bg-primary-50 text-primary-600 rounded-lg border border-primary-100 hover:bg-primary-100 transition-all flex items-center gap-1.5 text-[8px] font-black uppercase"
                      >
                        <Wand2 size={12} />
                        <span className="hidden sm:inline">Set 3 Días</span>
                      </button>
                  </div>

                  <button onClick={() => setShowRoutineEditor(false)} className="p-2 hover:bg-slate-100 rounded-full"><X size={18} /></button>
              </header>

              <div className="flex-1 overflow-x-auto p-4 scroll-container bg-slate-50">
                  <div className="flex items-start gap-4 h-full min-w-max pb-10">
                      {patient.routine.days.map((day, dIdx) => (
                          <div key={day.id} className="w-64 bg-white rounded-xl border border-slate-200 shadow-sm flex flex-col h-full shrink-0 group">
                              <div className="p-3 border-b border-slate-50 flex items-center justify-between">
                                  <div className="flex items-center gap-2">
                                      <span className="text-[9px] font-black text-slate-300">#{dIdx+1}</span>
                                      <input 
                                        className="font-black text-xs text-slate-800 bg-transparent border-none focus:ring-0 p-0 w-28"
                                        value={day.name}
                                        onChange={(e) => handleRenameDay(day.id, e.target.value)}
                                      />
                                  </div>
                                  <button onClick={() => handleRemoveDay(day.id)} className="text-slate-200 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all"><Trash2 size={12}/></button>
                              </div>

                              <div className="flex-1 overflow-y-auto p-2 space-y-1.5 scroll-container">
                                  {day.exercises.map((ex) => (
                                      <div key={ex.id} className="flex items-center justify-between p-2 bg-slate-50 rounded-lg border border-transparent hover:border-slate-200 transition-all">
                                          <div className="flex items-center gap-2 min-w-0">
                                              <img src={ex.definition.videoUrl} className="w-7 h-7 rounded-md object-cover bg-slate-200 shrink-0" />
                                              <div className="min-w-0">
                                                  <p className="font-bold text-[9px] text-slate-800 truncate leading-none">{ex.definition.name}</p>
                                                  <p className="text-[7px] text-slate-400 mt-1 uppercase font-black">{ex.targetSets}x{ex.targetReps}</p>
                                              </div>
                                          </div>
                                          <button onClick={() => handleRemoveExercise(day.id, ex.id)} className="p-1 text-slate-300 hover:text-red-500"><X size={10}/></button>
                                      </div>
                                  ))}
                                  <button 
                                    onClick={() => setIsAddingExerciseModal({show: true, dayId: day.id})}
                                    className="w-full py-3 border border-dashed border-slate-200 rounded-lg text-[9px] font-black text-slate-400 uppercase hover:bg-slate-50 hover:text-primary-600 hover:border-primary-200 transition-all"
                                  >
                                      + Agregar Ejercicio
                                  </button>
                              </div>
                          </div>
                      ))}

                      {/* Botón "+" intuitivo al final */}
                      <button 
                        onClick={handleAddDay}
                        disabled={patient.routine.days.length >= 7}
                        className="w-16 h-full flex flex-col items-center justify-center bg-white/40 rounded-xl border-2 border-dashed border-slate-200 text-slate-300 hover:bg-white hover:text-primary-500 hover:border-primary-300 transition-all group shrink-0 disabled:opacity-0 disabled:pointer-events-none"
                      >
                          <Plus size={24} className="group-hover:scale-125 transition-transform" />
                          <span className="text-[7px] font-black uppercase mt-2">Día</span>
                      </button>
                  </div>
              </div>
          </div>
      )}

      {/* Tabs / Selectores de vista principal */}
      <div className="bg-white border-b border-slate-200 px-4 flex justify-between shrink-0 h-10 items-end">
          <div className="flex gap-1 overflow-x-auto no-scrollbar">
            {patient.routine.days.map((day) => (
              <button 
                key={day.id} 
                onClick={() => {setActiveDayId(day.id); setViewMode('daily');}} 
                className={`px-3 py-1.5 rounded-t-lg font-bold text-[9px] uppercase tracking-wider transition-all border-t border-x ${activeDayId === day.id && viewMode === 'daily' ? 'bg-slate-50 border-slate-200 text-primary-600' : 'bg-white border-transparent text-slate-400'}`}
              >
                {day.name}
              </button>
            ))}
          </div>
          <div className="flex items-center pb-1 gap-1 border-l pl-2 ml-2 shrink-0">
              <button 
                onClick={() => setViewMode('weekly')} 
                title="Semana actual"
                className={`p-1.5 rounded-md transition-all ${viewMode === 'weekly' ? 'bg-primary-600 text-white shadow-sm' : 'bg-slate-50 text-slate-400 hover:text-slate-600'}`}
              >
                <Calendar size={14}/>
              </button>
              <button 
                onClick={() => setViewMode('monthly')} 
                title="Proyección Mensual"
                className={`p-1.5 rounded-md transition-all ${viewMode === 'monthly' ? 'bg-gym text-white shadow-sm' : 'bg-slate-50 text-slate-400 hover:text-slate-600'}`}
              >
                <Layers size={14}/>
              </button>
          </div>
      </div>

      <main className="flex-1 overflow-y-auto p-4 md:p-6 scroll-container">
        <div className="max-w-4xl mx-auto h-full">
          {viewMode === 'daily' && activeDay ? (
              <div className="space-y-2 max-w-lg mx-auto pb-20">
                  {activeDay.exercises.map(ex => (
                      <ExerciseCard 
                        key={ex.id} 
                        exercise={ex} 
                        role={role}
                        onUpdate={(id, up) => handleExerciseUpdate(id, up)} 
                        onShowHistory={(e) => setChartExercise(e)} 
                        onDelete={(id) => handleRemoveExercise(activeDayId, id)} 
                      />
                  ))}
                  {activeDay.exercises.length === 0 && (
                      <div className="text-center py-20 opacity-20">
                          <Activity size={48} className="mx-auto mb-4" />
                          <p className="font-black uppercase text-xs">Sin ejercicios asignados</p>
                      </div>
                  )}
              </div>
          ) : viewMode === 'weekly' ? (
              <div className="h-full overflow-x-auto scroll-container">
                  <div className="flex items-start gap-4 min-w-max pb-10">
                      {patient.routine.days.map((day, idx) => (
                          <div key={day.id} className="w-60 shrink-0 bg-white rounded-xl p-3 shadow-sm border border-slate-100">
                              <div className="flex items-center gap-2 mb-3 border-b pb-1.5">
                                  <span className="text-[8px] font-black text-slate-400 tracking-tighter uppercase">Día {idx + 1}</span>
                                  <h4 className="text-[10px] font-black text-slate-800 truncate uppercase">{day.name}</h4>
                              </div>
                              <div className="space-y-1">
                                  {day.exercises.map(ex => (
                                      <div key={ex.id} className="flex items-center gap-2 p-1.5 bg-slate-50 rounded-lg border border-slate-50">
                                          <img src={ex.definition.videoUrl} className="w-6 h-6 rounded-md object-cover shrink-0" />
                                          <div className="flex-1 min-w-0">
                                              <p className="font-bold text-[9px] text-slate-700 leading-tight truncate">{ex.definition.name}</p>
                                              <p className="text-[8px] font-black text-slate-400 uppercase mt-0.5">{ex.targetSets}x{ex.targetReps} • {ex.targetLoad}kg</p>
                                          </div>
                                      </div>
                                  ))}
                              </div>
                          </div>
                      ))}
                  </div>
              </div>
          ) : viewMode === 'monthly' ? (
              /* VISTA MENSUAL MEJORADA */
              <div className="space-y-10 pb-20 max-w-3xl mx-auto">
                  <div className="bg-white p-4 rounded-2xl border border-slate-200 flex items-center justify-between mb-8 shadow-sm">
                      <div className="flex items-center gap-4">
                        <div className="w-10 h-10 bg-gym/10 text-gym rounded-xl flex items-center justify-center">
                            <Trending Up size={20} />
                        </div>
                        <div>
                            <h3 className="font-black text-sm uppercase text-slate-900 leading-none">Progresión Mensual</h3>
                            <p className="text-[9px] font-bold text-slate-400 mt-1 uppercase">Estimación de carga semanal (+5%)</p>
                        </div>
                      </div>
                  </div>

                  {[1, 2, 3, 4].map((weekNum) => (
                      <div key={weekNum} className="relative pl-6 border-l-2 border-slate-200 space-y-4">
                          <div className="absolute -left-2 top-0 w-4 h-4 bg-white border-2 border-slate-400 rounded-full flex items-center justify-center">
                              <div className="w-1.5 h-1.5 bg-slate-400 rounded-full"></div>
                          </div>

                          <div className="flex items-center gap-3 mb-2">
                              <h4 className="font-black text-[10px] uppercase tracking-widest text-slate-900 bg-slate-100 px-3 py-1 rounded-full border border-slate-200 shadow-sm">
                                  Semana {weekNum}
                              </h4>
                          </div>

                          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3">
                              {patient.routine.days.map((day, dIdx) => (
                                  <div key={`${weekNum}-${day.id}`} className="bg-white p-3 rounded-xl border border-slate-100 shadow-sm">
                                      <p className="text-[8px] font-black text-slate-400 uppercase mb-2">Día {dIdx+1}</p>
                                      <div className="space-y-1.5">
                                          {day.exercises.map(ex => {
                                              const projectedLoad = (ex.targetLoad * (1 + (weekNum - 1) * 0.05)).toFixed(1);
                                              return (
                                                <div key={`${weekNum}-${ex.id}`} className="flex justify-between items-center text-[9px] p-1.5 bg-slate-50 rounded-lg">
                                                    <span className="font-bold text-slate-600 truncate mr-2">{ex.definition.name}</span>
                                                    <span className="font-black text-primary-600 shrink-0">{projectedLoad}kg</span>
                                                </div>
                                              );
                                          })}
                                          {day.exercises.length === 0 && <p className="text-[8px] text-slate-300 italic">Sin datos</p>}
                                      </div>
                                  </div>
                              ))}
                          </div>
                      </div>
                  ))}
              </div>
          ) : null}
        </div>
      </main>

      {chartExercise && <ProgressChart exercise={chartExercise} onClose={() => setChartExercise(null)} />}

      {isAddingExerciseModal.show && (
          <div className="fixed inset-0 z-[350] bg-slate-900/40 backdrop-blur-sm flex items-center justify-center p-4">
              <div className="bg-white w-full max-w-sm h-[60vh] rounded-2xl shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95 duration-200">
                  <div className="p-3 border-b flex items-center gap-2">
                      <div className="relative flex-1">
                          <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 text-slate-300" size={14} />
                          <input 
                              type="text" 
                              placeholder="Buscar..." 
                              className="w-full pl-8 pr-3 py-1.5 bg-slate-50 border-none rounded-lg text-[10px] font-bold outline-none" 
                              value={exerciseSearch} 
                              onChange={e => setExerciseSearch(e.target.value)} 
                          />
                      </div>
                      <button onClick={() => setIsAddingExerciseModal({show:false, dayId:''})} className="p-1.5 text-slate-400 hover:bg-slate-50 rounded-lg"><X size={16}/></button>
                  </div>
                  <div className="flex-1 overflow-y-auto p-2 space-y-1 scroll-container">
                      {EXERCISES.filter(ex => ex.name.toLowerCase().includes(exerciseSearch.toLowerCase())).map(ex => {
                          const isSelected = selectedExerciseIds.includes(ex.id);
                          return (
                              <button 
                                key={ex.id} 
                                onClick={() => setSelectedExerciseIds(prev => isSelected ? prev.filter(i => i !== ex.id) : [...prev, ex.id])} 
                                className={`w-full flex items-center p-2 rounded-lg border-2 transition-all ${isSelected ? 'bg-primary-50 border-primary-400' : 'bg-white border-slate-50'}`}
                              >
                                  <div className="mr-2">{isSelected ? <CheckSquare size={14} className="text-primary-600"/> : <Square size={14} className="text-slate-200"/>}</div>
                                  <img src={ex.videoUrl} className="w-8 h-8 rounded-md object-cover mr-2" />
                                  <div className="text-left flex-1 min-w-0">
                                      <p className="font-bold text-slate-800 text-[10px] truncate leading-none">{ex.name}</p>
                                      <span className="text-[8px] text-slate-400 uppercase font-black">{ex.category}</span>
                                  </div>
                              </button>
                          );
                      })}
                  </div>
                  <div className="p-3 bg-white border-t">
                        <button 
                            disabled={selectedExerciseIds.length === 0}
                            className="bg-primary-600 text-white w-full py-2.5 rounded-lg font-bold text-xs disabled:opacity-30"
                            onClick={() => {
                                const newExs: RoutineExercise[] = selectedExerciseIds.map(id => ({
                                    id: `re-${Date.now()}-${id}`,
                                    definitionId: id,
                                    definition: EXERCISES.find(e => e.id === id)!,
                                    targetSets: 3, targetReps: 12, targetLoad: 0, isDone: false, history: []
                                }));
                                const newDays = patient.routine.days.map(d => d.id === isAddingExerciseModal.dayId ? { ...d, exercises: [...d.exercises, ...newExs] } : d);
                                onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
                                setIsAddingExerciseModal({show:false, dayId:''});
                                setSelectedExerciseIds([]);
                            }}
                        >
                            Confirmar ({selectedExerciseIds.length})
                        </button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

import React from 'react';
import { Patient } from '../types';
import { X, Home, Wifi, WifiOff, Activity } from 'lucide-react';

interface SidebarProps {
