      <nav className="p-1 space-y-1">
        <button 
          onClick={onGoHome}
          title="Panel Central"
          className={`w-full flex flex-col items-center justify-center gap-1 py-4 rounded-xl transition-all ${!selectedPatientId ? 'bg-primary-50 text-primary-600' : 'text-slate-400 hover:bg-slate-50'}`}
        >
          <Home size={22} />
          <span className="text-[6px] font-black uppercase tracking-tighter">Panel</span>
