        <div className="space-y-3">
          {activePatients.map((patient) => (
            <div 
              key={patient.id}
              onClick={() => onSelectPatient(patient.id)}
              title={patient.firstName}
              className={`group relative flex flex-col items-center p-1 rounded-xl cursor-pointer transition-all border ${selectedPatientId === patient.id ? 'bg-white border-primary-100 shadow-sm ring-2 ring-primary-50' : 'border-transparent hover:bg-slate-50'}`}
            >
              <img src={patient.photoUrl} className="w-10 h-10 rounded-lg object-cover shrink-0 shadow-sm" />
              <p className={`font-black text-[6px] truncate max-w-full uppercase mt-1 tracking-tighter text-center leading-none ${selectedPatientId === patient.id ? 'text-slate-900' : 'text-slate-400'}`}>
                {patient.firstName}
              </p>
              <button 
                onClick={(e) => onRemoveActive(patient.id, e)}
