import React, { useState, useEffect } from 'react';
import { Patient, RoutineExercise, Stage, UserRole, RoutineDay } from '../types';
import { EXERCISES } from '../constants';
import { ExerciseCard } from './ExerciseCard';
import { ProgressChart } from './ProgressChart';
import { 
  LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, AreaChart, Area
} from 'recharts';
import { 
    FileText, Plus, Search, X, Calendar, Trash2, Edit2, Save, Wand2,
    Activity, Minus, Layers, TrendingUp, CheckSquare, Square, BarChart2
} from 'lucide-react';

interface PatientDetailProps {
  patient: Patient;
  role: UserRole;
  onUpdatePatient: (updated: Patient) => void;
}

export const PatientDetail: React.FC<PatientDetailProps> = ({
  patient,
  role,
  onUpdatePatient,
}) => {
  const [activeDayId, setActiveDayId] = useState<string>(patient.routine.days[0]?.id || '');
  const [viewMode, setViewMode] = useState<'daily' | 'weekly' | 'monthly' | 'stats'>('daily');
  const [showHistory, setShowHistory] = useState(false);
  const [showRoutineEditor, setShowRoutineEditor] = useState(false);
  const [chartExercise, setChartExercise] = useState<RoutineExercise | null>(null);

  const [isAddingExerciseModal, setIsAddingExerciseModal] = useState<{show: boolean, dayId: string}>({show: false, dayId: ''});
  const [exerciseSearch, setExerciseSearch] = useState('');
  const [selectedExerciseIds, setSelectedExerciseIds] = useState<string[]>([]);
  const [notes, setNotes] = useState(patient.history[0] || '');

  const isKine = role === UserRole.KINE;

  useEffect(() => {
    if (patient.routine.days.length > 0 && (!activeDayId || !patient.routine.days.find(d => d.id === activeDayId))) {
        setActiveDayId(patient.routine.days[0].id);
    }
  }, [patient, activeDayId]);

  const activeDay = patient.routine.days.find(d => d.id === activeDayId);

  // Calcula si se puede borrar el último día (solo si no tiene ejercicios)
  const canDeleteLastDay = patient.routine.days.length > 1 && 
    patient.routine.days[patient.routine.days.length - 1].exercises.length === 0;

  const handleExerciseUpdate = (exerciseId: string, updates: Partial<RoutineExercise>) => {
    const newDays = patient.routine.days.map(day => ({
        ...day,
        exercises: day.exercises.map(ex => ex.id === exerciseId ? { ...ex, ...updates } : ex)
    }));
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  const handleRemoveExercise = (dayId: string, exerciseId: string) => {
    const newDays = patient.routine.days.map(day => 
        day.id === dayId ? { ...day, exercises: day.exercises.filter(ex => ex.id !== exerciseId) } : day
    );
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  const handleUpdateStage = (newStage: Stage) => {
    onUpdatePatient({ ...patient, routine: { ...patient.routine, stage: newStage } });
  };

  const handleAddDay = () => {
    if (patient.routine.days.length >= 7) return;
    const newDay: RoutineDay = {
      id: `day-${Date.now()}`,
      name: `Día ${patient.routine.days.length + 1}`,
      exercises: []
    };
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: [...patient.routine.days, newDay] } });
  };

  const handleRemoveLastDay = () => {
    if (!canDeleteLastDay) return;
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: patient.routine.days.slice(0, -1) } });
  };

  const handleRemoveDay = (dayId: string) => {
    const day = patient.routine.days.find(d => d.id === dayId);
    if (!day || day.exercises.length > 0) return; // Protegemos días con contenido
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: patient.routine.days.filter(d => d.id !== dayId) } });
  };

  const handleRenameDay = (dayId: string, newName: string) => {
    const newDays = patient.routine.days.map(day => 
      day.id === dayId ? { ...day, name: newName } : day
    );
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  // Generación de datos simulados para el gráfico de volumen total
  const statsData = [
    { name: 'Sem 1', volumen: 4500 },
    { name: 'Sem 2', volumen: 4850 },
    { name: 'Sem 3', volumen: 5200 },
    { name: 'Sem 4', volumen: 5100 },
    { name: 'Sem 5', volumen: 5800 },
    { name: 'Sem 6', volumen: 6400 },
  ];

  return (
    <div className="flex-1 h-full flex flex-col bg-slate-50 overflow-hidden relative">
      <header className="bg-white border-b border-slate-200 px-4 py-2 flex items-center justify-between shrink-0 z-30 pt-[calc(0.25rem+var(--sat))]">
        <div className="flex flex-col min-w-0">
          <h2 className="text-sm font-black text-slate-900 leading-none truncate uppercase tracking-tighter">
            {patient.firstName} {patient.lastName}
          </h2>
          <p className="text-[7px] text-slate-400 font-black mt-0.5 uppercase tracking-widest leading-none">{patient.condition}</p>
        </div>
        <div className="flex gap-1.5 items-center">
            <span className={`px-2 py-1 rounded text-[7px] font-black uppercase ${patient.routine.stage === Stage.KINESIOLOGY ? 'bg-kine/10 text-kine' : 'bg-gym/10 text-gym'}`}>
                {patient.routine.stage}
            </span>
            {isKine && (
                <button 
                  onClick={() => setShowRoutineEditor(true)} 
                  className="bg-slate-900 text-white px-3 py-1.5 rounded-xl font-bold text-[8px] uppercase hover:bg-slate-800 transition-all flex items-center gap-1"
                >
                    <Edit2 size={10} />
                    <span>Rutina</span>
                </button>
            )}
            <button 
              onClick={() => setShowHistory(!showHistory)} 
              className={`p-1.5 rounded-xl border transition-all ${showHistory ? 'bg-primary-50 border-primary-200 text-primary-600' : 'bg-white border-slate-200 text-slate-400'}`}
            >
                <FileText size={16} />
            </button>
        </div>
      </header>

      {showHistory && (
          <div className="bg-slate-900 text-white p-3 shadow-xl z-20 border-b border-slate-800 animate-in slide-in-from-top duration-200">
              <div className="max-w-4xl mx-auto flex gap-4 items-center">
                  <textarea 
                    className="flex-1 h-12 bg-slate-800/50 text-slate-200 p-2 rounded-xl border border-slate-700 outline-none resize-none text-[10px]" 
                    value={notes} 
                    onChange={(e) => setNotes(e.target.value)} 
                    placeholder="Notas clínicas..." 
                  />
                  <button className="bg-primary-600 text-white p-3 rounded-xl hover:bg-primary-500 transition-colors"><Save size={16}/></button>
              </div>
          </div>
      )}

      {showRoutineEditor && (
          <div className="fixed inset-0 z-[100] bg-slate-50 flex flex-col pt-[var(--sat)] animate-in slide-in-from-bottom-5 duration-300">
              <header className="bg-white border-b border-slate-200 px-4 py-2 flex items-center justify-between shrink-0">
                  <div className="flex items-center gap-6">
                      <div className="flex bg-slate-100 p-0.5 rounded-xl">
                          <button 
                            onClick={() => handleUpdateStage(Stage.KINESIOLOGY)}
                            className={`px-4 py-1.5 rounded-lg text-[8px] font-black uppercase transition-all ${patient.routine.stage === Stage.KINESIOLOGY ? 'bg-white text-kine shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
                          >
                            Etapa Kine
                          </button>
                          <button 
                            onClick={() => handleUpdateStage(Stage.GYM)}
                            className={`px-4 py-1.5 rounded-lg text-[8px] font-black uppercase transition-all ${patient.routine.stage === Stage.GYM ? 'bg-white text-gym shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
                          >
                            Etapa Gym
                          </button>
                      </div>

                      <div className="flex items-center gap-2 bg-white px-3 py-1.5 rounded-xl border border-slate-200 shadow-sm">
                          <button 
                            onClick={handleRemoveLastDay} 
                            disabled={!canDeleteLastDay}
                            className="text-slate-400 hover:text-red-500 disabled:opacity-20 transition-colors"
                            title={!canDeleteLastDay ? "No se puede borrar un día que ya tiene ejercicios" : "Quitar día"}
                          >
                            <Minus size={18}/>
                          </button>
                          <div className="flex flex-col items-center min-w-[40px]">
                              <span className="text-[12px] font-black leading-none">{patient.routine.days.length}</span>
                              <span className="text-[6px] font-black uppercase text-slate-300 tracking-tighter">Días de Entrenamiento</span>
                          </div>
                          <button 
                            onClick={handleAddDay} 
                            disabled={patient.routine.days.length >= 7}
                            className="text-slate-400 hover:text-primary-600 disabled:opacity-20 transition-colors"
                          >
                            <Plus size={18}/>
                          </button>
                      </div>
                  </div>

                  <button onClick={() => setShowRoutineEditor(false)} className="p-2 hover:bg-slate-100 rounded-full transition-colors"><X size={20} /></button>
              </header>

              <div className="flex-1 overflow-x-auto p-4 scroll-container bg-slate-50">
                  <div className="flex items-start gap-4 h-full min-w-max pb-10">
                      {patient.routine.days.map((day, dIdx) => (
                          <div key={day.id} className="w-64 bg-white rounded-2xl border border-slate-200 shadow-sm flex flex-col h-full shrink-0 group hover:shadow-md transition-shadow">
                              <div className="p-4 border-b border-slate-50 flex items-center justify-between">
                                  <div className="flex items-center gap-2">
                                      <span className="text-[10px] font-black text-slate-300">DÍA {dIdx+1}</span>
                                      <input 
                                        className="font-black text-xs text-slate-800 bg-transparent border-none focus:ring-0 p-0 w-28 uppercase"
                                        value={day.name}
                                        onChange={(e) => handleRenameDay(day.id, e.target.value)}
                                      />
                                  </div>
                                  <button 
                                    onClick={() => handleRemoveDay(day.id)} 
                                    disabled={day.exercises.length > 0}
                                    className={`transition-all ${day.exercises.length > 0 ? 'opacity-0 cursor-default' : 'text-slate-200 hover:text-red-500'}`}
                                  >
                                    <Trash2 size={14}/>
                                  </button>
                              </div>

                              <div className="flex-1 overflow-y-auto p-3 space-y-2 scroll-container">
                                  {day.exercises.map((ex) => (
                                      <div key={ex.id} className="flex items-center justify-between p-2.5 bg-slate-50 rounded-xl border border-transparent hover:border-slate-200 transition-all group/ex">
                                          <div className="flex items-center gap-2 min-w-0">
                                              <img src={ex.definition.videoUrl} className="w-8 h-8 rounded-lg object-cover bg-slate-200 shrink-0" />
                                              <div className="min-w-0">
                                                  <p className="font-bold text-[10px] text-slate-800 truncate leading-none">{ex.definition.name}</p>
                                                  <p className="text-[8px] text-slate-400 mt-1 uppercase font-black">{ex.targetSets}x{ex.targetReps} @ {ex.targetLoad}kg</p>
                                              </div>
                                          </div>
                                          <button onClick={() => handleRemoveExercise(day.id, ex.id)} className="p-1.5 text-slate-300 hover:text-red-500 hover:bg-white rounded-lg transition-colors"><X size={12}/></button>
                                      </div>
                                  ))}
                                  <button 
                                    onClick={() => setIsAddingExerciseModal({show: true, dayId: day.id})}
                                    className="w-full py-4 border-2 border-dashed border-slate-200 rounded-xl text-[9px] font-black text-slate-400 uppercase hover:bg-slate-50 hover:text-primary-600 hover:border-primary-200 transition-all flex flex-col items-center gap-1"
                                  >
                                      <Plus size={14} />
                                      Agregar Ejercicio
                                  </button>
                              </div>
                          </div>
                      ))}

                      <button 
                        onClick={handleAddDay}
                        disabled={patient.routine.days.length >= 7}
                        className="w-20 h-full flex flex-col items-center justify-center bg-white/40 rounded-2xl border-2 border-dashed border-slate-200 text-slate-300 hover:bg-white hover:text-primary-500 hover:border-primary-300 transition-all group shrink-0 disabled:opacity-0"
                      >
                          <Plus size={28} className="group-hover:scale-110 transition-transform" />
                          <span className="text-[7px] font-black uppercase mt-2">Nuevo Día</span>
                      </button>
                  </div>
              </div>
          </div>
      )}

      {/* Selector de Navegación Principal */}
      <div className="bg-white border-b border-slate-200 px-4 flex justify-between shrink-0 h-12 items-end">
          <div className="flex gap-1 overflow-x-auto no-scrollbar">
            {patient.routine.days.map((day) => (
              <button 
                key={day.id} 
                onClick={() => {setActiveDayId(day.id); setViewMode('daily');}} 
                className={`px-4 py-2.5 rounded-t-xl font-bold text-[10px] uppercase tracking-wider transition-all border-t border-x ${activeDayId === day.id && viewMode === 'daily' ? 'bg-slate-50 border-slate-200 text-primary-600' : 'bg-white border-transparent text-slate-300 hover:text-slate-400'}`}
              >
                {day.name}
              </button>
            ))}
          </div>
          <div className="flex items-center pb-2 gap-1.5 border-l pl-3 ml-2 shrink-0">
              <button 
                onClick={() => setViewMode('weekly')} 
                title="Vista Semanal"
                className={`p-2 rounded-xl transition-all ${viewMode === 'weekly' ? 'bg-primary-600 text-white shadow-lg' : 'bg-slate-50 text-slate-400 hover:text-slate-600'}`}
              >
                <Calendar size={18}/>
              </button>
              <button 
                onClick={() => setViewMode('monthly')} 
                title="Ciclo Mensual"
                className={`p-2 rounded-xl transition-all ${viewMode === 'monthly' ? 'bg-gym text-white shadow-lg' : 'bg-slate-50 text-slate-400 hover:text-slate-600'}`}
              >
                <Layers size={18}/>
              </button>
              <button 
                onClick={() => setViewMode('stats')} 
                title="Estadísticas de Progreso"
                className={`p-2 rounded-xl transition-all ${viewMode === 'stats' ? 'bg-slate-900 text-white shadow-lg' : 'bg-slate-50 text-slate-400 hover:text-slate-600'}`}
              >
                <BarChart2 size={18}/>
              </button>
          </div>
      </div>

      <main className="flex-1 overflow-y-auto p-4 md:p-6 scroll-container">
        <div className="max-w-4xl mx-auto h-full">
          {viewMode === 'daily' && activeDay ? (
              <div className="space-y-3 max-w-xl mx-auto pb-20">
                  {activeDay.exercises.map(ex => (
                      <ExerciseCard 
                        key={ex.id} 
                        exercise={ex} 
                        role={role}
                        onUpdate={(id, up) => handleExerciseUpdate(id, up)} 
                        onShowHistory={(e) => setChartExercise(e)} 
                        onDelete={(id) => handleRemoveExercise(activeDayId, id)} 
                      />
                  ))}
              </div>
          ) : viewMode === 'weekly' ? (
              <div className="h-full overflow-x-auto scroll-container">
                  <div className="flex items-start gap-5 min-w-max pb-10">
                      {patient.routine.days.map((day, idx) => (
                          <div key={day.id} className="w-64 shrink-0 bg-white rounded-2xl p-4 shadow-md border border-slate-100">
                              <div className="flex items-center gap-2 mb-4 border-b border-slate-50 pb-2">
                                  <span className="text-[10px] font-black text-slate-400 tracking-tighter uppercase">DÍA {idx + 1}</span>
                                  <h4 className="text-[11px] font-black text-slate-800 truncate uppercase">{day.name}</h4>
                              </div>
                              <div className="space-y-2">
                                  {day.exercises.map(ex => (
                                      <div key={ex.id} className="flex items-center gap-3 p-2 bg-slate-50 rounded-xl border border-slate-50">
                                          <img src={ex.definition.videoUrl} className="w-8 h-8 rounded-lg object-cover shrink-0" />
                                          <div className="flex-1 min-w-0">
                                              <p className="font-bold text-[10px] text-slate-700 leading-tight truncate">{ex.definition.name}</p>
                                              <p className="text-[9px] font-black text-primary-600 uppercase mt-0.5">{ex.targetSets}x{ex.targetReps} • {ex.targetLoad}kg</p>
                                          </div>
                                      </div>
                                  ))}
                              </div>
                          </div>
                      ))}
                  </div>
              </div>
          ) : viewMode === 'monthly' ? (
              /* VISTA MENSUAL: APILADO VERTICAL DE SEMANAS */
              <div className="space-y-12 pb-20 max-w-4xl mx-auto">
                  <div className="text-center space-y-2 mb-8">
                      <h3 className="text-xl font-black text-slate-900 uppercase">Ciclo de Entrenamiento Mensual</h3>
                      <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Planificación con sobrecarga progresiva (+5%)</p>
                  </div>

                  {[1, 2, 3, 4].map((weekNum) => (
                      <div key={weekNum} className="bg-white rounded-[2rem] border border-slate-200 overflow-hidden shadow-sm">
                          <div className="bg-slate-900 px-6 py-3 flex justify-between items-center">
                              <h4 className="text-white font-black text-xs uppercase tracking-[0.2em]">Semana {weekNum}</h4>
                              <span className="text-slate-400 text-[9px] font-black uppercase">Progreso: +{((weekNum-1)*5)}% Carga</span>
                          </div>
                          <div className="p-6 overflow-x-auto no-scrollbar">
                              <div className="flex gap-4 min-w-max">
                                  {patient.routine.days.map((day, idx) => (
                                      <div key={`${weekNum}-${day.id}`} className="w-56 shrink-0 bg-slate-50/50 rounded-2xl p-4 border border-slate-100">
                                          <p className="text-[9px] font-black text-slate-400 uppercase mb-3 pb-2 border-b">Día {idx+1}</p>
                                          <div className="space-y-2">
                                              {day.exercises.map(ex => {
                                                  const baseLoad = ex.targetLoad;
                                                  const projected = (baseLoad * (1 + (weekNum-1)*0.05)).toFixed(1);
                                                  return (
                                                    <div key={`${weekNum}-${ex.id}`} className="flex flex-col gap-1 p-2 bg-white rounded-xl border border-slate-100 shadow-sm">
                                                        <span className="text-[9px] font-bold text-slate-800 truncate">{ex.definition.name}</span>
                                                        <div className="flex justify-between items-center">
                                                          <span className="text-[8px] font-black text-slate-400">{ex.targetSets}x{ex.targetReps}</span>
                                                          <span className="text-[10px] font-black text-primary-600">{projected}kg</span>
                                                        </div>
                                                    </div>
                                                  );
                                              })}
                                          </div>
                                      </div>
                                  ))}
                              </div>
                          </div>
                      </div>
                  ))}
              </div>
          ) : viewMode === 'stats' ? (
              /* DASHBOARD DE ESTADÍSTICAS */
              <div className="space-y-6 pb-20 max-w-4xl mx-auto">
                  <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                      <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm flex flex-col items-center">
                          <span className="text-[10px] font-black text-slate-400 uppercase mb-2">Volumen Total Semanal</span>
                          <span className="text-3xl font-black text-slate-900">6,400 <small className="text-xs text-slate-400">kg</small></span>
                          <span className="text-[10px] font-bold text-kine mt-1 flex items-center gap-1"><TrendingUp size={10}/> +12% vs sem. ant</span>
                      </div>
                      <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm flex flex-col items-center">
                          <span className="text-[10px] font-black text-slate-400 uppercase mb-2">Adherencia al Plan</span>
                          <span className="text-3xl font-black text-slate-900">85<small className="text-xs text-slate-400">%</small></span>
                          <span className="text-[10px] font-bold text-slate-400 mt-1 uppercase">Muy Bueno</span>
                      </div>
                      <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm flex flex-col items-center">
                          <span className="text-[10px] font-black text-slate-400 uppercase mb-2">Promedio RPE</span>
                          <span className="text-3xl font-black text-slate-900">7.2</span>
                          <span className="text-[10px] font-bold text-gym mt-1 uppercase">Zona de Hipertrofia</span>
                      </div>
                  </div>

                  <div className="bg-white p-6 rounded-[2.5rem] border border-slate-200 shadow-sm">
                      <div className="flex justify-between items-center mb-8 px-2">
                        <div>
                          <h4 className="font-black text-sm uppercase text-slate-900">Curva de Volumen de Carga</h4>
                          <p className="text-[9px] text-slate-400 uppercase font-bold">Progreso consolidado de todos los ejercicios</p>
                        </div>
                        <BarChart2 className="text-slate-200" size={32} />
                      </div>
                      <div className="h-64 w-full">
                          <ResponsiveContainer width="100%" height="100%">
                              <AreaChart data={statsData}>
                                <defs>
                                  <linearGradient id="colorVol" x1="0" y1="0" x2="0" y2="1">
                                    <stop offset="5%" stopColor="#0ea5e9" stopOpacity={0.1}/>
                                    <stop offset="95%" stopColor="#0ea5e9" stopOpacity={0}/>
                                  </linearGradient>
                                </defs>
                                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                                <XAxis 
                                  dataKey="name" 
                                  axisLine={false} 
                                  tickLine={false} 
                                  tick={{fontSize: 9, fontWeight: 800, fill: '#94a3b8'}} 
                                />
                                <YAxis hide />
                                <Tooltip 
                                  contentStyle={{borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)', fontSize: '10px'}}
                                />
                                <Area 
                                  type="monotone" 
                                  dataKey="volumen" 
                                  stroke="#0ea5e9" 
                                  strokeWidth={4} 
                                  fillOpacity={1} 
                                  fill="url(#colorVol)" 
                                />
                              </AreaChart>
                          </ResponsiveContainer>
                      </div>
                  </div>
              </div>
          ) : null}
        </div>
      </main>

      {chartExercise && <ProgressChart exercise={chartExercise} onClose={() => setChartExercise(null)} />}

      {isAddingExerciseModal.show && (
          <div className="fixed inset-0 z-[350] bg-slate-900/40 backdrop-blur-sm flex items-center justify-center p-4">
              <div className="bg-white w-full max-w-md h-[70vh] rounded-[2.5rem] shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95 duration-200">
                  <div className="p-4 border-b flex items-center gap-3">
                      <div className="relative flex-1">
                          <Search className="absolute left-3.5 top-1/2 -translate-y-1/2 text-slate-300" size={16} />
                          <input 
                              type="text" 
                              placeholder="Buscar ejercicio..." 
                              className="w-full pl-10 pr-4 py-3 bg-slate-50 border-none rounded-2xl text-[12px] font-bold outline-none focus:ring-2 focus:ring-primary-500 transition-all" 
                              value={exerciseSearch} 
                              onChange={e => setExerciseSearch(e.target.value)} 
                          />
                      </div>
                      <button onClick={() => setIsAddingExerciseModal({show:false, dayId:''})} className="p-2 text-slate-400 hover:bg-slate-50 rounded-full transition-colors"><X size={20}/></button>
                  </div>
                  <div className="flex-1 overflow-y-auto p-4 space-y-2 scroll-container">
                      {EXERCISES.filter(ex => ex.name.toLowerCase().includes(exerciseSearch.toLowerCase())).map(ex => {
                          const isSelected = selectedExerciseIds.includes(ex.id);
                          return (
                              <button 
                                key={ex.id} 
                                onClick={() => setSelectedExerciseIds(prev => isSelected ? prev.filter(i => i !== ex.id) : [...prev, ex.id])} 
                                className={`w-full flex items-center p-3 rounded-2xl border-2 transition-all text-left ${isSelected ? 'bg-primary-50 border-primary-500' : 'bg-white border-slate-50 hover:bg-slate-50'}`}
                              >
                                  <div className="mr-3">{isSelected ? <CheckSquare size={20} className="text-primary-600"/> : <Square size={20} className="text-slate-200"/>}</div>
                                  <img src={ex.videoUrl} className="w-10 h-10 rounded-xl object-cover mr-3 shadow-sm" />
                                  <div className="flex-1 min-w-0">
                                      <p className="font-black text-slate-800 text-[11px] truncate uppercase leading-none">{ex.name}</p>
                                      <span className="text-[8px] text-slate-400 uppercase font-black tracking-widest mt-1 inline-block">{ex.category}</span>
                                  </div>
                              </button>
                          );
                      })}
                  </div>
                  <div className="p-4 bg-white border-t">
                        <button 
                            disabled={selectedExerciseIds.length === 0}
                            className="bg-primary-600 text-white w-full py-4 rounded-2xl font-black text-[10px] uppercase tracking-widest disabled:opacity-30 shadow-xl shadow-primary-200 transition-all"
                            onClick={() => {
                                const newExs: RoutineExercise[] = selectedExerciseIds.map(id => ({
                                    id: `re-${Date.now()}-${id}`,
                                    definitionId: id,
                                    definition: EXERCISES.find(e => e.id === id)!,
                                    targetSets: 3, targetReps: 12, targetLoad: 0, isDone: false, history: []
                                }));
                                const newDays = patient.routine.days.map(d => d.id === isAddingExerciseModal.dayId ? { ...d, exercises: [...d.exercises, ...newExs] } : d);
                                onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
                                setIsAddingExerciseModal({show:false, dayId:''});
                                setSelectedExerciseIds([]);
                            }}
                        >
                            Confirmar Selección ({selectedExerciseIds.length})
                        </button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

import React from 'react';
import { Patient } from '../types';
import { X, Home, Wifi, WifiOff, Activity } from 'lucide-react';

interface SidebarProps {
