          <div 
            key={patient.id}
            onClick={() => onSelectPatient(patient.id)}
            title={`${patient.firstName} ${patient.lastName}`}
            className={`group relative flex flex-col items-center p-0.5 rounded-xl cursor-pointer transition-all border-2 shrink-0 ${selectedPatientId === patient.id ? 'bg-white border-primary-500 shadow-sm ring-4 ring-primary-50' : 'border-transparent hover:bg-slate-50'}`}
          >
