            <div className="absolute -top-0.5 -right-0.5 w-1.5 h-1.5 bg-kine rounded-full animate-ping"></div>
          </div>
        ) : (
          <WifiOff size={20} className="text-red-500 animate-pulse" />
        )}
      </div>
    </aside>
  );
};

