const generateHistory = (baseLoad: number): any[] => {
  const history = [];
  let currentLoad = baseLoad;
  for (let i = 5; i >= 1; i--) {
    history.push({
      date: new Date(Date.now() - i * 86400000 * 3).toISOString().split('T')[0],
      load: currentLoad,
      reps: 10,
      rpe: Math.floor(Math.random() * 3) + 6,
    });
    currentLoad += 2.5;
  }
  return history;
};

