interface PatientDetailProps {
  patient: Patient;
  role: UserRole;
  onUpdatePatient: (updated: Patient) => void;
}

export const PatientDetail: React.FC<PatientDetailProps> = ({
  patient,
  role,
  onUpdatePatient,
}) => {
  const [activeDayId, setActiveDayId] = useState<string>(patient.routine.days[0]?.id || '');
  const [viewMode, setViewMode] = useState<'daily' | 'plan' | 'stats'>('daily');
  const [showHistory, setShowHistory] = useState(false);
  const [showRoutineEditor, setShowRoutineEditor] = useState(false);
  const [chartExercise, setChartExercise] = useState<RoutineExercise | null>(null);
  const [exerciseSearch, setExerciseSearch] = useState('');
  const [selectedExerciseIds, setSelectedExerciseIds] = useState<string[]>([]);
  const [isAddingExerciseModal, setIsAddingExerciseModal] = useState<{show: boolean, dayId: string}>({show: false, dayId: ''});
  const [notes, setNotes] = useState(patient.history[0] || '');

  const isKine = role === UserRole.KINE;

  useEffect(() => {
    if (patient.routine.days.length > 0 && (!activeDayId || !patient.routine.days.find(d => d.id === activeDayId))) {
        setActiveDayId(patient.routine.days[0].id);
    }
  }, [patient, activeDayId]);

  const activeDay = patient.routine.days.find(d => d.id === activeDayId);

  // LOGICA PARA CERRAR LA SEMANA Y PASAR A LA SIGUIENTE
  const handleStartNewWeek = () => {
    const hasAnyProgress = patient.routine.days.some(day => day.exercises.some(ex => ex.isDone));

    if (!hasAnyProgress) {
        if (!window.confirm("No hay ejercicios marcados esta semana. ¿Quieres pasar a la siguiente de todas formas?")) return;
    } else {
        if (!window.confirm("¿Finalizar esta semana? Se archivarán todos los progresos realizados y la rutina se limpiará para la semana siguiente. Los pesos actuales se mantendrán como base.")) return;
    }

    const today = new Date().toISOString().split('T')[0];
    const newDays = patient.routine.days.map(day => ({
      ...day,
      exercises: day.exercises.map(ex => {
        // Solo guardamos en historial si se marcó como hecho en algún momento
        const newHistory = [...(ex.history || [])];
        if (ex.isDone) {
            newHistory.push({
                date: today,
                load: ex.targetLoad,
                reps: ex.targetReps,
                rpe: ex.currentRpe || 5
            });
        }

        return {
          ...ex,
          isDone: false, // Limpiar check
          currentRpe: undefined, // Limpiar esfuerzo
          history: newHistory
        };
      })
    }));

    onUpdatePatient({
      ...patient,
      routine: {
        ...patient.routine,
        days: newDays,
        currentWeek: (patient.routine.currentWeek || 1) + 1
      },
      lastVisit: today
    });

    alert(`¡Semana ${(patient.routine.currentWeek || 1)} finalizada! Ahora estás en la Semana ${(patient.routine.currentWeek || 1) + 1}.`);
  };

  const handleExerciseUpdate = (exerciseId: string, updates: Partial<RoutineExercise>) => {
    const newDays = patient.routine.days.map(day => ({
        ...day,
        exercises: day.exercises.map(ex => ex.id === exerciseId ? { ...ex, ...updates } : ex)
    }));
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  const handleRemoveExercise = (dayId: string, exerciseId: string) => {
    const newDays = patient.routine.days.map(day => 
        day.id === dayId ? { ...day, exercises: day.exercises.filter(ex => ex.id !== exerciseId) } : day
    );
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  const handleUpdateStage = (newStage: Stage) => {
    onUpdatePatient({ ...patient, routine: { ...patient.routine, stage: newStage } });
  };

  const handleAddDay = () => {
    if (patient.routine.days.length >= 7) return;
    const newDay: RoutineDay = { id: `day-${Date.now()}`, name: `Día ${patient.routine.days.length + 1}`, exercises: [] };
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: [...patient.routine.days, newDay] } });
  };

  const handleRemoveLastDay = () => {
    const lastDay = patient.routine.days[patient.routine.days.length - 1];
    if (patient.routine.days.length <= 1 || lastDay.exercises.length > 0) return;
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: patient.routine.days.slice(0, -1) } });
  };

  const handleRenameDay = (dayId: string, newName: string) => {
    const newDays = patient.routine.days.map(day => day.id === dayId ? { ...day, name: newName } : day);
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  return (
    <div className="flex-1 h-full flex flex-col bg-slate-50 overflow-hidden relative">
      <header className="bg-white border-b border-slate-200 px-4 py-2 flex items-center justify-between shrink-0 z-30 pt-[calc(0.25rem+var(--sat))]">
        <div className="flex flex-col min-w-0">
          <div className="flex items-center gap-2">
            <h2 className="text-sm font-black text-slate-900 leading-none truncate uppercase tracking-tighter">{patient.firstName} {patient.lastName}</h2>
            <span className="bg-slate-900 text-white text-[7px] px-1.5 py-0.5 rounded font-black uppercase">Sem {patient.routine.currentWeek || 1}</span>
          </div>
          <p className="text-[7px] text-slate-400 font-black mt-0.5 uppercase tracking-widest leading-none">{patient.condition}</p>
        </div>
        <div className="flex gap-1.5 items-center">
            <span className={`px-2 py-1 rounded text-[7px] font-black uppercase ${patient.routine.stage === Stage.KINESIOLOGY ? 'bg-kine/10 text-kine' : 'bg-gym/10 text-gym'}`}>{patient.routine.stage}</span>
            {isKine && (
                <button onClick={() => setShowRoutineEditor(true)} className="bg-slate-900 text-white px-3 py-1.5 rounded-xl font-bold text-[8px] uppercase hover:bg-slate-800 transition-all flex items-center gap-1">
                    <Edit2 size={10} /> <span>Editar Routine</span>
                </button>
            )}
            <button onClick={() => setShowHistory(!showHistory)} className={`p-1.5 rounded-xl border transition-all ${showHistory ? 'bg-primary-50 border-primary-200 text-primary-600' : 'bg-white border-slate-200 text-slate-400'}`}>
                <FileText size={16} />
            </button>
        </div>
      </header>

      {showHistory && (
          <div className="bg-slate-900 text-white p-3 shadow-xl z-20 border-b border-slate-800 animate-in slide-in-from-top duration-200">
              <div className="max-w-4xl mx-auto flex gap-4 items-center">
                  <textarea className="flex-1 h-12 bg-slate-800/50 text-slate-200 p-2 rounded-xl border border-slate-700 outline-none resize-none text-[10px]" value={notes} onChange={(e) => setNotes(e.target.value)} placeholder="Notas clínicas..." />
                  <button className="bg-primary-600 text-white p-3 rounded-xl hover:bg-primary-500 transition-colors"><Save size={16}/></button>
              </div>
          </div>
      )}

      {/* Routine Editor Modal Remains the same */}
      {showRoutineEditor && (
          <div className="fixed inset-0 z-[100] bg-slate-50 flex flex-col pt-[var(--sat)] animate-in slide-in-from-bottom-5 duration-300">
              <header className="bg-white border-b border-slate-200 px-4 py-2 flex items-center justify-between shrink-0">
                  <div className="flex items-center gap-6">
                      <div className="flex bg-slate-100 p-0.5 rounded-xl">
                          <button onClick={() => handleUpdateStage(Stage.KINESIOLOGY)} className={`px-4 py-1.5 rounded-lg text-[8px] font-black uppercase transition-all ${patient.routine.stage === Stage.KINESIOLOGY ? 'bg-white text-kine shadow-sm' : 'text-slate-400'}`}>Etapa Kine</button>
                          <button onClick={() => handleUpdateStage(Stage.GYM)} className={`px-4 py-1.5 rounded-lg text-[8px] font-black uppercase transition-all ${patient.routine.stage === Stage.GYM ? 'bg-white text-gym shadow-sm' : 'text-slate-400'}`}>Etapa Gym</button>
                      </div>
                      <div className="flex items-center gap-2 bg-white px-3 py-1.5 rounded-xl border border-slate-200 shadow-sm">
                          <button onClick={handleRemoveLastDay} className="text-slate-400 hover:text-red-500 disabled:opacity-20 transition-colors"><Minus size={18}/></button>
                          <div className="flex flex-col items-center min-w-[40px]"><span className="text-[12px] font-black leading-none">{patient.routine.days.length}</span><span className="text-[6px] font-black uppercase text-slate-300 tracking-tighter">Días</span></div>
                          <button onClick={handleAddDay} disabled={patient.routine.days.length >= 7} className="text-slate-400 hover:text-primary-600 disabled:opacity-20 transition-colors"><Plus size={18}/></button>
                      </div>
                  </div>
                  <button onClick={() => setShowRoutineEditor(false)} className="p-2 hover:bg-slate-100 rounded-full transition-colors"><X size={20} /></button>
              </header>
              <div className="flex-1 overflow-x-auto p-4 bg-slate-50">
                  <div className="flex items-start gap-4 h-full min-w-max pb-10">
                      {patient.routine.days.map((day, dIdx) => (
                          <div key={day.id} className="w-64 bg-white rounded-2xl border border-slate-200 shadow-sm flex flex-col h-full shrink-0 group">
                              <div className="p-4 border-b border-slate-50 flex items-center justify-between">
                                  <div className="flex items-center gap-2">
                                      <span className="text-[10px] font-black text-slate-300 uppercase">DÍA {dIdx+1}</span>
                                      <input className="font-black text-xs text-slate-800 bg-transparent border-none focus:ring-0 p-0 w-28 uppercase" value={day.name} onChange={(e) => handleRenameDay(day.id, e.target.value)} />
                                  </div>
                              </div>
                              <div className="flex-1 overflow-y-auto p-3 space-y-2 scroll-container">
                                  {day.exercises.map((ex) => (
                                      <div key={ex.id} className="flex flex-col gap-2 p-3 bg-slate-50 rounded-xl border border-transparent hover:border-slate-200 transition-all">
                                          <div className="flex items-center justify-between">
                                              <div className="flex items-center gap-2 min-w-0">
                                                  <img src={ex.definition.videoUrl} className="w-8 h-8 rounded-lg object-cover shrink-0" />
                                                  <div className="min-w-0"><p className="font-bold text-[10px] text-slate-800 truncate leading-none">{ex.definition.name}</p></div>
                                              </div>
                                              <button onClick={() => handleRemoveExercise(day.id, ex.id)} className="p-1.5 text-slate-300 hover:text-red-500"><Trash2 size={12}/></button>
                                          </div>
                                          <div className="grid grid-cols-3 gap-1">
                                              <div className="flex flex-col bg-white p-1 rounded-lg border border-slate-100">
                                                  <span className="text-[6px] font-black uppercase text-slate-400 text-center">Sets</span>
                                                  <input type="number" className="w-full text-center font-black text-[10px] p-0 border-none focus:ring-0" value={ex.targetSets} onChange={(e) => handleExerciseUpdate(ex.id, { targetSets: Number(e.target.value) })} />
                                              </div>
                                              <div className="flex flex-col bg-white p-1 rounded-lg border border-slate-100">
                                                  <span className="text-[6px] font-black uppercase text-slate-400 text-center">Reps</span>
                                                  <input type="number" className="w-full text-center font-black text-[10px] p-0 border-none focus:ring-0" value={ex.targetReps} onChange={(e) => handleExerciseUpdate(ex.id, { targetReps: Number(e.target.value) })} />
                                              </div>
                                              <div className="flex flex-col bg-white p-1 rounded-lg border border-slate-100">
                                                  <span className="text-[6px] font-black uppercase text-slate-400 text-center">Kg</span>
                                                  <input type="number" className="w-full text-center font-black text-[10px] p-0 border-none focus:ring-0" value={ex.targetLoad} onChange={(e) => handleExerciseUpdate(ex.id, { targetLoad: Number(e.target.value) })} />
                                              </div>
                                          </div>
                                      </div>
                                  ))}
                                  <button onClick={() => setIsAddingExerciseModal({show: true, dayId: day.id})} className="w-full py-4 border-2 border-dashed border-slate-200 rounded-xl text-[9px] font-black text-slate-400 uppercase hover:bg-slate-50 hover:text-primary-600 transition-all flex flex-col items-center gap-1">
                                      <Plus size={14} /> Agregar
                                  </button>
                              </div>
                          </div>
                      ))}
                  </div>
              </div>
          </div>
      )}

      {/* SUB-NAV CON BOTÓN DE NUEVA SEMANA */}
      <div className="bg-white border-b border-slate-200 px-4 flex justify-between shrink-0 h-14 items-center">
          <div className="flex gap-1 overflow-x-auto no-scrollbar items-center h-full pt-2">
            {patient.routine.days.map((day) => (
              <button key={day.id} onClick={() => {setActiveDayId(day.id); setViewMode('daily');}} className={`px-4 h-full rounded-t-xl font-bold text-[10px] uppercase tracking-wider transition-all border-t border-x ${activeDayId === day.id && viewMode === 'daily' ? 'bg-slate-50 border-slate-200 text-primary-600' : 'bg-white border-transparent text-slate-300 hover:text-slate-400'}`}>
                {day.name}
              </button>
            ))}

            <div className="w-[1px] h-6 bg-slate-100 mx-2 shrink-0"></div>

            <button 
                onClick={handleStartNewWeek}
                className="flex items-center gap-2 px-4 py-2 bg-kine text-white rounded-full font-black text-[9px] uppercase tracking-widest shadow-lg shadow-kine/20 hover:scale-105 active:scale-95 transition-all shrink-0 mr-4"
            >
                <ChevronRightCircle size={14} />
                Nueva Semana
            </button>
          </div>
          <div className="flex items-center gap-1.5 border-l pl-3 ml-2 shrink-0">
              <button onClick={() => setViewMode('plan')} title="Plan Mensual (Master)" className={`p-2 rounded-xl transition-all ${viewMode === 'plan' ? 'bg-primary-600 text-white shadow-lg' : 'bg-slate-50 text-slate-400'}`}><Layers size={18}/></button>
              <button onClick={() => setViewMode('stats')} title="Estadísticas e Historial" className={`p-2 rounded-xl transition-all ${viewMode === 'stats' ? 'bg-slate-900 text-white shadow-lg' : 'bg-slate-50 text-slate-400'}`}><BarChart2 size={18}/></button>
          </div>
      </div>

      <main className="flex-1 overflow-y-auto p-4 md:p-6 scroll-container">
        <div className="max-w-4xl mx-auto h-full">
          {viewMode === 'daily' && activeDay ? (
              <div className="space-y-3 max-w-xl mx-auto pb-24">
                  <div className="flex justify-between items-center px-1 mb-2">
                      <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">{activeDay.name}</h3>
                      <span className="text-[9px] font-bold text-slate-300">Semana {patient.routine.currentWeek || 1}</span>
                  </div>
                  {activeDay.exercises.map(ex => (
                    <ExerciseCard key={ex.id} exercise={ex} role={role} onUpdate={(id, up) => handleExerciseUpdate(id, up)} onShowHistory={(e) => setChartExercise(e)} onDelete={(id) => handleRemoveExercise(activeDayId, id)} />
                  ))}
                  {activeDay.exercises.length === 0 && (
                    <div className="py-20 text-center opacity-30">
                        <Activity className="mx-auto mb-4" size={40} />
                        <p className="text-xs font-bold uppercase">Sin ejercicios asignados</p>
                    </div>
                  )}
              </div>
          ) : viewMode === 'plan' ? (
              <div className="space-y-12 pb-20 max-w-4xl mx-auto">
                  <div className="text-center space-y-2 mb-8">
                      <h3 className="text-xl font-black text-slate-900 uppercase">Proyección del Mes</h3>
                      <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Base de entrenamiento actual</p>
                  </div>

                  {[1, 2, 3, 4].map((weekNum) => {
                      const isCurrent = weekNum === (patient.routine.currentWeek || 1);
                      return (
                        <div key={weekNum} className={`bg-white rounded-[2.5rem] border overflow-hidden shadow-sm ${isCurrent ? 'border-primary-500 ring-4 ring-primary-50' : 'border-slate-200'}`}>
                            <div className={`px-6 py-4 flex justify-between items-center ${isCurrent ? 'bg-primary-600' : 'bg-slate-900'}`}>
                                <h4 className="text-white font-black text-xs uppercase tracking-[0.2em]">Semana {weekNum}</h4>
                                {isCurrent && <div className="bg-white text-primary-600 px-3 py-1 rounded-full text-[8px] font-black uppercase">Actual</div>}
                            </div>
                            <div className="p-6 overflow-x-auto no-scrollbar">
                                <div className="flex gap-4 min-w-max">
                                    {patient.routine.days.map((day, idx) => (
                                        <div key={`${weekNum}-${day.id}`} className="w-52 shrink-0 bg-slate-50/50 rounded-2xl p-4 border border-slate-100">
                                            <p className="text-[9px] font-black text-slate-400 uppercase mb-3 pb-1 border-b">Día {idx+1}: {day.name}</p>
                                            <div className="space-y-2">
                                                {day.exercises.map(ex => (
                                                    <div key={`${weekNum}-${ex.id}`} className="flex flex-col gap-1 p-2 bg-white rounded-xl border border-slate-100 shadow-sm">
                                                        <span className="text-[9px] font-bold text-slate-800 truncate">{ex.definition.name}</span>
                                                        <div className="flex justify-between items-center">
                                                          <span className="text-[8px] font-black text-slate-400">{ex.targetSets}x{ex.targetReps}</span>
                                                          <span className="text-[10px] font-black text-primary-600">{ex.targetLoad}kg</span>
                                                        </div>
                                                    </div>
                                                ))}
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        </div>
                      );
                  })}
              </div>
          ) : viewMode === 'stats' ? (
              <div className="space-y-8 pb-20 max-w-4xl mx-auto">
                  <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                      <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm flex flex-col items-center">
                          <span className="text-[10px] font-black text-slate-400 uppercase mb-2">Semana Actual</span>
                          <span className="text-3xl font-black text-slate-900">{patient.routine.currentWeek || 1}</span>
                      </div>
                      <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm flex flex-col items-center">
                          <span className="text-[10px] font-black text-slate-400 uppercase mb-2">Adherencia</span>
                          <span className="text-3xl font-black text-slate-900">92%</span>
                      </div>
                      <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm flex flex-col items-center">
                          <span className="text-[10px] font-black text-slate-400 uppercase mb-2">RPE Promedio</span>
                          <span className="text-3xl font-black text-slate-900">7.4</span>
                      </div>
                  </div>

                  <div className="space-y-6">
                      <div className="flex items-center gap-3 px-2">
                        <History size={20} className="text-slate-400" />
                        <h4 className="font-black text-sm uppercase text-slate-900">Historial de Semanas Finalizadas</h4>
                      </div>

                      {[1, 2, 3].map((num) => {
                          const weekToShow = (patient.routine.currentWeek || 1) - num;
                          if (weekToShow < 1) return null;

                          return (
                            <div key={num} className="bg-white rounded-[2rem] border border-slate-200 overflow-hidden shadow-sm">
                                <div className="bg-slate-900 px-6 py-3 flex justify-between items-center">
                                    <h4 className="text-white font-black text-[10px] uppercase tracking-widest">Semana {weekToShow}</h4>
                                    <span className="text-kine text-[8px] font-black uppercase">Archivado</span>
                                </div>
                                <div className="p-4 overflow-x-auto no-scrollbar">
                                    <div className="flex gap-4 min-w-max">
                                        {patient.routine.days.map((day, idx) => (
                                            <div key={`hist-${num}-${day.id}`} className="w-52 bg-slate-50 rounded-2xl p-4 border border-slate-100">
                                                <p className="text-[8px] font-black text-slate-400 uppercase mb-3">Día {idx+1}</p>
                                                <div className="space-y-2">
                                                    {day.exercises.map(ex => {
                                                        const log = ex.history && ex.history.find(h => {
                                                            // Lógica simple de búsqueda por cercanía de fecha o índice
                                                            return true; // En un app real buscaríamos el log exacto de esa semana
                                                        });
                                                        return (
                                                          <div key={`h-ex-${ex.id}`} className="p-2 bg-white rounded-xl border border-slate-100">
                                                              <p className="font-bold text-[9px] text-slate-700 truncate mb-1">{ex.definition.name}</p>
                                                              <div className="flex justify-between items-center">
                                                                  <span className="text-[8px] font-bold text-slate-400">{ex.targetLoad}kg</span>
                                                                  <span className="text-[10px] font-black text-slate-800">Finalizado</span>
                                                              </div>
                                                          </div>
                                                        );
                                                    })}
                                                </div>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            </div>
                          );
                      })}
                  </div>
              </div>
          ) : null}
        </div>
      </main>

      {chartExercise && <ProgressChart exercise={chartExercise} onClose={() => setChartExercise(null)} />}

      {/* Modal Exercise Selection Remains the same */}
      {isAddingExerciseModal.show && (
          <div className="fixed inset-0 z-[350] bg-slate-900/40 backdrop-blur-sm flex items-center justify-center p-4">
              <div className="bg-white w-full max-w-md h-[75vh] rounded-[2.5rem] shadow-2xl flex flex-col overflow-hidden">
                  <div className="p-5 border-b flex items-center gap-3">
                      <div className="relative flex-1">
                          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={18} />
                          <input type="text" placeholder="Buscar..." className="w-full pl-12 pr-4 py-4 bg-slate-50 border-none rounded-2xl text-[12px] font-bold outline-none" value={exerciseSearch} onChange={e => setExerciseSearch(e.target.value)} />
                      </div>
                      <button onClick={() => { setIsAddingExerciseModal({show:false, dayId:''}); setSelectedExerciseIds([]); }} className="p-2 text-slate-400 hover:bg-slate-50 rounded-full"><X size={24}/></button>
                  </div>
                  <div className="flex-1 overflow-y-auto p-4 space-y-2 scroll-container">
                      {EXERCISES.filter(ex => ex.name.toLowerCase().includes(exerciseSearch.toLowerCase())).map(ex => {
                          const isSelected = selectedExerciseIds.includes(ex.id);
                          return (
                              <button key={ex.id} onClick={() => setSelectedExerciseIds(prev => isSelected ? prev.filter(i => i !== ex.id) : [...prev, ex.id])} className={`w-full flex items-center p-4 rounded-3xl border-2 transition-all text-left ${isSelected ? 'bg-primary-50 border-primary-500 shadow-md' : 'bg-white border-slate-50 hover:border-slate-200'}`}>
                                  <div className="mr-4">{isSelected ? <CheckSquare size={22} className="text-primary-600"/> : <Square size={22} className="text-slate-200"/>}</div>
                                  <img src={ex.videoUrl} className="w-12 h-12 rounded-xl object-cover mr-4" />
                                  <div className="flex-1 min-w-0"><p className="font-black text-slate-800 text-[11px] truncate uppercase leading-none">{ex.name}</p></div>
                              </button>
                          );
                      })}
                  </div>
                  <div className="p-6 bg-white border-t">
                        <button disabled={selectedExerciseIds.length === 0} className="bg-primary-600 text-white w-full py-5 rounded-[1.5rem] font-black text-[10px] uppercase tracking-[0.15em] disabled:opacity-30 shadow-xl" onClick={() => {
                                const newExs: RoutineExercise[] = selectedExerciseIds.map(id => ({
                                    id: `re-${Date.now()}-${id}`, definitionId: id, definition: EXERCISES.find(e => e.id === id)!,
                                    targetSets: 3, targetReps: 12, targetLoad: 0, isDone: false, history: []
                                }));
                                const newDays = patient.routine.days.map(d => d.id === isAddingExerciseModal.dayId ? { ...d, exercises: [...d.exercises, ...newExs] } : d);
                                onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
                                setIsAddingExerciseModal({show:false, dayId:''});
                                setSelectedExerciseIds([]);
                            }}>Confirmar ({selectedExerciseIds.length})</button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { Patient, Stage } from '../types';
import { Search, ChevronRight, UserPlus, X, Settings2 } from 'lucide-react';

interface PatientListProps {
  patients: Patient[];
  onSelectPatient: (patient: Patient) => void;
  onAddPatient: (patient: Patient) => void;
  onUpdatePatient: (patient: Patient) => void;
  onDeletePatient: (patientId: string) => void;
}

export const PatientList: React.FC<PatientListProps> = ({
  patients,
  onSelectPatient,
  onAddPatient,
  onUpdatePatient,
  onDeletePatient
}) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [modalState, setModalState] = useState<{ show: boolean, editingPatient: Patient | null }>({
    show: false,
    editingPatient: null
  });

  const [formData, setFormData] = useState({
    firstName: '',
    lastName: '',
    condition: '',
    age: 30,
    stage: Stage.KINESIOLOGY
  });

  const filteredPatients = patients.filter((p) => {
    const fullName = `${p.firstName} ${p.lastName}`.toLowerCase();
    return fullName.includes(searchTerm.toLowerCase());
  });

  const openModal = (patient: Patient | null = null) => {
    if (patient) {
      setFormData({
        firstName: patient.firstName,
        lastName: patient.lastName,
        condition: patient.condition,
        age: patient.age,
        stage: patient.routine.stage
      });
      setModalState({ show: true, editingPatient: patient });
    } else {
      setFormData({ firstName: '', lastName: '', condition: '', age: 30, stage: Stage.KINESIOLOGY });
      setModalState({ show: true, editingPatient: null });
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.firstName || !formData.lastName) return;

    if (modalState.editingPatient) {
      onUpdatePatient({
        ...modalState.editingPatient,
        firstName: formData.firstName,
        lastName: formData.lastName,
        age: formData.age,
        condition: formData.condition,
        routine: { ...modalState.editingPatient.routine, stage: formData.stage }
      });
    } else {
      const newPatient: Patient = {
        id: `p-${Date.now()}`,
        firstName: formData.firstName,
        lastName: formData.lastName,
        age: formData.age,
        condition: formData.condition || 'Sin diagnóstico',
        photoUrl: `https://ui-avatars.com/api/?name=${formData.firstName}+${formData.lastName}&background=random`,
        lastVisit: new Date().toISOString().split('T')[0],
        history: [],
        routine: {
          id: `r-${Date.now()}`,
          stage: formData.stage,
          // Fixed: Added missing 'currentWeek' property required by Routine interface
          currentWeek: 1,
          days: [{ id: `d1-${Date.now()}`, name: 'Día 1', exercises: [] }]
        }
      };
      onAddPatient(newPatient);
    }
    setModalState({ show: false, editingPatient: null });
  };

  return (
    <div className="flex-1 h-screen overflow-y-auto bg-slate-50 p-4 md:p-8">
      <div className="max-w-4xl mx-auto space-y-6">
        <div className="flex justify-between items-center gap-4">
          <h1 className="text-2xl md:text-3xl font-bold text-slate-900">Pacientes</h1>
          <button onClick={() => openModal()} className="bg-primary-600 text-white px-4 py-2.5 rounded-xl font-bold flex items-center gap-2 shadow-lg hover:bg-primary-700 transition-all text-sm">
            <UserPlus size={18} />
            <span className="hidden xs:inline">Nuevo Paciente</span>
          </button>
        </div>

        <div className="relative">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
          <input
            type="text"
            placeholder="Buscar por nombre..."
            className="w-full h-14 pl-12 pr-6 rounded-2xl border-none shadow-sm text-base focus:ring-4 focus:ring-primary-100"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
          {filteredPatients.map((patient, index) => (
            <div key={patient.id} className={`flex items-center p-4 cursor-pointer hover:bg-slate-50 transition-colors ${index !== filteredPatients.length - 1 ? 'border-b border-slate-100' : ''}`} onClick={() => onSelectPatient(patient)}>
              <img src={patient.photoUrl} className="w-10 h-10 rounded-full object-cover mr-4" />
              <div className="flex-1 min-w-0">
                <h3 className="font-bold text-slate-800 truncate">{patient.firstName} {patient.lastName}</h3>
                <p className="text-slate-400 text-xs truncate">{patient.condition}</p>
              </div>
              <div className="flex items-center gap-2">
                <button onClick={(e) => { e.stopPropagation(); openModal(patient); }} className="p-2 text-slate-400 hover:text-primary-600"><Settings2 size={18} /></button>
                <ChevronRight className="text-slate-300" size={20} />
              </div>
            </div>
          ))}
          {filteredPatients.length === 0 && <div className="p-8 text-center text-slate-400 italic">No se encontraron pacientes</div>}
        </div>
      </div>

      {modalState.show && (
        <div className="fixed inset-0 z-[100] bg-black/50 backdrop-blur-sm flex items-center justify-center p-4">
             <div className="bg-white w-full max-w-md rounded-3xl p-6 space-y-6 shadow-2xl animate-in zoom-in-95">
                 <div className="flex justify-between items-center">
                     <h2 className="text-xl font-bold text-slate-900">{modalState.editingPatient ? 'Editar Paciente' : 'Nuevo Paciente'}</h2>
                     <button onClick={() => setModalState({ show: false, editingPatient: null })} className="p-2 hover:bg-slate-100 rounded-full transition-colors"><X size={20} /></button>
                 </div>

                 <form onSubmit={handleSubmit} className="space-y-4">
                     <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-1">
                            <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">Nombre</label>
                            <input type="text" required className="w-full p-3 bg-slate-50 rounded-xl outline-none focus:ring-2 focus:ring-primary-500" value={formData.firstName} onChange={e => setFormData({...formData, firstName: e.target.value})} />
                        </div>
                        <div className="space-y-1">
                            <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">Apellido</label>
                            <input type="text" required className="w-full p-3 bg-slate-50 rounded-xl outline-none focus:ring-2 focus:ring-primary-500" value={formData.lastName} onChange={e => setFormData({...formData, lastName: e.target.value})} />
                        </div>
                     </div>

                     <div className="grid grid-cols-3 gap-4">
                        <div className="col-span-1 space-y-1">
                            <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">Edad</label>
                            <input type="number" required className="w-full p-3 bg-slate-50 rounded-xl outline-none focus:ring-2 focus:ring-primary-500" value={formData.age} onChange={e => setFormData({...formData, age: Number(e.target.value)})} />
                        </div>
                        <div className="col-span-2 space-y-1">
                            <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">Etapa Inicial</label>
                            <select className="w-full p-3 bg-slate-50 rounded-xl outline-none focus:ring-2 focus:ring-primary-500" value={formData.stage} onChange={e => setFormData({...formData, stage: e.target.value as Stage})}>
                                <option value={Stage.KINESIOLOGY}>Kinesiología</option>
                                <option value={Stage.GYM}>Gimnasio</option>
                            </select>
                        </div>
                     </div>

                     <div className="space-y-1">
                        <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">Diagnóstico / Motivo</label>
                        <input type="text" className="w-full p-3 bg-slate-50 rounded-xl outline-none focus:ring-2 focus:ring-primary-500" value={formData.condition} onChange={e => setFormData({...formData, condition: e.target.value})} />
                     </div>

                     <div className="pt-4 flex flex-col gap-3">
                        <button type="submit" className="w-full bg-primary-600 text-white font-bold py-4 rounded-2xl shadow-lg shadow-primary-200 hover:bg-primary-700 transition-colors">
                            {modalState.editingPatient ? 'Actualizar Datos' : 'Crear Paciente'}
                        </button>
                        {modalState.editingPatient && (
                            <button type="button" onClick={() => { if(window.confirm('¿Eliminar paciente?')) { onDeletePatient(modalState.editingPatient!.id); setModalState({show:false, editingPatient:null}); } }} className="w-full text-red-500 font-bold py-2 hover:bg-red-50 rounded-xl transition-colors">
                                Eliminar Paciente
                            </button>
                        )}
                     </div>
                 </form>
             </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Patient, RoutineExercise, Stage, UserRole, RoutineDay, ExerciseLog } from '../types';
import { EXERCISES } from '../constants';
import { ExerciseCard } from './ExerciseCard';
import { ProgressChart } from './ProgressChart';
import { 
  AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer
} from 'recharts';
import { 
    FileText, Plus, Search, X, Calendar, Trash2, Edit2, Save,
    Activity, Minus, Layers, TrendingUp, CheckSquare, Square, BarChart2, CheckCircle2, History, ChevronRightCircle
} from 'lucide-react';

interface PatientDetailProps {
  patient: Patient;
  role: UserRole;
  onUpdatePatient: (updated: Patient) => void;
}

export const PatientDetail: React.FC<PatientDetailProps> = ({
  patient,
  role,
  onUpdatePatient,
}) => {
  const [activeDayId, setActiveDayId] = useState<string>(patient.routine.days[0]?.id || '');
  const [viewMode, setViewMode] = useState<'daily' | 'plan' | 'stats'>('daily');
  const [showHistory, setShowHistory] = useState(false);
  const [showRoutineEditor, setShowRoutineEditor] = useState(false);
  const [chartExercise, setChartExercise] = useState<RoutineExercise | null>(null);
  const [exerciseSearch, setExerciseSearch] = useState('');
  const [selectedExerciseIds, setSelectedExerciseIds] = useState<string[]>([]);
  const [isAddingExerciseModal, setIsAddingExerciseModal] = useState<{show: boolean, dayId: string}>({show: false, dayId: ''});
  const [notes, setNotes] = useState(patient.history[0] || '');

  const isKine = role === UserRole.KINE;
  const currentWeek = patient.routine.currentWeek || 1;

  useEffect(() => {
    if (patient.routine.days.length > 0 && (!activeDayId || !patient.routine.days.find(d => d.id === activeDayId))) {
        setActiveDayId(patient.routine.days[0].id);
    }
  }, [patient, activeDayId]);

  const activeDay = patient.routine.days.find(d => d.id === activeDayId);

  const handleStartNewWeek = () => {
    const hasAnyProgress = patient.routine.days.some(day => day.exercises.some(ex => ex.isDone));

    const confirmMessage = hasAnyProgress 
        ? `¿Finalizar Semana ${currentWeek}? Se archivarán los progresos y se limpiarán los checks para la Semana ${currentWeek + 1}.`
        : `No has marcado ejercicios en la Semana ${currentWeek}. ¿Pasar a la Semana ${currentWeek + 1} de todas formas?`;

    if (!window.confirm(confirmMessage)) return;

    const today = new Date().toISOString().split('T')[0];
    const newDays = patient.routine.days.map(day => ({
      ...day,
      exercises: day.exercises.map(ex => {
        const newHistory = [...(ex.history || [])];
        if (ex.isDone) {
            newHistory.push({
                date: today,
                load: ex.targetLoad,
                reps: ex.targetReps,
                rpe: ex.currentRpe || 5
            });
        }

        return {
          ...ex,
          isDone: false, // IMPORTANTE: Destildar ejercicios
          currentRpe: undefined, 
          history: newHistory
        };
      })
    }));

    onUpdatePatient({
      ...patient,
      routine: {
        ...patient.routine,
        days: newDays,
        currentWeek: currentWeek + 1
      },
      lastVisit: today
    });

    // Pequeño feedback visual de éxito
    setViewMode('plan'); 
  };

  const handleExerciseUpdate = (exerciseId: string, updates: Partial<RoutineExercise>) => {
    const newDays = patient.routine.days.map(day => ({
        ...day,
        exercises: day.exercises.map(ex => ex.id === exerciseId ? { ...ex, ...updates } : ex)
    }));
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  const handleRemoveExercise = (dayId: string, exerciseId: string) => {
    const newDays = patient.routine.days.map(day => 
        day.id === dayId ? { ...day, exercises: day.exercises.filter(ex => ex.id !== exerciseId) } : day
    );
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  const handleUpdateStage = (newStage: Stage) => {
    onUpdatePatient({ ...patient, routine: { ...patient.routine, stage: newStage } });
  };

  const handleAddDay = () => {
    if (patient.routine.days.length >= 7) return;
    const newDay: RoutineDay = { id: `day-${Date.now()}`, name: `Día ${patient.routine.days.length + 1}`, exercises: [] };
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: [...patient.routine.days, newDay] } });
  };

  const handleRemoveLastDay = () => {
    const lastDay = patient.routine.days[patient.routine.days.length - 1];
    if (patient.routine.days.length <= 1 || lastDay.exercises.length > 0) return;
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: patient.routine.days.slice(0, -1) } });
  };

  const handleRenameDay = (dayId: string, newName: string) => {
    const newDays = patient.routine.days.map(day => day.id === dayId ? { ...day, name: newName } : day);
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  const statsData = useMemo(() => {
    return [
      { name: `Sem ${currentWeek-4}`, volumen: 3200 },
      { name: `Sem ${currentWeek-3}`, volumen: 3500 },
      { name: `Sem ${currentWeek-2}`, volumen: 3450 },
      { name: `Sem ${currentWeek-1}`, volumen: 3800 },
      { name: `Actual`, volumen: 4100 },
    ];
  }, [currentWeek]);

  return (
    <div className="flex-1 h-full flex flex-col bg-slate-50 overflow-hidden relative">
      <header className="bg-white border-b border-slate-200 px-4 py-3 flex items-center justify-between shrink-0 z-30 pt-[calc(0.75rem+var(--sat))]">
        <div className="flex flex-col min-w-0">
          <div className="flex items-center gap-2">
            <h2 className="text-base font-black text-slate-900 leading-none truncate uppercase tracking-tighter">
                {patient.firstName} {patient.lastName}
            </h2>
            <div className="bg-slate-900 text-white text-[9px] px-2 py-1 rounded-lg font-black uppercase shadow-sm">
                Semana {currentWeek}
            </div>
          </div>
          <p className="text-[8px] text-slate-400 font-black mt-1 uppercase tracking-widest leading-none">{patient.condition}</p>
        </div>
        <div className="flex gap-2 items-center">
            <span className={`px-2 py-1.5 rounded-lg text-[8px] font-black uppercase ${patient.routine.stage === Stage.KINESIOLOGY ? 'bg-kine/10 text-kine' : 'bg-gym/10 text-gym'}`}>
                {patient.routine.stage}
            </span>
            {isKine && (
                <button onClick={() => setShowRoutineEditor(true)} className="bg-slate-900 text-white px-3 py-2 rounded-xl font-bold text-[9px] uppercase hover:bg-slate-800 transition-all flex items-center gap-1.5 shadow-md">
                    <Edit2 size={12} /> <span>Rutina</span>
                </button>
            )}
            <button onClick={() => setShowHistory(!showHistory)} className={`p-2 rounded-xl border transition-all ${showHistory ? 'bg-primary-50 border-primary-200 text-primary-600' : 'bg-white border-slate-200 text-slate-400'}`}>
                <FileText size={18} />
            </button>
        </div>
      </header>

      {showHistory && (
          <div className="bg-slate-900 text-white p-3 shadow-xl z-20 border-b border-slate-800 animate-in slide-in-from-top duration-200">
              <div className="max-w-4xl mx-auto flex gap-4 items-center">
                  <textarea className="flex-1 h-12 bg-slate-800/50 text-slate-200 p-2 rounded-xl border border-slate-700 outline-none resize-none text-[10px]" value={notes} onChange={(e) => setNotes(e.target.value)} placeholder="Notas clínicas del paciente..." />
                  <button className="bg-primary-600 text-white p-3 rounded-xl hover:bg-primary-500 transition-colors shadow-lg"><Save size={18}/></button>
              </div>
          </div>
      )}

      {/* Routine Editor remains mostly same logic but visual tweak */}
      {showRoutineEditor && (
          <div className="fixed inset-0 z-[100] bg-slate-50 flex flex-col pt-[var(--sat)] animate-in slide-in-from-bottom-5 duration-300">
              <header className="bg-white border-b border-slate-200 px-4 py-3 flex items-center justify-between shrink-0">
                  <div className="flex items-center gap-6">
                      <div className="flex bg-slate-100 p-1 rounded-xl">
                          <button onClick={() => handleUpdateStage(Stage.KINESIOLOGY)} className={`px-4 py-2 rounded-lg text-[9px] font-black uppercase transition-all ${patient.routine.stage === Stage.KINESIOLOGY ? 'bg-white text-kine shadow-sm' : 'text-slate-400'}`}>Kine</button>
                          <button onClick={() => handleUpdateStage(Stage.GYM)} className={`px-4 py-2 rounded-lg text-[9px] font-black uppercase transition-all ${patient.routine.stage === Stage.GYM ? 'bg-white text-gym shadow-sm' : 'text-slate-400'}`}>Gym</button>
                      </div>
                      <div className="flex items-center gap-2 bg-white px-3 py-1.5 rounded-xl border border-slate-200 shadow-sm">
                          <button onClick={handleRemoveLastDay} className="text-slate-400 hover:text-red-500 disabled:opacity-20 transition-colors"><Minus size={18}/></button>
                          <div className="flex flex-col items-center min-w-[40px]"><span className="text-[12px] font-black leading-none">{patient.routine.days.length}</span><span className="text-[6px] font-black uppercase text-slate-300 tracking-tighter">Días</span></div>
                          <button onClick={handleAddDay} disabled={patient.routine.days.length >= 7} className="text-slate-400 hover:text-primary-600 disabled:opacity-20 transition-colors"><Plus size={18}/></button>
                      </div>
                  </div>
                  <button onClick={() => setShowRoutineEditor(false)} className="p-2 hover:bg-slate-100 rounded-full transition-colors"><X size={24} /></button>
              </header>
              <div className="flex-1 overflow-x-auto p-4 bg-slate-50">
                  <div className="flex items-start gap-4 h-full min-w-max pb-10">
                      {patient.routine.days.map((day, dIdx) => (
                          <div key={day.id} className="w-64 bg-white rounded-3xl border border-slate-200 shadow-sm flex flex-col h-full shrink-0">
                              <div className="p-4 border-b border-slate-50 flex items-center justify-between">
                                  <input className="font-black text-xs text-slate-800 bg-transparent border-none focus:ring-0 p-0 w-full uppercase" value={day.name} onChange={(e) => handleRenameDay(day.id, e.target.value)} />
                              </div>
                              <div className="flex-1 overflow-y-auto p-3 space-y-2 scroll-container">
                                  {day.exercises.map((ex) => (
                                      <div key={ex.id} className="flex flex-col gap-2 p-3 bg-slate-50 rounded-2xl border border-transparent hover:border-slate-200 transition-all">
                                          <div className="flex items-center justify-between gap-2">
                                              <img src={ex.definition.videoUrl} className="w-8 h-8 rounded-lg object-cover" />
                                              <p className="font-bold text-[10px] text-slate-800 truncate flex-1 leading-tight">{ex.definition.name}</p>
                                              <button onClick={() => handleRemoveExercise(day.id, ex.id)} className="p-1.5 text-slate-300 hover:text-red-500"><Trash2 size={12}/></button>
                                          </div>
                                          <div className="grid grid-cols-3 gap-1">
                                              <input type="number" className="bg-white rounded-lg text-center font-black text-[10px] py-1 border-slate-100 focus:ring-primary-500" value={ex.targetSets} onChange={e => handleExerciseUpdate(ex.id, {targetSets: Number(e.target.value)})} />
                                              <input type="number" className="bg-white rounded-lg text-center font-black text-[10px] py-1 border-slate-100 focus:ring-primary-500" value={ex.targetReps} onChange={e => handleExerciseUpdate(ex.id, {targetReps: Number(e.target.value)})} />
                                              <input type="number" className="bg-white rounded-lg text-center font-black text-[10px] py-1 border-slate-100 focus:ring-primary-500" value={ex.targetLoad} onChange={e => handleExerciseUpdate(ex.id, {targetLoad: Number(e.target.value)})} />
                                          </div>
                                      </div>
                                  ))}
                                  <button onClick={() => setIsAddingExerciseModal({show: true, dayId: day.id})} className="w-full py-6 border-2 border-dashed border-slate-200 rounded-2xl text-[9px] font-black text-slate-400 uppercase hover:bg-slate-50 hover:text-primary-600 transition-all flex flex-col items-center gap-1.5">
                                      <Plus size={16} /> Agregar
                                  </button>
                              </div>
                          </div>
                      ))}
                  </div>
              </div>
          </div>
      )}

      {/* SUB-NAV CON BOTÓN DE NUEVA SEMANA ACTUALIZADO */}
      <div className="bg-white border-b border-slate-200 px-4 flex justify-between shrink-0 h-16 items-center">
          <div className="flex gap-1 overflow-x-auto no-scrollbar items-center h-full pt-3">
            {patient.routine.days.map((day) => (
              <button key={day.id} onClick={() => {setActiveDayId(day.id); setViewMode('daily');}} className={`px-4 h-full rounded-t-2xl font-black text-[10px] uppercase tracking-wider transition-all border-t border-x ${activeDayId === day.id && viewMode === 'daily' ? 'bg-slate-50 border-slate-200 text-primary-600' : 'bg-white border-transparent text-slate-300 hover:text-slate-400'}`}>
                {day.name}
              </button>
            ))}

            <div className="w-[1.5px] h-8 bg-slate-100 mx-3 shrink-0"></div>

            <button 
                onClick={handleStartNewWeek}
                className="flex items-center gap-2 px-5 py-2.5 bg-kine text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-lg shadow-kine/20 hover:bg-kine/90 active:scale-95 transition-all shrink-0 mr-4"
            >
                <ChevronRightCircle size={16} />
                Finalizar Semana
            </button>
          </div>
          <div className="flex items-center gap-2 border-l pl-4 ml-2 shrink-0">
              <button onClick={() => setViewMode('plan')} title="Proyección Mensual" className={`p-2.5 rounded-2xl transition-all ${viewMode === 'plan' ? 'bg-primary-600 text-white shadow-lg' : 'bg-slate-50 text-slate-400 hover:bg-slate-100'}`}><Layers size={22}/></button>
              <button onClick={() => setViewMode('stats')} title="Diagnóstico y Estadísticas" className={`p-2.5 rounded-2xl transition-all ${viewMode === 'stats' ? 'bg-slate-900 text-white shadow-lg' : 'bg-slate-50 text-slate-400 hover:bg-slate-100'}`}><BarChart2 size={22}/></button>
          </div>
      </div>

      <main className="flex-1 overflow-y-auto p-4 md:p-8 scroll-container">
        <div className="max-w-4xl mx-auto h-full">
          {viewMode === 'daily' && activeDay ? (
              <div className="space-y-4 max-w-xl mx-auto pb-24">
                  <div className="flex justify-between items-end px-2 mb-2">
                      <div className="flex flex-col">
                        <span className="text-[10px] font-black text-primary-600 uppercase tracking-widest">En Entrenamiento</span>
                        <h3 className="text-sm font-black text-slate-800 uppercase">{activeDay.name}</h3>
                      </div>
                      <span className="text-[10px] font-bold text-slate-300 italic">Ciclo {currentWeek}</span>
                  </div>
                  {activeDay.exercises.map(ex => (
                    <ExerciseCard key={ex.id} exercise={ex} role={role} onUpdate={(id, up) => handleExerciseUpdate(id, up)} onShowHistory={(e) => setChartExercise(e)} onDelete={(id) => handleRemoveExercise(activeDayId, id)} />
                  ))}
                  {activeDay.exercises.length === 0 && (
                    <div className="py-24 text-center">
                        <div className="w-20 h-20 bg-slate-100 rounded-full flex items-center justify-center mx-auto mb-6 text-slate-300">
                            <Activity size={32} />
                        </div>
                        <p className="text-xs font-black text-slate-400 uppercase tracking-widest">Este día no tiene ejercicios asignados</p>
                    </div>
                  )}
              </div>
          ) : viewMode === 'plan' ? (
              <div className="space-y-12 pb-24 max-w-4xl mx-auto">
                  <div className="text-center space-y-3 mb-12">
                      <h3 className="text-2xl font-black text-slate-900 uppercase tracking-tighter">Proyección de Cargas</h3>
                      <p className="text-[11px] font-bold text-slate-400 uppercase tracking-[0.2em]">Mapa maestro de las próximas 4 semanas</p>
                  </div>

                  {/* PROYECCIÓN DINÁMICA: Siempre muestra 4 semanas desde la actual */}
                  {[0, 1, 2, 3].map((offset) => {
                      const weekNum = currentWeek + offset;
                      const isCurrent = offset === 0;
                      return (
                        <div key={weekNum} className={`bg-white rounded-[3rem] border overflow-hidden shadow-md transition-all ${isCurrent ? 'border-primary-500 ring-8 ring-primary-50/50 scale-[1.02] z-10' : 'border-slate-200 opacity-90'}`}>
                            <div className={`px-8 py-5 flex justify-between items-center ${isCurrent ? 'bg-primary-600' : 'bg-slate-900'}`}>
                                <div className="flex items-center gap-3">
                                    <h4 className="text-white font-black text-sm uppercase tracking-[0.2em]">Semana {weekNum}</h4>
                                    {isCurrent && <span className="bg-white text-primary-600 px-3 py-1 rounded-full text-[9px] font-black uppercase shadow-sm">Actual</span>}
                                </div>
                                <span className="text-white/40 text-[9px] font-black uppercase tracking-widest">Master Plan</span>
                            </div>
                            <div className="p-8 overflow-x-auto no-scrollbar">
                                <div className="flex gap-5 min-w-max pb-4">
                                    {patient.routine.days.map((day, idx) => (
                                        <div key={`${weekNum}-${day.id}`} className="w-56 shrink-0 bg-slate-50/70 rounded-3xl p-5 border border-slate-100">
                                            <p className="text-[10px] font-black text-slate-400 uppercase mb-4 pb-2 border-b border-slate-200/50">Día {idx+1}: {day.name}</p>
                                            <div className="space-y-3">
                                                {day.exercises.map(ex => (
                                                    <div key={`${weekNum}-${ex.id}`} className="flex flex-col gap-1.5 p-3 bg-white rounded-2xl border border-slate-100 shadow-sm">
                                                        <span className="text-[10px] font-black text-slate-800 truncate leading-tight">{ex.definition.name}</span>
                                                        <div className="flex justify-between items-center mt-1">
                                                          <div className="flex items-center gap-1">
                                                              <span className="text-[8px] font-black text-slate-300 uppercase">Sets</span>
                                                              <span className="text-[10px] font-black text-slate-600">{ex.targetSets}x{ex.targetReps}</span>
                                                          </div>
                                                          <span className="text-[12px] font-black text-primary-600">{ex.targetLoad}kg</span>
                                                        </div>
                                                    </div>
                                                ))}
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        </div>
                      );
                  })}
              </div>
          ) : viewMode === 'stats' ? (
              <div className="space-y-10 pb-24 max-w-4xl mx-auto">
                  <div className="grid grid-cols-1 md:grid-cols-3 gap-5">
                      <div className="bg-white p-8 rounded-[2rem] border border-slate-200 shadow-sm flex flex-col items-center">
                          <span className="text-[11px] font-black text-slate-400 uppercase mb-3 tracking-widest">Semana Actual</span>
                          <span className="text-4xl font-black text-slate-900">{currentWeek}</span>
                      </div>
                      <div className="bg-white p-8 rounded-[2rem] border border-slate-200 shadow-sm flex flex-col items-center">
                          <span className="text-[11px] font-black text-slate-400 uppercase mb-3 tracking-widest">Ejercicios Hechos</span>
                          <span className="text-4xl font-black text-primary-600">84%</span>
                      </div>
                      <div className="bg-white p-8 rounded-[2rem] border border-slate-200 shadow-sm flex flex-col items-center">
                          <span className="text-[11px] font-black text-slate-400 uppercase mb-3 tracking-widest">RPE Promedio</span>
                          <span className="text-4xl font-black text-gym">7.2</span>
                      </div>
                  </div>

                  <div className="space-y-8">
                      <div className="flex items-center gap-4 px-2">
                        <div className="p-2.5 bg-slate-900 rounded-xl text-white"><History size={20} /></div>
                        <div>
                            <h4 className="font-black text-base uppercase text-slate-900 leading-none">Historial Real</h4>
                            <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest mt-1">Lo que el paciente realmente levantó cada día</p>
                        </div>
                      </div>

                      {[1, 2, 3].map((num) => {
                          const weekToShow = currentWeek - num;
                          if (weekToShow < 1) return null;

                          return (
                            <div key={num} className="bg-white rounded-[2.5rem] border border-slate-200 overflow-hidden shadow-sm opacity-95">
                                <div className="bg-slate-900 px-8 py-4 flex justify-between items-center">
                                    <h4 className="text-white font-black text-[11px] uppercase tracking-[0.2em]">Cierre Semana {weekToShow}</h4>
                                    <div className="flex items-center gap-2 text-[9px] font-black text-kine uppercase">
                                        <CheckSquare size={12} /> Datos Archivados
                                    </div>
                                </div>
                                <div className="p-6 overflow-x-auto no-scrollbar">
                                    <div className="flex gap-4 min-w-max">
                                        {patient.routine.days.map((day, idx) => (
                                            <div key={`hist-${num}-${day.id}`} className="w-56 bg-slate-50 rounded-3xl p-5 border border-slate-100">
                                                <p className="text-[9px] font-black text-slate-400 uppercase mb-4">Día {idx+1}: {day.name}</p>
                                                <div className="space-y-2.5">
                                                    {day.exercises.map(ex => {
                                                        const log = ex.history && ex.history[ex.history.length - num];
                                                        return (
                                                          <div key={`h-ex-${ex.id}`} className="p-3 bg-white rounded-2xl border border-slate-100 shadow-sm">
                                                              <p className="font-bold text-[10px] text-slate-700 truncate mb-2 leading-tight">{ex.definition.name}</p>
                                                              <div className="flex justify-between items-center">
                                                                  <span className="text-[9px] font-bold text-slate-400 uppercase">{log ? `${log.reps} reps` : '--'}</span>
                                                                  <span className="text-[12px] font-black text-slate-900">{log ? `${log.load}kg` : '--'}</span>
                                                              </div>
                                                          </div>
                                                        );
                                                    })}
                                                </div>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            </div>
                          );
                      })}
                  </div>

                  <div className="bg-white p-10 rounded-[3rem] border border-slate-200 shadow-sm">
                      <div className="flex justify-between items-center mb-8">
                          <h4 className="font-black text-base uppercase text-slate-900">Curva de Volumen</h4>
                          <TrendingUp className="text-kine" size={24} />
                      </div>
                      <div className="h-72 w-full">
                          <ResponsiveContainer width="100%" height="100%">
                              <AreaChart data={statsData}>
                                <defs><linearGradient id="colorVol" x1="0" y1="0" x2="0" y2="1"><stop offset="5%" stopColor="#0ea5e9" stopOpacity={0.15}/><stop offset="95%" stopColor="#0ea5e9" stopOpacity={0}/></linearGradient></defs>
                                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fontSize: 10, fontWeight: 900, fill: '#94a3b8'}} />
                                <YAxis hide /><Tooltip contentStyle={{borderRadius: '24px', border: 'none', padding: '15px', fontWeight: 900}} />
                                <Area type="monotone" dataKey="volumen" stroke="#0ea5e9" strokeWidth={5} fillOpacity={1} fill="url(#colorVol)" />
                              </AreaChart>
                          </ResponsiveContainer>
                      </div>
                  </div>
              </div>
          ) : null}
        </div>
      </main>

      {chartExercise && <ProgressChart exercise={chartExercise} onClose={() => setChartExercise(null)} />}

      {/* Modal Exercise Selection remains functional as before */}
      {isAddingExerciseModal.show && (
          <div className="fixed inset-0 z-[350] bg-slate-900/40 backdrop-blur-sm flex items-center justify-center p-4">
              <div className="bg-white w-full max-w-md h-[75vh] rounded-[3rem] shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95 duration-200">
                  <div className="p-6 border-b flex items-center gap-4">
                      <div className="relative flex-1">
                          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={20} />
                          <input type="text" placeholder="Buscar ejercicio..." className="w-full pl-12 pr-4 py-4 bg-slate-50 border-none rounded-2xl text-[12px] font-bold outline-none" value={exerciseSearch} onChange={e => setExerciseSearch(e.target.value)} />
                      </div>
                      <button onClick={() => { setIsAddingExerciseModal({show:false, dayId:''}); setSelectedExerciseIds([]); }} className="p-2 text-slate-400 hover:bg-slate-50 rounded-full"><X size={28}/></button>
                  </div>
                  <div className="flex-1 overflow-y-auto p-4 space-y-2 scroll-container">
                      {EXERCISES.filter(ex => ex.name.toLowerCase().includes(exerciseSearch.toLowerCase())).map(ex => {
                          const isSelected = selectedExerciseIds.includes(ex.id);
                          return (
                              <button key={ex.id} onClick={() => setSelectedExerciseIds(prev => isSelected ? prev.filter(i => i !== ex.id) : [...prev, ex.id])} className={`w-full flex items-center p-4 rounded-3xl border-2 transition-all text-left ${isSelected ? 'bg-primary-50 border-primary-500 shadow-md' : 'bg-white border-slate-50 hover:border-slate-100'}`}>
                                  <div className="mr-4">{isSelected ? <CheckSquare size={24} className="text-primary-600"/> : <Square size={24} className="text-slate-200"/>}</div>
                                  <img src={ex.videoUrl} className="w-14 h-14 rounded-2xl object-cover mr-4" />
                                  <div className="flex-1 min-w-0">
                                      <p className="font-black text-slate-800 text-[12px] truncate uppercase leading-none">{ex.name}</p>
                                      <span className="text-[9px] text-slate-400 font-black uppercase mt-2 tracking-widest inline-block">{ex.category}</span>
                                  </div>
                              </button>
                          );
                      })}
                  </div>
                  <div className="p-8 bg-white border-t">
                        <button disabled={selectedExerciseIds.length === 0} className="bg-primary-600 text-white w-full py-5 rounded-2xl font-black text-[11px] uppercase tracking-widest disabled:opacity-30 shadow-xl shadow-primary-200 transition-all active:scale-95" onClick={() => {
                                const newExs: RoutineExercise[] = selectedExerciseIds.map(id => ({
                                    id: `re-${Date.now()}-${id}`, definitionId: id, definition: EXERCISES.find(e => e.id === id)!,
                                    targetSets: 3, targetReps: 12, targetLoad: 0, isDone: false, history: []
                                }));
                                const newDays = patient.routine.days.map(d => d.id === isAddingExerciseModal.dayId ? { ...d, exercises: [...d.exercises, ...newExs] } : d);
                                onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
                                setIsAddingExerciseModal({show:false, dayId:''});
                                setSelectedExerciseIds([]);
                            }}>Confirmar ({selectedExerciseIds.length})</button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Patient, RoutineExercise, Stage, UserRole, RoutineDay, ExerciseLog } from '../types';
import { EXERCISES } from '../constants';
import { ExerciseCard } from './ExerciseCard';
import { ProgressChart } from './ProgressChart';
import { 
  AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer
} from 'recharts';
import { 
    FileText, Plus, Search, X, Calendar, Trash2, Edit2, Save,
    Activity, Minus, Layers, TrendingUp, CheckSquare, Square, BarChart2, CheckCircle2, History, ChevronRightCircle
} from 'lucide-react';

interface PatientDetailProps {
  patient: Patient;
  role: UserRole;
  onUpdatePatient: (updated: Patient) => void;
}

export const PatientDetail: React.FC<PatientDetailProps> = ({
  patient,
  role,
  onUpdatePatient,
}) => {
  const [activeDayId, setActiveDayId] = useState<string>(patient.routine.days[0]?.id || '');
  const [viewMode, setViewMode] = useState<'daily' | 'plan' | 'stats'>('daily');
  const [showHistory, setShowHistory] = useState(false);
  const [showRoutineEditor, setShowRoutineEditor] = useState(false);
  const [chartExercise, setChartExercise] = useState<RoutineExercise | null>(null);
  const [exerciseSearch, setExerciseSearch] = useState('');
  const [selectedExerciseIds, setSelectedExerciseIds] = useState<string[]>([]);
  const [isAddingExerciseModal, setIsAddingExerciseModal] = useState<{show: boolean, dayId: string}>({show: false, dayId: ''});
  const [notes, setNotes] = useState(patient.history[0] || '');

  const isKine = role === UserRole.KINE;
  const currentWeekNum = patient.routine.currentWeek || 1;

  useEffect(() => {
    if (patient.routine.days.length > 0 && (!activeDayId || !patient.routine.days.find(d => d.id === activeDayId))) {
        setActiveDayId(patient.routine.days[0].id);
    }
  }, [patient, activeDayId]);

  const activeDay = patient.routine.days.find(d => d.id === activeDayId);

  // FUNCIÓN CRÍTICA: FINALIZAR SEMANA Y RESETEAR
  const handleStartNewWeek = () => {
    const confirmMessage = `¿Estás seguro de finalizar la SEMANA ${currentWeekNum}?\n\n- Se archivarán los pesos actuales.\n- Se limpiarán los checks de todos los días.\n- Pasarás a la SEMANA ${currentWeekNum + 1}.`;

    if (!window.confirm(confirmMessage)) return;

    const today = new Date().toISOString().split('T')[0];

    // 1. Limpiamos TODOS los días y TODOS los ejercicios
    const updatedDays = patient.routine.days.map(day => ({
      ...day,
      exercises: day.exercises.map(ex => {
        // Guardar en historial solo si se hizo algo
        const newHistory = [...(ex.history || [])];
        if (ex.isDone) {
            newHistory.push({
                date: today,
                load: ex.targetLoad,
                reps: ex.targetReps,
                rpe: ex.currentRpe || 5
            });
        }

        return {
          ...ex,
          isDone: false,        // DESTILDAR (CLAVE)
          currentRpe: undefined, // LIMPIAR ESFUERZO
          history: newHistory
        };
      })
    }));

    // 2. Ejecutamos la actualización completa
    onUpdatePatient({
      ...patient,
      routine: {
        ...patient.routine,
        days: updatedDays,
        currentWeek: currentWeekNum + 1 // INCREMENTAR SEMANA (CLAVE)
      },
      lastVisit: today
    });

    // 3. Feedback visual: Ir a la vista diaria para ver que todo está limpio
    setViewMode('daily');
    alert(`¡Semana ${currentWeekNum} cerrada! Bienvenido a la Semana ${currentWeekNum + 1}.`);
  };

  const handleExerciseUpdate = (exerciseId: string, updates: Partial<RoutineExercise>) => {
    const newDays = patient.routine.days.map(day => ({
        ...day,
        exercises: day.exercises.map(ex => ex.id === exerciseId ? { ...ex, ...updates } : ex)
    }));
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  const handleRemoveExercise = (dayId: string, exerciseId: string) => {
    const newDays = patient.routine.days.map(day => 
        day.id === dayId ? { ...day, exercises: day.exercises.filter(ex => ex.id !== exerciseId) } : day
    );
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  const handleUpdateStage = (newStage: Stage) => {
    onUpdatePatient({ ...patient, routine: { ...patient.routine, stage: newStage } });
  };

  const handleAddDay = () => {
    if (patient.routine.days.length >= 7) return;
    const newDay: RoutineDay = { id: `day-${Date.now()}`, name: `Día ${patient.routine.days.length + 1}`, exercises: [] };
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: [...patient.routine.days, newDay] } });
  };

  const handleRemoveLastDay = () => {
    const lastDay = patient.routine.days[patient.routine.days.length - 1];
    if (patient.routine.days.length <= 1 || lastDay.exercises.length > 0) return;
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: patient.routine.days.slice(0, -1) } });
  };

  const handleRenameDay = (dayId: string, newName: string) => {
    const newDays = patient.routine.days.map(day => day.id === dayId ? { ...day, name: newName } : day);
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  const statsData = useMemo(() => {
    return [
      { name: `S-${currentWeekNum-2}`, volumen: 3450 },
      { name: `S-${currentWeekNum-1}`, volumen: 3800 },
      { name: `Actual`, volumen: 4100 },
    ];
  }, [currentWeekNum]);

  return (
    <div className="flex-1 h-full flex flex-col bg-slate-50 overflow-hidden relative">
      <header className="bg-white border-b border-slate-200 px-4 py-3 flex items-center justify-between shrink-0 z-30 pt-[calc(0.75rem+var(--sat))]">
        <div className="flex flex-col min-w-0">
          <div className="flex items-center gap-3">
            <h2 className="text-base font-black text-slate-900 leading-none truncate uppercase tracking-tighter">
                {patient.firstName} {patient.lastName}
            </h2>
            {/* BADGE DE SEMANA MAS VISIBLE */}
            <div className="bg-primary-600 text-white text-[10px] px-2.5 py-1 rounded-full font-black uppercase shadow-md flex items-center gap-1.5 animate-in fade-in zoom-in duration-500">
                <Calendar size={10} />
                SEMANA {currentWeekNum}
            </div>
          </div>
          <p className="text-[9px] text-slate-400 font-black mt-1.5 uppercase tracking-widest leading-none">{patient.condition}</p>
        </div>
        <div className="flex gap-2 items-center">
            <span className={`px-2.5 py-1.5 rounded-xl text-[8px] font-black uppercase ${patient.routine.stage === Stage.KINESIOLOGY ? 'bg-kine/10 text-kine' : 'bg-gym/10 text-gym'}`}>
                {patient.routine.stage}
            </span>
            {isKine && (
                <button onClick={() => setShowRoutineEditor(true)} className="bg-slate-900 text-white px-3 py-2 rounded-xl font-bold text-[9px] uppercase hover:bg-slate-800 transition-all flex items-center gap-1.5 shadow-md">
                    <Edit2 size={12} /> <span>Editar</span>
                </button>
            )}
            <button onClick={() => setShowHistory(!showHistory)} className={`p-2.5 rounded-xl border transition-all ${showHistory ? 'bg-primary-50 border-primary-200 text-primary-600' : 'bg-white border-slate-200 text-slate-400'}`}>
                <FileText size={18} />
            </button>
        </div>
      </header>

      {showHistory && (
          <div className="bg-slate-900 text-white p-3 shadow-xl z-20 border-b border-slate-800 animate-in slide-in-from-top duration-200">
              <div className="max-w-4xl mx-auto flex gap-4 items-center">
                  <textarea className="flex-1 h-12 bg-slate-800/50 text-slate-200 p-2 rounded-xl border border-slate-700 outline-none resize-none text-[10px]" value={notes} onChange={(e) => setNotes(e.target.value)} placeholder="Notas clínicas..." />
                  <button className="bg-primary-600 text-white p-3 rounded-xl hover:bg-primary-500 transition-colors shadow-lg"><Save size={18}/></button>
              </div>
          </div>
      )}

      {showRoutineEditor && (
          <div className="fixed inset-0 z-[100] bg-slate-50 flex flex-col pt-[var(--sat)] animate-in slide-in-from-bottom-5 duration-300">
              <header className="bg-white border-b border-slate-200 px-4 py-3 flex items-center justify-between shrink-0">
                  <div className="flex items-center gap-6">
                      <div className="flex bg-slate-100 p-1 rounded-xl">
                          <button onClick={() => handleUpdateStage(Stage.KINESIOLOGY)} className={`px-4 py-2 rounded-lg text-[9px] font-black uppercase transition-all ${patient.routine.stage === Stage.KINESIOLOGY ? 'bg-white text-kine shadow-sm' : 'text-slate-400'}`}>Kine</button>
                          <button onClick={() => handleUpdateStage(Stage.GYM)} className={`px-4 py-2 rounded-lg text-[9px] font-black uppercase transition-all ${patient.routine.stage === Stage.GYM ? 'bg-white text-gym shadow-sm' : 'text-slate-400'}`}>Gym</button>
                      </div>
                      <div className="flex items-center gap-2 bg-white px-3 py-1.5 rounded-xl border border-slate-200 shadow-sm">
                          <button onClick={handleRemoveLastDay} className="text-slate-400 hover:text-red-500 disabled:opacity-20 transition-colors"><Minus size={18}/></button>
                          <div className="flex flex-col items-center min-w-[40px]"><span className="text-[12px] font-black leading-none">{patient.routine.days.length}</span><span className="text-[6px] font-black uppercase text-slate-300 tracking-tighter">Días</span></div>
                          <button onClick={handleAddDay} disabled={patient.routine.days.length >= 7} className="text-slate-400 hover:text-primary-600 disabled:opacity-20 transition-colors"><Plus size={18}/></button>
                      </div>
                  </div>
                  <button onClick={() => setShowRoutineEditor(false)} className="p-2 hover:bg-slate-100 rounded-full transition-colors"><X size={24} /></button>
              </header>
              <div className="flex-1 overflow-x-auto p-4 bg-slate-50">
                  <div className="flex items-start gap-4 h-full min-w-max pb-10">
                      {patient.routine.days.map((day, dIdx) => (
                          <div key={day.id} className="w-64 bg-white rounded-3xl border border-slate-200 shadow-sm flex flex-col h-full shrink-0">
                              <div className="p-4 border-b border-slate-50 flex items-center justify-between">
                                  <input className="font-black text-xs text-slate-800 bg-transparent border-none focus:ring-0 p-0 w-full uppercase" value={day.name} onChange={(e) => handleRenameDay(day.id, e.target.value)} />
                              </div>
                              <div className="flex-1 overflow-y-auto p-3 space-y-2 scroll-container">
                                  {day.exercises.map((ex) => (
                                      <div key={ex.id} className="flex flex-col gap-2 p-3 bg-slate-50 rounded-2xl border border-transparent hover:border-slate-200 transition-all">
                                          <div className="flex items-center justify-between gap-2">
                                              <img src={ex.definition.videoUrl} className="w-8 h-8 rounded-lg object-cover" />
                                              <p className="font-bold text-[10px] text-slate-800 truncate flex-1 leading-tight">{ex.definition.name}</p>
                                              <button onClick={() => handleRemoveExercise(day.id, ex.id)} className="p-1.5 text-slate-300 hover:text-red-500"><Trash2 size={12}/></button>
                                          </div>
                                          <div className="grid grid-cols-3 gap-1">
                                              <input type="number" className="bg-white rounded-lg text-center font-black text-[10px] py-1 border-slate-100 focus:ring-primary-500" value={ex.targetSets} onChange={e => handleExerciseUpdate(ex.id, {targetSets: Number(e.target.value)})} />
                                              <input type="number" className="bg-white rounded-lg text-center font-black text-[10px] py-1 border-slate-100 focus:ring-primary-500" value={ex.targetReps} onChange={e => handleExerciseUpdate(ex.id, {targetReps: Number(e.target.value)})} />
                                              <input type="number" className="bg-white rounded-lg text-center font-black text-[10px] py-1 border-slate-100 focus:ring-primary-500" value={ex.targetLoad} onChange={e => handleExerciseUpdate(ex.id, {targetLoad: Number(e.target.value)})} />
                                          </div>
                                      </div>
                                  ))}
                                  <button onClick={() => setIsAddingExerciseModal({show: true, dayId: day.id})} className="w-full py-6 border-2 border-dashed border-slate-200 rounded-2xl text-[9px] font-black text-slate-400 uppercase hover:bg-slate-50 hover:text-primary-600 transition-all flex flex-col items-center gap-1.5">
                                      <Plus size={16} /> Agregar
                                  </button>
                              </div>
                          </div>
                      ))}
                  </div>
              </div>
          </div>
      )}

      {/* SUB-NAV CON BOTÓN DE NUEVA SEMANA */}
      <div className="bg-white border-b border-slate-200 px-4 flex justify-between shrink-0 h-16 items-center">
          <div className="flex gap-1 overflow-x-auto no-scrollbar items-center h-full pt-3">
            {patient.routine.days.map((day) => (
              <button key={day.id} onClick={() => {setActiveDayId(day.id); setViewMode('daily');}} className={`px-4 h-full rounded-t-2xl font-black text-[10px] uppercase tracking-wider transition-all border-t border-x ${activeDayId === day.id && viewMode === 'daily' ? 'bg-slate-50 border-slate-200 text-primary-600' : 'bg-white border-transparent text-slate-300 hover:text-slate-400'}`}>
                {day.name}
              </button>
            ))}

            <div className="w-[1.5px] h-8 bg-slate-100 mx-3 shrink-0"></div>

            {/* BOTÓN REFORZADO */}
            <button 
                onClick={handleStartNewWeek}
                className="flex items-center gap-2 px-5 py-2.5 bg-kine text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-lg shadow-kine/20 hover:scale-105 active:scale-95 transition-all shrink-0 mr-4"
            >
                <ChevronRightCircle size={16} />
                Finalizar Semana
            </button>
          </div>
          <div className="flex items-center gap-2 border-l pl-4 ml-2 shrink-0">
              <button onClick={() => setViewMode('plan')} title="Proyección Mensual" className={`p-2.5 rounded-2xl transition-all ${viewMode === 'plan' ? 'bg-primary-600 text-white shadow-lg' : 'bg-slate-50 text-slate-400 hover:bg-slate-100'}`}><Layers size={22}/></button>
              <button onClick={() => setViewMode('stats')} title="Estadísticas" className={`p-2.5 rounded-2xl transition-all ${viewMode === 'stats' ? 'bg-slate-900 text-white shadow-lg' : 'bg-slate-50 text-slate-400 hover:bg-slate-100'}`}><BarChart2 size={22}/></button>
          </div>
      </div>

      <main className="flex-1 overflow-y-auto p-4 md:p-8 scroll-container">
        <div className="max-w-4xl mx-auto h-full">
          {viewMode === 'daily' && activeDay ? (
              <div className="space-y-4 max-w-xl mx-auto pb-24">
                  <div className="flex justify-between items-end px-2 mb-2">
                      <div className="flex flex-col">
                        <span className="text-[10px] font-black text-primary-600 uppercase tracking-widest">Entrenamiento de hoy</span>
                        <h3 className="text-sm font-black text-slate-800 uppercase">{activeDay.name}</h3>
                      </div>
                      <span className="text-[10px] font-bold text-slate-300 italic">Ciclo Semana {currentWeekNum}</span>
                  </div>
                  {activeDay.exercises.map(ex => (
                    <ExerciseCard key={ex.id} exercise={ex} role={role} onUpdate={(id, up) => handleExerciseUpdate(id, up)} onShowHistory={(e) => setChartExercise(e)} onDelete={(id) => handleRemoveExercise(activeDayId, id)} />
                  ))}
                  {activeDay.exercises.length === 0 && (
                    <div className="py-24 text-center opacity-30">
                        <Activity className="mx-auto mb-4" size={40} />
                        <p className="text-xs font-black uppercase">Sin ejercicios para este día</p>
                    </div>
                  )}
              </div>
          ) : viewMode === 'plan' ? (
              <div className="space-y-12 pb-24 max-w-4xl mx-auto">
                  <div className="text-center space-y-3 mb-12">
                      <h3 className="text-2xl font-black text-slate-900 uppercase tracking-tighter">Proyección de Cargas</h3>
                      <p className="text-[11px] font-bold text-slate-400 uppercase tracking-[0.2em]">Mapa de las próximas semanas</p>
                  </div>

                  {[0, 1, 2, 3].map((offset) => {
                      const weekNum = currentWeekNum + offset;
                      const isCurrent = offset === 0;
                      return (
                        <div key={weekNum} className={`bg-white rounded-[3rem] border overflow-hidden shadow-md transition-all ${isCurrent ? 'border-primary-500 ring-8 ring-primary-50/50 scale-[1.02] z-10' : 'border-slate-200 opacity-90'}`}>
                            <div className={`px-8 py-5 flex justify-between items-center ${isCurrent ? 'bg-primary-600' : 'bg-slate-900'}`}>
                                <div className="flex items-center gap-3">
                                    <h4 className="text-white font-black text-sm uppercase tracking-[0.2em]">Semana {weekNum}</h4>
                                    {isCurrent && <span className="bg-white text-primary-600 px-3 py-1 rounded-full text-[9px] font-black uppercase shadow-sm">SEMANA ACTUAL</span>}
                                </div>
                            </div>
                            <div className="p-8 overflow-x-auto no-scrollbar">
                                <div className="flex gap-5 min-w-max pb-4">
                                    {patient.routine.days.map((day, idx) => (
                                        <div key={`${weekNum}-${day.id}`} className="w-56 shrink-0 bg-slate-50/70 rounded-3xl p-5 border border-slate-100">
                                            <p className="text-[10px] font-black text-slate-400 uppercase mb-4 pb-2 border-b">Día {idx+1}: {day.name}</p>
                                            <div className="space-y-3">
                                                {day.exercises.map(ex => (
                                                    <div key={`${weekNum}-${ex.id}`} className="flex flex-col gap-1.5 p-3 bg-white rounded-2xl border border-slate-100 shadow-sm">
                                                        <span className="text-[10px] font-black text-slate-800 truncate">{ex.definition.name}</span>
                                                        <div className="flex justify-between items-center mt-1">
                                                          <span className="text-[10px] font-black text-slate-400">{ex.targetSets}x{ex.targetReps}</span>
                                                          <span className="text-[12px] font-black text-primary-600">{ex.targetLoad}kg</span>
                                                        </div>
                                                    </div>
                                                ))}
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        </div>
                      );
                  })}
              </div>
          ) : viewMode === 'stats' ? (
              <div className="space-y-10 pb-24 max-w-4xl mx-auto">
                  {/* Vista Stats Resumida */}
                  <div className="grid grid-cols-1 md:grid-cols-3 gap-5">
                      <div className="bg-white p-8 rounded-[2rem] border border-slate-200 shadow-sm flex flex-col items-center">
                          <span className="text-[11px] font-black text-slate-400 uppercase mb-3 tracking-widest">Semana Activa</span>
                          <span className="text-4xl font-black text-slate-900">{currentWeekNum}</span>
                      </div>
                      <div className="bg-white p-8 rounded-[2rem] border border-slate-200 shadow-sm flex flex-col items-center">
                          <span className="text-[11px] font-black text-slate-400 uppercase mb-3 tracking-widest">Volumen</span>
                          <span className="text-4xl font-black text-primary-600">84%</span>
                      </div>
                      <div className="bg-white p-8 rounded-[2rem] border border-slate-200 shadow-sm flex flex-col items-center">
                          <span className="text-[11px] font-black text-slate-400 uppercase mb-3 tracking-widest">RPE</span>
                          <span className="text-4xl font-black text-gym">7.2</span>
                      </div>
                  </div>

                  <div className="space-y-8">
                      <div className="flex items-center gap-4 px-2">
                        <div className="p-2.5 bg-slate-900 rounded-xl text-white"><History size={20} /></div>
                        <h4 className="font-black text-base uppercase text-slate-900 leading-none">Historial Real</h4>
                      </div>

                      {[1, 2].map((num) => {
                          const weekToShow = currentWeekNum - num;
                          if (weekToShow < 1) return null;
                          return (
                            <div key={num} className="bg-white rounded-[2.5rem] border border-slate-200 overflow-hidden shadow-sm">
                                <div className="bg-slate-900 px-8 py-4 flex justify-between items-center">
                                    <h4 className="text-white font-black text-[11px] uppercase tracking-[0.2em]">Semana {weekToShow} (Archivado)</h4>
                                </div>
                                <div className="p-6 overflow-x-auto no-scrollbar">
                                    <div className="flex gap-4 min-w-max">
                                        {patient.routine.days.map((day, idx) => (
                                            <div key={`hist-${num}-${day.id}`} className="w-56 bg-slate-50 rounded-3xl p-5 border border-slate-100">
                                                <p className="text-[9px] font-black text-slate-400 uppercase mb-4">Día {idx+1}</p>
                                                <div className="space-y-2.5">
                                                    {day.exercises.map(ex => (
                                                      <div key={`h-ex-${ex.id}`} className="p-3 bg-white rounded-2xl border border-slate-100 shadow-sm">
                                                          <p className="font-bold text-[10px] text-slate-700 truncate mb-2">{ex.definition.name}</p>
                                                          <div className="flex justify-between items-center">
                                                              <span className="text-[9px] font-bold text-slate-400 uppercase">{ex.targetLoad}kg</span>
                                                              <span className="text-[10px] font-black text-slate-900">Finalizado</span>
                                                          </div>
                                                      </div>
                                                    ))}
                                                </div>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            </div>
                          );
                      })}
                  </div>
              </div>
          ) : null}
        </div>
      </main>

      {chartExercise && <ProgressChart exercise={chartExercise} onClose={() => setChartExercise(null)} />}

      {isAddingExerciseModal.show && (
          <div className="fixed inset-0 z-[350] bg-slate-900/40 backdrop-blur-sm flex items-center justify-center p-4">
              <div className="bg-white w-full max-w-md h-[75vh] rounded-[3rem] shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95 duration-200">
                  <div className="p-6 border-b flex items-center gap-4">
                      <div className="relative flex-1">
                          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={20} />
                          <input type="text" placeholder="Buscar ejercicio..." className="w-full pl-12 pr-4 py-4 bg-slate-50 border-none rounded-2xl text-[12px] font-bold outline-none" value={exerciseSearch} onChange={e => setExerciseSearch(e.target.value)} />
                      </div>
                      <button onClick={() => { setIsAddingExerciseModal({show:false, dayId:''}); setSelectedExerciseIds([]); }} className="p-2 text-slate-400 hover:bg-slate-50 rounded-full"><X size={28}/></button>
                  </div>
                  <div className="flex-1 overflow-y-auto p-4 space-y-2 scroll-container">
                      {EXERCISES.filter(ex => ex.name.toLowerCase().includes(exerciseSearch.toLowerCase())).map(ex => {
                          const isSelected = selectedExerciseIds.includes(ex.id);
                          return (
                              <button key={ex.id} onClick={() => setSelectedExerciseIds(prev => isSelected ? prev.filter(i => i !== ex.id) : [...prev, ex.id])} className={`w-full flex items-center p-4 rounded-3xl border-2 transition-all text-left ${isSelected ? 'bg-primary-50 border-primary-500 shadow-md' : 'bg-white border-slate-50 hover:border-slate-100'}`}>
                                  <div className="mr-4">{isSelected ? <CheckSquare size={24} className="text-primary-600"/> : <Square size={24} className="text-slate-200"/>}</div>
                                  <img src={ex.videoUrl} className="w-14 h-14 rounded-2xl object-cover mr-4" />
                                  <div className="flex-1 min-w-0">
                                      <p className="font-black text-slate-800 text-[12px] truncate uppercase leading-none">{ex.name}</p>
                                      <span className="text-[9px] text-slate-400 font-black uppercase mt-2 tracking-widest inline-block">{ex.category}</span>
                                  </div>
                              </button>
                          );
                      })}
                  </div>
                  <div className="p-8 bg-white border-t">
                        <button disabled={selectedExerciseIds.length === 0} className="bg-primary-600 text-white w-full py-5 rounded-2xl font-black text-[11px] uppercase tracking-widest disabled:opacity-30 shadow-xl shadow-primary-200 transition-all active:scale-95" onClick={() => {
                                const newExs: RoutineExercise[] = selectedExerciseIds.map(id => ({
                                    id: `re-${Date.now()}-${id}`, definitionId: id, definition: EXERCISES.find(e => e.id === id)!,
                                    targetSets: 3, targetReps: 12, targetLoad: 0, isDone: false, history: []
                                }));
                                const newDays = patient.routine.days.map(d => d.id === isAddingExerciseModal.dayId ? { ...d, exercises: [...d.exercises, ...newExs] } : d);
                                onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
                                setIsAddingExerciseModal({show:false, dayId:''});
                                setSelectedExerciseIds([]);
                            }}>Confirmar ({selectedExerciseIds.length})</button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Patient, RoutineExercise, Stage, UserRole, RoutineDay, ExerciseLog } from '../types';
import { EXERCISES } from '../constants';
import { ExerciseCard } from './ExerciseCard';
import { ProgressChart } from './ProgressChart';
import { 
  AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer
} from 'recharts';
import { 
    FileText, Plus, Search, X, Calendar, Trash2, Edit2, Save,
    Activity, Minus, Layers, TrendingUp, CheckSquare, Square, BarChart2, CheckCircle2, History, ChevronRightCircle
} from 'lucide-react';

interface PatientDetailProps {
  patient: Patient;
  role: UserRole;
  onUpdatePatient: (updated: Patient) => void;
}

export const PatientDetail: React.FC<PatientDetailProps> = ({
  patient,
  role,
  onUpdatePatient,
}) => {
  // Estado local para la navegación
  const [activeDayId, setActiveDayId] = useState<string>(patient.routine.days[0]?.id || '');
  const [viewMode, setViewMode] = useState<'daily' | 'plan' | 'stats'>('daily');
  const [showHistory, setShowHistory] = useState(false);
  const [showRoutineEditor, setShowRoutineEditor] = useState(false);

  // Estados para modales y edición
  const [chartExercise, setChartExercise] = useState<RoutineExercise | null>(null);
  const [exerciseSearch, setExerciseSearch] = useState('');
  const [selectedExerciseIds, setSelectedExerciseIds] = useState<string[]>([]);
  const [isAddingExerciseModal, setIsAddingExerciseModal] = useState<{show: boolean, dayId: string}>({show: false, dayId: ''});
  const [notes, setNotes] = useState(patient.history[0] || '');

  const isKine = role === UserRole.KINE;

  // IMPORTANTE: Obtenemos el número de semana siempre de la prop patient
  const currentWeek = patient.routine.currentWeek || 1;

  // Sincronizar el día activo si cambia la rutina
  useEffect(() => {
    if (patient.routine.days.length > 0 && (!activeDayId || !patient.routine.days.find(d => d.id === activeDayId))) {
        setActiveDayId(patient.routine.days[0].id);
    }
  }, [patient.routine.days, activeDayId]);

  const activeDay = patient.routine.days.find(d => d.id === activeDayId);

  // LOGICA MAESTRA: FINALIZAR SEMANA
  const handleStartNewWeek = () => {
    const confirmText = `¿Finalizar la SEMANA ${currentWeek}?\n\nEsto hará:\n1. Destildar todos los ejercicios realizados.\n2. Archivar el progreso en el historial.\n3. Avanzar a la SEMANA ${currentWeek + 1}.`;

    if (!window.confirm(confirmText)) return;

    const today = new Date().toISOString().split('T')[0];

    // Clonamos y reseteamos profundamente
    const resetDays = patient.routine.days.map(day => ({
      ...day,
      exercises: day.exercises.map(ex => {
        const newHistory = [...(ex.history || [])];

        // Si el ejercicio se marcó como hecho, guardamos esa foto en el historial
        if (ex.isDone) {
          newHistory.push({
            date: today,
            load: ex.targetLoad,
            reps: ex.targetReps,
            rpe: ex.currentRpe || 5
          });
        }

        return {
          ...ex,
          isDone: false,        // DESTILDAR (RESET)
          currentRpe: undefined, // LIMPIAR ESFUERZO
          history: newHistory
        };
      })
    }));

    // Actualizamos el objeto completo
    const updatedPatient: Patient = {
      ...patient,
      lastVisit: today,
      routine: {
        ...patient.routine,
        currentWeek: currentWeek + 1, // INCREMENTAR SEMANA
        days: resetDays
      }
    };

    onUpdatePatient(updatedPatient);

    // Feedback inmediato
    setViewMode('daily');
    alert(`¡Semana ${currentWeek} cerrada con éxito!\nAhora estás en la Semana ${currentWeek + 1}.`);
  };

  const handleExerciseUpdate = (exerciseId: string, updates: Partial<RoutineExercise>) => {
    const newDays = patient.routine.days.map(day => ({
        ...day,
        exercises: day.exercises.map(ex => ex.id === exerciseId ? { ...ex, ...updates } : ex)
    }));
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  const handleRemoveExercise = (dayId: string, exerciseId: string) => {
    const newDays = patient.routine.days.map(day => 
        day.id === dayId ? { ...day, exercises: day.exercises.filter(ex => ex.id !== exerciseId) } : day
    );
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  const handleUpdateStage = (newStage: Stage) => {
    onUpdatePatient({ ...patient, routine: { ...patient.routine, stage: newStage } });
  };

  const handleAddDay = () => {
    if (patient.routine.days.length >= 7) return;
    const newDay: RoutineDay = { id: `day-${Date.now()}`, name: `Día ${patient.routine.days.length + 1}`, exercises: [] };
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: [...patient.routine.days, newDay] } });
  };

  const handleRemoveLastDay = () => {
    const lastDay = patient.routine.days[patient.routine.days.length - 1];
    if (patient.routine.days.length <= 1 || lastDay.exercises.length > 0) return;
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: patient.routine.days.slice(0, -1) } });
  };

  const handleRenameDay = (dayId: string, newName: string) => {
    const newDays = patient.routine.days.map(day => day.id === dayId ? { ...day, name: newName } : day);
    onUpdatePatient({ ...patient, routine: { ...patient.routine, days: newDays } });
  };

  return (
    <div className="flex-1 h-full flex flex-col bg-slate-50 overflow-hidden relative">
      {/* HEADER DINÁMICO */}
      <header className="bg-white border-b border-slate-200 px-4 py-3 flex items-center justify-between shrink-0 z-30 pt-[calc(0.75rem+var(--sat))]">
        <div className="flex flex-col min-w-0">
          <div className="flex items-center gap-3">
            <h2 className="text-base font-black text-slate-900 leading-none truncate uppercase tracking-tighter">
                {patient.firstName} {patient.lastName}
            </h2>
            {/* BADGE DE SEMANA - SE ACTUALIZA CON LA PROP */}
            <div key={currentWeek} className="bg-primary-600 text-white text-[10px] px-3 py-1 rounded-full font-black uppercase shadow-lg shadow-primary-200 flex items-center gap-1.5 animate-in zoom-in fade-in duration-500">
                <Calendar size={12} />
                Semana {currentWeek}
            </div>
          </div>
          <p className="text-[9px] text-slate-400 font-black mt-1.5 uppercase tracking-widest leading-none">{patient.condition}</p>
        </div>
        <div className="flex gap-2 items-center">
            <span className={`px-2.5 py-1.5 rounded-xl text-[8px] font-black uppercase ${patient.routine.stage === Stage.KINESIOLOGY ? 'bg-kine/10 text-kine' : 'bg-gym/10 text-gym'}`}>
                {patient.routine.stage}
            </span>
            {isKine && (
                <button onClick={() => setShowRoutineEditor(true)} className="bg-slate-900 text-white px-3 py-2 rounded-xl font-bold text-[9px] uppercase hover:bg-slate-800 transition-all flex items-center gap-1.5 shadow-md">
                    <Edit2 size={12} /> <span>Editar Rutina</span>
                </button>
            )}
            <button onClick={() => setShowHistory(!showHistory)} className={`p-2.5 rounded-xl border transition-all ${showHistory ? 'bg-primary-50 border-primary-200 text-primary-600' : 'bg-white border-slate-200 text-slate-400'}`}>
                <FileText size={18} />
            </button>
        </div>
      </header>

      {/* SUB-NAV CON BOTÓN DE CIERRE DE SEMANA */}
      <div className="bg-white border-b border-slate-200 px-4 flex justify-between shrink-0 h-16 items-center">
          <div className="flex gap-1 overflow-x-auto no-scrollbar items-center h-full pt-3">
            {patient.routine.days.map((day) => (
              <button key={day.id} onClick={() => {setActiveDayId(day.id); setViewMode('daily');}} className={`px-5 h-full rounded-t-2xl font-black text-[10px] uppercase tracking-wider transition-all border-t border-x ${activeDayId === day.id && viewMode === 'daily' ? 'bg-slate-50 border-slate-200 text-primary-600' : 'bg-white border-transparent text-slate-300 hover:text-slate-400'}`}>
                {day.name}
              </button>
            ))}

            <div className="w-[1.5px] h-8 bg-slate-100 mx-3 shrink-0"></div>

            <button 
                onClick={handleStartNewWeek}
                className="flex items-center gap-2 px-6 py-2.5 bg-kine text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl shadow-kine/20 hover:scale-105 active:scale-95 transition-all shrink-0 mr-4"
            >
                <ChevronRightCircle size={16} />
                Finalizar Semana
            </button>
          </div>
          <div className="flex items-center gap-2 border-l pl-4 ml-2 shrink-0">
              <button onClick={() => setViewMode('plan')} title="Proyección Mensual" className={`p-2.5 rounded-2xl transition-all ${viewMode === 'plan' ? 'bg-primary-600 text-white shadow-lg' : 'bg-slate-50 text-slate-400 hover:bg-slate-100'}`}><Layers size={22}/></button>
              <button onClick={() => setViewMode('stats')} title="Estadísticas" className={`p-2.5 rounded-2xl transition-all ${viewMode === 'stats' ? 'bg-slate-900 text-white shadow-lg' : 'bg-slate-50 text-slate-400 hover:bg-slate-100'}`}><BarChart2 size={22}/></button>
          </div>
      </div>

      <main className="flex-1 overflow-y-auto p-4 md:p-8 scroll-container">
        <div className="max-w-4xl mx-auto h-full">
          {/* VISTA DIARIA */}
          {viewMode === 'daily' && activeDay ? (
              <div className="space-y-4 max-w-xl mx-auto pb-24">
                  <div className="flex justify-between items-end px-2 mb-2">
                      <div className="flex flex-col">
                        <span className="text-[10px] font-black text-primary-600 uppercase tracking-widest">Plan del Día</span>
                        <h3 className="text-sm font-black text-slate-800 uppercase">{activeDay.name}</h3>
                      </div>
                      <span className="text-[10px] font-bold text-slate-300 italic">Ciclo Semana {currentWeek}</span>
                  </div>
                  {activeDay.exercises.map(ex => (
                    <ExerciseCard key={ex.id} exercise={ex} role={role} onUpdate={(id, up) => handleExerciseUpdate(id, up)} onShowHistory={(e) => setChartExercise(e)} onDelete={(id) => handleRemoveExercise(activeDayId, id)} />
                  ))}
                  {activeDay.exercises.length === 0 && (
                    <div className="py-24 text-center">
                        <Activity className="mx-auto mb-4 text-slate-200" size={48} />
                        <p className="text-xs font-black text-slate-400 uppercase tracking-widest">Día sin ejercicios</p>
                    </div>
                  )}
              </div>
          ) : viewMode === 'plan' ? (
              /* PLAN MENSUAL ACTUALIZADO */
              <div className="space-y-12 pb-24 max-w-4xl mx-auto">
                  <div className="text-center space-y-3 mb-12">
                      <h3 className="text-2xl font-black text-slate-900 uppercase tracking-tighter">Proyección Mensual</h3>
                      <p className="text-[11px] font-bold text-slate-400 uppercase tracking-[0.2em]">Semanas proyectadas desde la actual</p>
                  </div>

                  {/* Mostramos 4 semanas: actual y 3 siguientes */}
                  {[0, 1, 2, 3].map((offset) => {
                      const weekNum = currentWeek + offset;
                      const isCurrent = offset === 0;
                      return (
                        <div key={weekNum} className={`bg-white rounded-[3rem] border overflow-hidden shadow-md transition-all ${isCurrent ? 'border-primary-500 ring-8 ring-primary-50/50 scale-[1.02] z-10' : 'border-slate-200 opacity-80'}`}>
                            <div className={`px-8 py-5 flex justify-between items-center ${isCurrent ? 'bg-primary-600' : 'bg-slate-900'}`}>
                                <div className="flex items-center gap-3">
                                    <h4 className="text-white font-black text-sm uppercase tracking-[0.2em]">Semana {weekNum}</h4>
                                    {isCurrent && <span className="bg-white text-primary-600 px-3 py-1 rounded-full text-[9px] font-black uppercase shadow-sm">SEMANA ACTUAL</span>}
                                </div>
                                <span className="text-white/30 text-[9px] font-black uppercase tracking-widest">Proyección</span>
                            </div>
                            <div className="p-8 overflow-x-auto no-scrollbar">
                                <div className="flex gap-5 min-w-max pb-4">
                                    {patient.routine.days.map((day, idx) => (
                                        <div key={`${weekNum}-${day.id}`} className="w-56 shrink-0 bg-slate-50/70 rounded-3xl p-5 border border-slate-100">
                                            <p className="text-[10px] font-black text-slate-400 uppercase mb-4 pb-2 border-b">Día {idx+1}</p>
                                            <div className="space-y-3">
                                                {day.exercises.map(ex => (
                                                    <div key={`${weekNum}-${ex.id}`} className="flex flex-col gap-1.5 p-3 bg-white rounded-2xl border border-slate-100 shadow-sm">
                                                        <span className="text-[10px] font-black text-slate-800 truncate">{ex.definition.name}</span>
                                                        <div className="flex justify-between items-center mt-1">
                                                          <span className="text-[10px] font-black text-slate-400">{ex.targetSets}x{ex.targetReps}</span>
                                                          <span className="text-[12px] font-black text-primary-600">{ex.targetLoad}kg</span>
                                                        </div>
                                                    </div>
                                                ))}
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        </div>
                      );
                  })}
              </div>
          ) : viewMode === 'stats' ? (
              /* VISTA DE ESTADÍSTICAS */
              <div className="space-y-10 pb-24 max-w-4xl mx-auto">
                  <div className="grid grid-cols-1 md:grid-cols-3 gap-5">
                      <div className="bg-white p-8 rounded-[2rem] border border-slate-200 shadow-sm flex flex-col items-center">
                          <span className="text-[11px] font-black text-slate-400 uppercase mb-3 tracking-widest">Semana Activa</span>
                          <span className="text-4xl font-black text-slate-900">{currentWeek}</span>
                      </div>
                      <div className="bg-white p-8 rounded-[2rem] border border-slate-200 shadow-sm flex flex-col items-center">
                          <span className="text-[11px] font-black text-slate-400 uppercase mb-3 tracking-widest">Cumplimiento</span>
                          <span className="text-4xl font-black text-kine">90%</span>
                      </div>
                      <div className="bg-white p-8 rounded-[2rem] border border-slate-200 shadow-sm flex flex-col items-center">
                          <span className="text-[11px] font-black text-slate-400 uppercase mb-3 tracking-widest">Esfuerzo Medio</span>
                          <span className="text-4xl font-black text-gym">7.4</span>
                      </div>
                  </div>

