                    <ExerciseCard key={ex.id} exercise={ex} role={role} onUpdate={(id, up) => handleExerciseUpdate(id, up)} onShowHistory={(e) => setChartExercise(e)} onDelete={(id) => handleRemoveExercise(activeDayId, id)} />
