const generateHistory = (baseLoad: number): any[] => {
  const history = [];
  let currentLoad = baseLoad;
  for (let i = 1; i <= 5; i++) {
    history.push({
      date: new Date(Date.now() - (6 - i) * 86400000 * 7).toISOString().split('T')[0],
      week: i,
      load: currentLoad,
      reps: 10,
      rpe: Math.floor(Math.random() * 3) + 6,
    });
    currentLoad += 2.5;
  }
  return history;
};

